# ============================================================================
# SINGLE INSTANCE LOCK
# ============================================================================

def acquire_single_instance_lock():
    """Sprawdź czy to jedyna instancja aplikacji.
    
    Returns:
        lock_file Path jeśli sukces, None jeśli inna instancja działa
    """
    lock_file = Path(DEFAULT_LOCAL_DIR) / "app.lock"
    
    # Sprawdź czy lock istnieje
    if lock_file.exists():
        try:
            # Sprawdź czy proces jeszcze działa
            with open(lock_file, 'r') as f:
                data = json.load(f)
                old_pid = data.get('pid')
                
                # Sprawdź czy proces o tym PID nadal działa
                try:
                    # Na Windows i Linux działa kill(pid, 0)
                    os.kill(old_pid, 0)
                    # Proces istnieje - nie możemy uruchomić drugiej instancji
                    return None
                except (OSError, ProcessLookupError):
                    # Proces nie istnieje - usuwamy stary lock
                    print(f"🧹 Stary lock z PID {old_pid} (proces martwy) - usuwam")
                    lock_file.unlink()
        except:
            # Błąd odczytu - usuwamy lock i próbujemy ponownie
            try:
                lock_file.unlink()
            except:
                pass
    
    # Twórz nowy lock
    try:
        lock_file.parent.mkdir(parents=True, exist_ok=True)
        with open(lock_file, 'w') as f:
            json.dump({
                'pid': os.getpid(),
                'started_at': datetime.now().isoformat(),
                'computer': socket.gethostname()
            }, f)
        return lock_file
    except Exception as e:
        print(f"⚠️  Nie można utworzyć lock file: {e}")
        return lock_file  # Kontynuuj mimo błędu


def release_single_instance_lock(lock_file):
    """Usuń lock pliku aplikacji"""
    if lock_file and lock_file.exists():
        try:
            lock_file.unlink()
            print(f"🗑️  Usunięto app.lock")
        except Exception as e:
            print(f"⚠️  Błąd usuwania app.lock: {e}")


