    def _safe_db_call(self, func, timeout_s: float = 5.0, label: str = "DB"):
        """Wykonaj operację bazodanową w wątku z timeoutem.
        
        KLUCZOWE: Zapobiega zawieszaniu głównego wątku GUI na martwym SMB.
        Po uśpieniu/obudzeniu komputera, sqlite3 na SMB może wisieć 30-60s.
        
        Args:
            func: Funkcja do wywołania (bez argumentów)
            timeout_s: Maksymalny czas oczekiwania
            label: Etykieta do logów
        
        Returns:
            (True, result) jeśli sukces
            (False, error) jeśli błąd lub timeout
        """
        result = [None]
        error = [None]
        
        def _worker():
            try:
                result[0] = func()
            except Exception as e:
                error[0] = e
        
        t = threading.Thread(target=_worker, daemon=True)
        t.start()
        t.join(timeout=timeout_s)
        
        if t.is_alive():
            print(f"⚠️  _safe_db_call({label}): TIMEOUT ({timeout_s}s) — dysk sieciowy nie odpowiada")
            return (False, TimeoutError(f"{label}: timeout {timeout_s}s"))
        
        if error[0]:
            return (False, error[0])
        
        return (True, result[0])
    
