    def _show_connection_lost_banner(self, source: str = "master"):
        """Pokaż niemodalny banner o utracie połączenia (zamiast messagebox).
        
        Banner nie blokuje GUI - użytkownik może kliknąć 'Ponów' kiedy chce.
        Ta metoda NIGDY nie powinna crashować — cały kod GUI owrapowany.
        """
        try:
            self._show_connection_lost_banner_inner(source)
        except Exception as e:
            # Absolutnie NIE może crashować — loguj i informuj na statusbar
            print(f"⚠️  _show_connection_lost_banner CRASH (pominięto): {e}")
            import traceback
            traceback.print_exc()
            self._connection_lost_shown = True  # Ustaw flagę mimo błędu
            try:
                if hasattr(self, 'info_label'):
                    self.info_label.config(text="🔴 Brak połączenia z bazą", fg="red")
            except:
                pass
    
    def _show_connection_lost_banner_inner(self, source: str = "master"):
        """Wewnętrzna implementacja bannera — może rzucić wyjątek."""
        if self._connection_lost_shown:
            return  # Już widoczny
        
        self._connection_lost_shown = True
        
        # Uruchom auto-reconnect timer (sprawdza co 5s)
        self._start_auto_reconnect_timer(source)
        
        # Utwórz banner na górze okna
        if self._connection_lost_banner:
            try:
                self._connection_lost_banner.destroy()
            except:
                pass
        
        banner = tk.Frame(self, bg="#e74c3c", height=40)
        # Znajdź pierwszy packed widget (Menu nie jest packed, więc skip)
        _pack_before = None
        try:
            for child in self.winfo_children():
                try:
                    child.pack_info()
                    _pack_before = child
                    break
                except tk.TclError:
                    continue  # widget nie jest packed (np. Menu)
        except Exception:
            pass
        
        if _pack_before:
            banner.pack(fill=tk.X, before=_pack_before)
        else:
            banner.pack(fill=tk.X, side=tk.TOP)
        banner.pack_propagate(False)
        
        if source == "master":
            msg = "⚠️  Utracono połączenie z bazą główną (dysk sieciowy niedostępny) - auto-sprawdzanie co 5s..."
        else:
            msg = "⚠️  Utracono połączenie z bazą projektu (dysk sieciowy niedostępny) - auto-sprawdzanie co 5s..."
        
        lbl = tk.Label(banner, text=msg, bg="#e74c3c", fg="white", 
                       font=("Arial", 10, "bold"))
        lbl.pack(side=tk.LEFT, padx=10, pady=5)
        
        def try_reconnect():
            """Próba ponownego połączenia po kliknięciu przycisku."""
            try:
                btn_retry.config(state=tk.DISABLED, text="⏳ Łączenie...")
                self.update_idletasks()
                
                def _reconnect_worker():
                    try:
                        if source == "master":
                            ok = self.db_manager.ensure_master_alive()
                        else:
                            ok = self.db_manager.ensure_project_alive()
                    except Exception as e:
                        self._safe_print(f"⚠️  _reconnect_worker exception: {e}")
                        ok = False
                    
                    try:
                        self.after(0, lambda: _reconnect_done(ok))
                    except Exception as e:
                        self._safe_print(f"⚠️  after() failed in _reconnect_worker: {e}")
                
                def _reconnect_done(ok):
                    try:
                        if ok:
                            self._hide_connection_lost_banner()  # Tutaj automatycznie odświeży użytkowników
                            if hasattr(self, 'info_label'):
                                try:
                                    self.info_label.config(text="✅ Połączenie przywrócone", fg="lime")
                                except:
                                    pass
                            # Odśwież dane w tabeli
                            try:
                                self.refresh_data()
                            except Exception as e:
                                self._safe_print(f"⚠️  Błąd odświeżania danych: {e}")
                        else:
                            btn_retry.config(state=tk.NORMAL, text="🔄 Ponów połączenie")
                    except Exception as e:
                        self._safe_print(f"❌ _reconnect_done crashed: {e}")
                
                threading.Thread(target=_reconnect_worker, daemon=True).start()
            except Exception as e:
                self._safe_print(f"❌ try_reconnect crashed: {e}")
        
        btn_retry = tk.Button(banner, text="🔄 Ponów połączenie", 
                              command=try_reconnect,
                              bg="#c0392b", fg="white", font=("Arial", 9, "bold"),
                              relief=tk.FLAT, padx=10)
        btn_retry.pack(side=tk.RIGHT, padx=10, pady=5)
        
        self._connection_lost_banner = banner
        
        # Aktualizuj info_label
        if hasattr(self, 'info_label'):
            try:
                self.info_label.config(text="🔴 Brak połączenia z bazą", fg="red")
            except:
                pass
        
        self._safe_print(f"🔴 Banner utraty połączenia pokazany ({source})")
    
    def _hide_connection_lost_banner(self):
        """Ukryj banner utraty połączenia (połączenie przywrócone)."""
        try:
            if not self._connection_lost_shown:
                return
            
            self._connection_lost_shown = False
            
            # Zatrzymaj auto-reconnect timer
            try:
                self._stop_auto_reconnect_timer()
            except Exception as e:
                self._safe_print(f"⚠️  Błąd zatrzymania timera: {e}")
            
            if self._connection_lost_banner:
                try:
                    self._connection_lost_banner.destroy()
                except:
                    pass
                self._connection_lost_banner = None
            
            # KRYTYCZNE: Wymuś pełny reconnect do bazy master
            # Po utracie połączenia SQLite connection jest uszkodzone
            # i próby zapytań kończą się "disk I/O error"
            try:
                self._safe_print(f"🔄 Wymuszam pełny reconnect do master.sqlite...")
                if self.db_manager and self.db_manager.master_con:
                    try:
                        self.db_manager.master_con.close()
                    except:
                        pass
                    self.db_manager.master_con = None
                
                # Reconnect z odpowiednią rolą (READ-WRITE dla ADMIN/USER$$)
                if self.db_manager:
                    if self.current_user_role in ("ADMIN", "USER$$", "USER$"):
                        self.db_manager.reconnect_master_rw()
                    else:
                        self.db_manager.connect_master()
                
                self._safe_print(f"✅ Pełny reconnect do master.sqlite zakończony")
            except Exception as e:
                self._safe_print(f"⚠️  Błąd reconnectu do master: {e}")
            
            # Odśwież listę użytkowników po przywróceniu połączenia
            try:
                self.load_users()
                self._safe_print(f"✅ Lista użytkowników odświeżona po przywróceniu połączenia")
            except Exception as e:
                self._safe_print(f"⚠️  Błąd odświeżania użytkowników po reconnect: {e}")
            
            self._safe_print(f"🟢 Banner utraty połączenia ukryty - połączenie OK")
        except Exception as e:
            # KRYTYCZNE - nie może crashować
            self._safe_print(f"❌ CRITICAL: _hide_connection_lost_banner crashed: {e}")

    def _handle_db_locked(self, error: Exception) -> bool:
        """Obsłuż błąd 'database is locked' — typowy po uśpieniu/obudzeniu komputera.
        
        Próbuje wymusić reconnect do master.sqlite i informuje użytkownika.
        
        Args:
            error: Wyjątek sqlite3.OperationalError
            
        Returns:
            True jeśli reconnect się udał i operację można powtórzyć,
            False jeśli nie udało się przywrócić połączenia
        """
        import time
        err_msg = str(error).lower()
        
        if "locked" not in err_msg:
            return False
        
        print(f"🔄 _handle_db_locked: wykryto 'database is locked' — próba reconnect...")
        
        # Pokaż status użytkownikowi
        if hasattr(self, 'info_label'):
            try:
                self.info_label.config(text="🔄 Odbudowuję połączenie z bazą...", fg="orange")
                self.update_idletasks()
            except:
                pass
        
        # Wymuś reconnect — W WĄTKU z timeoutem (żeby nie zawiesić GUI)
        ok, reconnect_result = self._safe_db_call(
            self.db_manager._reconnect_master_after_locked,
            timeout_s=8.0,
            label="_reconnect_master"
        )
        
        if ok and reconnect_result:
            print(f"✅ _handle_db_locked: reconnect OK")
            if hasattr(self, 'info_label'):
                try:
                    self.info_label.config(text="✅ Połączenie przywrócone", fg="green")
                except:
                    pass
            self._hide_connection_lost_banner()
            return True
        else:
            print(f"❌ _handle_db_locked: reconnect failed — pokazuję banner")
            self._show_connection_lost_banner("master")
            return False

    def _start_heartbeat_timer(self):
        """Uruchom timer heartbeat - odświeżanie locków co 2 minuty."""
        print(f"💓 Uruchamiam timer heartbeat (2 min)...")
        print(f"   interval_ms = {self._heartbeat_interval_ms}")
        print(f"   lock_manager = {self.lock_manager}")
        # Pierwsze odświeżenie po 2 minutach
        self._heartbeat_after_id = self.after(self._heartbeat_interval_ms, self._heartbeat_tick)
        print(f"   after_id = {self._heartbeat_after_id}")
        print(f"✅ Timer heartbeat zaplanowany")
    
    def _stop_heartbeat_timer(self):
        """Zatrzymaj timer heartbeat."""
        if not self._heartbeat_after_id:
            return
        try:
            self.after_cancel(self._heartbeat_after_id)
        except Exception:
            pass
        self._heartbeat_after_id = None
        print("💔 Timer heartbeat zatrzymany")
    
    def _heartbeat_tick(self):
        """Tick timera heartbeat - odśwież locki W OSOBNYM WĄTKU (nie blokuje GUI)."""
        def _heartbeat_worker():
            try:
                from datetime import datetime
                print(f"💓 HEARTBEAT TICK o {datetime.now().strftime('%H:%M:%S')}")
                if self.lock_manager:
                    self.lock_manager.refresh_all_my_locks()
                    self.lock_manager.cleanup_stale_locks()
                else:
                    print("⚠️  Heartbeat tick: brak lock_manager!")
                
                # Sprawdź nowe wiadomości w chacie
                self.after(0, self.check_new_chat_messages)
                
            except Exception as e:
                print(f"❌ Błąd w heartbeat tick: {e}")
                import traceback
                traceback.print_exc()
                # Jeśli błąd sieciowy - pokaż banner (z GUI thread)
                err_msg = str(e).lower()
                if any(kw in err_msg for kw in ("network", "errno", "permission", "timeout", "refused")):
                    self.after(0, lambda: self._show_connection_lost_banner("master"))
        
        # Uruchom w osobnym wątku z timeoutem 10s
        t = threading.Thread(target=_heartbeat_worker, daemon=True)
        t.start()
        
        # Zaplanuj następny tick (nawet jeśli był błąd)
        self._heartbeat_after_id = self.after(self._heartbeat_interval_ms, self._heartbeat_tick)

    def _start_auto_reconnect_timer(self, source: str = "master"):
        """Uruchom timer który automatycznie próbuje odzyskać połączenie co 5 sekund.
        
        Działa tylko gdy banner jest widoczny (_connection_lost_shown == True).
        """
        try:
            # Zatrzymaj poprzedni timer jeśli istnieje
            self._stop_auto_reconnect_timer()
            
            self._safe_print(f"🔄 Uruchamiam auto-reconnect timer (co 5s) dla {source}...")
            
            def _auto_reconnect_tick():
                """Próba automatycznego reconnectu"""
                try:
                    # Jeśli banner został ukryty - zatrzymaj timer
                    if not self._connection_lost_shown:
                        self._safe_print(f"🛑 Auto-reconnect: banner ukryty - zatrzymuję timer")
                        return
                    
                    self._safe_print(f"🔄 Auto-reconnect tick - sprawdzam połączenie...")
                    
                    def _check_worker():
                        try:
                            if source == "master":
                                ok = self.db_manager.ensure_master_alive()
                            else:
                                ok = self.db_manager.ensure_project_alive()
                        except Exception as e:
                            self._safe_print(f"⚠️  Auto-reconnect exception: {e}")
                            ok = False
                        
                        # Bezpieczne wywołanie GUI z wątku
                        try:
                            self.after(0, lambda: _check_done(ok))
                        except Exception as e:
                            self._safe_print(f"⚠️  Auto-reconnect after() failed: {e}")
                    
                    def _check_done(ok):
                        try:
                            if ok:
                                self._safe_print(f"✅ Auto-reconnect: połączenie przywrócone!")
                                self._hide_connection_lost_banner()
                                if hasattr(self, 'info_label'):
                                    try:
                                        self.info_label.config(text="✅ Połączenie przywrócone - wybierz projekt", fg="lime")
                                    except:
                                        pass
                                
                                # Wyzeruj stan projektu - użytkownik wybierze projekt ręcznie
                                self.current_project_id = None
                                self.db_manager.current_project_type = None
                                self.have_lock = False
                                self.current_lock_id = None
                                
                                # Resetuj UI do stanu początkowego
                                try:
                                    self.status_label.config(text="🔵 INIT", fg="gray")
                                    self.btn_acquire_lock.config(state=tk.DISABLED)
                                    self.btn_force_lock.config(state=tk.DISABLED)
                                    self.btn_cancel_lock.config(state=tk.DISABLED)
                                    self.btn_release_lock.config(state=tk.DISABLED)
                                    self.btn_add_item.config(state=tk.DISABLED)
                                    self.btn_hide_selected.config(state=tk.DISABLED)
                                    self.btn_restore_hidden.config(state=tk.DISABLED)
                                    self.btn_scanner.config(state=tk.DISABLED)
                                    # Wyczyść tabelę
                                    for row in self.sheet.get_children():
                                        self.sheet.delete(row)
                                except Exception as e:
                                    self._safe_print(f"⚠️  Błąd resetowania UI: {e}")
                            else:
                                self._safe_print(f"⏳ Auto-reconnect: połączenie nadal niedostępne, próbuję za 5s...")
                                # Zaplanuj następną próbę tylko jeśli banner nadal widoczny
                                if self._connection_lost_shown:
                                    try:
                                        self._auto_reconnect_after_id = self.after(
                                            self._auto_reconnect_interval_ms, 
                                            _auto_reconnect_tick
                                        )
                                    except Exception as e:
                                        self._safe_print(f"⚠️  Błąd planowania retry: {e}")
                        except Exception as e:
                            self._safe_print(f"❌ _check_done crashed: {e}")
                    
                    # Uruchom sprawdzanie w osobnym wątku
                    threading.Thread(target=_check_worker, daemon=True).start()
                except Exception as e:
                    self._safe_print(f"❌ _auto_reconnect_tick crashed: {e}")
        
            # Uruchom pierwszy tick
            _auto_reconnect_tick()
        except Exception as e:
            self._safe_print(f"❌ CRITICAL: _start_auto_reconnect_timer crashed: {e}")
    
    def _stop_auto_reconnect_timer(self):
        """Zatrzymaj timer auto-reconnect."""
        try:
            if self._auto_reconnect_after_id:
                try:
                    self.after_cancel(self._auto_reconnect_after_id)
                    self._safe_print(f"🛑 Auto-reconnect timer zatrzymany")
                except Exception:
                    pass
                self._auto_reconnect_after_id = None
        except Exception as e:
            self._safe_print(f"⚠️  Błąd _stop_auto_reconnect_timer: {e}")
    
    def _safe_print(self, msg: str):
        """Bezpieczny print - nie crashuje w trybie --noconsole."""
        try:
            print(msg)
        except:
            pass  # Ignoruj błędy print w --noconsole

    def _start_initialize_background(self):
        """Startuj inicjalizację w tle (bez blokowania GUI)."""
        import threading

        if getattr(self, "_init_thread", None) and self._init_thread.is_alive():
            return

        self._init_thread = threading.Thread(target=self._initialize_worker, daemon=True)
        self._init_thread.start()

    def _initialize_worker(self):
        """Wątek roboczy inicjalizacji - bez wywołań GUI."""
        try:
            init_data = self.initialize_core()
            self.after(0, lambda: self._finish_initialize(True, init_data, None))
        except Exception as e:
            import traceback
            tb = traceback.format_exc()
            # Ważne: przekaż e i tb jako domyślne argumenty do lambda (closure fix)
            self.after(0, lambda err=e, trace=tb: self._finish_initialize(False, None, (err, trace)))

    def _finish_initialize(self, success, init_data, error_info):
        """Zakończ inicjalizację w wątku GUI."""
        # Odblokuj UI niezależnie od wyniku
        self._unblock_ui()
        if success:
            # Zastosuj dane z tła
            self.load_projects(projects=init_data.get("projects"))
            self.load_suppliers(suppliers=init_data.get("suppliers"))
            self.load_users(users_rows=init_data.get("users"))

            # Wczytaj szerokości kolumn (UI)
            self._load_column_widths()
            
            # Ustaw ostatnio wybraną kategorię pliku
            if hasattr(self, 'loaded_last_file_category') and hasattr(self, 'file_category_var'):
                self.file_category_var.set(self.loaded_last_file_category)
                print(f"  ✅ Przywrócono kategorię pliku: {self.loaded_last_file_category}")

            self._initialized = True
            print("✅ Inicjalizacja zakończona pomyślnie")
            
            # Wyczyść komunikat ładowania - aplikacja gotowa
            if hasattr(self, 'info_label'):
                self.info_label.config(text="Brak projektu", fg="white")
            
            # Uruchom tray icon (jeśli dostępny)
            if TRAY_AVAILABLE:
                self.start_tray_icon()

            # Przywróć normalny kursor
            self.config(cursor="")

            # Ustaw stan menu Plik na podstawie domyślnego typu projektu
            self.update_menu_state()

            # Wykonaj backup w tle (po 2 sekundach, żeby nie blokować GUI)
            self.after(2000, self.run_backup_in_background)
            
            # Uruchom timer heartbeat dla locków
            self._start_heartbeat_timer()
            return

        # Błąd - przywróć kursor
        self.config(cursor="")

        err, tb = error_info
        if isinstance(err, InitConfigRequired):
            result = self.show_initial_config_dialog()
            if not result:
                messagebox.showinfo(
                    "Konfiguracja anulowana",
                    "Aplikacja wymaga poprawnej ścieżki do bazy master.sqlite.\n\n"
                    "Uruchom aplikację ponownie i podaj prawidłową ścieżkę."
                )
                self.destroy()
                return

            # Użytkownik podał nowe ścieżki - spróbuj ponownie
            self.config(cursor="wait")
            if hasattr(self, 'info_label'):
                self.info_label.config(text="🔄 Ładowanie aplikacji...", fg="orange")
            self.update_idletasks()
            self._start_initialize_background()
            return

        messagebox.showerror(
            "Błąd inicjalizacji",
            f"Nie udało się uruchomić aplikacji:\n\n{err}"
        )
        print(tb)
        self.destroy()
    
    def initialize(self):        # Skróty klawiszowe
        self.bind("<Control-z>", self.undo_last_action)
        self.bind("<Control-Z>", self.undo_last_action)
    
    def initialize_core(self):
        """Główna inicjalizacja aplikacji (wywoływana w osobnym wątku)"""
        print("🔧 START initialize_core()")
        
        try:
            # Wczytaj ścieżki z configu
            global MASTER_PATH, PROJECTS_DIR, PROJECTS_MAG_DIR, SERVER_DIR, LOCAL_DIR, LOCKS_DIR, BACKUP_DIR, CONFIG_FILE
            
            print("  → Wczytuję konfigurację...")
            if not CONFIG_FILE.exists():
                print("  → Tworzę domyślny config...")
                self.create_default_config()
            
            loaded_config_file = CONFIG_FILE
            with open(loaded_config_file) as f:
                config = json.load(f)
            
            # PIERWSZE URUCHOMIENIE: Sprawdź czy master.sqlite istnieje
            paths = config.get("paths", {})
            test_master_path = Path(paths.get("master", DEFAULT_MASTER_PATH))

            # Użyj is_file_accessible z timeoutem 5s zamiast Path.exists()
            # (Path.exists() na zamapowanym ale niedostępnym dysku sieciowym
            #  może wisieć 30-60s czekając na timeout SMB)
            if not self._file_accessible_with_timeout(test_master_path, timeout_s=5.0):
                print("  ⚠️  Brak master.sqlite (lub dysk niedostępny) - wymagana konfiguracja")
                raise InitConfigRequired("Brak master.sqlite")
            
            # Wczytaj ścieżki z configu (lub użyj domyślnych)
            paths = config.get("paths", {})
            temp_local_dir = paths.get("local_dir", DEFAULT_LOCAL_DIR)
            
            # WAŻNE: Jeśli LOCAL_DIR w config jest inny niż DEFAULT_LOCAL_DIR,
            # to znaczy że użytkownik zmienił lokalizację i musimy wczytać config z NOWEJ lokalizacji
            temp_config_file = Path(temp_local_dir) / "sync_config.json"
            
            if temp_config_file != CONFIG_FILE and temp_config_file.exists():
                print(f"  🔄 LOCAL_DIR zmieniony - przeładowuję config z: {temp_config_file}")
                with open(temp_config_file) as f:
                    config = json.load(f)
                paths = config.get("paths", {})
                loaded_config_file = temp_config_file
            
            # Teraz wczytaj ostateczne ścieżki
            MASTER_PATH = paths.get("master", DEFAULT_MASTER_PATH)
            PROJECTS_DIR = paths.get("projects_dir", DEFAULT_PROJECTS_DIR)
            PROJECTS_MAG_DIR = paths.get("projects_mag_dir", DEFAULT_PROJECTS_MAG_DIR)
            SERVER_DIR = paths.get("server_dir", DEFAULT_SERVER_DIR)
            LOCAL_DIR = paths.get("local_dir", DEFAULT_LOCAL_DIR)
            LOCKS_DIR = paths.get("locks_dir", DEFAULT_LOCKS_DIR)
            BACKUP_DIR = paths.get("backup_dir", DEFAULT_BACKUP_DIR)
            
            # Aktualizuj CONFIG_FILE
            CONFIG_FILE = Path(LOCAL_DIR) / "sync_config.json"

            # Jeśli finalny CONFIG_FILE jest inny - przeładuj i nadpisz ścieżki
            if CONFIG_FILE != loaded_config_file and CONFIG_FILE.exists():
                print(f"  🔄 Finalny config z innej ścieżki - przeładowuję: {CONFIG_FILE}")
                with open(CONFIG_FILE) as f:
                    config = json.load(f)
                paths = config.get("paths", {})
                MASTER_PATH = paths.get("master", DEFAULT_MASTER_PATH)
                PROJECTS_DIR = paths.get("projects_dir", DEFAULT_PROJECTS_DIR)
                PROJECTS_MAG_DIR = paths.get("projects_mag_dir", DEFAULT_PROJECTS_MAG_DIR)
                SERVER_DIR = paths.get("server_dir", DEFAULT_SERVER_DIR)
                LOCAL_DIR = paths.get("local_dir", DEFAULT_LOCAL_DIR)
                LOCKS_DIR = paths.get("locks_dir", DEFAULT_LOCKS_DIR)
                BACKUP_DIR = paths.get("backup_dir", DEFAULT_BACKUP_DIR)
                test_master_path = Path(MASTER_PATH)
                if not self._file_accessible_with_timeout(test_master_path, timeout_s=5.0):
                    print("  ⚠️  Brak master.sqlite (lub dysk niedostępny) - wymagana konfiguracja")
                    raise InitConfigRequired("Brak master.sqlite")
            
            print(f"  ✅ Ścieżki wczytane z: {CONFIG_FILE}")
            print(f"     Master: {MASTER_PATH}")
            print(f"     Projekty: {PROJECTS_DIR}")
            print(f"     Projekty MAG: {PROJECTS_MAG_DIR}")
            print(f"     Serwer: {SERVER_DIR}")
            print(f"     Lokalny: {LOCAL_DIR}")
            print(f"     Locki: {LOCKS_DIR}")
            print(f"     Backupy: {BACKUP_DIR}")
            
            # Wczytaj ustawienia UI
            ui_settings = config.get("ui", {})
            self.loaded_last_file_category = ui_settings.get("last_file_category", "DWF")
            print(f"     UI: Ostatnia kategoria pliku: {self.loaded_last_file_category}")
            
            # Database Manager
            print("  → Tworzę DatabaseManager...")
            self.db_manager = DatabaseManager(
                master_path=MASTER_PATH,
                projects_dir=PROJECTS_DIR,
                local_dir=LOCAL_DIR,
                projects_mag_dir=PROJECTS_MAG_DIR
            )
            print("  ✅ DatabaseManager OK")
            
            # Callback dla aktualizacji statusu (z wątku tła)
            def update_status(msg):
                try:
                    if hasattr(self, 'info_label'):
                        self.after(0, lambda: self.info_label.config(text=msg, fg="orange"))
                except:
                    pass
            
            self.db_manager.status_callback = update_status
            
            print("  → Łączę z master...")
            update_status("🔄 Łączę z bazą główną...")
            
            if not self.db_manager.connect_master():
                print("  ❌ Nie można połączyć z master.sqlite")
                raise ConnectionError(
                    f"Nie można połączyć z bazą master.sqlite: {MASTER_PATH}"
                )
            print("  ✅ Master połączony")
            update_status("✅ Połączono z bazą główną")
            
            # MIGRACJA: Dodaj kolumnę project_type jeśli nie istnieje
            print("  → Sprawdzam kolumnę project_type...")
            try:
                # Sprawdź czy kolumna istnieje
                cursor_check = self.db_manager.master_con.execute("PRAGMA table_info(projects)")
                columns = [row[1] for row in cursor_check.fetchall()]
                
                if 'project_type' not in columns:
                    print("  ⚠️  Kolumna project_type nie istnieje - próbuję dodać...")
                    try:
                        # Próba dodania kolumny (wymaga READ-WRITE!)
                        self.db_manager.master_con.execute(
                            "ALTER TABLE projects ADD COLUMN project_type TEXT NOT NULL DEFAULT 'MACHINE'"
                        )
                        self.db_manager.master_con.commit()
                        print("  ✅ Kolumna project_type dodana pomyślnie")
                    except sqlite3.OperationalError as alter_err:
                        if "read-only" in str(alter_err).lower() or "readonly" in str(alter_err).lower():
                            print("  ⚠️  Master DB jest READ-ONLY - kolumna project_type nie została dodana")
                            print("     Wszystkie projekty będą traktowane jako typ MACHINE")
                        else:
                            print(f"  ⚠️  Nie udało się dodać kolumny project_type: {alter_err}")
                else:
                    print("  ✅ Kolumna project_type istnieje")
            except Exception as pt_err:
                print(f"  ⚠️  Błąd sprawdzania kolumny project_type: {pt_err}")
            
            # MIGRACJA KOLUMN DLA STATYSTYK PRODUKCJI
            print("  → Sprawdzam kolumny dla statystyk produkcji...")
            try:
                cursor_check = self.db_manager.master_con.execute("PRAGMA table_info(projects)")
                columns = [row[1] for row in cursor_check.fetchall()]

                # ⚡ Skrócony busy_timeout TYLKO dla migracji — żeby nie wisieć
                # po 5s gdy inny klient w sieci trzyma writer-lock na master.sqlite.
                # Po migracji przywracamy domyślne 5000ms (w finally).
                _migration_needed = any(c not in columns for c in
                                        ('designer', 'completed_at', 'status', 'received_percent'))
                if _migration_needed:
                    try:
                        self.db_manager.master_con.execute("PRAGMA busy_timeout=800")
                    except Exception:
                        pass
                # designer - konstruktor przypisany do projektu
                if 'designer' not in columns:
                    print("  → Dodaję kolumnę designer...")
                    try:
                        self.db_manager.master_con.execute(
                            "ALTER TABLE projects ADD COLUMN designer TEXT"
                        )
                        self.db_manager.master_con.commit()
                        print("  ✅ Kolumna designer dodana")
                    except Exception as e:
                        print(f"  ⚠️  Błąd dodawania designer: {e}")
                
                # completed_at - data zakończenia projektu
                if 'completed_at' not in columns:
                    print("  → Dodaję kolumnę completed_at...")
                    try:
                        self.db_manager.master_con.execute(
                            "ALTER TABLE projects ADD COLUMN completed_at TEXT"
                        )
                        self.db_manager.master_con.commit()
                        print("  ✅ Kolumna completed_at dodana")
                    except Exception as e:
                        print(f"  ⚠️  Błąd dodawania completed_at: {e}")
                
                # status - status projektu (W_REALIZACJI, ZAKOŃCZONY, WSTRZYMANY)
                if 'status' not in columns:
                    print("  → Dodaję kolumnę status...")
                    try:
                        self.db_manager.master_con.execute(
                            "ALTER TABLE projects ADD COLUMN status TEXT DEFAULT 'W_REALIZACJI'"
                        )
                        self.db_manager.master_con.commit()
                        print("  ✅ Kolumna status dodana")
                    except Exception as e:
                        print(f"  ⚠️  Błąd dodawania status: {e}")
                
                # received_percent - procent odebranych elementów (dla RM_MANAGER)
                if 'received_percent' not in columns:
                    print("  → Dodaję kolumnę received_percent...")
                    try:
                        self.db_manager.master_con.execute(
                            "ALTER TABLE projects ADD COLUMN received_percent TEXT"
                        )
                        self.db_manager.master_con.commit()
                        print("  ✅ Kolumna received_percent dodana")
                    except Exception as e:
                        print(f"  ⚠️  Błąd dodawania received_percent: {e}")
                
                print("  ✅ Kolumny statystyk produkcji OK")
            except Exception as e:
                print(f"  ⚠️  Błąd sprawdzania kolumn statystyk: {e}")
            finally:
                # przywróć domyślny busy_timeout
                try:
                    self.db_manager.master_con.execute("PRAGMA busy_timeout=5000")
                except Exception:
                    pass
            
            # MIGRACJA TABELI SUPPLIERS (jeśli nie istnieje)
            print("  → Sprawdzam tabelę suppliers...")
            try:
                self.db_manager.master_con.execute("""
                    CREATE TABLE IF NOT EXISTS suppliers (
                        supplier_id INTEGER PRIMARY KEY AUTOINCREMENT,
                        name TEXT NOT NULL,
                        contact TEXT,
                        phone TEXT,
                        email TEXT,
                        description TEXT,
                        is_active INTEGER DEFAULT 1
                    )
                """)
                self.db_manager.master_con.commit()
                print("  ✅ Tabela suppliers OK")
            except Exception as e:
                print(f"  ⚠️  Błąd migracji suppliers: {e}")
            
            # Inicjalizuj tabelę settings w master DB
            print("  → Inicjalizuję settings...")
            self._init_settings_table()
            print("  ✅ Settings OK")
            
            # Inicjalizuj tabelę user_changes_log (audit trail)
            print("  → Inicjalizuję audit log użytkowników...")
            self._init_user_audit_log()
            print("  ✅ User audit log OK")
            
            # UWAGA: items_changes_log jest inicjalizowana po przejęciu locka,
            # nie tutaj (wymaga dostępu do zapisu do bazy projektu)
            
            # Lock Manager
            print("  → Sprawdzam config...")
            if not CONFIG_FILE.exists():
                print("  → Tworzę config...")
                self.create_default_config()
                print("  ✅ Config utworzony")
            
            print("  → Ładuję config...")
            with open(CONFIG_FILE) as f:
                config = json.load(f)
            print(f"  ✅ Config: {config.get('client', {}).get('name', 'unknown')}")
            
            # SYNCHRONIZUJ ścieżkę locks z wczytanym LOCKS_DIR
            if 'locks' not in config:
                config['locks'] = {}
            config['locks']['folder'] = str(LOCKS_DIR)
            print(f"  → Ścieżka locks: {LOCKS_DIR}")
            
            # Upewnij się że folder locks istnieje
            Path(LOCKS_DIR).mkdir(parents=True, exist_ok=True)
            print(f"  ✅ Folder locks utworzony/zweryfikowany")
            
            print("  → Tworzę LockManager...")
            self.lock_manager = ProjectLockManager(config)
            print("  ✅ LockManager OK")
            
            # Pobierz dane do UI (bez wywołań GUI)
            print("  → Pobieram projekty...")
            projects = self.db_manager.get_projects()
            print("  ✅ Projekty pobrane")

            print("  → Pobieram dostawców...")
            suppliers = self.db_manager.get_suppliers()
            print("  ✅ Dostawcy pobrani")

            print("  → Pobieram użytkowników...")
            users = self.db_manager.master_con.execute(
                "SELECT id, username, display_name, role FROM users WHERE is_active = 1 ORDER BY username"
            ).fetchall()
            print("  ✅ Użytkownicy pobrani")
            
            # BackupManager (przekaż db_manager dla projektów magazynowych)
            print("  → Tworzę BackupManager...")
            self.backup_manager = BackupManager(
                master_path=Path(MASTER_PATH),
                projects_dir=self.db_manager.projects_dir,
                backup_dir=Path(BACKUP_DIR),
                db_manager=self.db_manager  # NOWE: dla projektów magazynowych
            )
            print("  ✅ BackupManager OK")
            
            # UWAGA: Backup NIE jest wykonywany podczas initialize_core!
            # Zostanie uruchomiony ASYNCHRONICZNIE po starcie aplikacji (patrz finish_init)
            
            print("✅ INITIALIZE_CORE ZAKOŃCZONE\n")
            return {
                "projects": projects,
                "suppliers": suppliers,
                "users": users
            }
        except Exception as e:
            print(f"\n❌ BŁĄD W INITIALIZE_CORE: {e}")
            import traceback
            traceback.print_exc()
            raise  # Przekaż błąd do wątku nadrzędnego
    
    def _init_settings_table(self):
        """Inicjalizuj tabelę settings w master DB"""
        try:
            # Utwórz tabelę settings jeśli nie istnieje
            self.db_manager.master_con.execute("""
                CREATE TABLE IF NOT EXISTS settings (
                    key TEXT PRIMARY KEY,
                    value TEXT,
                    updated_at TEXT
                )
            """)
            self.db_manager.master_con.commit()
            
            # Ustaw domyślną wartość backup_on_release jeśli nie istnieje
            cursor = self.db_manager.master_con.execute("""
                SELECT value FROM settings WHERE key = 'backup_on_release'
            """)
            row = cursor.fetchone()
            
            if not row:
                # Domyślnie włączone
                self.db_manager.master_con.execute("""
                    INSERT INTO settings (key, value, updated_at)
                    VALUES ('backup_on_release', '1', ?)
                """, (datetime.now().isoformat(),))
                self.db_manager.master_con.commit()
                print("    ℹ️  Ustawienie backup_on_release = 1 (domyślnie)")
            else:
                print(f"    ℹ️  Ustawienie backup_on_release = {row[0]}")
            
            # Wczytaj wartość do zmiennej
            cursor = self.db_manager.master_con.execute("""
                SELECT value FROM settings WHERE key = 'backup_on_release'
            """)
            row = cursor.fetchone()
            if row:
                self.backup_on_release_var.set(bool(int(row[0])))
                
        except Exception as e:
            print(f"⚠️  Błąd inicjalizacji settings: {e}")
            import traceback
            traceback.print_exc()
    
    def _init_user_audit_log(self):
        """Inicjalizuj tabelę logowania zmian użytkowników"""
        try:
            # Jeśli master jest READ-ONLY, pomiń inicjalizację logów
            try:
                cur = self.db_manager.master_con.execute("PRAGMA query_only")
                if cur.fetchone()[0] == 1:
                    print("  ℹ️  Master READ-ONLY - pomijam init user_changes_log")
                    return
            except Exception:
                pass

            # Utwórz tabelę audit log jeśli nie istnieje
            self.db_manager.master_con.execute("""
                CREATE TABLE IF NOT EXISTS user_changes_log (
                    change_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    action TEXT NOT NULL,
                    user_id INTEGER,
                    username TEXT,
                    display_name TEXT,
                    role TEXT,
                    changed_by TEXT,
                    timestamp TEXT NOT NULL,
                    details TEXT
                )
            """)
            self.db_manager.master_con.commit()
            
            # Snapshot aktualnego stanu użytkowników (jeśli tabela jest pusta)
            cursor = self.db_manager.master_con.execute(
                "SELECT COUNT(*) FROM user_changes_log"
            )
            if cursor.fetchone()[0] == 0:
                # Zapisz snapshot
                users = self.db_manager.master_con.execute(
                    "SELECT id, username, display_name, role FROM users"
                ).fetchall()
                
                for u in users:
                    self.db_manager.master_con.execute("""
                        INSERT INTO user_changes_log 
                        (action, user_id, username, display_name, role, changed_by, timestamp, details)
                        VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                    """, (
                        'SNAPSHOT',
                        u[0], u[1], u[2], u[3],
                        'SYSTEM',
                        datetime.now().isoformat(),
                        'Initial snapshot at app start'
                    ))
                self.db_manager.master_con.commit()
                print(f"    ℹ️  Zapisano snapshot {len(users)} użytkowników")
            else:
                print(f"    ℹ️  Audit log już istnieje - sprawdzam zmiany...")
                self._check_user_changes_on_startup()
                
        except Exception as e:
            msg = str(e).lower()
            if "readonly" in msg or "read-only" in msg:
                print("  ℹ️  Master READ-ONLY - pomijam init user_changes_log")
                return
            print(f"⚠️  Błąd inicjalizacji user audit log: {e}")
            import traceback
            traceback.print_exc()
    
    def _check_user_changes_on_startup(self):
        """Sprawdź czy użytkownicy w bazie zgadzają się z ostatnim logiem"""
        try:
            # Sprawdź czy master jest READ-ONLY
            try:
                cur = self.db_manager.master_con.execute("PRAGMA query_only")
                if cur.fetchone()[0] == 1:
                    print("  ℹ️  Master READ-ONLY - pomijam check user changes")
                    return
            except Exception:
                pass
            
            # Pobierz aktualnych użytkowników
            current_users = {}
            for row in self.db_manager.master_con.execute(
                "SELECT id, username, display_name, role FROM users"
            ).fetchall():
                current_users[row[0]] = {'username': row[1], 'display_name': row[2], 'role': row[3]}
            
            # Pobierz ostatni snapshot/stan z logów
            # Budujemy stan na podstawie logów: SNAPSHOT/ADD dodają, DELETE usuwa
            last_known_users = {}
            for row in self.db_manager.master_con.execute("""
                SELECT action, user_id, username, display_name, role 
                FROM user_changes_log 
                ORDER BY change_id ASC
            """).fetchall():
                action, uid, username, display_name, role = row
                if action in ('SNAPSHOT', 'ADD'):
                    last_known_users[uid] = {'username': username, 'display_name': display_name, 'role': role}
                elif action == 'DELETE':
                    last_known_users.pop(uid, None)
            
            # Porównaj: czy ktoś zniknął?
            missing_users = []
            for uid, udata in last_known_users.items():
                if uid not in current_users:
                    missing_users.append(f"{udata['username']} ({udata['display_name']})")
            
            # Porównaj: czy ktoś pojawił się nowy?
            new_users = []
            for uid, udata in current_users.items():
                if uid not in last_known_users:
                    new_users.append(f"{udata['username']} ({udata['display_name']})")
            
            if missing_users or new_users:
                print(f"\n⚠️⚠️⚠️  WYKRYTO NIEOCZEKIWANE ZMIANY UŻYTKOWNIKÓW! ⚠️⚠️⚠️")
                if missing_users:
                    print(f"    🔴 ZAGINĘLI użytkownicy: {', '.join(missing_users)}")
                if new_users:
                    print(f"    🟢 POJAWILI SIĘ użytkownicy: {', '.join(new_users)}")
                
                # Zaloguj anomalię (tylko jeśli baza nie jest READ-ONLY)
                try:
                    details = f"Missing: {missing_users}, New: {new_users}"
                    self.db_manager.master_con.execute("""
                        INSERT INTO user_changes_log 
                        (action, user_id, username, display_name, role, changed_by, timestamp, details)
                        VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                    """, (
                        'ANOMALY',
                        None, None, None, None,
                        'SYSTEM',
                        datetime.now().isoformat(),
                        details
                    ))
                    self.db_manager.master_con.commit()
                    print(f"    📝 Zalogowano anomalię do user_changes_log\n")
                except sqlite3.OperationalError as e:
                    if "readonly" in str(e).lower():
                        print(f"    ℹ️  Baza READ-ONLY - pominięto zapis anomalii\n")
                    else:
                        raise
            else:
                print(f"    ✅ Użytkownicy bez zmian od ostatniego logowania")
            
            # Wyświetl ostatnie 10 zmian z logów
            print(f"\n📜 Ostatnie 10 zmian w user_changes_log:")
            cursor = self.db_manager.master_con.execute("""
                SELECT change_id, action, username, display_name, changed_by, timestamp, details
                FROM user_changes_log
                ORDER BY change_id DESC
                LIMIT 10
            """)
            for row in cursor.fetchall():
                change_id, action, username, display_name, changed_by, timestamp, details = row
                print(f"    #{change_id:3d} [{action:8s}] {username or 'N/A':15s} | przez: {changed_by:10s} | {timestamp} | {details or ''}")
            print("")
                
        except Exception as e:
            print(f"⚠️  Błąd sprawdzania zmian użytkowników: {e}")
            import traceback
            traceback.print_exc()
    
    def _init_items_audit_log(self):
        """Inicjalizuj tabelę logowania zmian pozycji projektu"""
        try:
            # Sprawdź czy projekt jest otwarty
            if not self.db_manager.project_con:
                print("  ℹ️  Brak otwartego projektu - pomijam init items_changes_log")
                return
            
            # Sprawdź czy projekt jest READ-ONLY
            try:
                cur = self.db_manager.project_con.execute("PRAGMA query_only")
                if cur.fetchone()[0] == 1:
                    print("  ℹ️  Projekt READ-ONLY - pomijam init items_changes_log")
                    return
            except Exception:
                pass
            
            # Utwórz tabelę audit log jeśli nie istnieje
            self.db_manager.project_con.execute("""
                CREATE TABLE IF NOT EXISTS items_changes_log (
                    change_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    item_id INTEGER NOT NULL,
                    action TEXT NOT NULL,
                    field_name TEXT,
                    old_value TEXT,
                    new_value TEXT,
                    changed_by TEXT NOT NULL,
                    timestamp TEXT NOT NULL,
                    drawing_no TEXT,
                    item_name TEXT
                )
            """)
            self.db_manager.project_con.commit()
            
            # Sprawdź ile jest już logów
            cursor = self.db_manager.project_con.execute(
                "SELECT COUNT(*) FROM items_changes_log"
            )
            log_count = cursor.fetchone()[0]
            
            if log_count == 0:
                print(f"    ℹ️  Tabela items_changes_log utworzona (pusta)")
            else:
                print(f"    ℹ️  Tabela items_changes_log zawiera {log_count} wpisów")
            
        except Exception as e:
            msg = str(e).lower()
            if "readonly" in msg or "read-only" in msg:
                print("  ℹ️  Projekt READ-ONLY - pomijam init items_changes_log")
                return
            print(f"⚠️  Błąd inicjalizacji items audit log: {e}")
            import traceback
            traceback.print_exc()
    
    def _log_item_change(self, item_id, action, field_name=None, old_value=None, new_value=None):
        """Zaloguj zmianę pozycji do audit log"""
        try:
            # Sprawdź czy projekt jest otwarty
            if not self.db_manager.project_con:
                print(f"⚠️  _log_item_change: Brak połączenia z projektem")
                return
            
            # Sprawdź czy jest READ-ONLY
            try:
                cur = self.db_manager.project_con.execute("PRAGMA query_only")
                if cur.fetchone()[0] == 1:
                    print(f"⚠️  _log_item_change: Projekt READ-ONLY")
                    return
            except Exception:
                pass
            
            # Sprawdź czy tabela istnieje
            try:
                cursor = self.db_manager.project_con.execute(
                    "SELECT name FROM sqlite_master WHERE type='table' AND name='items_changes_log'"
                )
                if not cursor.fetchone():
                    print(f"⚠️  _log_item_change: Tabela items_changes_log nie istnieje! Tworzę...")
                    self._init_items_audit_log()
            except Exception as e:
                print(f"⚠️  _log_item_change: Błąd sprawdzania tabeli: {e}")
                return
            
            # Pobierz informacje o pozycji (drawing_no, name)
            # WAŻNE: używamy COALESCE bo work_* może być NULL, a wartość jest w src_*
            cursor = self.db_manager.project_con.execute("""
                SELECT 
                    COALESCE(work_drawing_no, src_drawing_no) as drawing_no,
                    COALESCE(work_name, src_name) as item_name
                FROM items WHERE id = ?
            """, (item_id,))
            row = cursor.fetchone()
            drawing_no = row[0] if row else None
            item_name = row[1] if row else None
            
            # Zapisz do logu
            self.db_manager.project_con.execute("""
                INSERT INTO items_changes_log 
                (item_id, action, field_name, old_value, new_value, changed_by, timestamp, drawing_no, item_name)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
            """, (
                item_id,
                action,
                field_name,
                str(old_value) if old_value is not None else None,
                str(new_value) if new_value is not None else None,
                self.current_user or 'UNKNOWN',
                datetime.now().strftime('%Y-%m-%d     %H:%M:%S'),
                drawing_no,
                item_name
            ))
            self.db_manager.project_con.commit()
            
        except Exception as e:
            # Błędy logowania nie powinny blokować głównych operacji
            print(f"❌ Błąd logowania zmiany pozycji: {e}")
            import traceback
            traceback.print_exc()
    
    def _save_column_widths(self):
        """Zapisz szerokości kolumn do lokalnego pliku JSON"""
        try:
            # Nie zapisuj jeśli nie ma wybranego projektu (wtedy są domyślne szerokości)
            if not self.current_project_id:
                print("  ℹ️  Brak wybranego projektu - pomijam zapis szerokości kolumn")
                return
            
            # Pobierz aktualne szerokości kolumn z sheet
            # tksheet przechowuje szerokości w różnych miejscach w zależności od wersji
            widths = {}
            method_used = None
            
            # Próba 1: Użyj get_column_widths() jeśli istnieje
            if hasattr(self.sheet, 'get_column_widths') and callable(getattr(self.sheet, 'get_column_widths')):
                try:
                    widths_result = self.sheet.get_column_widths()
                    if isinstance(widths_result, dict):
                        widths = {int(k): v for k, v in widths_result.items()}
                        method_used = "get_column_widths()"
                    elif isinstance(widths_result, list):
                        widths = {i: w for i, w in enumerate(widths_result) if w}
                        method_used = "get_column_widths() [list]"
                except Exception as e:
                    print(f"  ⚠️  get_column_widths() nie zadziałało: {e}")
            
            # Próba 2: Dostęp bezpośredni do atrybutu column_widths
            if not widths and hasattr(self.sheet, 'column_widths') and not callable(getattr(self.sheet, 'column_widths')):
                try:
                    col_widths_attr = self.sheet.column_widths
                    if isinstance(col_widths_attr, dict):
                        widths = {int(k): v for k, v in col_widths_attr.items()}
                        method_used = "column_widths [dict attr]"
                    elif isinstance(col_widths_attr, list):
                        widths = {i: w for i, w in enumerate(col_widths_attr) if w}
                        method_used = "column_widths [list attr]"
                except Exception as e:
                    print(f"  ⚠️  Atrybut column_widths nie zadziałał: {e}")
            
            # Próba 3: Użyj MT.col_positions (główna tablica pozycji kolumn)
            if not widths and hasattr(self.sheet, 'MT') and hasattr(self.sheet.MT, 'col_positions'):
                try:
                    col_positions = self.sheet.MT.col_positions
                    # col_positions to lista [0, width1, width1+width2, width1+width2+width3, ...]
                    # Szerokość kolumny i to col_positions[i+1] - col_positions[i]
                    for i in range(len(col_positions) - 1):
                        width = col_positions[i + 1] - col_positions[i]
                        if width > 0:
                            widths[i] = width
                    method_used = "MT.col_positions"
                except Exception as e:
                    print(f"  ⚠️  MT.col_positions nie zadziałało: {e}")
            
            if not widths:
                print("⚠️  Nie znaleziono szerokości kolumn do zapisania")
                return
            
            # Zapisz do lokalnego pliku JSON
            global CONFIG_FILE
            CONFIG_FILE.parent.mkdir(parents=True, exist_ok=True)
            
            # Wczytaj istniejący config lub utwórz nowy
            config = {}
            if CONFIG_FILE.exists():
                try:
                    with open(CONFIG_FILE, 'r') as f:
                        config = json.load(f)
                except Exception as e:
                    print(f"  ⚠️  Nie można wczytać config: {e}")
            
            # Dodaj/zaktualizuj szerokości kolumn
            config['column_widths'] = {str(k): v for k, v in widths.items()}
            
            # Zapisz
            with open(CONFIG_FILE, 'w') as f:
                json.dump(config, f, indent=2)
            
            print(f"  ✅ Zapisano szerokości kolumn do {CONFIG_FILE} (metoda: {method_used})")
            
        except Exception as e:
            print(f"⚠️  Błąd zapisu szerokości kolumn: {e}")
            import traceback
            traceback.print_exc()
    
    def _load_column_widths(self):
        """Wczytaj szerokości kolumn z lokalnego pliku JSON"""
        try:
            global CONFIG_FILE
            
            # Sprawdź czy plik config istnieje
            if not CONFIG_FILE.exists():
                print("  ℹ️  Brak pliku config - nie można wczytać szerokości kolumn")
                return
            
            # Wczytaj config
            try:
                with open(CONFIG_FILE, 'r') as f:
                    config = json.load(f)
            except Exception as e:
                print(f"  ⚠️  Błąd wczytywania config: {e}")
                return
            
            # Pobierz szerokości kolumn
            if 'column_widths' not in config:
                print("  ℹ️  Brak zapisanych szerokości kolumn w config")
                return
            
            widths = config['column_widths']
            print(f"  📏 Wczytano szerokości z {CONFIG_FILE}: {widths}")
            
            # ZAPISYWANIE używa get_column_widths() która zwraca LISTĘ
            # Więc musimy użyć set_column_widths() lub column_width() z each=False
            
            success_count = 0
            method_used = None
            
            # Próba 1: column_width() z each=False (ustawia wiele kolumn naraz z listy)
            try:
                # Konwertuj dict na listę (indeksy muszą być po kolei)
                widths_list = []
                for i in range(max(int(k) for k in widths.keys()) + 1):
                    widths_list.append(widths.get(str(i), 100))
                
                if hasattr(self.sheet, 'column_width'):
                    self.sheet.column_width(widths=widths_list)
                    success_count = len(widths_list)
                    method_used = "column_width(widths=list)"
                    print(f"  ✅ Ustawiono szerokości metodą: {method_used}")
            except Exception as e:
                print(f"  ⚠️  Próba 1 (column_width with list) nie zadziałała: {e}")
            
            # Próba 2: Ustaw każdą kolumnę osobno przez column_width(column=idx, width=val)
            if success_count == 0:
                try:
                    for col_idx_str, width in widths.items():
                        col_idx = int(col_idx_str)
                        if hasattr(self.sheet, 'column_width'):
                            self.sheet.column_width(column=col_idx, width=width)
                            success_count += 1
                    method_used = "column_width(column=X, width=Y)"
                    print(f"  ✅ Ustawiono szerokości metodą: {method_used}")
                except Exception as e:
                    print(f"  ⚠️  Próba 2 (column_width per column) nie zadziałała: {e}")
                    success_count = 0
            
            # Próba 3: Bezpośredni dostęp do MT.set_width()
            if success_count == 0 and hasattr(self.sheet, 'MT'):
                try:
                    for col_idx_str, width in widths.items():
                        col_idx = int(col_idx_str)
                        if hasattr(self.sheet.MT, 'set_width'):
                            self.sheet.MT.set_width(col_idx, width)
                            success_count += 1
                    method_used = "MT.set_width()"
                    print(f"  ✅ Ustawiono szerokości metodą: {method_used}")
                except Exception as e:
                    print(f"  ⚠️  Próba 3 (MT.set_width) nie zadziałała: {e}")
                    success_count = 0
            
            if success_count > 0:
                print(f"✅ Wczytano szerokości {success_count} kolumn")
                # Wymuś odświeżenie widoku
                try:
                    self.sheet.refresh()
                except:
                    pass
            else:
                print(f"⚠️  Nie udało się wczytać żadnej szerokości kolumny")
                print(f"     Dostępne metody sheet: {[m for m in dir(self.sheet) if 'width' in m.lower()]}")
                
        except Exception as e:
            print(f"⚠️  Błąd wczytania szerokości kolumn: {e}")
            import traceback
            traceback.print_exc()
    
    def _apply_saved_column_widths(self):
        """Zastosuj zapisane szerokości kolumn (cicha wersja bez logów - dla refresh_data)"""
        try:
            global CONFIG_FILE
            
            # Sprawdź czy plik config istnieje
            if not CONFIG_FILE.exists():
                return
            
            # Wczytaj config
            try:
                with open(CONFIG_FILE, 'r') as f:
                    config = json.load(f)
            except:
                return
            
            # Pobierz szerokości kolumn
            if 'column_widths' not in config:
                return
            
            widths = config['column_widths']
            
            # Użyj metody która działa (z testów wiemy że to column_width(column=X, width=Y))
            for col_idx_str, width in widths.items():
                col_idx = int(col_idx_str)
                try:
                    if hasattr(self.sheet, 'column_width'):
                        self.sheet.column_width(column=col_idx, width=width)
                except:
                    pass
            
            # NIE wywołuj refresh() tutaj - zostanie wywołany później przez _rebuild_all_cell_colors_with_selection()
                
        except:
            pass  # Cicho ignoruj błędy
    
