    def _maybe_update_received_percent(self, pid: int, db_str: str):
        """Zapisuje received_percent do master.sqlite TYLKO gdy zmieniła się wartość.

        Trzyma cache w pamięci (self._received_pct_cache) — eliminuje setki
        zbędnych UPDATE-ów na master, które na SMB blokowały innych klientów
        (database is locked, mulenie GUI). Zapisuje też z krótkim busy_timeout
        żeby nigdy nie blokować GUI > 500 ms.
        """
        if not self.db_manager or not self.db_manager.master_con:
            return
        cache = getattr(self, '_received_pct_cache', None)
        if cache is None:
            cache = {}
            self._received_pct_cache = cache
        if cache.get(pid) == db_str:
            return  # bez zmian — nie pisz
        try:
            con = self.db_manager.master_con
            try:
                con.execute("PRAGMA busy_timeout=500")  # max 0.5s czekania
            except Exception:
                pass
            con.execute(
                "UPDATE projects SET received_percent = ? WHERE project_id = ?",
                (db_str, pid),
            )
            con.commit()
            cache[pid] = db_str
        except sqlite3.OperationalError as db_err:
            # database is locked / readonly — pomiń, spróbujemy następnym razem
            if "locked" not in str(db_err).lower() and "readonly" not in str(db_err).lower():
                print(f"⚠️ BŁĄD zapisu received_percent: {db_err}")
        except Exception as db_err:
            print(f"⚠️ BŁĄD zapisu received_percent: {db_err}")
        finally:
            try:
                con.execute("PRAGMA busy_timeout=5000")  # przywróć
            except Exception:
                pass

    def _update_odebrano_stat(self):
        """Aktualizuj statystykę ODEBRANO: procent = odebrane / (wszystkie - ZZ)
        
        Liczy BEZPOŚREDNIO z bazy SQL (wszystkie nie-ukryte pozycje).
        Filtry UI NIE wpływają na wynik.
        """
        try:
            if not self.current_project_id or not self.db_manager or not self.db_manager.project_con:
                return
            
            con = self.db_manager.project_con
            pid = self.current_project_id
            
            # Wszystkie widoczne pozycje (nie-ukryte)
            total_rows = con.execute(
                "SELECT COUNT(*) FROM items WHERE project_id = ? AND COALESCE(is_hidden, 0) = 0",
                (pid,)
            ).fetchone()[0]
            
            if total_rows == 0:
                self.lbl_odebrano_stat.config(text="0%")
                self._maybe_update_received_percent(pid, "0% (0)")
                return
            
            # Pozycje z ZZ w numerze rysunku
            zz_count = con.execute("""
                SELECT COUNT(*) FROM items 
                WHERE project_id = ? AND COALESCE(is_hidden, 0) = 0
                AND UPPER(TRIM(COALESCE(NULLIF(work_drawing_no,''), src_drawing_no, ''))) LIKE '%ZZ'
            """, (pid,)).fetchone()[0]
            
            # Odebrane: delivered_qty >= order_qty (ta sama logika co symbol ● w arkuszu)
            # BEZ pozycji ZZ
            odebrane_count = con.execute("""
                SELECT COUNT(*) FROM items 
                WHERE project_id = ? AND COALESCE(is_hidden, 0) = 0
                AND UPPER(TRIM(COALESCE(NULLIF(work_drawing_no,''), src_drawing_no, ''))) NOT LIKE '%ZZ'
                AND delivered_qty IS NOT NULL
                AND COALESCE(order_qty, work_qty, src_qty) IS NOT NULL
                AND CAST(delivered_qty AS REAL) >= CAST(COALESCE(order_qty, work_qty, src_qty) AS REAL)
            """, (pid,)).fetchone()[0]
            
            valid_count = total_rows - zz_count
            if valid_count > 0:
                percent = (odebrane_count / valid_count) * 100
                percent_str = f"{percent:.0f}%"
                self.lbl_odebrano_stat.config(text=percent_str)
                
                db_str = f"{percent_str} ({total_rows})"
                self._maybe_update_received_percent(pid, db_str)
            else:
                self.lbl_odebrano_stat.config(text="0%")
                self._maybe_update_received_percent(pid, "0% (0)")
        except Exception as e:
            print(f"⚠️  Błąd aktualizacji statystyki ODEBRANO: {e}")
            self.lbl_odebrano_stat.config(text="-")
    
    def _on_project_combo_click(self, event=None):
        """Odśwież listę projektów przy kliknięciu dropdown (debounce 5s)"""
        try:
            import time
            now = time.time()
            if now - self._projects_last_refresh_ts < self._projects_refresh_interval_s:
                return
            self._projects_last_refresh_ts = now
            old_selection = self.project_var.get()
            self.load_projects()
            if old_selection and old_selection in list(self.project_combo['values']):
                self.project_var.set(old_selection)
        except Exception as e:
            print(f"⚠️  _on_project_combo_click error: {e}")
            import traceback
            traceback.print_exc()

    def load_projects(self, projects=None):
        """Załaduj projekty do dropdown z informacją o lockach - filtruj po typie"""
        # 🔄 Sprawdź żywotność połączenia (bezpiecznie, bez blokowania GUI)
        if not self._safe_ensure_master_alive():
            return
        
        if projects is None:
            # 🔥 KLUCZOWE: Pobierz projekty W WĄTKU z timeoutem!
            # get_projects() wywołuje SQL na SMB — po sleep/wake może wisieć 30-60s.
            # BEZ tego wrappera główny wątek GUI się zawiesza.
            ok, result = self._safe_db_call(
                self.db_manager.get_projects, 
                timeout_s=5.0, 
                label="get_projects"
            )
            
            if not ok:
                err = result
                err_msg = str(err).lower()
                
                if isinstance(err, TimeoutError):
                    # Timeout — dysk sieciowy nie odpowiada
                    print(f"⚠️  load_projects: timeout — dysk sieciowy nie odpowiada")
                    try:
                        self._show_connection_lost_banner("master")
                    except:
                        pass
                    return
                elif "locked" in err_msg:
                    # Database locked — spróbuj reconnect
                    if self._handle_db_locked(err):
                        ok2, result2 = self._safe_db_call(
                            self.db_manager.get_projects,
                            timeout_s=5.0,
                            label="get_projects_retry"
                        )
                        if ok2:
                            projects = result2
                        else:
                            print(f"❌ load_projects: ponowny błąd po reconnect: {result2}")
                            return
                    else:
                        return
                else:
                    print(f"❌ load_projects: błąd: {err}")
                    return
            else:
                projects = result
        
        # Pobierz wybrany typ projektu (zmapowany na wewnętrzny)
        project_type = self._get_internal_project_type()
        
        # Filtruj po typie i aktywności
        active_projects = [
            (pid, name) 
            for pid, name, active, ptype in projects 
            if active == 1 and ptype == project_type
        ]
        
        # Sortuj specjalnie: cyfry malejąco, potem litery A-Z (z numerami malejąco)
        def sort_key(item):
            pid, name = item
            name_lower = name.lower()
            
            # Sprawdź czy zaczyna się od cyfry
            if name_lower and name_lower[0].isdigit():
                # Wyciągnij początkowy numer
                import re
                match = re.match(r'^(\d+)', name_lower)
                if match:
                    num = int(match.group(1))
                    # Zwróć (0, -num) - 0 = cyfry na początku, -num = malejąco
                    return (0, -num, name_lower)
            
            # Zaczyna się od litery
            import re
            # Wyciągnij część literową i ewentualny numer
            match = re.match(r'^([a-z]+)(\d+)?', name_lower)
            if match:
                letter_part = match.group(1)  # np. "zp", "fh"
                num_part = match.group(2)      # np. "163", "01"
                
                if num_part:
                    # Ma numer - sortuj alfabetycznie A-Z, potem numery malejąco
                    return (1, letter_part, -int(num_part), name_lower)
                else:
                    # Brak numeru - sortuj po nazwie A-Z
                    return (1, letter_part, 0, name_lower)
            
            # Fallback - alfabetycznie
            return (1, name_lower, 0, "")
        
        active_projects.sort(key=sort_key)
        
        # Dropdown values: Nazwy z informacją o lockach
        values = []
        for pid, name in active_projects:
            # Sprawdź czy projekt jest zlockowany
            lock_info = self.lock_manager.get_project_lock_owner(pid)
            if lock_info:
                username = lock_info.get('user', '')  # LOGIN
                locked_by = self._get_user_display_name(username)  # NAZWA
                # Format: "Nazwa projektu 🔒 [Nazwa Usera]"
                display_name = f"{name} 🔒 [{locked_by}]"
            else:
                display_name = name
            values.append(display_name)
        
        # Zapisz dla innych metod (ID, Nazwa)
        self.projects_list = active_projects
        
        self.project_combo['values'] = values
        
        print(f"✅ Załadowano {len(active_projects)} projektów ({project_type}, sortowanie: cyfry malejąco → litery A-Z + numery malejąco)")
    
    def _get_user_display_name(self, username):
        """Pobierz display_name użytkownika na podstawie username (LOGIN)
        
        Args:
            username: LOGIN użytkownika
            
        Returns:
            str: display_name użytkownika lub username jeśli nie znaleziono
        """
        if not username:
            return "Nieznany"
        
        try:
            cursor = self.db_manager.master_con.execute(
                "SELECT display_name FROM users WHERE username = ?",
                (username,)
            )
            row = cursor.fetchone()
            if row and row[0]:
                return row[0]  # display_name
        except Exception as e:
            print(f"⚠️ Błąd pobierania display_name dla {username}: {e}")
        
        # Fallback - zwróć username jeśli nie ma display_name
        return username
    
    def _get_project_display_name(self, project_id, project_name):
        """Zwróć nazwę projektu z informacją o locku jeśli istnieje
        
        Args:
            project_id: ID projektu
            project_name: Nazwa projektu
            
        Returns:
            str: "Nazwa projektu 🔒 [User]" jeśli jest lock, lub "Nazwa projektu" jeśli nie ma
        """
        try:
            lock_info = self.lock_manager.get_project_lock_owner(project_id)
            if lock_info:
                username = lock_info.get('user', '')  # LOGIN
                locked_by = self._get_user_display_name(username)  # NAZWA
                return f"{project_name} 🔒 [{locked_by}]"
        except Exception as e:
            print(f"⚠️ Błąd sprawdzania locka dla projektu {project_id}: {e}")
        
        return project_name
    
    def load_suppliers(self, suppliers=None):
        """Załaduj dostawców do mapy"""
        if suppliers is None:
            suppliers = self.db_manager.get_suppliers()
        self.suppliers_map = {sid: name for sid, name in suppliers}
        
        # Zaktualizuj wartości w filtrze dostawców
        # 🔍 Filtruj dostawców - pokaż tylko tych, którzy występują w aktualnym projekcie
        try:
            # Pobierz unikalne supplier_id z items dla bieżącego projektu
            project_supplier_ids = set()
            if self.current_project_id and self.db_manager and self.db_manager.project_con:
                try:
                    # Pobierz unikalne supplier_id z tabeli items dla bieżącego projektu
                    proj_cursor = self.db_manager.project_con.execute(
                        "SELECT DISTINCT supplier_id FROM items WHERE supplier_id IS NOT NULL"
                    )
                    project_supplier_ids = {row[0] for row in proj_cursor.fetchall()}
                except Exception as proj_e:
                    print(f"⚠️  Nie udało się pobrać dostawców z projektu: {proj_e}")
                    # Przy błędzie - pokaż wszystkich dostawców (fallback)
                    project_supplier_ids = set(self.suppliers_map.keys())
            
            # Jeśli nie ma projektu lub błąd - pokaż wszystkich
            if not project_supplier_ids:
                project_supplier_ids = set(self.suppliers_map.keys())
            
            # Filtruj listę dostawców - tylko ci z aktualnego projektu
            supplier_filter_values = [FILTER_SUPPLIER_ALL] + [
                name for sid, name in sorted(suppliers, key=lambda x: x[1].lower())
                if sid in project_supplier_ids and name != SUPPLIER_EMPTY
            ]
            self.cmb_filter_supplier['values'] = supplier_filter_values
            
            print(f"✅ Filtr dostawców: {len(supplier_filter_values)-1} z {len(suppliers)} (projekt: {self.current_project_id})")
        except Exception as e:
            print(f"⚠️  Nie udało się zaktualizować filtra dostawców: {e}")
        
        print(f"✅ Załadowano {len(suppliers)} dostawców")
    
    def _apply_cell_colors(self):
        """Aplikuj kolory: szare tło BOM + alarmy (jak v6)
        
        UWAGA: Ta funkcja NIE obsługuje podświetlenia wiersza.
        Zamiast tej funkcji używaj _rebuild_all_cell_colors_with_selection(),
        która wywołuje _apply_cell_colors() + _apply_selected_row_highlight_only().
        """
        try:
            import datetime as dt
            today = dt.date.today()
            
            # Wyczyść zbiór komórek specjalnych
            self._cells_special_bg = set()
            
            # Kolory (jak v6)
            GRAY_BG = "#D3D3D3"      # Szare tło BOM
            GREEN_BG_LIGHT = "#D9EDF7"   # Zielone Zamówiono (jasne, stary kolor)
            GREEN_BG_BRIGHT = "#90EE90"  # Zielone Odebrane (wyraziste, nowy kolor)
            YELLOW_BG = "#FCF8E3"    # Żółty alarm (jasny)
            RED_BG = "#F2DEDE"       # Czerwony po terminie (jasny)
            
            # Helper parse date
            def parse_date(d):
                if not d:
                    return None
                try:
                    return dt.date.fromisoformat(str(d)[:10])
                except:
                    return None
            
            # === 0. WYCZYŚĆ WSZYSTKIE KOLORY (usunięcie artefaktów podświetlenia) ===
            for row_idx in range(len(self._sheet_row_ids)):
                try:
                    # Wyczyść WSZYSTKIE 19 kolumn aby usunąć artefakty podświetlenia wiersza
                    for col in range(19):
                        self.sheet.highlight_cells(row=row_idx, column=col, bg="white", fg="black")
                except:
                    pass
            
            # === 1. SZARE TŁO BOM ===
            for row_idx, overridden in enumerate(self._sheet_overridden):
                for col in [0, 1, 2, 3, 7, 8, 9, 18]:
                    if col in overridden:  # NADPISANE = szare
                        # NIE koloruj pustych komórek (Nr rysunku może być pusty w BOM)
                        try:
                            val = self.sheet.get_cell_data(row_idx, col)
                            if not val or str(val).strip() == "":
                                continue  # Pomiń puste
                        except:
                            pass
                        
                        self.sheet.highlight_cells(row=row_idx, column=col, bg=GRAY_BG)
                        # Dodaj do special_bg - podświetlenie wiersza nie nadpisze tego koloru
                        self._cells_special_bg.add((row_idx, col))
            
            # === 2. KOLORY ALARMÓW - JEDNO ZAPYTANIE SQL (jak v6) ===
            row_ids = [rid for rid in self._sheet_row_ids if rid]
            if not row_ids:
                return
            
            # Guard: po sleep/wake lub zmianie projektu project_con może być None
            if not self.db_manager.project_con:
                print("⚠️  _apply_cell_colors: project_con is None — pomijam kolory alarmów")
                return
            
            # Pobierz WSZYSTKIE dane jednym zapytaniem
            qs = ",".join(["?"] * len(row_ids))
            sql = f"""
                SELECT 
                    id,
                    COALESCE(ordered_flag, 0) AS ordered_flag,
                    deadline_date,
                    alarm_date,
                    COALESCE(order_qty, work_qty, src_qty) AS target_qty,
                    COALESCE(delivered_qty, 0) AS delivered_qty,
                    alarm_offset,
                    alarm_unit,
                    COALESCE(dwf_biblioteka, 0) AS dwf_biblioteka,
                    COALESCE(is_manual, 0) AS is_manual
                FROM items
                WHERE id IN ({qs})
            """
            
            cursor = self.db_manager.project_con.execute(sql, row_ids)
            
            # Mapuj id → dane
            data_map = {}
            for row in cursor.fetchall():
                iid, ordered_flag, deadline_date, alarm_date, target_qty, delivered_qty, alarm_offset, alarm_unit, dwf_biblioteka, is_manual = row
                data_map[int(iid)] = {
                    'ordered_flag': int(ordered_flag or 0),
                    'deadline_date': deadline_date,
                    'alarm_date': alarm_date,
                    'target_qty': target_qty,
                    'delivered_qty': delivered_qty,
                    'alarm_offset': alarm_offset,
                    'alarm_unit': alarm_unit,
                    'dwf_biblioteka': int(dwf_biblioteka or 0),
                    'is_manual': int(is_manual or 0)
                }
            
            
            # === 3. KOLORUJ KAŻDY WIERSZ ===
            colored_count = 0
            biblioteka_colored = 0
            
            for row_idx, item_id in enumerate(self._sheet_row_ids):
                if not item_id or item_id not in data_map:
                    continue
                
                data = data_map[item_id]
                
                # === NIEBIESKA CZCIONKA dla pozycji BIBLIOTEKA (kolumna NUMER) ===
                if data.get('dwf_biblioteka', 0) == 1:
                    try:
                        # Sprawdź czy komórka NUMER nie jest pusta
                        numer_val = self.sheet.get_cell_data(row_idx, 0)
                        if numer_val and str(numer_val).strip():
                            # Ustaw niebieską czcionkę dla kolumny NUMER (indeks 0)
                            # Sprawdź czy komórka ma szare tło (BOM override)
                            if (row_idx, 0) in self._cells_special_bg:
                                # Zachowaj szare tło, zmień tylko czcionkę
                                self.sheet.highlight_cells(row=row_idx, column=0, bg=GRAY_BG, fg="blue")
                            else:
                                # Białe tło, niebieska czcionka
                                self.sheet.highlight_cells(row=row_idx, column=0, bg="white", fg="blue")
                            # Dodaj do special_bg żeby podświetlenie wiersza nie nadpisało koloru czcionki
                            self._cells_special_bg.add((row_idx, 0))
                            biblioteka_colored += 1
                    except:
                        pass
                                
                # === NIEBIESKIE TŁO dla DELTA (kolumna 5) pozycji RĘCZNYCH ===
                if data.get('is_manual', 0) == 1:
                    try:
                        # Kolumna DELTA zawsze podkreslana dla ręcznych (nawet jeśli pusta)
                        self.sheet.highlight_cells(row=row_idx, column=5, bg="#e1f6f7", fg="black")
                        # Dodaj do special_bg żeby podświetlenie wiersza nie nadpisało tła
                        self._cells_special_bg.add((row_idx, 5))
                    except:
                        pass
                
                # === CZERWONA CZCIONKA dla NAZWY i DOSTAWCY gdy Dostawca = "anulowane" ===
                try:
                    # Pobierz wartość z kolumny Dostawca (10)
                    dostawca_val = self.sheet.get_cell_data(row_idx, 10)
                    if dostawca_val and str(dostawca_val).strip().lower() == "anulowane":
                        # Sprawdź czy kolumna 1 (NAZWA) ma szare tło (BOM override)
                        bg_col1 = GRAY_BG if (1 in self._sheet_overridden[row_idx]) else "white"
                        self.sheet.highlight_cells(row=row_idx, column=1, bg=bg_col1, fg="red")
                        self._cells_special_bg.add((row_idx, 1))
                        
                        # Kolumna 10 (DOSTAWCA) - czerwona czcionka
                        self.sheet.highlight_cells(row=row_idx, column=10, bg="white", fg="red")
                        self._cells_special_bg.add((row_idx, 10))
                except:
                    pass
                
                # DEBUG pierwszych 3 wierszy
                
                # Parse dat
                deadline_dt = parse_date(data['deadline_date'])
                alarm_dt = parse_date(data['alarm_date'])
                
                # Wylicz alarm_date dynamicznie jeśli NULL
                if alarm_dt is None and deadline_dt and data['alarm_offset']:
                    try:
                        off = int(data['alarm_offset'])
                        mul = 7 if str(data['alarm_unit'] or "").upper().startswith("W") else 1
                        alarm_dt = deadline_dt - dt.timedelta(days=off * mul)
                    except:
                        alarm_dt = None
                
                # Sprawdź czy kompletne (delivered >= target)
                is_complete = False
                try:
                    if data['target_qty'] is not None and data['delivered_qty'] is not None:
                        if float(data['target_qty']) > 0 and float(data['delivered_qty']) >= float(data['target_qty']):
                            is_complete = True
                except:
                    pass
                
                # Jeśli kompletne - BEZ KOLORÓW (białe tło zamiast dehighlight)
                # + WYRAZISTE ZIELONE tło dla kolumny "Ilość dostarczonych"
                if is_complete:
                    try:
                        self.sheet.highlight_cells(row=row_idx, column=6, bg=GREEN_BG_BRIGHT)   # Ilość dostarczonych (wyraziste)
                        self._cells_special_bg.add((row_idx, 6))
                        self.sheet.highlight_cells(row=row_idx, column=12, bg="white")  # Zamówiono
                        self.sheet.highlight_cells(row=row_idx, column=13, bg="white")  # Termin
                        self.sheet.highlight_cells(row=row_idx, column=14, bg="white")  # ALARM
                    except:
                        pass
                    continue
                
                # === JASNE ZIELONE "Zamówiono" gdy ordered_flag=1 (stary kolor) ===
                if data['ordered_flag']:
                    try:
                        self.sheet.highlight_cells(row=row_idx, column=12, bg=GREEN_BG_LIGHT)
                        self._cells_special_bg.add((row_idx, 12))
                    except:
                        pass
                else:
                    # Wyczyść zielone jeśli NIE zamówione
                    try:
                        self.sheet.highlight_cells(row=row_idx, column=12, bg="white")
                    except:
                        pass
                
                # === CZERWONE: po terminie (today > deadline) ===
                if deadline_dt and today > deadline_dt:
                    try:
                        self.sheet.highlight_cells(row=row_idx, column=13, bg=RED_BG)  # Termin
                        self.sheet.highlight_cells(row=row_idx, column=14, bg=RED_BG)  # ALARM
                        self._cells_special_bg.add((row_idx, 13))
                        self._cells_special_bg.add((row_idx, 14))
                    except:
                        pass
                
                # === ŻÓŁTE: alarm aktywny (today >= alarm && today <= deadline) ===
                elif alarm_dt and (deadline_dt is None or today <= deadline_dt) and today >= alarm_dt:
                    try:
                        self.sheet.highlight_cells(row=row_idx, column=14, bg=YELLOW_BG)  # ALARM
                        self._cells_special_bg.add((row_idx, 14))
                    except:
                        pass
                
                # === BEZ ALARMU: już wyczyszczone na początku ===
                else:
                    pass
        
        except Exception as e:
            print(f"⚠️  Błąd kolorowania: {e}")
            import traceback
            traceback.print_exc()
        
        # Wymuś odświeżenie widoku
        try:
            self.sheet.refresh()
        except:
            pass
    
    def _apply_selected_row_highlight_only(self):
        """Nakłada delikatny highlight na cały wiersz, w którym jest aktualnie zaznaczona komórka.
        
        Pomija komórki z kolorami specjalnymi (alarmy, szare BOM) zapisane w _cells_special_bg.
        """
        try:
            r = getattr(self, "_selected_row_idx", None)
            if r is None:
                return
            r = int(r)
            if r < 0:
                return
            if r >= len(self._sheet_row_ids):
                return
            
            bg = getattr(self, "_selected_row_bg", "#DDEEFF")
            fg = getattr(self, "_selected_row_fg", None)
            
            # 19 kolumn w arkuszu (0-18, włącznie z Moduł)
            for c in range(19):
                # Pomiń komórki ze specjalnymi kolorami
                if (r, c) in (getattr(self, '_cells_special_bg', set()) or set()):
                    continue
                try:
                    if fg is None:
                        self.sheet.highlight_cells(row=r, column=c, bg=bg)
                    else:
                        self.sheet.highlight_cells(row=r, column=c, bg=bg, fg=fg)
                except:
                    pass
        except Exception as e:
            print(f"⚠️  Błąd podświetlenia wiersza: {e}")
    
    def _rebuild_all_cell_colors_with_selection(self):
        """Odtwarza wszystkie kolory komórek (szarości + alarmy) i na końcu nakłada highlight wiersza selekcji.
        
        To jest główna funkcja do odświeżania kolorów - wywołuj JĄ zamiast _apply_cell_colors().
        """
        try:
            self._cells_special_bg = set()
        except Exception:
            pass
        try:
            self._apply_cell_colors()
        except Exception as e:
            print(f"⚠️  Błąd kolorowania komórek: {e}")
        try:
            self._apply_selected_row_highlight_only()
        except Exception as e:
            print(f"⚠️  Błąd podświetlenia wiersza: {e}")
        try:
            self.sheet.refresh()
        except Exception:
            pass

    def get_last_user_from_config(self):
        """Odczytaj ID ostatniego użytkownika z config"""
        try:
            if CONFIG_FILE.exists():
                with open(CONFIG_FILE) as f:
                    config = json.load(f)
                return config.get('last_user_id')
        except:
            pass
        return None
    
    def save_last_user_to_config(self, user_id):
        """Zapisz ID ostatniego użytkownika do config"""
        try:
            if CONFIG_FILE.exists():
                with open(CONFIG_FILE) as f:
                    config = json.load(f)
            else:
                config = {"client": {"name": socket.gethostname()}, "locks": {"folder": str(Path(LOCKS_DIR))}}
            
            config['last_user_id'] = user_id
            
            with open(CONFIG_FILE, 'w') as f:
                json.dump(config, f, indent=2)
        except Exception as e:
            print(f"⚠️  Nie udało się zapisać ostatniego użytkownika: {e}")

    def _start_silent_login_background(self, user_id):
        """Uruchom ciche logowanie w tle, aby nie blokować GUI."""
        import threading

        if getattr(self, "_login_thread", None) and self._login_thread.is_alive():
            return

        self._login_in_progress = True
        self._login_thread = threading.Thread(
            target=self._silent_login_worker,
            args=(user_id,),
            daemon=True
        )
        self._login_thread.start()

    def _silent_login_worker(self, user_id):
        """Wątek roboczy: pobierz usera i przełącz tryb DB bez dotykania GUI."""
        try:
            sql = "SELECT id, username, display_name, role FROM users WHERE id = ?"
            cursor = self.db_manager.master_con.execute(sql, (user_id,))
            row = cursor.fetchone()
            if not row:
                self.after(0, lambda: self._finish_silent_login(False, None, None, None, None, "Brak użytkownika"))
                return

            uid, username, display_name, role = row
            rw_error = None

            if role in ("ADMIN", "USER$$", "USER$"):
                try:
                    self.db_manager.reconnect_master_rw()
                except Exception as e:
                    rw_error = e
                    self.db_manager.connect_master()
            else:
                self.db_manager.connect_master()

            self.after(0, lambda: self._finish_silent_login(True, uid, username, display_name, role, rw_error))
        except Exception as e:
            self.after(0, lambda: self._finish_silent_login(False, None, None, None, None, e))

    def _finish_silent_login(self, success, uid, username, display_name, role, error):
        """Aktualizacja GUI po cichym logowaniu."""
        self._login_in_progress = False

        if not success:
            print(f"⚠️  Błąd cichego logowania: {error}")
            return

        self.current_user_id = uid
        self.current_user = username
        self.current_user_role = role
        
        # Zaktualizuj nazwę użytkownika w LockManager
        if hasattr(self, 'lock_manager') and self.lock_manager:
            self.lock_manager.update_user_name(username)

        if error:
            messagebox.showwarning(
                "Ostrzeżenie",
                "Nie można włączyć trybu zapisu.\nPracujesz w trybie READ-ONLY."
            )

        if role in ("ADMIN", "USER$$", "USER$"):
            print(f"✅ Zalogowano automatycznie: {username} (ID={uid}, Rola={role}) - tryb READ-WRITE")
        else:
            print(f"✅ Zalogowano automatycznie: {username} (ID={uid}, Rola={role}) - tryb READ-ONLY")

        # Wyczyść komunikat ładowania - użytkownik zalogowany
        if hasattr(self, 'info_label'):
            self.info_label.config(text="Brak projektu", fg="white")

        self._update_export_button_state()
        self._update_lock_buttons_state()
        self._update_tools_menu()  # Aktualizuj menu Narzędzia (dodaj Monitor jeśli uprawnienia)
    
    def _silent_login_last_user(self, user_id):
        """Ciche zalogowanie ostatniego użytkownika (bez promptu hasła)"""
        try:
            sql = "SELECT id, username, display_name, role FROM users WHERE id = ?"
            cursor = self.db_manager.master_con.execute(sql, (user_id,))
            row = cursor.fetchone()
            
            if row:
                uid, username, display_name, role = row
                self.current_user_id = uid
                self.current_user = username
                self.current_user_role = role
                
                # Zaktualizuj nazwę użytkownika w LockManager
                if hasattr(self, 'lock_manager') and self.lock_manager:
                    self.lock_manager.update_user_name(username)
                
                # Logika dla roli ADMIN, USER$$ i USER$ - otwórz master w trybie READ-WRITE
                if role in ("ADMIN", "USER$$", "USER$"):
                    try:
                        print(f"🔄 Przełączanie do trybu READ-WRITE...")
                        self.db_manager.reconnect_master_rw()
                        print(f"✅ Zalogowano automatycznie: {username} (ID={uid}, Rola={role}) - tryb READ-WRITE")
                    except Exception as e:
                        print(f"⚠️  Błąd trybu ADMIN/USER$$: {e}")
                        messagebox.showwarning("Ostrzeżenie", f"Nie można włączyć trybu zapisu.\nPracujesz w trybie READ-ONLY.")
                        self.db_manager.connect_master()  # Fallback do READ-ONLY
                else:
                    self.db_manager.connect_master()
                    print(f"✅ Zalogowano automatycznie: {username} (ID={uid}, Rola={role}) - tryb READ-ONLY")
                
                # Aktualizuj dostępność przycisków
                self._update_export_button_state()
                self._update_lock_buttons_state()
                self._update_tools_menu()  # Aktualizuj menu Narzędzia (dodaj Monitor jeśli uprawnienia)
        except Exception as e:
            print(f"⚠️  Błąd cichego logowania: {e}")
    
    def load_users(self, users_rows=None):
        """Załaduj listę użytkowników do dropdown"""
        try:
            # 🔄 Sprawdź żywotność połączenia (bezpiecznie, bez blokowania GUI)
            if not self._safe_ensure_master_alive():
                return
            
            users = []
            if users_rows is None:
                # DODATKOWA WALIDACJA - sprawdź historię zmian w users (jeśli istnieje audit log)
                try:
                    # Sprawdź czy są dziwne zmiany w bazie
                    audit_sql = """
                        SELECT name FROM sqlite_master 
                        WHERE type='table' AND name='user_audit_log'
                    """
                    has_audit = self.db_manager.master_con.execute(audit_sql).fetchone()
                    if has_audit:
                        print(f"🔍 Sprawdzam audit log użytkowników...")
                        audit_data = self.db_manager.master_con.execute(
                            "SELECT * FROM user_audit_log ORDER BY timestamp DESC LIMIT 10"
                        ).fetchall()
                        for row in audit_data:
                            print(f"   {row}")
                except:
                    pass

                # Pobierz aktywnych użytkowników
                sql = "SELECT id, username, display_name, role FROM users WHERE is_active = 1 ORDER BY username"
                users_rows = self.db_manager.master_con.execute(sql).fetchall()

            print(f"📋 Lista użytkowników z bazy:")
            for row in users_rows:
                uid, username, display_name, role = row
                print(f"   ID={uid}, username='{username}', display_name='{display_name}', role='{role}'")
                
                # Walidacja - pomiń użytkowników z pustymi/nieprawidłowymi danymi
                if not username or not str(username).strip():
                    print(f"   ⚠️  POMINIĘTO: użytkownik ID={uid} ma puste username!")
                    continue
                
                # Walidacja - POMIŃ użytkowników z cyfrowym username (prawdopodobnie błędne dane)
                if username.isdigit() and len(username) <= 4:
                    print(f"   ⚠️  POMIJAM: użytkownik ID={uid} ma nieprawidłowe username='{username}' (same cyfry - prawdopodobnie pomyłka)")
                    continue
                
                label = f"{uid} | {username}"
                if display_name and display_name != username:
                    label += f" ({display_name})"
                label += f" [{role}]"
                users.append(label)
            
            # Zabezpieczenie - jeśli lista pusta, dodaj awaryjnego admina
            if not users:
                print(f"⚠️  BRAK UŻYTKOWNIKÓW W BAZIE! Dodaję awaryjnego ADMIN...")
                users = ["11 | ADMIN [ADMIN]"]
            
            self.user_combo['values'] = users
            
            # Załaduj ostatniego użytkownika z config (bez auto-logowania)
            if users:
                last_user = self.get_last_user_from_config()
                print(f"🔍 Ostatni użytkownik z config: {last_user}")
                
                if last_user:
                    # Znajdź użytkownika w liście
                    found = False
                    for u in users:
                        if u.startswith(f"{last_user} |"):
                            self.user_var.set(u)
                            # Auto-logowanie bez hasła dla ostatniego użytkownika
                            self._start_silent_login_background(last_user)
                            print(f"🔍 Przywrócono ostatniego użytkownika: {u}")
                            found = True
                            break
                    
                    if not found:
                        # Ostatni użytkownik nie istnieje - ustaw pierwszego bez logowania
                        self.user_var.set(users[0])
                        print(f"⚠️  Ostatni użytkownik ID={last_user} nie znaleziony w bazie!")
                        print(f"🔍 Ustawiono: {users[0]}")
                else:
                    # Brak zapisanego użytkownika - ustaw pierwszego bez logowania
                    self.user_var.set(users[0])
                    print(f"🔍 Brak ostatniego użytkownika, ustawiono: {users[0]}")
            
            print(f"✅ Załadowano {len(users)} użytkowników")
        
        except Exception as e:
            print(f"⚠️  Błąd ładowania użytkowników: {e}")
            import traceback
            traceback.print_exc()
    
    def prompt_password(self, username):
        """Dialog zapytania o hasło"""
        dlg = tk.Toplevel(self)
        dlg.title(f"Logowanie: {username}")
        dlg.geometry("400x180")
        dlg.transient(self)
        dlg.grab_set()
        dlg.resizable(False, False)
        # Wycentruj względem okna aplikacji (nie ekranu)
        dlg.update_idletasks()
        self.update_idletasks()
        try:
            parent_x = self.winfo_rootx()
            parent_y = self.winfo_rooty()
            parent_width = self.winfo_width()
            parent_height = self.winfo_height()
            x = parent_x + (parent_width - 400) // 2
            y = parent_y + (parent_height - 180) // 2
        except:
            # Fallback - wycentruj na ekranie
            sw = dlg.winfo_screenwidth()
            sh = dlg.winfo_screenheight()
            x = (sw - 400) // 2
            y = (sh - 180) // 2
        dlg.geometry(f"400x180+{x}+{y}")
        
        frm = tk.Frame(dlg, padx=25, pady=20)
        frm.pack(fill=tk.BOTH, expand=True)
        
        tk.Label(frm, text=f"Podaj hasło dla: {username}", font=("Arial", 10, "bold")).pack(pady=(0, 15))
        
        tk.Label(frm, text="Hasło:").pack(anchor="w")
        var_pwd = tk.StringVar()
        entry_pwd = tk.Entry(frm, textvariable=var_pwd, show="*", width=35)
        entry_pwd.pack(pady=5, fill=tk.X)
        entry_pwd.focus()
        
        result = {"ok": False, "password": ""}
        
        def on_ok():
            result["ok"] = True
            result["password"] = var_pwd.get()
            dlg.destroy()
        
        def on_cancel():
            dlg.destroy()
        
        # Bind Enter
        entry_pwd.bind("<Return>", lambda e: on_ok())
        
        btn_frame = tk.Frame(frm)
        btn_frame.pack(pady=15, fill=tk.X)
        
        tk.Button(btn_frame, text="OK", command=on_ok, width=12).pack(side=tk.LEFT, padx=10, expand=True)
        tk.Button(btn_frame, text="Anuluj", command=on_cancel, width=12).pack(side=tk.LEFT, padx=10, expand=True)
        
        dlg.wait_window()
        return result
    
    def on_user_selected(self, event=None):
        """Obsługa wyboru użytkownika z dropdown"""
        selected = self.user_var.get()

        # Walidacja wyboru
        if not selected or "|" not in selected:
            return  # Pomijamy, jeśli niepoprawny wybór
        
        # 🔄 Sprawdź żywotność połączenia (bezpiecznie, bez blokowania GUI)
        if not self._safe_ensure_master_alive():
            return

        # Parsowanie ID użytkownika (format: "ID | username (display_name) [role]")
        try:
            new_user_id = int(selected.split("|")[0].strip())
        except ValueError:
            return
        
        # Jeśli to ten sam użytkownik - nic nie rób
        if self.current_user_id == new_user_id:
            return

        # Funkcja pomocnicza do przywrócenia poprzedniego użytkownika w dropdown
        def restore_previous_user():
            """Przywróć poprzedniego użytkownika w dropdown"""
            # ZAWSZE odepnij event przed zmianą wartości
            try:
                self.user_combo.unbind("<<ComboboxSelected>>")
            except:
                pass
            
            try:
                if self.current_user_id:
                    # Pobierz aktualnego użytkownika z bazy aby odtworzyć pełny format
                    sql = "SELECT id, username, display_name, role FROM users WHERE id = ?"
                    
                    # RETRY LOOP - 3 próby z opóźnieniem i reconnect przy I/O error
                    row = None
                    for attempt in range(3):
                        try:
                            self.db_manager.master_con.commit()  # Zwolnij locki
                            cursor = self.db_manager.master_con.execute(sql, (self.current_user_id,))
                            row = cursor.fetchone()
                            break
                        except sqlite3.OperationalError as e:
                            err_msg = str(e).lower()
                            if "locked" in err_msg and attempt < 2:
                                print(f"⚠️  restore_previous_user: database locked (próba {attempt+1}/3), czekam 100ms...")
                                time.sleep(0.1)
                            elif "disk i/o error" in err_msg and attempt < 2:
                                print(f"⚠️  restore_previous_user: disk I/O error (próba {attempt+1}/3), wymuszam reconnect...")
                                # Wymuś reconnect
                                try:
                                    self.db_manager.master_con.close()
                                except:
                                    pass
                                self.db_manager.master_con = None
                                if self.current_user_role in ("ADMIN", "USER$$", "USER$"):
                                    self.db_manager.reconnect_master_rw()
                                else:
                                    self.db_manager.connect_master()
                                time.sleep(0.1)
                            else:
                                raise
                    
                    if row:
                        uid, username, display_name, role = row
                        label = f"{uid} | {username}"
                        if display_name and display_name != username:
                            label += f" ({display_name})"
                        label += f" [{role}]"
                        
                        # Ustaw wartość w dropdown
                        self.user_var.set(label)
                        print(f"🔄 Przywrócono użytkownika w dropdown: {label}")
                    else:
                        # Jeśli nie znaleziono w bazie, wyczyść dropdown
                        self.user_var.set("")
                        print("⚠️  Nie znaleziono poprzedniego użytkownika w bazie")
                else:
                    # Brak poprzedniego użytkownika - wyczyść dropdown
                    self.user_var.set("")
                    print("🔄 Wyczyszczono wybór użytkownika (brak poprzedniego)")
                    
            except Exception as e:
                print(f"⚠️  Błąd przywracania użytkownika: {e}")
                import traceback
                traceback.print_exc()
                # W przypadku błędu - wyczyść dropdown
                try:
                    self.user_var.set("")
                except:
                    pass
            
            finally:
                # ZAWSZE przyepnij event z powrotem
                try:
                    self.user_combo.bind("<<ComboboxSelected>>", self.on_user_selected)
                except Exception as e:
                    print(f"⚠️  Błąd podpinania eventu: {e}")

        # Sprawdź, czy lock istnieje i wyświetl odpowiednie informacje
        if self.have_lock and self.current_user_id and new_user_id != self.current_user_id:
            # Pobierz nazwę BIEŻĄCEGO projektu z projects_list na podstawie current_project_id
            current_project_name = None
            for pid, pname in self.projects_list:
                if pid == self.current_project_id:
                    current_project_name = pname
                    break
            
            if not current_project_name:
                current_project_name = f"Projekt {self.current_project_id}"
            
            result = messagebox.askyesnocancel(
                "Zmiana użytkownika",
                f"Masz aktywny lock na projekcie: {current_project_name}\n\n"
                f"TAK - zapisać zmiany i zmienić użytkownika\n"
                f"ANULUJ / zamknięcie okna - odrzucić zmiany i zmienić użytkownika\n"
                f"NIE - zostań jako {self.current_user}",
                icon='warning'
            )
            
            if result is None:  # ANULUJ (lub krzyżyk) - odrzuć zmiany i zmień użytkownika
                try:
                    if not self.cancel_lock(skip_confirmation=True):
                        restore_previous_user()
                        return
                except Exception as e:
                    print(f"⚠️  Błąd przy anulowaniu locka: {e}")
                    messagebox.showerror("Błąd", f"Nie udało się anulować locka:\n{e}")
                    restore_previous_user()
                    return
            elif result is True:  # TAK - zapisz zmiany i zmień użytkownika
                try:
                    self.release_lock()
                except Exception as e:
                    print(f"⚠️  Błąd przy zwalnianiu locka: {e}")
                    messagebox.showerror("Błąd", f"Nie udało się zwolnić locka:\n{e}")
                    restore_previous_user()
                    return
            else:  # NIE (False) - zostań przy obecnym użytkowniku
                restore_previous_user()
                return

        # Parsowanie szczegółowych informacji o użytkowniku
        try:
            parts = selected.split("|")
            if len(parts) >= 2:
                username = parts[1].strip().split("(")[0].strip().split("[")[0].strip()
                role = selected.split("[")[-1].split("]")[0].strip()

                # Weryfikacja hasła - RETRY LOOP (sieć + locki + I/O errors)
                stored_hash = None
                for attempt in range(3):
                    try:
                        self.db_manager.master_con.commit()  # Zwolnij locki przed SELECT
                        cursor = self.db_manager.master_con.execute(
                            "SELECT password_hash FROM users WHERE id = ?", (new_user_id,)
                        )
                        stored_hash = cursor.fetchone()
                        break
                    except sqlite3.OperationalError as e:
                        err_msg = str(e).lower()
                        if "locked" in err_msg and attempt < 2:
                            print(f"⚠️  on_user_selected: database locked (próba {attempt+1}/3), czekam 200ms...")
                            time.sleep(0.2)
                        elif "disk i/o error" in err_msg and attempt < 2:
                            print(f"⚠️  on_user_selected: disk I/O error (próba {attempt+1}/3), wymuszam reconnect...")
                            # Wymuś reconnect
                            try:
                                self.db_manager.master_con.close()
                            except:
                                pass
                            self.db_manager.master_con = None
                            # Użyj bieżącej roli (przed zmianą użytkownika)
                            if self.current_user_role in ("ADMIN", "USER$$", "USER$"):
                                self.db_manager.reconnect_master_rw()
                            else:
                                self.db_manager.connect_master()
                            time.sleep(0.2)
                        else:
                            raise
                
                if stored_hash and stored_hash[0]:
                    result = self.prompt_password(username)
                    if not result["ok"]:
                        # Anulowanie zmiany użytkownika - przywróć poprzedniego
                        restore_previous_user()
                        return
                    import hashlib
                    entered_hash = hashlib.sha256(result["password"].encode()).hexdigest()
                    if entered_hash != stored_hash[0]:
                        messagebox.showerror("Błąd logowania", "Nieprawidłowe hasło!")
                        restore_previous_user()
                        return

                # Ustawienie nowego użytkownika
                self.current_user_id = new_user_id
                self.current_user = username
                self.current_user_role = role
                
                # Zaktualizuj nazwę użytkownika w LockManager
                if hasattr(self, 'lock_manager') and self.lock_manager:
                    self.lock_manager.update_user_name(username)
                
                # Zamknij okno chatu jeśli jest otwarte (zmienił się użytkownik)
                if self.chat_window and self.chat_window.winfo_exists():
                    self.chat_window.on_close()
                
                # Zapisz ostatniego użytkownika do config
                self.save_last_user_to_config(new_user_id)

                # Logika dla roli ADMIN, USER$$ i USER$ - otwórz master w trybie READ-WRITE
                if role in ("ADMIN", "USER$$", "USER$"):
                    try:
                        print(f"🔄 Przełączanie do trybu READ-WRITE...")
                        self.update_idletasks()  # Odśwież GUI przed operacją bazodanową
                        self.db_manager.reconnect_master_rw()
                        print(f"✅ Wybrano użytkownika: {username} (ID={new_user_id}, Rola={role}) - tryb READ-WRITE")
                    except Exception as e:
                        print(f"⚠️  Błąd trybu ADMIN/USER$$: {e}")
                        messagebox.showwarning("Ostrzeżenie", f"Nie można włączyć trybu zapisu.\nPracujesz w trybie READ-ONLY.")
                        self.db_manager.connect_master()  # Fallback do READ-ONLY
                else:
                    # Przywróć tryb READ-ONLY
                    self.db_manager.connect_master()
                    print(f"✅ Wybrano użytkownika: {username} (ID={new_user_id}, Rola={role}) - tryb READ-ONLY")
                
                # Aktualizuj dostępność przycisków
                self._update_export_button_state()
                self._update_lock_buttons_state()
                self._update_tools_menu()  # Aktualizuj menu Narzędzia (dodaj Monitor jeśli uprawnienia)

        except Exception as e:
            print(f"⚠️  Wystąpił błąd podczas wyboru użytkownika: {e}")
            restore_previous_user()
    
    def _update_export_button_state(self):
        """Aktualizuje stan przycisku EXPORT i DRUKUJ w zależności od roli użytkownika"""
        if not hasattr(self, 'export_btn'):
            return
        
        allowed_roles = ["USER", "USER$", "USER$$", "ADMIN"]
        if self.current_user_role in allowed_roles:
            self.export_btn.config(state=tk.NORMAL)
            # Aktywuj też przycisk DRUKUJ jeśli istnieje
            if hasattr(self, 'btn_print'):
                self.btn_print.config(state=tk.NORMAL)
        else:
            self.export_btn.config(state=tk.DISABLED)
            if hasattr(self, 'btn_print'):
                self.btn_print.config(state=tk.DISABLED)
    
    def _update_lock_buttons_state(self):
        """Aktualizuje stan przycisków lock w zależności od roli użytkownika"""
        # Przyciski Przejmij Lock i Wymuś nieaktywne dla GUEST
        is_guest = self.current_user_role == "GUEST"
        
        if hasattr(self, 'btn_acquire_lock'):
            self.btn_acquire_lock.config(state=tk.DISABLED if is_guest else tk.NORMAL)
        
        if hasattr(self, 'btn_force_lock'):
            self.btn_force_lock.config(state=tk.DISABLED if is_guest else tk.NORMAL)
    
    def _update_tools_menu(self):
        """Aktualizuje menu Narzędzia - dodaje Monitor dla ADMIN i GKI"""
        if not hasattr(self, 'toolsm'):
            return
        
        # Sprawdź czy Monitor już istnieje w menu
        try:
            menu_len = self.toolsm.index('end')
            if menu_len is not None and menu_len >= 1:
                # Menu ma więcej niż 1 element - sprawdź czy ostatni to Monitor
                last_label = self.toolsm.entrycget(menu_len, 'label')
                if 'MONITOR' in last_label.upper():
                    # Monitor już jest - nie dodawaj ponownie
                    return
        except:
            pass
        
        # Dodaj Monitor jeśli użytkownik ma uprawnienia
        if self.current_user_role == "ADMIN" or self.current_user == "GKI":
            self.toolsm.add_separator()
            self.toolsm.add_command(label="📊 RM_MONITOR", command=self.launch_monitor)
            print(f"✅ Dodano opcję Monitor do menu Narzędzia (użytkownik: {self.current_user}, rola: {self.current_user_role})")
    
    def load_backup_dates(self):
        """Załaduj dostępne daty backupów dla bieżącego projektu"""
        if not self.current_project_id or not self.backup_manager:
            self.backup_combo['values'] = ["Aktualny stan"]
            self.backup_combo.set("Aktualny stan")
            return
        
        try:
            # Pobierz listę backupów projektu
            backups = self.backup_manager.list_project_backups(self.current_project_id)
            
            # Sortuj od najnowszych
            dates = [b['date'] for b in backups]
            
            # Dodaj "Aktualny stan" na początku
            values = ["Aktualny stan"] + dates
            
            self.backup_combo['values'] = values
            self.backup_combo.set("Aktualny stan")
            
        except Exception as e:
            print(f"⚠️  Błąd ładowania backupów: {e}")
            self.backup_combo['values'] = ["Aktualny stan"]
            self.backup_combo.set("Aktualny stan")
    
    def on_backup_selected(self, event=None):
        """Wybrano datę backupu do podglądu"""
        selected = self.backup_date_var.get()
        
        if selected == "Aktualny stan":
            # Wróć do aktualnego stanu
            if self.viewing_backup:
                self.viewing_backup = False
                self.backup_date = None
                self.info_label.config(fg="white")
                
                # Przywróć właściwy tekst w zależności od stanu locka
                if self.have_lock:
                    self.info_label.config(text=f"Projekt {self.current_project_id} (LOCAL - edycja włączona)")
                else:
                    self.info_label.config(text=f"Projekt {self.current_project_id} (READ-ONLY)")
                
                # Reaktywuj przycisk Przejmij Lock (jeśli nie mamy locka)
                if not self.have_lock:
                    self.btn_acquire_lock.config(state=tk.NORMAL)
                    self.btn_force_lock.config(state=tk.NORMAL)
                
                self.refresh_data()
                print("📄 Powrót do aktualnego stanu")
        else:
            # Załaduj podgląd backupu
            self.viewing_backup = True
            self.backup_date = selected
            self.load_backup_preview(selected)
    
    def load_backup_preview(self, backup_date: str):
        """Załaduj dane z backupu do podglądu"""
        if not self.current_project_id or not self.backup_manager:
            return
        
        try:
            # Ścieżka do backupu
            project_backup_subdir = self.backup_manager.projects_backup_dir / f"project_{self.current_project_id}"
            backup_file = project_backup_subdir / f"project_{self.current_project_id}_{backup_date}.sqlite"
            
            if not backup_file.exists():
                messagebox.showerror("Błąd", f"Backup z {backup_date} nie istnieje!")
                self.backup_combo.set("Aktualny stan")
                return
            
            # Wczytaj dane z backupu
            print(f"\n📅 Ładuję podgląd backupu z {backup_date}...")
            self.info_label.config(
                text=f"PODGLĄD BACKUPU z {backup_date} (TYLKO ODCZYT)",
                fg="#f39c12"
            )
            
            # Dezaktywuj przycisk Przejmij Lock
            self.btn_acquire_lock.config(state=tk.DISABLED)
            self.btn_force_lock.config(state=tk.DISABLED)
            
            # Użyj tej samej logiki co refresh_data, ale z inną bazą
            self._load_items_from_backup(backup_file)
            
            messagebox.showinfo(
                "Podgląd backupu",
                f"Wyświetlam dane z backupu projektu z dnia:\n{backup_date}\n\n"
                "To jest tylko PODGLĄD - nie możesz edytować.\n"
                "Aby wrócić do aktualnego stanu, wybierz 'Aktualny stan'."
            )
            
        except Exception as e:
            messagebox.showerror("Błąd", f"Nie udało się załadować backupu:\n{e}")
            self.backup_combo.set("Aktualny stan")
            self.viewing_backup = False
            self.backup_date = None
    
    def _load_items_from_backup(self, backup_path: Path):
        """Załaduj items z pliku backupu i wyświetl w arkuszu"""
        import sqlite3
        import datetime as dt
        
        # DEBUG - wypisz info o pliku
        import time
        time.sleep(0.2)
        
        print(f"\n  📂 Backup file: {backup_path}")
        print(f"  📏 Rozmiar: {backup_path.stat().st_size / 1024:.1f} KB")
        print(f"  🕐 Modyfikacja: {dt.datetime.fromtimestamp(backup_path.stat().st_mtime)}")
        
        # Połącz z backupem - z PRAGMA SMB-safe
        backup_con = _open_baza_connection(backup_path, timeout=30.0)
        
        try:
            # Pobierz items
            sql = """
                SELECT 
                    id,
                    COALESCE(work_drawing_no, src_drawing_no) as drawing_no,
                    COALESCE(work_name, src_name) as name,
                    COALESCE(work_desc, src_desc) as descr,
                    COALESCE(work_qty, src_qty) as qty_bom,
                    order_qty,
                    delivered_qty,
                    COALESCE(class_manual, class_auto, '') as class_effective,
                    COALESCE(mat_manual_text, mat_auto_text, src_material_text, '') as mat_effective_text,
                    thickness_mm,
                    supplier_id,
                    price_pln,
                    ordered_flag,
                    ordered_at,
                    deadline_date,
                    alarm_date,
                    alarm_offset,
                    alarm_unit,
                    notes,
                    dwf_biblioteka,
                    src_drawing_no,
                    src_name,
                    src_desc,
                    src_qty,
                    src_material_text,
                    class_manual,
                    class_auto,
                    mat_manual_text,
                    mat_auto_text,
                    COALESCE(is_manual, 0) as is_manual
                FROM items
                ORDER BY id
            """
            
            cursor = backup_con.execute(sql)
            items = [dict(row) for row in cursor.fetchall()]
            
            # Użyj tej samej logiki co refresh_data
            # Tymczasowo podstaw backup_con jako project_con
            original_con = self.db_manager.project_con
            self.db_manager.project_con = backup_con
            
            # Wywołaj refresh_data - pomiń migrację i pobieranie (już mamy items)
            self._display_items_in_sheet(items)
            
            # Przywróć oryginalną bazę
            self.db_manager.project_con = original_con
            
            print(f"✅ Załadowano {len(items)} items z backupu {backup_path.name}")
            
        finally:
            backup_con.close()

    def _get_internal_project_type(self):
        """Mapowanie nazw wyświetlanych na wewnętrzne typy projektów"""
        display_to_internal = {
            "PRODUKCJA": "MACHINE",
            "MAGAZYN": "WAREHOUSE"
        }
        display_type = self.project_type_var.get() if hasattr(self, 'project_type_var') else "PRODUKCJA"
        return display_to_internal.get(display_type, "MACHINE")
    
    def update_menu_state(self):
        """Aktualizacja stanu menu na podstawie typu projektu"""
        if not hasattr(self, 'filem'):
            return
            
        project_type = self._get_internal_project_type()
        
        # Menu indeksy:
        # 0: Import BOM… (tylko MACHINE)
        # 1: Aktualizuj BOM… (tylko MACHINE)
        # 2: Dodaj BOM… (tylko MACHINE)
        # 3: Import moduł… (tylko WAREHOUSE)
        
        if project_type == "MACHINE":
            # PRODUKCJA: włącz "Import BOM…", "Aktualizuj BOM…" i "Dodaj BOM…", wyłącz "Import moduł…"
            self.filem.entryconfig(0, state='normal')
            self.filem.entryconfig(1, state='normal')
            self.filem.entryconfig(2, state='normal')
            self.filem.entryconfig(3, state='disabled')
        elif project_type == "WAREHOUSE":
            # MAGAZYN: włącz "Import moduł…", wyłącz "Import BOM…", "Aktualizuj BOM…" i "Dodaj BOM…"
            self.filem.entryconfig(0, state='disabled')
            self.filem.entryconfig(1, state='disabled')
            self.filem.entryconfig(2, state='disabled')
            self.filem.entryconfig(3, state='normal')
        else:
            # Domyślnie wyłącz wszystkie
            self.filem.entryconfig(0, state='disabled')
            self.filem.entryconfig(1, state='disabled')
            self.filem.entryconfig(2, state='disabled')
            self.filem.entryconfig(3, state='disabled')
        
        # Aktualizuj przycisk "Usuń dla zaznaczonych" - tylko WAREHOUSE
        if hasattr(self, 'btn_delete_selected'):
            if project_type == "WAREHOUSE":
                self.btn_delete_selected.config(state=tk.NORMAL)
            else:
                self.btn_delete_selected.config(state=tk.DISABLED)
    
    def on_project_type_changed(self, event=None):
        """Zmieniono typ projektu (PRODUKCJA/MAGAZYN) - przeładuj listę projektów"""
        new_internal_type = self._get_internal_project_type()
        new_display_type = self.project_type_var.get()
        print(f"\n🔄 Zmiana typu projektu na: {new_display_type} (wewnętrznie: {new_internal_type})")
        
        # Jeśli mamy lock - zapytaj użytkownika co zrobić
        if self.have_lock and self.current_project_id:
            # Pobierz nazwę BIEŻĄCEGO projektu z projects_list
            current_project_name = None
            for pid, pname in self.projects_list:
                if pid == self.current_project_id:
                    current_project_name = pname
                    break
            
            if not current_project_name:
                current_project_name = f"Projekt {self.current_project_id}"
            
            # Poprzedni typ projektu (przed zmianą)
            old_display_type = "PRODUKCJA" if new_display_type == "MAGAZYN" else "MAGAZYN"
            
            result = messagebox.askyesnocancel(
                "Zmiana środowiska",
                f"Masz aktywny lock na projekcie: {current_project_name}\n"
                f"(środowisko: {old_display_type})\n\n"
                f"TAK - zapisać zmiany i przejść do środowiska: {new_display_type}\n"
                f"ANULUJ / zamknięcie okna - odrzucić zmiany i przejść do: {new_display_type}\n"
                f"NIE - zostań w środowisku: {old_display_type}",
                icon='warning'
            )
            
            if result is None:  # ANULUJ (lub krzyżyk) - odrzuć zmiany i przejdź
                if not self.cancel_lock(skip_confirmation=True):
                    # Przywróć poprzedni typ w dropdown
                    self.project_type_var.set(old_display_type)
                    return
            elif result is True:  # TAK - zapisz zmiany i przejdź
                self.release_lock()
            else:  # NIE (False) - zostań w poprzednim środowisku
                # Przywróć poprzedni typ w dropdown
                self.project_type_var.set(old_display_type)
                return
        
        # Wyczyść aktualny wybór
        self.project_var.set("")
        
        # RESET FILTRÓW przy przełączaniu typu projektu
        print("🗑️  Resetowanie filtrów...")
        self._clear_filter_vars()
        
        # Przeładuj listę projektów dla wybranego typu
        self.load_projects()
        
        # Zaktualizuj stan menu
        self.update_menu_state()
        
        # Jeśli mamy otwarty projekt (bez locka), zamknij go
        if self.current_project_id:
            print(f"⚠️  Zamykam otwarty projekt {self.current_project_id}")
            self.db_manager._close_project()
            self.current_project_id = None
            self.info_label.config(text="Brak projektu")
        
        # Wyczyść arkusz - sygnalizuje użytkownikowi zmianę środowiska
        self.sheet.set_sheet_data([])
        print(f"✅ Ekran wyczyszczony - zmieniono środowisko")

    def on_project_selected(self, event=None):
        """Wybrano projekt z dropdown"""
        selected = self.project_var.get()
        
        print(f"\n{'='*60}")
        print(f"📂 on_project_selected() wywołane")
        print(f"   Selected: {selected}")
        print(f"   Current project_id: {self.current_project_id}")
        
        if not selected:
            print(f"❌ Brak wybranego projektu - kończymy")
            return
        
        # 🔄 Sprawdź żywotność połączenia (bezpiecznie, bez blokowania GUI)
        if not self._safe_ensure_master_alive():
            return
        
        # Usuń suffix z informacją o locku jeśli istnieje (format: "Nazwa 🔒 [User]")
        # Usuwamy wszystko od " 🔒" do końca
        project_name = selected
        if " 🔒 " in selected:
            project_name = selected.split(" 🔒 ")[0]
        
        # Znajdź ID po nazwie w projects_list
        project_id = None
        for pid, name in self.projects_list:
            if name == project_name:
                project_id = pid
                break
        
        print(f"   Project name (bez locka): {project_name}")
        print(f"   Znaleziony project_id: {project_id}")
        
        if project_id is None:
            print(f"❌ Nie znaleziono ID projektu - kończymy")
            return
        
        # Jeśli ten sam projekt - skip
        if self.current_project_id == project_id:
            print(f"ℹ️  Ten sam projekt ({project_id}) - pomijam")
            return
        
        print(f"✅ Przełączam na projekt {project_id}")
        print(f"{'='*60}\n")
        
        # Jeśli mamy lock na innym projekcie - ostrzeżenie
        if self.have_lock and self.current_project_id != project_id:
            # Pobierz nazwę BIEŻĄCEGO projektu z projects_list na podstawie current_project_id
            current_project_name = None
            for pid, pname in self.projects_list:
                if pid == self.current_project_id:
                    current_project_name = pname
                    break
            
            if not current_project_name:
                current_project_name = f"Projekt {self.current_project_id}"
            
            # Pobierz pełną nazwę z informacją o locku dla wyświetlenia w dropdownie
            current_project_display_name = self._get_project_display_name(self.current_project_id, current_project_name)
            
            result = messagebox.askyesnocancel(
                "Zmiana projektu",
                f"Masz lock na projekcie: {current_project_name}\n\n"
                f"TAK - zapisać zmiany i przejść do: {project_name}\n"
                f"ANULUJ / zamknięcie okna - odrzucić zmiany i przejść do: {project_name}\n"
                f"NIE - zostań na projekcie: {current_project_name}",
                icon='warning'
            )
            
            if result is None:  # ANULUJ (lub krzyżyk) - odrzuć zmiany i przejdź
                if not self.cancel_lock(skip_confirmation=True):
                    # Przywróć dropdown do aktualnego projektu (z informacją o locku)
                    self.project_var.set(current_project_display_name)
                    return
            elif result is True:  # TAK - zapisz zmiany i przejdź
                self.release_lock()
            else:  # NIE (False) - zostań na obecnym projekcie
                # Przywróć dropdown do aktualnego projektu (z informacją o locku)
                self.project_var.set(current_project_display_name)
                return
        
        # Zapisz szerokości kolumn przed zmianą projektu
        if self.current_project_id:
            self._save_column_widths()
        
        # Otwórz projekt (READ-ONLY)
        try:
            # DIAGNOSTYKA: pomiar czasu poszczególnych operacji
            t_start = time.time()
            
            # Pobierz aktualny typ projektu (zmapowany na wewnętrzny)
            project_type = self._get_internal_project_type()
            
            self.db_manager.open_project_remote(project_id, project_type)
            t_open = time.time()
            print(f"  ⏱️  open_project_remote: {t_open - t_start:.3f}s")
            
            self.current_project_id = project_id
            
            # Załaduj mnożniki modułów z bazy
            self.modul_multipliers = self._get_multipliers_from_database()
            print(f"  📊 Załadowano {len(self.modul_multipliers)} mnożników modułów")
            
            # Załaduj dostawców
            self.reload_suppliers()
            t_suppliers = time.time()
            print(f"  ⏱️  reload_suppliers: {t_suppliers - t_open:.3f}s")
            
            # Załaduj dane
            self.refresh_data()
            t_refresh = time.time()
            print(f"  ⏱️  refresh_data: {t_refresh - t_suppliers:.3f}s")
            
            # Załaduj dostępne backupy do combobox
            self.load_backup_dates()
            t_backups = time.time()
            print(f"  ⏱️  load_backup_dates: {t_backups - t_refresh:.3f}s")
            
            print(f"  ⏱️  CAŁKOWITY CZAS: {t_backups - t_start:.3f}s")
            
            # Update UI
            self.info_label.config(text=f"Projekt {project_id} (READ-ONLY)")
            self.btn_acquire_lock.config(state=tk.NORMAL)
            self.btn_force_lock.config(state=tk.NORMAL)
            self.btn_add_item.config(state=tk.DISABLED)
            self.btn_hide_selected.config(state=tk.DISABLED)
            self.btn_restore_hidden.config(state=tk.DISABLED)
            self.btn_scanner.config(state=tk.DISABLED)
            
            # Przyciski wyszukiwania - aktywne gdy projekt jest wybrany
            self.btn_search_project.config(state=tk.NORMAL)
            self.btn_search_server.config(state=tk.NORMAL)
            self.btn_search_library.config(state=tk.NORMAL)
            
            # Update menu state based on project type
            self.update_menu_state()
            
        except Exception as e:
            messagebox.showerror("Błąd", f"Nie udało się otworzyć projektu:\n{e}")
    
    def _migrate_project_schema(self):
        """
        Automatyczna migracja schemy projektu (dla starych baz).
        Dodaje brakujące kolumny do tabeli items.
        Pełna struktura: 63 kolumny (zgodnie z project_1.sqlite).
        
        UWAGA: Działa tylko gdy mamy lock (LOCAL READ/WRITE).
        """
        if not self.db_manager or not self.db_manager.project_con:
            return
        
        # Sprawdź czy baza jest READ-ONLY
        try:
            # Test zapisu - jeśli fail to READ-ONLY
            self.db_manager.project_con.execute("BEGIN IMMEDIATE")
            self.db_manager.project_con.rollback()
        except sqlite3.OperationalError as e:
            if "readonly" in str(e).lower():
                # READ-ONLY - migracja niemożliwa, pomiń cicho
                return
            # Inny błąd - pomiń
            return
        
        try:
            con = self.db_manager.project_con
            
            # Sprawdź jakie kolumny już istnieją
            cursor = con.execute("PRAGMA table_info(items)")
            existing_cols = {row[1].lower() for row in cursor.fetchall()}
            
            # PEŁNA lista wymaganych kolumn (63 kolumny z project_1.sqlite)
            required_cols = {
                'project_id': 'INTEGER',
                'source': 'TEXT',
                'src_doc': 'TEXT',
                'src_row': 'INTEGER',
                'src_uid': 'TEXT',
                'src_pos': 'TEXT',
                'src_qty': 'INTEGER',
                'src_material_text': 'TEXT',
                'src_supplier_text': 'TEXT',
                'norm_drawing_no': 'TEXT',
                'norm_name_key': 'TEXT',
                'work_qty': 'REAL',
                'order_qty': 'REAL',
                'delivered_qty': 'REAL',
                'delivered_updated_at': 'TEXT',
                'drawing_over': 'INTEGER',
                'name_over': 'INTEGER',
                'desc_over': 'INTEGER',
                'order_qty_over': 'INTEGER',
                'supplier_over': 'INTEGER',
                'mat_over': 'INTEGER',
                'class_auto': 'TEXT',
                'class_manual': 'TEXT',
                'class_effective': 'TEXT',
                'mat_auto_text': 'TEXT',
                'mat_manual_text': 'TEXT',
                'mat_effective_text': 'TEXT',
                'mat_grade': 'TEXT',
                'thickness_mm': 'REAL',
                'thickness_src': 'TEXT',
                'has_dxf': 'INTEGER',
                'has_dwf': 'INTEGER',
                'has_idw': 'INTEGER',
                'has_stp': 'INTEGER',
                'has_stl': 'INTEGER',
                'alarm_date': 'TEXT',
                'alarm_offset': 'INTEGER',
                'alarm_unit': 'TEXT',
                'deadline_date': 'TEXT',
                'ordered_at': 'TEXT',
                'ordered_flag': 'INTEGER',
                'price_pln': 'REAL',
                'notes': 'TEXT',
                'is_manual': 'INTEGER',
                'dwf_biblioteka': 'INTEGER',
                'is_hidden': 'INTEGER',
                'min_qty': 'REAL',
                'rank': 'INTEGER',
                'sync_error': 'TEXT',
                'sync_hash': 'TEXT',
                'sync_last_at': 'TEXT',
                'sync_status': 'TEXT',
                'src_modul': 'TEXT',
                'work_modul': 'TEXT'
            }
            
            # Dodaj brakujące kolumny
            migrated = False
            migrated_count = 0
            
            for col_name, col_type in required_cols.items():
                if col_name not in existing_cols:
                    try:
                        sql = f"ALTER TABLE items ADD COLUMN {col_name} {col_type}"
                        con.execute(sql)
                        print(f"✅ Migracja: Dodano kolumnę '{col_name}'")
                        migrated = True
                        migrated_count += 1
                    except sqlite3.OperationalError as e:
                        # Kolumna już istnieje lub inny błąd - ignoruj
                        if "duplicate column" not in str(e).lower():
                            print(f"⚠️  Nie udało się dodać kolumny '{col_name}': {e}")
            
            if migrated:
                con.commit()
                print(f"✅ Migracja schemy zakończona - dodano {migrated_count} kolumn")
            else:
                print("✅ Schema aktualna - brak potrzeby migracji")
        
        except Exception as e:
            print(f"⚠️  Błąd migracji schemy: {e}")
    
    def _display_items_in_sheet(self, items):
        """Wyświetl items w arkuszu (wspólna logika dla refresh_data i backup preview)"""
        import datetime as dt
        today = dt.date.today()
        
        # Ustaw stałą szerokość kolumny indeksowej (LP) na podstawie liczby wierszy
        num_rows = len(items)
        
        # NIE czyść tabeli - to resetuje scroll!
        # Zamiast tego bezpośrednio ustaw nowe dane
        
        # Helper: formatowanie ilości
        def fmt_qty(val):
            if val is None:
                return ""
            try:
                f = float(val)
                if f == int(f):
                    return str(int(f))
                return f"{f:.2f}".rstrip('0').rstrip('.')
            except:
                return str(val)
        
        def fmt_delivered_qty(val):
            """Formatuj ilość dostarczoną - jeśli 0 to pusta komórka"""
            if val is None:
                return ""
            try:
                f = float(val)
                if f == 0:
                    return ""
                if f == int(f):
                    return str(int(f))
                return f"{f:.2f}".rstrip('0').rstrip('.')
            except:
                return str(val)
        
        # Helper: parse date
        def parse_date(d):
            if not d:
                return None
            try:
                return dt.date.fromisoformat(str(d)[:10])
            except:
                return None
        
        # Wypełnij danymi
        data = []
        self._sheet_row_ids = []
        self._sheet_src_values = []
        self._sheet_overridden = []
        
        for item in items:
            # === Oblicz qty_bom i order_qty NAJPIERW ===
            qty_bom = item['qty_bom']
            order_qty = item['order_qty'] if item['order_qty'] is not None else qty_bom
            
            # === MNOŻENIE DLA WAREHOUSE (jeśli są ustawione mnożniki w bazie) ===
            project_type_for_display = self._get_internal_project_type()
            
            if project_type_for_display == "WAREHOUSE":
                # Pobierz kolumnę MODUŁ (modul_disp = COALESCE(work_modul, src_modul))
                modul_raw = item.get('modul_disp', '') or ''
                
                # Użyj wartości z bazy bez modyfikacji (pozwala edytować pierwszy moduł)
                modul_str = modul_raw
                
                # Parsuj modul_str do obliczeń (bez podmianki ilości!)
                # Rozdziel po przecinku i wyciągnij wszystkie pary NAZWA(ilość)xmnożnik
                import re
                parts = [p.strip() for p in modul_str.split(',')]
                modul_matches = []
                
                for part in parts:
                    # Regex: NAZWA(ilość)xmnożnik lub NAZWA(ilość)
                    match = re.match(r'([^(]+)\s*\((\d+)\)(?:x(\d+))?', part)
                    if match:
                        modul_name = match.group(1).strip()
                        modul_qty = match.group(2)
                        modul_multiplier = match.group(3)  # Może być None
                        if modul_name:  # Pomijamy puste
                            modul_matches.append((modul_name, modul_qty, modul_multiplier))
                
                # Oblicz wynik mnożenia: suma(moduł_ilość × mnożnik)
                multiplied_qty = 0
                
                for modul_name, modul_qty_str, modul_mult_str in modul_matches:
                    try:
                        modul_qty = int(modul_qty_str)
                        # Użyj mnożnika z bazy (jeśli jest) lub wartości domyślnej 1
                        multiplier = int(modul_mult_str) if modul_mult_str else 1
                        multiplied_qty += modul_qty * multiplier
                    except:
                        pass
                
                # Jeśli są moduły - wynik mnożenia wpisz do Ilość (zam.)
                # Ilość BOM pozostaje bez zmian (oryginalna z bazy)
                if modul_matches:
                    # qty_bom NIE ZMIENIAMY - zostaje oryginalna wartość z bazy
                    order_qty = multiplied_qty  # Wynik mnożenia -> Ilość (zam.)
            
            # === STAN ALARMU (żółty/czerwony) ===
            alarm_state = "none"  # none, yellow, red
            
            # Sprawdź czy kompletne (delivered >= order)
            is_complete = False
            try:
                if item['delivered_qty'] is not None and order_qty is not None:
                    if float(item['delivered_qty']) >= float(order_qty):
                        is_complete = True
            except:
                pass
            
            if not is_complete:  # Alarm tylko gdy NIEkompletne
                deadline_dt = parse_date(item['deadline_date'])
                alarm_dt = parse_date(item['alarm_date'])
                
                # Jeśli brak alarm_date ale jest deadline + offset -> wylicz dynamicznie
                if alarm_dt is None and deadline_dt and item['alarm_offset']:
                    try:
                        offset = int(item['alarm_offset'])
                        mul = 7 if str(item['alarm_unit'] or "").upper().startswith("W") else 1
                        alarm_dt = deadline_dt - dt.timedelta(days=offset * mul)
                    except:
                        alarm_dt = None
                
                # 🔴 CZERWONY: po terminie (deadline passed)
                if deadline_dt and today > deadline_dt:
                    alarm_state = "red"
                # 🟡 ŻÓŁTY: alarm aktywny (today >= alarm_dt && today <= deadline_dt)
                elif alarm_dt and today >= alarm_dt:
                    if deadline_dt is None or today <= deadline_dt:
                        alarm_state = "yellow"
            
            # =========================================
            
            # === TRACKING BOM OVERRIDES ===
            # Kolumny BOM (0,1,2,3,7,8,9) mogą być nadpisane (work_* vs src_*)
            overridden = {}
            src_vals = {}
            
            # 0: Nr rysunku
            drawing_work = item['drawing_no'] or ""
            drawing_src = item['src_drawing_no'] or ""
            if drawing_work != drawing_src:
                overridden[0] = True
                src_vals[0] = drawing_src
            else:
                src_vals[0] = drawing_src
            
            # 1: Nazwa
            name_work = item['name'] or ""
            name_src = item['src_name'] or ""
            if name_work != name_src:
                overridden[1] = True
                src_vals[1] = name_src
            else:
                src_vals[1] = name_src
            
            # 2: Opis
            desc_work = item['descr'] or ""
            desc_src = item['src_desc'] or ""
            if desc_work != desc_src:
                overridden[2] = True
                src_vals[2] = desc_src
            else:
                src_vals[2] = desc_src
            
            # 3: Ilość BOM
            qty_bom_val = qty_bom if qty_bom is not None else 0
            src_qty_val = item['src_qty'] if item['src_qty'] is not None else 0
            if qty_bom_val != src_qty_val:
                overridden[3] = True
                src_vals[3] = fmt_qty(item['src_qty'])
            else:
                src_vals[3] = fmt_qty(item['src_qty'])
            
            # 7: Typ (class_effective) - nadpisane jeśli class_manual != NULL
            # ALE nie dla ręcznie dodanych pozycji (is_manual=1)
            try:
                class_manual_val = None
                class_auto_val = None
                is_manual_item = False
                try:
                    class_manual_val = item['class_manual']
                except (KeyError, IndexError):
                    pass
                try:
                    class_auto_val = item['class_auto']
                except (KeyError, IndexError):
                    pass
                try:
                    is_manual_item = bool(item['is_manual']) if item['is_manual'] else False
                except:
                    pass
                
                # Sprawdź czy nadpisane
                if is_manual_item:
                    # Dla ręcznych: porównaj class_manual vs class_auto (wartość początkowa)
                    if class_manual_val and class_auto_val:
                        if class_manual_val != class_auto_val:
                            overridden[7] = True
                    elif class_manual_val and not class_auto_val:
                        # Manual jest, auto nie ma - nadpisane
                        overridden[7] = True
                else:
                    # Dla BOM: class_manual != NULL → nadpisane
                    if class_manual_val:
                        overridden[7] = True
                
                # src to class_auto (auto z numeru rysunku/importu lub wartość początkowa dla ręcznych)
                src_vals[7] = class_auto_val if class_auto_val else ''
            except (KeyError, TypeError, IndexError) as e:
                pass
            
            # 8: Materiał (mat_effective_text)
            # ALE nie dla ręcznie dodanych pozycji (is_manual=1)
            try:
                # mat_effective_text = mat_manual_text || mat_auto_text || src_material_text
                # Nadpisane jeśli mat_manual_text != NULL
                mat_manual = None
                mat_auto = ''
                is_manual_item = False
                try:
                    mat_manual = item['mat_manual_text']
                except (KeyError, IndexError):
                    pass
                try:
                    mat_auto = item['mat_auto_text'] or ''
                except (KeyError, IndexError):
                    pass
                try:
                    is_manual_item = bool(item['is_manual']) if item['is_manual'] else False
                except:
                    pass
                
                # Sprawdź czy nadpisane
                if is_manual_item:
                    # Dla ręcznych: porównaj mat_manual_text vs mat_auto_text (wartość początkowa)
                    # Uwaga: mat_auto_text może mieć sufiks "grXmm" który mat_manual nie ma!
                    if mat_manual and mat_auto:
                        # Usuń sufiks grXmm z porównania
                        import re
                        mat_auto_clean = re.sub(r'\s*gr[\d.]+mm\s*$', '', mat_auto, flags=re.IGNORECASE).strip()
                        if mat_manual.strip() != mat_auto_clean:
                            overridden[8] = True
                    elif mat_manual and not mat_auto:
                        # Manual jest, auto nie ma - nadpisane
                        overridden[8] = True
                else:
                    # Dla BOM: mat_manual_text != NULL → nadpisane
                    if mat_manual:
                        overridden[8] = True
                
                # Wartość źródłowa = mat_auto_text (bez sufiks grXmm dla wyświetlenia)
                if mat_auto:
                    import re
                    mat_auto_clean = re.sub(r'\s*gr[\d.]+mm\s*$', '', mat_auto, flags=re.IGNORECASE).strip()
                    src_vals[8] = mat_auto_clean if mat_auto_clean else ''
                else:
                    src_vals[8] = ''
            except (KeyError, TypeError, IndexError) as e:
                pass
            
            # 9: Grubość (thickness_mm) - nadpisane jeśli różni się od sparsowanej z materiału
            # ALE nie dla ręcznie dodanych pozycji (is_manual=1)
            try:
                # Pobierz grubość ręczną (work)
                thick_work = None
                is_manual_item = False
                try:
                    thick_work = item['thickness_mm']
                except (KeyError, IndexError):
                    pass
                try:
                    is_manual_item = bool(item['is_manual']) if item['is_manual'] else False
                except:
                    pass
                
                # Sparsuj grubość z mat_auto_text (automatycznie parsowany materiał)
                thick_src = None
                try:
                    mat_auto = ''
                    try:
                        mat_auto = item['mat_auto_text'] or ""
                    except (KeyError, IndexError):
                        pass
                    if mat_auto:
                        # Parsuj "304 gr8mm" → 8.0
                        from import_bom import parse_thickness_mm
                        thick_src = parse_thickness_mm(mat_auto)
                except:
                    pass
                
                # Porównaj - jeśli różne to nadpisane (dla BOM i ręcznych)
                if thick_work is not None and thick_src is not None:
                    if abs(float(thick_work) - float(thick_src)) > 0.01:  # Tolerancja 0.01mm
                        overridden[9] = True
                elif thick_work is not None and thick_src is None:
                    # Work jest a src nie ma → nadpisane (jeśli różne od 0)
                    if float(thick_work) > 0.01:
                        overridden[9] = True
                
                # Zawsze zapisz src_vals - formatuj ładnie
                if thick_src:
                    src_vals[9] = f"{thick_src} mm" if thick_src else ""
                else:
                    src_vals[9] = ""
            except (KeyError, TypeError, IndexError) as e:
                pass

            # Moduł (col 18): nadpisane jeśli work_modul != NULL
            try:
                modul_work = item['work_modul']
                modul_src = item['src_modul'] or ""
                if modul_work is not None:
                    # work_modul jest ustawione (edytowane przez usera)
                    overridden[18] = True
                    src_vals[18] = modul_src
                else:
                    src_vals[18] = modul_src
            except (KeyError, TypeError, IndexError) as e:
                # Kolumny moduł nie istnieją w starszej bazie - pomiń
                pass
            
            # Zapisz tracking
            overridden['alarm_state'] = alarm_state  # Dla kolorowania kolumny ALARM
            self._sheet_overridden.append(overridden)
            self._sheet_src_values.append(src_vals)
            
            # ===========================
            
            # Supplier name
            supplier_name = ""
            if item['supplier_id']:
                supplier_name = self.suppliers_map.get(item['supplier_id'], "")
            
            # Δ (delta) = order_qty - qty_bom
            # (qty_bom i order_qty już obliczone na górze)
            delta = ""
            try:
                if qty_bom is not None and order_qty is not None:
                    _d = float(order_qty) - float(qty_bom)
                    delta = int(round(_d))
            except:
                delta = ""
            
            # Wyświetlanie kolumny Δ:
            # - PRODUKCJA: delta (liczba) + ● dla ręcznych
            # - WAREHOUSE: tylko ● dla ręcznych (bez liczby, bo delta nie ma sensu dla magazynu)
            delta_disp = ""
            is_manual = item.get('is_manual') == 1
            project_type_internal = self._get_internal_project_type()
            
            if project_type_internal == "WAREHOUSE":
                # WAREHOUSE: pokazuj tylko ● dla pozycji ręcznych, bez liczby
                if is_manual:
                    delta_disp = "●"
                else:
                    delta_disp = ""
            else:
                # PRODUKCJA: pokazuj deltę + ● dla ręcznych
                if delta != "":
                    delta_disp = str(delta)
                    if is_manual:
                        delta_disp = f"{delta_disp} ●"
                else:
                    delta_disp = ""
            
            # Zamówiono: ☑ data lub ☐
            ordered_disp = "☐"
            if item['ordered_flag']:
                od = item['ordered_at'] or ""
                if len(od) >= 10:
                    od = od[:10]
                ordered_disp = f"☑ {od}" if od else "☑"
            
            # ALARM: np. "7d" lub "2w"
            alarm_disp = ""
            try:
                if item['alarm_offset'] and int(item['alarm_offset']) > 0:
                    u = (item['alarm_unit'] or "D").upper()
                    alarm_disp = f"{int(item['alarm_offset'])}{u.lower()}"
            except:
                alarm_disp = ""
            
            # Deadline
            deadline_disp = item['deadline_date'] or ""
            if len(deadline_disp) >= 10:
                deadline_disp = deadline_disp[:10]
            
            # Cena (nie wyświetlaj jeśli 0)
            price_disp = ""
            try:
                if item['price_pln'] is not None and str(item['price_pln']).strip():
                    price_val = float(item['price_pln'])
                    if price_val != 0:
                        price_disp = f"{price_val:.2f}"
            except:
                price_disp = ""
            
            # ODEBRANE: ● jeśli dostarczone >= zamówione (kompletne)
            received_flag = ""
            try:
                if item['delivered_qty'] is not None and order_qty is not None:
                    if float(item['delivered_qty']) >= float(order_qty):
                        received_flag = "●"
            except:
                received_flag = ""
            
            # Typ: skróć ZNORMALIZOWANE → ZNORM
            class_eff = item['class_effective'] or ""
            if class_eff == "ZNORMALIZOWANE":
                class_eff = "ZNORM"
            
            # Grubość: jeśli thickness_mm jest NULL, to sparsuj z materiału
            thickness_disp = ""
            
            # Bezpieczne pobranie thickness_mm (sqlite3.Row nie ma .get())
            try:
                thick_raw = item['thickness_mm']
            except (KeyError, IndexError):
                thick_raw = None
            
            if thick_raw is not None:
                # Formatuj grubość - jeśli liczba całkowita, nie pokazuj dziesiętnych
                try:
                    thick_val = float(thick_raw)
                    if thick_val == int(thick_val):
                        thickness_disp = str(int(thick_val))
                    else:
                        # Usuń końcowe zera
                        thickness_disp = f"{thick_val:.10f}".rstrip('0').rstrip('.')
                except:
                    thickness_disp = thick_raw
            else:
                # Auto-parsuj z src_material_text
                try:
                    mat_src = item['src_material_text'] or ""
                    if mat_src:
                        from import_bom import parse_thickness_mm
                        parsed_thick = parse_thickness_mm(mat_src)
                        if parsed_thick:
                            # Zastosuj te same reguły formatowania
                            try:
                                thick_val = float(parsed_thick)
                                if thick_val == int(thick_val):
                                    thickness_disp = str(int(thick_val))
                                else:
                                    thickness_disp = f"{thick_val:.10f}".rstrip('0').rstrip('.')
                            except:
                                thickness_disp = parsed_thick
                except:
                    pass
            
            # Moduł: COALESCE(work_modul, src_modul) z database_manager
            # Dla WAREHOUSE: wyświetl wartość z bazy bez modyfikacji (edytowalną)
            modul_disp = ""
            try:
                modul_raw = item['modul_disp'] or ""
                # Użyj wartości z bazy bez modyfikacji - pozwala edytować pierwszy moduł
                modul_disp = modul_raw
                
            except (KeyError, TypeError):
                # Baza bez kolumny modul - pomiń
                modul_disp = ""
            
            # ILOŚĆ BOM: Jeśli jest więcej niż jeden moduł I środowisko WAREHOUSE, pokaż symbol zamiast liczby
            qty_bom_display = fmt_qty(qty_bom)
            if project_type_for_display == "WAREHOUSE" and modul_disp and ',' in modul_disp:
                # Więcej niż jeden moduł w WAREHOUSE - pokaż symbol
                qty_bom_display = "●"
            
            # Wiersz danych (19 kolumn)
            row = [
                item['drawing_no'] or "",                   # 0: Nr rysunku (bez emoji)
                item['name'] or "",                          # 1: Nazwa
                item['descr'] or "",                         # 2: Opis
                qty_bom_display,                            # 3: Ilość BOM (● gdy >1 moduł)
                fmt_qty(order_qty),                         # 4: Ilość (zam.)
                delta_disp,                                 # 5: Δ (z ✎ dla ręcznych)
                fmt_delivered_qty(item['delivered_qty']),   # 6: Ilość dostarczonych (0 = pusty)
                class_eff,                                  # 7: Typ
                item['mat_effective_text'] or "",           # 8: Materiał
                thickness_disp if thickness_disp != "" else "",  # 9: Grubość (auto z materiału jeśli NULL)
                supplier_name,                              # 10: Dostawca
                price_disp,                                 # 11: Cena PLN
                ordered_disp,                               # 12: Zamówiono
                deadline_disp,                              # 13: Termin dosta
                alarm_disp,                                 # 14: ALARM
                item['notes'] or "",                        # 15: Uwagi
                str(int(item['dwf_biblioteka'] or 0)),      # 16: DWF_BIB
                received_flag,                              # 17: ODEBRANE
                modul_disp                                  # 18: Moduł
            ]
            
            data.append(row)
            self._sheet_row_ids.append(item['id'])
        
        self.sheet.set_sheet_data(data)
        
        # NATYCHMIAST przywróć szerokości kolumn (set_sheet_data() je resetuje!)
        self._apply_saved_column_widths()
        
        # Ustaw szerokość kolumny LP (numeracja wierszy) TUTAJ - po załadowaniu danych
        if num_rows > 0:
            max_digits = len(str(num_rows))
            row_index_width = max(50, max_digits * 12 + 15)
            try:
                # Spróbuj różnych metod ustawienia szerokości
                if hasattr(self.sheet, 'set_options'):
                    self.sheet.set_options(default_row_index_width=row_index_width)
                if hasattr(self.sheet, 'row_index_width'):
                    self.sheet.row_index_width(row_index_width)
                # Bezpośrednie ustawienie na RI canvas
                if hasattr(self.sheet, 'RI'):
                    self.sheet.RI.set_width(row_index_width, set_TL=True)
            except Exception as e:
                print(f"⚠️  Nie udało się ustawić szerokości kolumny LP: {e}")
        
        # Ustaw kolumny 7, 8, 9, 18 jako edytowalne (Typ, Materiał, Grubość, Moduł)
        # Czasem tksheet blokuje edycję jeśli format jest "dziwny"
        try:
            # Force editable dla tych kolumn
            for col_idx in [7, 8, 9, 18]:
                self.sheet.readonly_columns(columns=[col_idx], readonly=False)
        except Exception as e:
            print(f"⚠️  Nie udało się ustawić kolumn jako edytowalne: {e}")
        
        # === KOLOROWANIE + SZARE TŁO + HIGHLIGHT WIERSZA ===
        self._rebuild_all_cell_colors_with_selection()
        
        # Aktualizuj statystykę ODEBRANO
        self._update_odebrano_stat()
        
        print(f"✅ Załadowano {len(items)} items")
    
    def _apply_filters(self, items):
        """Zastosuj filtry do listy items"""
        import datetime as dt
        
        # Pobierz wartości filtrów
        filter_class = self.filter_class_var.get()
        filter_supplier = self.filter_supplier_var.get()
        search_text = (self.search_var.get() or "").strip().lower()  # Filtr tekstowy
        only_missing_supplier = bool(self.only_missing_supplier_var.get())
        only_overdue = bool(self.only_overdue_var.get())
        only_biblioteka = bool(self.only_biblioteka_var.get())
        only_manual = bool(self.only_manual_var.get())
        only_ordered = bool(self.only_ordered_var.get())
        only_to_order = bool(self.only_to_order_var.get())
        only_yellow = bool(self.only_alarm_yellow_var.get())
        only_red = bool(self.only_alarm_red_var.get())
        only_delivered = bool(self.only_delivered_var.get())
        only_not_delivered = bool(self.only_not_delivered_var.get())
        filter_modul_selection = self.filter_modul_selected  # Multi-select moduł
        filter_grub_selection = self.filter_grub_selected  # Multi-select grubość
        
        today = dt.date.today()
        
        def _parse_date(d):
            if not d:
                return None
            try:
                return dt.date.fromisoformat(str(d)[:10])
            except Exception:
                return None
        
        def _alarm_state(item):
            """Zwraca stan alarmu: 'red', 'yellow', lub 'none'"""
            deadline_dt = _parse_date(item.get('deadline_date'))
            alarm_date_str = item.get('alarm_date')
            alarm_offset = item.get('alarm_offset')
            alarm_unit = item.get('alarm_unit')
            
            # Używamy tej samej logiki co w refresh_data i SQL:
            # target_qty = order_qty ?? work_qty ?? src_qty
            order_qty = item.get('order_qty')
            work_qty = item.get('work_qty')
            src_qty = item.get('src_qty')
            delivered_qty = item.get('delivered_qty')
            
            # Komplet dostarczony -> brak alarmu
            try:
                target_qty = order_qty if order_qty is not None else (work_qty if work_qty is not None else src_qty)
                if target_qty is not None and delivered_qty is not None:
                    if float(target_qty) > 0 and float(delivered_qty) >= float(target_qty):
                        return 'none'
            except Exception:
                pass
            
            # Czerwony: po terminie (deadline_dt jest przeszły)
            if deadline_dt is not None and today > deadline_dt:
                return 'red'
            
            # Wylicz alarm_dt
            alarm_dt = _parse_date(alarm_date_str)
            if alarm_dt is None and deadline_dt is not None and alarm_offset is not None:
                try:
                    offi = int(alarm_offset)
                    mul = 7 if str(alarm_unit or "").upper().startswith("W") else 1
                    alarm_dt = deadline_dt - dt.timedelta(days=offi * mul)
                except Exception:
                    alarm_dt = None
            
            # Żółty: od alarmu do terminu (włącznie)
            if alarm_dt is not None:
                if (deadline_dt is None or today <= deadline_dt) and today >= alarm_dt:
                    return 'yellow'
            
            return 'none'
        
        filtered = []
        for item in items:
            # Filtr tekstowy (szukaj w: drawing_no, name, descr)
            if search_text:
                drawing_no = str(item.get('drawing_no') or '').lower()
                name = str(item.get('name') or '').lower()
                descr = str(item.get('descr') or '').lower()
                if search_text not in drawing_no and search_text not in name and search_text not in descr:
                    continue
            
            # Filtr Typ
            if filter_class and filter_class != "(WSZYSTKO)":
                class_eff = item.get('class_effective') or item.get('class_manual') or item.get('class_auto')
                # LASER = X + XX
                if filter_class == "LASER":
                    if class_eff not in ("X", "XX"):
                        continue
                # LASER EXPORT = X + XX (jak LASER, ale z sortowaniem)
                elif filter_class == "LASER EXPORT":
                    if class_eff not in ("X", "XX"):
                        continue
                else:
                    if class_eff != filter_class:
                        continue
            
            # Filtr Dostawca
            if filter_supplier and filter_supplier != FILTER_SUPPLIER_ALL:
                supplier_id = item.get('supplier_id')
                supplier_name = self.suppliers_map.get(supplier_id, "")
                if supplier_name != filter_supplier:
                    continue
            
            # Filtr Moduł (multi-select)
            if filter_modul_selection:
                modul_val = ""
                has_modul_column = True  # Czy projekt ma kolumnę MODUŁ
                
                try:
                    # Sprawdź czy kolumna modul_disp istnieje
                    if isinstance(item, dict):
                        if 'modul_disp' not in item:
                            has_modul_column = False
                        else:
                            modul_val = item.get('modul_disp') or ""
                    else:
                        # sqlite3.Row - dostęp przez klucz
                        modul_val = item['modul_disp'] if item['modul_disp'] else ""
                except (KeyError, TypeError, IndexError):
                    # Brak kolumny moduł w tym projekcie
                    has_modul_column = False
                
                # Jeśli projekt nie ma kolumny MODUŁ, pomiń filtr dla wszystkich wierszy
                if not has_modul_column:
                    pass  # Nie filtruj - pokazuj wszystkie wiersze
                elif not modul_val:
                    # Kolumna istnieje, ale wiersz ma pustą wartość - ukryj
                    continue
                else:
                    # Rozdziel po przecinku i wyciągnij nazwy modułów
                    # Obsługa dwóch formatów:
                    # 1. Z nawiasami (WAREHOUSE): "NAZWA(10)x2, MODUŁ1(5)"
                    # 2. Bez nawiasów (MACHINES): "MODUŁ1, MODUŁ2"
                    import re
                    parts = [p.strip() for p in modul_val.split(',') if p.strip()]
                    modul_names = []
                    for part in parts:
                        # Spróbuj dopasować format z nawiasem: NAZWA(ilość)xmnożnik lub NAZWA(ilość)
                        match = re.match(r'([^(]+)\s*\((\d+)\)(?:x(\d+))?', part)
                        if match:
                            # Format z nawiasem - wyciągnij nazwę
                            modul_names.append(match.group(1).strip())
                        else:
                            # Format bez nawiasu - użyj całej wartości
                            modul_names.append(part.strip())
                    
                    # Sprawdź czy którykolwiek z modułów jest zaznaczony
                    if not any(m in filter_modul_selection for m in modul_names):
                        continue
            
            # Filtr Grubość (multi-select)
            if filter_grub_selection:
                # Użyj tej samej logiki co przy wyświetlaniu kolumny
                thickness_disp = self._get_thickness_display(item)
                
                if thickness_disp not in filter_grub_selection:
                    continue
            
            # Tylko brak dostawcy
            if only_missing_supplier:
                supplier_id = item.get('supplier_id')
                if supplier_id:
                    continue
            
            # Tylko po terminie
            if only_overdue:
                deadline_dt = _parse_date(item.get('deadline_date'))
                if not deadline_dt or today <= deadline_dt:
                    continue

            # Tylko Biblioteka (DWF_BIB == 1)
            if only_biblioteka:
                if int(item.get('dwf_biblioteka') or 0) != 1:
                    continue
            
            # Tylko ręczne (is_manual == 1)
            if only_manual:
                if int(item.get('is_manual') or 0) != 1:
                    continue
            
            # Zamówione / Do zamówienia
            ordered_flag = int(item.get('ordered_flag') or 0)
            if only_ordered and ordered_flag != 1:
                continue
            if only_to_order and ordered_flag == 1:
                continue
            
            # Alarmy (żółty / czerwony)
            if only_yellow or only_red:
                state = _alarm_state(item)
                if only_yellow and only_red:
                    if state not in ('yellow', 'red'):
                        continue
                elif only_yellow:
                    if state != 'yellow':
                        continue
                elif only_red:
                    if state != 'red':
                        continue
            
            # Dostarczono / Nie dostarczono
            if only_delivered or only_not_delivered:
                # Użyj tej samej logiki co przy wyświetlaniu kropki:
                # order_qty ?? work_qty ?? src_qty
                delivered_qty = item.get('delivered_qty')
                order_qty_val = item.get('order_qty')
                work_qty_val = item.get('work_qty')
                src_qty_val = item.get('src_qty')
                
                # Oblicz target_qty (ta sama logika co w refresh_data)
                target_qty = order_qty_val if order_qty_val is not None else (
                    work_qty_val if work_qty_val is not None else src_qty_val
                )
                
                is_delivered = False
                try:
                    if delivered_qty is not None and target_qty is not None:
                        if float(delivered_qty) >= float(target_qty):
                            is_delivered = True
                except Exception:
                    pass
                
                if only_delivered and not is_delivered:
                    continue
                if only_not_delivered and is_delivered:
                    continue
            
            filtered.append(item)
        
        # Specjalne sortowanie dla LASER EXPORT
        if filter_class == "LASER EXPORT":
            def sort_key_laser_export(item):
                # Pobierz TYP
                class_eff = item.get('class_effective') or item.get('class_manual') or item.get('class_auto') or ''
                
                # Pobierz grubość (używamy tej samej logiki co w wyświetlaniu)
                thickness_disp = self._get_thickness_display(item)
                
                # Konwertuj grubość na float (0 jeśli brak)
                thickness_float = 0.0
                try:
                    if thickness_disp and thickness_disp.strip():
                        thickness_float = float(thickness_disp)
                except:
                    thickness_float = 0.0
                
                # Sortuj: X przed XX, potem po grubości rosnąco
                # X = 0, XX = 1 (żeby X były pierwsze)
                type_order = 0 if class_eff == 'X' else 1
                
                return (type_order, thickness_float)
            
            filtered.sort(key=sort_key_laser_export)
        
        return filtered
    
    def check_and_show_duplicates(self):
        """Sprawdź duplikaty numerów rysunków i pokaż banner ostrzeżenia"""
        if not self.current_project_id or not self.warning_banner:
            return
        
        try:
            # Pobierz wszystkie drawing_no z projektu (pomijając puste i ukryte opcjonalnie)
            rows = self.db_manager.project_con.execute("""
                SELECT COALESCE(NULLIF(work_drawing_no, ''), src_drawing_no) AS drawing_no,
                       COALESCE(NULLIF(work_name, ''), src_name) AS name
                FROM items
                WHERE project_id = ?
                  AND COALESCE(NULLIF(work_drawing_no, ''), src_drawing_no) IS NOT NULL
                  AND COALESCE(NULLIF(work_drawing_no, ''), src_drawing_no) != ''
            """, (self.current_project_id,)).fetchall()
            
            # Zlicz duplikaty
            from collections import Counter
            drawing_counter = Counter(row[0] for row in rows)
            duplicates = {dn: count for dn, count in drawing_counter.items() if count > 1}
            
            if duplicates:
                # Są duplikaty - pokaż banner
                dup_list = sorted(duplicates.items(), key=lambda x: x[1], reverse=True)[:10]  # Pierwsze 10
                dup_text = ", ".join([f"{dn} (×{count})" for dn, count in dup_list])
                more_text = f" ... i {len(duplicates) - 10} więcej" if len(duplicates) > 10 else ""
                
                warning_text = f"⚠️⚠️⚠️ DUPLIKATY NUMERÓW RYSUNKÓW ({len(duplicates)} unikalnych): {dup_text}{more_text} ⚠️⚠️⚠️"
                self.warning_label.config(text=warning_text)
                
                # Pokaż banner jeśli nie jest widoczny
                if not self.warning_banner.winfo_ismapped():
                    self.warning_banner.config(height=45)
                    self.warning_banner.pack(side=tk.TOP, fill=tk.X, before=self.top_frame2)
            else:
                # Brak duplikatów - ukryj banner
                if self.warning_banner.winfo_ismapped():
                    self.warning_banner.pack_forget()
                    self.warning_banner.config(height=0)
        
        except Exception as e:
            print(f"⚠️ Błąd sprawdzania duplikatów: {e}")
            import traceback
            traceback.print_exc()
    
    def refresh_data(self):
        """Odśwież dane w tabeli"""
        if not self.current_project_id:
            return
        
        # Sprawdź duplikaty i aktualizuj banner ostrzeżeń
        self.check_and_show_duplicates()
        
        # 🔄 Sprawdź żywotność połączenia (bezpiecznie, bez blokowania GUI)
        if not self._safe_ensure_project_alive():
            return
        
        # Odblokuj GUI przed sprawdzeniem
        self.update_idletasks()
        
        # ⚠️ SPRAWDŹ CZY NIE STRACILIŚMY LOCKA!
        if self.have_lock and self.current_lock_id:
            current_owner = self.lock_manager.get_project_lock_owner(self.current_project_id)
            
            # Sprawdź czy lock zniknął lub zmienił właściciela
            lock_lost = False
            reason = ""
            
            if not current_owner:
                # Lock zniknął całkowicie (ktoś go zwolnił)
                lock_lost = True
                reason = "Lock został zwolniony przez innego użytkownika"
            elif current_owner.get('lock_id') != self.current_lock_id:
                # Lock_id się zmienił (ktoś wymusia lock)
                lock_lost = True
                new_owner = current_owner.get('user', 'Unknown')
                new_computer = current_owner.get('computer', 'Unknown')
                reason = f"Lock został wymuszony przez:\n{new_owner}@{new_computer}"
            
            if lock_lost:
                print(f"⚠️⚠️⚠️ UTRATA LOCKA! Powód: {reason}")
                
                # Anuluj lock bez pytania (bo już go nie mamy!)
                self._force_cancel_lock_on_lost(reason)
                return  # Nie kontynuuj refresh - już nie mamy locka
        
        # Automatyczna migracja schemy (dla starych projektów)
        self._migrate_project_schema()
        
        try:
            # Pobierz items (z filtrowaniem is_hidden)
            show_hidden = self.show_hidden_var.get()
            items = self.db_manager.get_project_items(self.current_project_id, show_hidden=show_hidden)
            
            # Konwertuj sqlite3.Row na dict (jeśli potrzeba)
            items = [dict(item) if not isinstance(item, dict) else item for item in items]
            
            # Zastosuj filtry
            items = self._apply_filters(items)
            
            # Wyświetl w arkuszu (bez czyszczenia - zachowuje scroll!)
            self._display_items_in_sheet(items)
            
        except Exception as e:
            messagebox.showerror("Błąd", f"Nie udało się załadować danych:\n{e}")
            import traceback
            traceback.print_exc()

    
    def on_sheet_cell_select(self, event=None):
        """Obsługa zaznaczenia komórki - podświetla cały wiersz (jak v6)
        
        WAŻNE: Działa tylko dla POJEDYNCZEGO zaznaczenia (nie blokuje SHIFT/CTRL multi-select)
        """
        try:
            # Zapobiegaj rekurencji
            if getattr(self, "_in_row_highlight", False):
                return
            
            # Pobierz zaznaczenie
            sel = self.sheet.get_currently_selected()
            if not sel:
                return
            
            # Sprawdź czy to multi-select (wiele wierszy zaznaczonych)
            # Jeśli tak - NIE podświetlaj pojedynczego wiersza
            try:
                selected_rows = self.sheet.get_selected_rows()
                if selected_rows and len(selected_rows) > 1:
                    # Multi-select aktywny - nie podświetlaj
                    return
            except:
                pass
            
            # Parsuj row z sel (może być dict lub tuple)
            r0 = None
            if isinstance(sel, dict):
                r0 = sel.get("row", sel.get("r"))
            elif isinstance(sel, (tuple, list)) and len(sel) >= 1:
                r0 = sel[0]
            
            if r0 is not None and int(r0) >= 0:
                self._in_row_highlight = True
                try:
                    self._selected_row_idx = int(r0)
                    # Odtwórz kolory (szarości + alarmy) i nałóż highlight wiersza
                    self._rebuild_all_cell_colors_with_selection()
                finally:
                    self._in_row_highlight = False
        except Exception as e:
            print(f"⚠️  Błąd on_sheet_cell_select: {e}")
    
    def on_delivered_click_popup(self, event=None):
        """Popup z datą modyfikacji dla kolumny DOSTARCZONO (kol 6)"""
        try:
            if not event:
                return
            
            # Identyfikuj klikniętą komórkę
            row = self.sheet.identify_row(event, exclude_index=True)
            col = self.sheet.identify_column(event, exclude_header=True)
            
            if row is None or col is None or row < 0:
                return
            
            # Kolumna 6 = Ilość dostarczonych
            if col != 6:
                return
            
            # Pobierz ID itemu
            if row >= len(self._sheet_row_ids):
                print(f"⚠️  on_delivered_click_popup: row {row} >= len(_sheet_row_ids) {len(self._sheet_row_ids)}")
                return
            
            item_id = self._sheet_row_ids[row]
            if not item_id:
                print(f"⚠️  on_delivered_click_popup: brak item_id dla wiersza {row}")
                return
            
            # Sprawdź czy połączenie dostępne
            if not self.db_manager.project_con:
                print(f"⚠️  on_delivered_click_popup: brak połączenia z projektem")
                return
            
            # Pobierz datę modyfikacji z bazy
            cursor = self.db_manager.project_con.execute(
                "SELECT delivered_updated_at, delivered_qty FROM items WHERE id = ?",
                (item_id,)
            )
            result = cursor.fetchone()
            
            if not result:
                print(f"⚠️  on_delivered_click_popup: brak wyniku z bazy dla item_id={item_id}")
                return
            
            delivered_updated_at, delivered_qty = result
            
            # Utwórz tekst tooltipa
            if delivered_updated_at:
                try:
                    # Parsuj datę (datetime już zaimportowane na górze pliku)
                    dt = datetime.fromisoformat(delivered_updated_at)
                    formatted_date = dt.strftime("%Y-%m-%d %H:%M:%S")
                    tooltip_text = f"Ostatnia modyfikacja:\n{formatted_date}"
                except Exception as parse_err:
                    print(f"⚠️ Błąd parsowania daty: {parse_err}")
                    tooltip_text = f"Ostatnia modyfikacja:\n{delivered_updated_at}"
            else:
                tooltip_text = "Brak danych o modyfikacji"
            
            # Wyświetl tooltip (jak w BOM)
            self._show_delivered_tooltip(event.x_root, event.y_root, tooltip_text)
            
        except Exception as e:
            print(f"⚠️  Błąd tooltip delivered: {e}")
            import traceback
            traceback.print_exc()
    
    def on_sheet_click(self, event=None):
        """Obsługa kliknięcia - Zamówiono (lewy) + Dostawca (prawy)"""
        # Sprawdź czy to kliknięcie myszy
        is_left_click = False
        is_right_click = False
        
        try:
            if event:
                is_left_click = (getattr(event, "num", None) == 1)
                is_right_click = (getattr(event, "num", None) == 3)
        except:
            pass
        
        if not is_left_click and not is_right_click:
            return
        
        try:
            # Dla prawego kliku - użyj identify (event ma współrzędne)
            if is_right_click and event:
                try:
                    row = self.sheet.identify_row(event, exclude_index=True)
                    col = self.sheet.identify_column(event, exclude_header=True)
                    
                    if row is not None and col is not None and row >= 0 and col >= 0:
                        # Kolumna 10 = Dostawca
                        if col == 10:
                            self._show_supplier_context_menu(row, col, event)
                            return
                except Exception as e:
                    print(f"⚠️  Błąd prawego kliku: {e}")
                    return
            
            # Dla lewego kliku - użyj get_currently_selected
            if is_left_click:
                sel = self.sheet.get_currently_selected()
                
                if isinstance(sel, dict):
                    row = sel.get("row", sel.get("r"))
                    col = sel.get("column", sel.get("c"))
                elif isinstance(sel, (tuple, list)) and len(sel) >= 2:
                    row, col = sel[0], sel[1]
                else:
                    return
                
                if row is None or col is None or row < 0 or col < 0:
                    return
                
                # Kolumna 10 = Dostawca - pokaż menu wyboru (jak prawy klik)
                if col == 10:
                    if not self.have_lock:
                        return
                    # Stwórz event-like obiekt dla _show_supplier_context_menu
                    class FakeEvent:
                        def __init__(self, x, y):
                            self.x_root = x
                            self.y_root = y
                    
                    # Pobierz pozycję komórki na ekranie
                    try:
                        # NIE scrolluj widoku - user już widzi komórkę skoro na nią kliknął
                        # self.sheet.see(row, col, check_cell_visibility=False)  # WYŁĄCZONE
                        
                        # Pobierz współrzędne ekranu - użyj prostej heurystyki
                        # Pozycja menu przy kursorze myszki
                        screen_x = self.winfo_pointerx()
                        screen_y = self.winfo_pointery()
                        fake_event = FakeEvent(screen_x, screen_y)
                        self._show_supplier_context_menu(row, col, fake_event)
                    except Exception as e:
                        print(f"⚠️  Błąd pokazywania menu dostawcy: {e}")
                        import traceback
                        traceback.print_exc()
                    return
                
                # Kolumna 12 = Zamówiono
                if col == 12:
                    if not self.have_lock:
                        return
                    self._handle_zamowiono_click(row, col)
        
        except Exception as e:
            print(f"⚠️  Błąd on_sheet_click: {e}")
    
    def on_ctrl_click_block(self, event):
        """CTRL+klik - TYLKO dla LP (toggle wierszy), blokuj w komórkach danych"""
        try:
            # Sprawdź czy kliknięto w kolumnę (nie w LP/index)
            col = self.sheet.identify_column(event, exclude_header=True)
            
            # Jeśli col nie jest None - to kliknięcie w dane, nie w LP
            if col is not None:
                # Zablokuj - nie pozwól na zaznaczanie komórek
                return "break"
            
            # col is None = kliknięcie w LP - toggle wiersza
            row = self.sheet.identify_row(event, exclude_index=False)
            if row is not None and row >= 0:
                # Toggle - dodaj lub usuń wiersz z zaznaczenia
                currently_selected = set(self.sheet.get_selected_rows())
                
                if row in currently_selected:
                    # Odznacz - zaznacz wszystko oprócz tego wiersza
                    currently_selected.discard(row)
                    self.sheet.deselect("all", redraw=False)
                    for r in currently_selected:
                        try:
                            self.sheet.add_row_selection(r, redraw=False)
                        except:
                            self.sheet.select_row(r, redraw=False)
                    self.sheet.refresh()
                else:
                    # Dodaj do zaznaczenia - użyj add_row_selection
                    try:
                        self.sheet.add_row_selection(row, redraw=True)
                    except:
                        # Jeśli add_row_selection nie działa, użyj MT API
                        self.sheet.MT.add_selection(row, 0, row + 1, self.sheet.total_columns(), "rows")
                        self.sheet.refresh()
            
            return "break"  # Zawsze blokuj dalszą propagację
            
        except Exception as e:
            print(f"⚠️  Błąd on_ctrl_click_block: {e}")
            import traceback
            traceback.print_exc()
            return "break"
    
    def on_sheet_left_click(self, event):
        """Obsługa lewego kliku - dla kolumn BOM pokazuj tooltip z wartością src_*"""
        try:
            # Zamknij poprzedni tooltip jeśli istnieje
            if self.active_tooltip:
                self.active_tooltip.destroy()
                self.active_tooltip = None
            
            row = self.sheet.identify_row(event, exclude_index=True)
            col = self.sheet.identify_column(event, exclude_header=True)
            
            if row is None or col is None or row < 0 or col < 0:
                return
            
            # Tylko dla kolumn BOM: 0, 1, 2, 3, 7, 8, 9
            bom_columns = [0, 1, 2, 3, 7, 8, 9]
            if col not in bom_columns:
                return
            
            # KONWERSJA INDEKSU: Kolumna 16 jest ukryta
            if col >= 16:
                col += 1
            
            if row >= len(self._sheet_row_ids):
                return
            
            item_id = self._sheet_row_ids[row]
            if not item_id:
                return
            
            # Sprawdź czy komórka ma override (jeśli tak, to nie jest szara)
            if row >= len(self._sheet_overridden):
                return
            
            overridden = self._sheet_overridden[row]
            src_vals = self._sheet_src_values[row]
            
            # Jeśli kolumna NIE jest nadpisana, to NIE pokazuj tooltipa
            if col not in overridden:
                return  # Nienadpisane = białe tło, brak tooltipa
            
            # Pobierz wartość źródłową z cache
            src_value = src_vals.get(col)
            
            # Jeśli wartość źródłowa pusta - pokaż "BRAK"
            if src_value is None or str(src_value).strip() == '':
                src_value = "BRAK"
            
            # Pokaż tooltip
            self._show_bom_tooltip(event.x_root, event.y_root, src_value)
            
        except Exception as e:
            print(f"⚠️  Błąd on_sheet_left_click: {e}")
            import traceback
            traceback.print_exc()
    
    def on_sheet_right_click(self, event=None):
        """Obsługa prawego kliku - dla kolumny Dostawca pokazuj dropdown"""
        if not event:
            return
        
        try:
            row = self.sheet.identify_row(event, exclude_index=True)
            col = self.sheet.identify_column(event, exclude_header=True)
            
            if row is not None and col is not None and row >= 0 and col >= 0:
                # Kolumna 10 = Dostawca - obsłuż bezpośrednio dropdown
                if col == 10:
                    self._show_supplier_context_menu(row, col, event)
                    return "break"  # Zablokuj domyślne menu tksheet dla tej kolumny
                # Dla innych kolumn - pozwól tksheet pokazać swoje menu (nie zwracamy "break")
        except Exception as e:
            print(f"⚠️  Błąd on_sheet_right_click: {e}")
    
    def _handle_zamowiono_click(self, row, col):
        """Popup dla Zamówiono (jak w v6)"""
        if row >= len(self._sheet_row_ids):
            return
        
        item_id = self._sheet_row_ids[row]
        if not item_id:
            return
        
        try:
            cur_val = str(self.sheet.get_cell_data(row, col) or "").strip()
        except:
            cur_val = ""
        
        is_on = ("☑" in cur_val)
        
        if not is_on:
            # ☐ → Włącz
            d = self._prompt_date("Data zamówienia", datetime.now().date().isoformat())
            if not d:
                return
            
            try:
                # Pobierz stary stan dla UNDO
                cursor = self.db_manager.project_con.execute("""
                    SELECT ordered_flag, ordered_at FROM items WHERE id = ?
                """, (item_id,))
                row_data = cursor.fetchone()
                old_flag = row_data[0] if row_data else 0
                old_date = row_data[1] if row_data else None
                
                self.db_manager.project_con.execute("""
                    UPDATE items 
                    SET ordered_flag = 1, ordered_at = ?, updated_at = ?
                    WHERE id = ?
                """, (d, datetime.now().isoformat(), item_id))
                self.db_manager.project_con.commit()
                
                print(f"✅ Zamówiono item {item_id}: {d}")
                
                # Zapisz UNDO
                self._last_undo_action = {
                    'type': 'edit_ordered',
                    'item_id': item_id,
                    'row': row,
                    'old_flag': old_flag,
                    'old_date': old_date,
                    'new_flag': 1,
                    'new_date': d
                }
                self._last_redo_action = None
                print(f"💾 Zapisano UNDO dla zamówiono: {old_flag}/{old_date} → 1/{d}")
                
                # Loguj zmianę do audit trail
                self._log_item_change(item_id, 'EDIT', 'ordered_at', f"BRAK (flag={old_flag})" if not old_date else old_date, d)
                
                # update_activity() nie jest potrzebne - lock_manager_v2 nie ma heartbeat
                
                self.refresh_data()
            except Exception as e:
                messagebox.showerror("Błąd", f"Nie udało się zapisać:\n{e}")
        else:
            # ☑ → Edytuj/Wyczyść
            action = self._prompt_ordered_action()
            
            if action == "edit":
                parts = cur_val.replace("☑", "").strip().split()
                d0 = parts[0] if parts else datetime.now().date().isoformat()
                
                d = self._prompt_date("Edytuj datę zamówienia", d0)
                if not d:
                    return
                
                try:
                    # Pobierz stary stan dla UNDO
                    cursor = self.db_manager.project_con.execute("""
                        SELECT ordered_flag, ordered_at FROM items WHERE id = ?
                    """, (item_id,))
                    row_data = cursor.fetchone()
                    old_flag = row_data[0] if row_data else 0
                    old_date = row_data[1] if row_data else None
                    
                    self.db_manager.project_con.execute("""
                        UPDATE items 
                        SET ordered_flag = 1, ordered_at = ?, updated_at = ?
                        WHERE id = ?
                    """, (d, datetime.now().isoformat(), item_id))
                    self.db_manager.project_con.commit()
                    
                    print(f"✅ Edytowano zamówienie item {item_id}: {d}")
                    
                    # Zapisz UNDO
                    self._last_undo_action = {
                        'type': 'edit_ordered',
                        'item_id': item_id,
                        'row': row,
                        'old_flag': old_flag,
                        'old_date': old_date,
                        'new_flag': 1,
                        'new_date': d
                    }
                    self._last_redo_action = None
                    print(f"💾 Zapisano UNDO dla edycji zamówiono: {old_flag}/{old_date} → 1/{d}")
                    
                    # Loguj zmianę do audit trail
                    self._log_item_change(item_id, 'EDIT', 'ordered_at', old_date, d)
                    
                    # update_activity() nie jest potrzebne - lock_manager_v2 nie ma heartbeat
                    
                    self.refresh_data()
                except Exception as e:
                    messagebox.showerror("Błąd", f"Nie udało się zapisać:\n{e}")
            
            elif action == "clear":
                if not messagebox.askyesno("Wyczyść", "Czy na pewno wyczyścić zamówienie?\n\nZostanie również wyczyszczony Termin dostawy i ALARM."):
                    return
                
                try:
                    # Pobierz pełny stary stan dla UNDO (może być skomplikowany, bo kasuje też deadline/alarm)
                    cursor = self.db_manager.project_con.execute("""
                        SELECT ordered_flag, ordered_at, deadline_date, alarm_offset, alarm_unit 
                        FROM items WHERE id = ?
                    """, (item_id,))
                    row_data = cursor.fetchone()
                    old_flag = row_data[0] if row_data else 0
                    old_date = row_data[1] if row_data else None
                    old_deadline = row_data[2] if row_data else None
                    old_alarm_offset = row_data[3] if row_data else None
                    old_alarm_unit = row_data[4] if row_data else None
                    
                    self.db_manager.project_con.execute("""
                        UPDATE items 
                        SET ordered_flag = 0, 
                            ordered_at = NULL, 
                            deadline_date = NULL,
                            alarm_date = NULL,
                            alarm_offset = NULL,
                            alarm_unit = NULL,
                            updated_at = ?
                        WHERE id = ?
                    """, (datetime.now().isoformat(), item_id))
                    self.db_manager.project_con.commit()
                    
                    print(f"✅ Wyczyszczono zamówienie + termin + alarm item {item_id}")
                    
                    # Zapisz UNDO z pełnym stanem
                    self._last_undo_action = {
                        'type': 'clear_ordered',
                        'item_id': item_id,
                        'row': row,
                        'old_flag': old_flag,
                        'old_date': old_date,
                        'old_deadline': old_deadline,
                        'old_alarm_offset': old_alarm_offset,
                        'old_alarm_unit': old_alarm_unit
                    }
                    self._last_redo_action = None
                    print(f"💾 Zapisano UNDO dla clear zamówiono: {old_flag}/{old_date}/{old_deadline}/{old_alarm_offset}/{old_alarm_unit}")
                    
                    # Loguj zmianę do audit trail
                    self._log_item_change(item_id, 'CLEAR', 'ordered_at', f"{old_date} (deadline={old_deadline})" if old_date else "BRAK", None)
                    
                    # update_activity() nie jest potrzebne - lock_manager_v2 nie ma heartbeat
                    
                    self.refresh_data()
                except Exception as e:
                    messagebox.showerror("Błąd", f"Nie udało się zapisać:\n{e}")
    
    def _prompt_date(self, title, initial):
        """Dialog wpisania daty"""
        dialog = tk.Toplevel(self)
        dialog.title(title)
        dialog.geometry("300x120")
        dialog.transient(self)
        dialog.grab_set()
        
        dialog.update_idletasks()
        x = self.winfo_x() + (self.winfo_width() // 2) - (dialog.winfo_width() // 2)
        y = self.winfo_y() + (self.winfo_height() // 2) - (dialog.winfo_height() // 2)
        dialog.geometry(f"+{x}+{y}")
        
        tk.Label(dialog, text="Data (YYYY-MM-DD):").pack(pady=(10, 5))
        
        date_var = tk.StringVar(value=initial or datetime.now().date().isoformat())
        date_entry = tk.Entry(dialog, textvariable=date_var, width=20)
        date_entry.pack(pady=5)
        date_entry.select_range(0, tk.END)
        date_entry.focus()
        
        result = {"val": None}
        
        def on_ok():
            val = date_var.get().strip()
            if not val:
                result["val"] = None
                dialog.destroy()
                return
            
            if not re.match(r'^\d{4}-\d{2}-\d{2}$', val):
                messagebox.showwarning("Błąd", "Data musi być w formacie YYYY-MM-DD")
                return
            
            try:
                datetime.strptime(val, '%Y-%m-%d')
            except ValueError:
                messagebox.showwarning("Błąd", "Niepoprawna data!")
                return
            
            result["val"] = val
            dialog.destroy()
        
        def on_cancel():
            result["val"] = None
            dialog.destroy()
        
        btn_frame = tk.Frame(dialog)
        btn_frame.pack(pady=10)
        
        tk.Button(btn_frame, text="OK", command=on_ok, width=8).pack(side=tk.LEFT, padx=5)
        tk.Button(btn_frame, text="Anuluj", command=on_cancel, width=8).pack(side=tk.LEFT, padx=5)
        
        date_entry.bind('<Return>', lambda e: on_ok())
        dialog.bind('<Escape>', lambda e: on_cancel())
        
        self.wait_window(dialog)
        return result["val"]
    
    def _prompt_ordered_action(self):
        """Dialog: Edytuj / Wyczyść / Anuluj"""
        dialog = tk.Toplevel(self)
        dialog.title("Zamówiono")
        dialog.geometry("350x120")
        dialog.transient(self)
        dialog.grab_set()
        
        dialog.update_idletasks()
        x = self.winfo_x() + (self.winfo_width() // 2) - (dialog.winfo_width() // 2)
        y = self.winfo_y() + (self.winfo_height() // 2) - (dialog.winfo_height() // 2)
        dialog.geometry(f"+{x}+{y}")
        
        tk.Label(dialog, text="Pozycja już zamówiona. Co chcesz zrobić?").pack(pady=(10, 15))
        
        result = {"val": None}
        
        def setv(v):
            result["val"] = v
            dialog.destroy()
        
        btn_frame = tk.Frame(dialog)
        btn_frame.pack()
        
        tk.Button(btn_frame, text="Edytuj datę", command=lambda: setv("edit"), width=12).pack(side=tk.LEFT, padx=5)
        tk.Button(btn_frame, text="Wyczyść", command=lambda: setv("clear"), width=12).pack(side=tk.LEFT, padx=5)
        tk.Button(btn_frame, text="Anuluj", command=lambda: setv(None), width=12).pack(side=tk.LEFT, padx=5)
        
        dialog.bind('<Escape>', lambda e: setv(None))
        
        self.wait_window(dialog)
        return result["val"]
    
    def acquire_lock(self):
        """Przejmij lock projektu"""
        # GUEST nie może edytować!
        if self.current_user_role == "GUEST":
            messagebox.showerror("Brak uprawnień", "GUEST nie może edytować projektów!\n\nZaloguj się jako USER lub ADMIN.", parent=self)
            return
        
        if not self.current_project_id:
            messagebox.showwarning("Brak projektu", "Wybierz projekt najpierw!", parent=self)
            return
        
        # Zapisz szerokości kolumn PRZED przejęciem locka
        # (żeby refresh_data() po acquire nie nadpisał aktualnych szerokości)
        self._save_column_widths()
        
        try:
            # Sprawdź czy możemy przejąć
            success, lock_id = self.lock_manager.acquire_project_lock(self.current_project_id, force=False)
            
            if not success:
                # Kto ma lock?
                owner = self.lock_manager.get_project_lock_owner(self.current_project_id)
                owner_user = owner.get('user', 'Unknown') if owner else 'Unknown'
                owner_comp = owner.get('computer', 'Unknown') if owner else 'Unknown'
                owner_at = owner.get('locked_at', 'Unknown') if owner else 'Unknown'
                
                # Wymuś focus na główne okno przed pokazaniem dialogu
                self.lift()
                self.focus_force()
                
                messagebox.showwarning(
                    "Projekt zajęty",
                    f"Projekt {self.current_project_id} jest zajęty przez:\n"
                    f"{owner_user}@{owner_comp}\n"
                    f"Lock od: {owner_at}",
                    parent=self
                )
                return
            
            # OK - mamy lock!
            # Zamknij remote, otwórz local
            self.db_manager.open_project_local(
                self.current_project_id,
                self.db_manager.current_project_type
            )
            
            self.have_lock = True
            self.current_lock_id = lock_id  # Zapisz lock_id!
            
            # Inicjalizuj tabelę audit log dla pozycji (teraz mamy dostęp do zapisu)
            print("  → Inicjalizuję items_changes_log...")
            self._init_items_audit_log()
            print("  ✅ Items audit log OK")
            
            # Update UI
            self.status_label.config(text="🟢 WRITER", fg="#27ae60")
            self.info_label.config(text=f"Projekt {self.current_project_id} (LOCAL - edycja włączona)")
            self.btn_acquire_lock.config(state=tk.DISABLED)
            self.btn_force_lock.config(state=tk.DISABLED)
            self.btn_cancel_lock.config(state=tk.NORMAL)
            self.btn_release_lock.config(state=tk.NORMAL)
            self.btn_add_item.config(state=tk.NORMAL)
            self.btn_hide_selected.config(state=tk.NORMAL)
            self.btn_restore_hidden.config(state=tk.NORMAL)
            self.btn_scanner.config(state=tk.NORMAL)

            # Start idle watch
            self._start_idle_watch()
            
            # Odśwież dane (teraz z lokalnej bazy)
            self.refresh_data()
            
            # Odśwież listę projektów (aby zaktualizować informacje o lockach)
            self.load_projects()
            
        except Exception as e:
            messagebox.showerror("Błąd", f"Nie udało się przejąć locka:\n{e}", parent=self)
    
    def force_acquire_lock(self):
        """Wymuś przejęcie locka (FORCE) - dla martwych/zawieszonych locków"""
        if not self.current_project_id:
            messagebox.showwarning("Brak projektu", "Wybierz projekt najpierw!", parent=self)
            return
        
        # Sprawdź czy lock istnieje
        owner = self.lock_manager.get_project_lock_owner(self.current_project_id)
        
        if owner:
            owner_user = owner.get('user', 'Unknown')
            owner_comp = owner.get('computer', 'Unknown')
            acquired_at = owner.get('locked_at', 'Unknown')
            
            # Wymuś focus na główne okno przed pokazaniem dialogu
            self.lift()
            self.focus_force()
            
            # Potwierdź wymuszenie
            response = messagebox.askyesno(
                "⚡ Wymuś przejęcie locka",
                f"⚠️ UWAGA! Wymuszasz przejęcie locka.\n\n"
                f"Aktualny właściciel: {owner_user}@{owner_comp}\n"
                f"Lock założony: {acquired_at}\n\n"
                f"Użyj tej opcji TYLKO gdy:\n"
                f"• Poprzednia sesja zawiesiła się\n"
                f"• Lock \"wisi w powietrzu\"\n"
                f"• Nie ma innego aktywnego użytkownika\n\n"
                f"Czy na pewno wymusić przejęcie?",
                icon='warning',
                parent=self
            )
            
            if not response:
                print(f"❌ Użytkownik anulował wymuszenie locka")
                return
        else:
            # Brak locka - normalne przejęcie
            messagebox.showinfo("Info", "Brak locka - użyj przycisku 'Przejmij Lock'", parent=self)
            return
        
        # Zapisz szerokości kolumn PRZED przejęciem locka
        # (żeby refresh_data() po acquire nie nadpisał aktualnych szerokości)
        self._save_column_widths()
        
        try:
            # Wymuś przejęcie (force=True)
            success, lock_id = self.lock_manager.acquire_project_lock(self.current_project_id, force=True)
            
            if not success:
                messagebox.showerror("Błąd", "Nie udało się wymusić przejęcia locka!", parent=self)
                return
            
            # OK - mamy lock!
            # Zamknij remote, otwórz local
            self.db_manager.open_project_local(
                self.current_project_id,
                self.db_manager.current_project_type
            )
            
            self.have_lock = True
            self.current_lock_id = lock_id  # Zapisz lock_id!
            
            # Inicjalizuj tabelę audit log dla pozycji (teraz mamy dostęp do zapisu)
            print("  → Inicjalizuję items_changes_log (FORCE)...")
            self._init_items_audit_log()
            print("  ✅ Items audit log OK")
            
            # Update UI
            self.status_label.config(text="🟢 WRITER", fg="#27ae60")
            self.info_label.config(text=f"Projekt {self.current_project_id} (LOCAL - edycja włączona)")
            self.btn_acquire_lock.config(state=tk.DISABLED)
            self.btn_force_lock.config(state=tk.DISABLED)
            self.btn_cancel_lock.config(state=tk.NORMAL)
            self.btn_release_lock.config(state=tk.NORMAL)
            self.btn_add_item.config(state=tk.NORMAL)
            self.btn_hide_selected.config(state=tk.NORMAL)
            self.btn_restore_hidden.config(state=tk.NORMAL)
            self.btn_scanner.config(state=tk.NORMAL)

            # Start idle watch
            self._start_idle_watch()
            
            # Odśwież dane (teraz z lokalnej bazy)
            self.refresh_data()
            
            # Odśwież listę projektów (aby zaktualizować informacje o lockach)
            self.load_projects()
            
        except Exception as e:
            messagebox.showerror("Błąd", f"Nie udało się wymusić przejęcia locka:\n{e}", parent=self)
    
    def _force_cancel_lock_on_lost(self, reason: str):
        """Wymuszone anulowanie locka gdy wykryto że straciliśmy lock
        
        Ta metoda jest wywołana automatycznie gdy refresh_data() wykryje że:
        - Lock zniknął (ktoś go zwolnił)
        - Lock_id się zmienił (ktoś wymusza lock)
        
        Args:
            reason: Powód utraty locka (wyświetlany użytkownikowi)
        """
        try:
            print(f"🚨 WYMUSZENIE ANULOWANIA LOCKA! Powód: {reason}")
            
            # WAŻNE: Zapamiętaj informacje PRZED zamknięciem
            saved_project_id = self.current_project_id
            saved_project_type = self.db_manager.current_project_type
            
            # Zamknij lokalną kopię (z niezapisanymi zmianami)
            self.db_manager.close_project_and_cleanup(
                self.current_project_id,
                saved_project_type
            )
            
            # Wyzeruj stan locka
            self.have_lock = False
            self.current_lock_id = None
            self._stop_idle_watch()
            
            # Spróbuj otworzyć ponownie REMOTE (READ-ONLY) - ale tylko jeśli dysk dostępny
            project_reopened = False
            try:
                # Sprawdź czy dysk sieciowy jest dostępny
                if self._safe_ensure_master_alive():
                    self.db_manager.open_project_remote(
                        saved_project_id,
                        saved_project_type
                    )
                    project_reopened = True
                    print(f"✅ Projekt {saved_project_id} otwarty ponownie jako READ-ONLY")
                else:
                    print(f"⚠️  Dysk sieciowy niedostępny - projekt zostanie zamknięty")
            except Exception as e:
                print(f"⚠️  Nie można otworzyć projektu REMOTE: {e}")
            
            # Update UI w zależności od tego czy udało się otworzyć projekt
            if project_reopened:
                # Projekt otwarty READ-ONLY
                self.status_label.config(text="🔴 READER", fg="#e74c3c")
                self.info_label.config(text=f"Projekt {saved_project_id} (READ-ONLY) - lock utracony")
                self.btn_acquire_lock.config(state=tk.NORMAL)
                self.btn_force_lock.config(state=tk.NORMAL)
                self.btn_cancel_lock.config(state=tk.DISABLED)
                self.btn_release_lock.config(state=tk.DISABLED)
                self.btn_add_item.config(state=tk.DISABLED)
                self.btn_hide_selected.config(state=tk.DISABLED)
                self.btn_restore_hidden.config(state=tk.DISABLED)
                self.btn_scanner.config(state=tk.DISABLED)
                
                # Odśwież dane (z wersji sieciowej)
                try:
                    self.refresh_data()
                except Exception as e:
                    print(f"⚠️  Błąd refresh_data: {e}")
            else:
                # Projekt niedostępny - zresetuj UI do stanu początkowego
                self.current_project_id = None
                self.db_manager.current_project_type = None
                
                self.status_label.config(text="🔵 INIT", fg="gray")
                self.info_label.config(text="⚠️ Utrata locka + dysk niedostępny - wybierz projekt po przywróceniu połączenia", fg="orange")
                self.btn_acquire_lock.config(state=tk.DISABLED)
                self.btn_force_lock.config(state=tk.DISABLED)
                self.btn_cancel_lock.config(state=tk.DISABLED)
                self.btn_release_lock.config(state=tk.DISABLED)
                self.btn_add_item.config(state=tk.DISABLED)
                self.btn_hide_selected.config(state=tk.DISABLED)
                self.btn_restore_hidden.config(state=tk.DISABLED)
                self.btn_scanner.config(state=tk.DISABLED)
                
                # Wyczyść tabelę
                try:
                    for row in self.sheet.get_children():
                        self.sheet.delete(row)
                except Exception as e:
                    print(f"⚠️  Błąd czyszczenia tabeli: {e}")
            
            # Pokaż ostrzeżenie użytkownikowi
            if project_reopened:
                messagebox.showerror(
                    "⚠️ Utrata locka - Stracono niezapisane dane!",
                    f"Lock projektu {saved_project_id} został przejęty!\n\n"
                    f"Powód:\n{reason}\n\n"
                    f"⚠️ WSZYSTKIE TWOJE NIEZAPISANE ZMIANY ZOSTAŁY UTRACONE!\n\n"
                    f"Dane zostały przywrócone do wersji sieciowej.\n"
                    f"Tryb: READ-ONLY"
                )
            else:
                messagebox.showerror(
                    "⚠️ Utrata locka + dysk niedostępny!",
                    f"Lock projektu {saved_project_id} został przejęty + dysk sieciowy jest niedostępny!\n\n"
                    f"Powód utraty locka:\n{reason}\n\n"
                    f"⚠️ WSZYSTKIE TWOJE NIEZAPISANE ZMIANY ZOSTAŁY UTRACONE!\n\n"
                    f"Projekt został zamknięty.\n"
                    f"Wybierz projekt ponownie po przywróceniu połączenia."
                )
            
        except Exception as e:
            print(f"❌ Błąd wymuszenia anulowania locka: {e}")
            import traceback
            traceback.print_exc()
    
    def cancel_lock(self, skip_confirmation=False):
        """Anuluj lock (zwolnij bez zapisywania)
        
        Args:
            skip_confirmation: Jeśli True, nie wyświetla dialogu potwierdzenia
        
        Zwraca:
            True - lock został anulowany
            False - użytkownik zrezygnował z anulowania
        """
        if not self.have_lock:
            return False
        
        if not self.current_project_id:
            return False
        
        # Potwierdź anulowanie (jeśli nie pominięto)
        if not skip_confirmation:
            if not messagebox.askyesno(
                "Potwierdź anulowanie",
                f"Czy na pewno anulować zmiany w projekcie {self.current_project_id}?\n\n"
                "⚠️ WSZYSTKIE zmiany od momentu przejęcia locka zostaną UTRACONE!\n\n"
                "Dane zostaną przywrócone z wersji sieciowej.",
                icon='warning'
            ):
                return False  # Użytkownik wybrał NIE - nie anuluj
        
        try:
            # >>> KROK 1: Zwolnij lock OD RAZU <<<
            print(f"🗑️ Anulowanie locka (bez zapisu zmian)...")
            self.lock_manager.release_project_lock(self.current_project_id)
            
            # Wyczyść stan locka w aplikacji
            self.have_lock = False
            self.current_lock_id = None
            self._stop_idle_watch()
            
            # Update UI (przed cleanup - żeby użytkownik widział że lock został zwolniony)
            self.status_label.config(text="🔴 READER", fg="#e74c3c")
            self.btn_acquire_lock.config(state=tk.NORMAL)
            self.btn_force_lock.config(state=tk.NORMAL)
            self.btn_cancel_lock.config(state=tk.DISABLED)
            self.btn_release_lock.config(state=tk.DISABLED)
            self.btn_add_item.config(state=tk.DISABLED)
            self.btn_hide_selected.config(state=tk.DISABLED)
            self.btn_restore_hidden.config(state=tk.DISABLED)
            self.btn_scanner.config(state=tk.DISABLED)
            
            # >>> KROK 2: Cleanup (jeśli tu jest błąd, lock już jest zwolniony!) <<<
            # NIE synchronizuj! - odrzuć lokalne zmiany
            
            # WAŻNE: Zapamiętaj typ projektu PRZED close_project_and_cleanup
            saved_project_type = self.db_manager.current_project_type
            
            # Zamknij i usuń lokalną kopię (z niezapisanymi zmianami)
            self.db_manager.close_project_and_cleanup(
                self.current_project_id,
                saved_project_type
            )
            
            # Otwórz ponownie REMOTE (READ-ONLY) - przywróci dane sprzed edycji
            self.db_manager.open_project_remote(
                self.current_project_id,
                saved_project_type
            )
            
            # Update UI - dodatkowe informacje
            self.info_label.config(text=f"Projekt {self.current_project_id} (READ-ONLY)")
            
            # Odśwież dane (z wersji sieciowej)
            self.refresh_data()
            
            return True  # Sukces - lock anulowany
            
        except Exception as e:
            # Lock został zwolniony, ale był błąd podczas cleanup
            messagebox.showerror("Błąd podczas anulowania",
                f"Lock został zwolniony, ale wystąpił błąd podczas cleanup:\n{e}\n\n"
                f"Odśwież listę projektów ręcznie.")
            return False  # Błąd cleanup
    
    def release_lock(self):
        """Zwolnij lock projektu"""
        if not self.have_lock:
            return
        
        if not self.current_project_id:
            return
        
        # Odblokuj GUI przed operacją
        self.update_idletasks()
        
        # ⚠️ SPRAWDŹ CZY NADAL MAMY LOCK PRZED ZAPISEM!
        if self.current_lock_id:
            current_owner = self.lock_manager.get_project_lock_owner(self.current_project_id)
            
            # Sprawdź czy lock zniknął lub zmienił właściciela
            lock_lost = False
            reason = ""
            
            if not current_owner:
                # Lock zniknął całkowicie (ktoś go zwolnił)
                lock_lost = True
                reason = "Lock został zwolniony przez innego użytkownika"
            elif current_owner.get('lock_id') != self.current_lock_id:
                # Lock_id się zmienił (ktoś wymusza lock)
                lock_lost = True
                new_owner = current_owner.get('user', 'Unknown')
                new_computer = current_owner.get('computer', 'Unknown')
                reason = f"Lock został wymuszony przez:\n{new_owner}@{new_computer}"
            
            if lock_lost:
                print(f"⚠️⚠️⚠️ WYKRYTO UTRATĘ LOCKA przy próbie zwolnienia!")
                print(f"   Powód: {reason}")
                print(f"   ❌ ANULOWANIE zamiast zwalniania - NIE zapisujemy!")
                
                # Anuluj lock bez pytania (bo już go nie mamy!)
                self._force_cancel_lock_on_lost(reason)
                return  # NIE zapisuj danych na serwer!
        
        try:
            # >>> KROK 1: ZWOLNIJ LOCK OD RAZU (żeby nie wisał w razie błędu) <<<
            # Zwalniamy lock PRZED sync - jeśli sync się nie uda, lock i tak będzie zwolniony
            print(f"🔓 Zwalnianie locka...")
            self.lock_manager.release_project_lock(self.current_project_id)
            
            # Wyczyść stan locka w aplikacji
            self.have_lock = False
            self.current_lock_id = None
            self._stop_idle_watch()
            
            # Update UI na stan READ-ONLY (przed sync - żeby użytkownik widział że już nie ma locka)
            self.status_label.config(text="🔴 READER", fg="#e74c3c")
            self.btn_acquire_lock.config(state=tk.NORMAL)
            self.btn_force_lock.config(state=tk.NORMAL)
            self.btn_cancel_lock.config(state=tk.DISABLED)
            self.btn_release_lock.config(state=tk.DISABLED)
            self.btn_add_item.config(state=tk.DISABLED)
            self.btn_hide_selected.config(state=tk.DISABLED)
            self.btn_restore_hidden.config(state=tk.DISABLED)
            self.btn_scanner.config(state=tk.DISABLED)
            
            # >>> KROK 2: Sync i backup (jeśli teraz cos się zwali, lock już jest zwolniony!) <<<
            # 1. Zamknij połączenie przed sync (wymuś zapis wszystkiego)
            if self.db_manager.project_con:
                print(f"💾 Zamykam połączenie i zapisuję zmiany...")
                self.db_manager.project_con.commit()
                self.db_manager.project_con.execute("PRAGMA wal_checkpoint(TRUNCATE)")
                self.db_manager.project_con.commit()
                self.db_manager.project_con.close()
                self.db_manager.project_con = None
                print(f"✅ Połączenie zamknięte, WAL zapisany")
            
            # Poczekaj na flush systemu plików
            import time
            time.sleep(0.3)
            
            # Odblokuj GUI
            self.update_idletasks()
            
            # 2. Sync lokalny → serwer (plik jest zamknięty, kompletny)
            print(f"🔄 Synchronizacja lokalny → serwer...")
            
            # Użyj get_project_db_path dla poprawnej ścieżki + uwzględnij typ projektu
            from project_manager import get_project_db_path
            project_type = self.db_manager.current_project_type
            
            # Lokalna kopia - nazwa zależy od typu
            if project_type == "WAREHOUSE":
                local_db = self.db_manager.local_dir / f"project_MAG_{self.current_project_id}.sqlite"
                base_dir = self.db_manager.projects_mag_dir
            else:  # MACHINE
                local_db = self.db_manager.local_dir / f"project_{self.current_project_id}.sqlite"
                base_dir = self.db_manager.projects_dir
            
            remote_db = get_project_db_path(base_dir, self.current_project_id, project_type)
            
            print(f"  📁 Local: {local_db}")
            print(f"  📁 Remote: {remote_db}")
            
            import shutil
            
            # Utwórz katalog docelowy jeśli nie istnieje
            remote_db.parent.mkdir(parents=True, exist_ok=True)
            
            # KROK A: Usuń stare pliki WAL/SHM z serwera (mogą zawierać stare dane)
            remote_wal = Path(str(remote_db) + "-wal")
            remote_shm = Path(str(remote_db) + "-shm")
            
            for old_file in [remote_wal, remote_shm]:
                if old_file.exists():
                    try:
                        old_file.unlink()
                        print(f"🗑️  Usunięto stary plik: {old_file.name}")
                    except Exception as e:
                        print(f"⚠️  Nie udało się usunąć {old_file.name}: {e}")
            
            # KROK B: Skopiuj główny plik .sqlite
            shutil.copy2(local_db, remote_db)
            print(f"✅ Skopiowano {local_db.name} → serwer")
            
            # Odblokuj GUI po kopiowaniu
            self.update_idletasks()
            
            # Poczekaj na flush sieciowego dysku
            time.sleep(0.5)
            
            # KROK C: Otwórz, wymóż CHECKPOINT(TRUNCATE), zweryfikuj, zamknij
            verify_con = _open_baza_connection(remote_db, row_factory=False, timeout=30.0)
            
            # Integrity check
            verify_con.execute("PRAGMA integrity_check")
            
            # WAŻNE: Wymuś checkpoint TRUNCATE żeby:
            # 1. Wszystkie dane z WAL → główny plik .sqlite
            # 2. Usunąć pliki -wal i -shm
            print(f"🔧 Checkpoint TRUNCATE sieciowej bazy...")
            checkpoint_result = verify_con.execute("PRAGMA wal_checkpoint(TRUNCATE)")
            result = checkpoint_result.fetchone()
            print(f"   Checkpoint result: {result}")  # (busy, log, checkpointed)
            verify_con.commit()
            
            # Sprawdź czy dane są zapisane
            cursor = verify_con.execute("SELECT COUNT(*) FROM items")
            items_count = cursor.fetchone()[0]
            
            # Sprawdź przykładowe wiersze które właśnie edytowałeś
            cursor = verify_con.execute("""
                SELECT id, work_drawing_no, work_qty, mat_manual_text, thickness_mm 
                FROM items 
                WHERE thickness_mm IS NOT NULL OR mat_manual_text IS NOT NULL
                LIMIT 3
            """)
            sample_items = cursor.fetchall()
            print(f"✅ Weryfikacja sieciowej bazy: {items_count} items")
            for item in sample_items:
                print(f"   Item ID={item[0]}: rysun={item[1]}, ilość={item[2]}, mat={item[3]}, grubość={item[4]}")
            
            verify_con.close()
            
            # KROK D: Poczekaj żeby być pewnym że plik jest zamknięty
            time.sleep(0.3)
            
            # KROK E: Sprawdź czy WAL/SHM zostały usunięte
            if remote_wal.exists():
                print(f"⚠️  UWAGA: Plik {remote_wal.name} nadal istnieje po checkpoint!")
            if remote_shm.exists():
                print(f"⚠️  UWAGA: Plik {remote_shm.name} nadal istnieje po checkpoint!")
            
            if not remote_wal.exists() and not remote_shm.exists():
                print(f"✅ Pliki WAL/SHM usunięte - baza gotowa do backupu")
            
            # DODATKOWE OPÓŹNIENIE
            time.sleep(0.3)
            
            # FINALNY TEST: Otwórz bazę READONLY i sprawdź dane PRZED backupem
            final_con = _open_baza_connection(f"file:{remote_db}?mode=ro&immutable=1", uri=True, timeout=5.0)
            cursor = final_con.execute("""
                SELECT id, work_drawing_no, mat_manual_text, thickness_mm 
                FROM items 
                WHERE thickness_mm IS NOT NULL 
                ORDER BY id 
                LIMIT 5
            """)
            final_items = cursor.fetchall()
            print(f"   Wiersze z GRUBOŚCIĄ w bazie sieciowej (przed backupem):")
            for item in final_items:
                print(f"      ID={item['id']}, rysun={item['work_drawing_no']}, mat={item['mat_manual_text']}, GRUBOŚĆ={item['thickness_mm']}")
            final_con.close()
            
            time.sleep(0.2)
            
            # 3. Backup SIECIOWEJ bazy (teraz ma już zmiany!)
            # Przekazujemy skip_checkpoint=True bo już zrobiliśmy checkpoint powyżej
            # SPRAWDŹ CZY BACKUP PRZY RELEASE_LOCK JEST WŁĄCZONY
            if self.backup_on_release_var.get():
                try:
                    # Odblokuj GUI przed backupem
                    self.update_idletasks()
                    
                    print(f"📦 Tworzę backup projektu {self.current_project_id}...")
                    self.backup_manager.backup_project(self.current_project_id, skip_checkpoint=True)
                    print(f"✅ Backup projektu zakończony")
                except Exception as e:
                    print(f"⚠️  Błąd backupu (niegroźne): {e}")
                    import traceback
                    traceback.print_exc()
            else:
                print(f"⏭️  Backup przy release_lock WYŁĄCZONY (ustawienie w menu)")
            
            # >>> KROK 3: Cleanup i odświeżenie <<<
            # Zapisz szerokości kolumn
            self._save_column_widths()
            
            # WAŻNE: Zapamiętaj typ projektu PRZED close_project_and_cleanup!
            # (bo _close_project() resetuje current_project_type na "MACHINE")
            saved_project_type = self.db_manager.current_project_type
            
            # Zamknij lokalną kopię
            self.db_manager.close_project_and_cleanup(
                self.current_project_id,
                saved_project_type
            )
            
            # Otwórz ponownie REMOTE (READ-ONLY) - używaj ZAPISANEGO typu!
            self.db_manager.open_project_remote(
                self.current_project_id,
                saved_project_type  # Użyj zapisanego, nie current_project_type!
            )
            
            # Update UI - dodatkowe informacje
            self.info_label.config(text=f"Projekt {self.current_project_id} (READ-ONLY)")
            
            # Odśwież dane
            self.refresh_data()
            
            # Odśwież listę projektów (aby zaktualizować informacje o lockach)
            self.load_projects()
            
        except Exception as e:
            # WAŻNE: Lock już został zwolniony na początku try, więc nawet jeśli tutaj jest błąd,
            # lock nie będzie wisiał!
            messagebox.showerror("Błąd podczas zwalniania",
                f"Lock został zwolniony, ale wystąpił błąd podczas sync/cleanup:\n{e}\n\n"
                f"Projekt może wymagać ręcznej weryfikacji.")
    
    def _search_item_in_projects(self, drawing_no=None, name=None):
        """
        Szuka pozycji we wszystkich bazach projektowych (dla autouzupełniania)
        
        Args:
            drawing_no: Nr rysunku do wyszukania (dokładne dopasowanie)
            name: Nazwa do wyszukania (dokładne dopasowanie)
            
        Returns:
            dict z danymi pozycji lub None jeśli nie znaleziono
        """
        # print(f"🔍 _search_item_in_projects wywołane: drawing_no='{drawing_no}', name='{name}'")
        
        if not drawing_no and not name:
            # print("  ⚠️ Brak kryteriów wyszukiwania")
            return None
        
        # print(f"  📁 PROJECTS_DIR: {PROJECTS_DIR}")
        
        # Szukaj we WSZYSTKICH projektach - najpierw w bieżącym, potem w pozostałych
        try:
            # Znajdź wszystkie pliki project_*.sqlite w katalogach ze ścieżki config
            projects_machine = self.db_manager.projects_dir
            projects_warehouse = self.db_manager.projects_mag_dir
            
            project_files_machine = list(projects_machine.glob("project_*.sqlite")) if projects_machine.exists() else []
            project_files_warehouse = list(projects_warehouse.glob("project_MAG_*.sqlite")) if projects_warehouse.exists() else []
            
            project_files = sorted(project_files_machine + project_files_warehouse, reverse=True)
            
            # Wyciągnij ID projektu z nazwy pliku (project_10.sqlite -> 10, project_MAG_5.sqlite -> 5)
            all_project_ids = []
            for pf in project_files:
                try:
                    if pf.stem.startswith("project_MAG_"):
                        pid = int(pf.stem.split('_')[2])
                    else:
                        pid = int(pf.stem.split('_')[1])
                    all_project_ids.append(pid)
                except:
                    pass
            
            # Priorytetyzuj bieżący projekt - szukaj najpierw w nim
            current_pid = self.current_project_id
            if current_pid and current_pid in all_project_ids:
                # Przenieś bieżący na początek listy
                all_project_ids.remove(current_pid)
                all_project_ids.insert(0, current_pid)
                print(f"  🎯 Priorytet: bieżący projekt {current_pid}")
            
            # Pozostałe sortuj od najnowszego
            if len(all_project_ids) > 1:
                # Bieżący jest na pozycji [0], sortuj [1:]
                all_project_ids[1:] = sorted(all_project_ids[1:], reverse=True)
            
            print(f"  📂 Wyszukiwanie w {len(all_project_ids)} projektach (kolejność z priorytetem bieżącego)")
            print(f"     Projekty: {all_project_ids}")
            
            for project_id in all_project_ids:
                # Buduj ścieżkę do pliku projektu - katalogi ze ścieżki config
                project_file_machine = self.db_manager.projects_dir / f"project_{project_id}.sqlite"
                project_file_warehouse = self.db_manager.projects_mag_dir / f"project_MAG_{project_id}.sqlite"
                
                # Sprawdź który plik istnieje
                if project_file_machine.exists():
                    project_file = project_file_machine
                elif project_file_warehouse.exists():
                    project_file = project_file_warehouse
                else:
                    # print(f"  ⚠️ Plik nie istnieje ani jako {project_file_machine} ani {project_file_warehouse}")
                    continue
                
                try:
                    con = _open_baza_connection(f"file:{project_file}?mode=ro", uri=True, timeout=5.0)
                    
                    if drawing_no:
                        # Szukaj we WSZYSTKICH kolumnach z numerami (src, work, norm) + COLLATE NOCASE
                        sql = """SELECT * FROM items 
                                 WHERE (
                                    work_drawing_no = ? COLLATE NOCASE
                                    OR norm_drawing_no = ? COLLATE NOCASE
                                    OR src_drawing_no = ? COLLATE NOCASE
                                 )
                                 AND is_hidden = 0
                                 ORDER BY updated_at DESC LIMIT 1"""
                        row = con.execute(sql, (drawing_no, drawing_no, drawing_no)).fetchone()
                    elif name:
                        # Szukaj w work_name ORAZ src_name (może być NULL w work_*)
                        sql = """SELECT * FROM items 
                                 WHERE (work_name = ? COLLATE NOCASE OR src_name = ? COLLATE NOCASE)
                                 AND is_hidden = 0
                                 ORDER BY updated_at DESC LIMIT 1"""
                        row = con.execute(sql, (name, name)).fetchone()
                    
                    if row:
                        search_type = "nr rysunku" if drawing_no else "nazwy"
                        
                        print(f"   📌 DEBUG SQL z project_{project_id}:")
                        print(f"      work_desc: '{row['work_desc']}' (is None: {row['work_desc'] is None})")
                        print(f"      src_desc: '{row['src_desc']}' (is None: {row['src_desc'] is None})")
                        print(f"      thickness_mm: {row['thickness_mm']}")
                        print(f"      src_material_text: '{row['src_material_text']}'")
                        print(f"      supplier_id: {row['supplier_id']}")
                        print(f"      src_supplier_text: '{row['src_supplier_text']}'")  # TEKST dostawcy z BOM!
                        
                        # Grubość - jeśli thickness_mm jest NULL, parsuj z materiału
                        thickness_val = row['thickness_mm']
                        if thickness_val is None:
                            try:
                                mat_src = row['src_material_text'] or ""
                                if mat_src:
                                    from import_bom import parse_thickness_mm
                                    thickness_val = parse_thickness_mm(mat_src)
                                    print(f"      🔍 Sparsowano grubość z materiału '{mat_src}' → {thickness_val}")
                            except Exception as e:
                                print(f"      ⚠️ Błąd parsowania grubości: {e}")
                        
                        # Pobierz dane - preferuj work_*, ale użyj src_* jako fallback (COALESCE)
                        desc_value = row['work_desc'] if row['work_desc'] is not None else row['src_desc']
                        
                        # Moduł - COALESCE(work_modul, src_modul)
                        modul_value = None
                        try:
                            modul_value = row['work_modul'] if row['work_modul'] is not None else row['src_modul']
                        except (KeyError, IndexError):
                            # Stara baza bez kolumny moduł
                            pass
                        
                        result = {
                            'drawing_no': row['work_drawing_no'] if row['work_drawing_no'] is not None else (row['src_drawing_no'] or row['norm_drawing_no']),
                            'name': row['work_name'] if row['work_name'] is not None else row['src_name'],
                            'desc': desc_value,
                            'qty': row['work_qty'] if row['work_qty'] is not None else row['src_qty'],
                            'type': row['class_effective'] or row['class_manual'] or row['class_auto'],
                            'material': row['mat_effective_text'] or row['mat_manual_text'] or row['mat_auto_text'],
                            'thickness': thickness_val,
                            'supplier_id': row['supplier_id'],
                            'src_supplier_text': row['src_supplier_text'],
                            'modul': modul_value,
                            'source': f'project_{project_id}'
                        }
                        # print(f"      📋 Dane: {result['drawing_no']} | {result['name']} | {result['type']}")
                        con.close()
                        print(f"✅ Autouzupełniam z project_{project_id} (wyszukiwanie po {search_type})")
                        print(f"   📌 Znaleziona pozycja: {result['name']} | typ: {result['type']} | grubość: {result['thickness']} | dostawca_id: {result['supplier_id']} | opis: '{result['desc']}'")
                        return result
                    else:
                        pass
                        # DEBUG: Sprawdź pierwsze 3 numery z tego projektu
                        # try:
                        #     sample_rows = con.execute(
                        #         "SELECT work_drawing_no FROM items WHERE is_hidden = 0 AND work_drawing_no != '' LIMIT 3"
                        #     ).fetchall()
                        #     if sample_rows:
                        #         samples = [sr[0] for sr in sample_rows]
                        #         print(f"      📝 Przykłady: {samples}")
                        #     else:
                        #         print(f"      ⚠️ Brak pozycji w tym projekcie")
                        # except:
                        #     pass
                        # print(f"      ⚠️ Nie znaleziono w {project_file.name}")
                    
                    con.close()
                    
                except Exception as e:
                    # print(f"    ❌ Błąd przeszukiwania {project_file}: {e}")
                    # import traceback
                    # traceback.print_exc()
                    continue
        
        except Exception as e:
            print(f"❌ Błąd szukania w projektach: {e}")
            import traceback
            traceback.print_exc()
        
        # Nie znaleziono
        return None
    
    def add_item_manually(self):
        """Dialog do ręcznego dodawania pozycji"""
        if not self.have_lock:
            messagebox.showerror("Brak locka", "Musisz przejąć lock projektu, aby dodawać pozycje!")
            return
        
        if not self.current_project_id:
            messagebox.showerror("Błąd", "Nie wybrano projektu!")
            return
        
        dlg = tk.Toplevel(self)
        dlg.title("➕ Dodaj pozycję ręcznie")
        dlg.geometry("600x550")
        dlg.transient(self)
        dlg.grab_set()
        dlg.resizable(False, False)
        
        # Wycentruj
        dlg.update_idletasks()
        x = self.winfo_x() + (self.winfo_width() // 2) - (dlg.winfo_width() // 2)
        y = self.winfo_y() + (self.winfo_height() // 2) - (dlg.winfo_height() // 2)
        dlg.geometry(f"+{x}+{y}")
        
        main_frame = tk.Frame(dlg, padx=25, pady=20, bg="#f0f0f0")
        main_frame.pack(fill=tk.BOTH, expand=True)
        
        # Pola formularza
        fields = []
        
        # Nr rysunku
        tk.Label(main_frame, text="Nr rysunku:", bg="#f0f0f0", font=("Arial", 10, "bold")).grid(row=0, column=0, sticky="e", padx=10, pady=8)
        e_drawing = tk.Entry(main_frame, width=40, font=("Arial", 10))
        e_drawing.grid(row=0, column=1, padx=10, pady=8, sticky="ew")
        fields.append(("drawing", e_drawing))
        
        # Nazwa (z autocomplete)
        tk.Label(main_frame, text="Nazwa:", bg="#f0f0f0", font=("Arial", 10, "bold")).grid(row=1, column=0, sticky="e", padx=10, pady=8)
        name_var = tk.StringVar()
