    def copy_name_to_clipboard(self):
        """Kopiuj NUMER i NAZWĘ zaznaczonych wierszy do schowka (obsługuje wiele wierszy i pojedyncze podświetlenie)"""
        try:
            # Pobierz zaznaczone wiersze z arkusza (masowe zaznaczenie)
            selected_rows = self.sheet.get_selected_rows()
            
            # Jeśli nie ma zaznaczonych wierszy, użyj podświetlonego wiersza
            if not selected_rows:
                row_idx = getattr(self, '_selected_row_idx', None)
                if row_idx is not None:
                    selected_rows = [row_idx]
            
            if not selected_rows:
                messagebox.showwarning("Brak zaznaczenia", "Nie zaznaczono żadnego wiersza!")
                return
            
            # Lista tekstów do skopiowania
            texts_to_copy = []
            
            # Iteruj po zaznaczonych wierszach
            for row_idx in sorted(selected_rows):
                # Sprawdź czy wiersz jest w zakresie
                if row_idx >= len(self._sheet_row_ids):
                    continue
                
                # Pobierz dane z arkusza (kolumna 0 = Nr rysunku, kolumna 1 = Nazwa)
                try:
                    numer = self.sheet.get_cell_data(row_idx, 0) or ""
                    nazwa = self.sheet.get_cell_data(row_idx, 1) or ""
                except:
                    continue
                
                # Format: "NUMER Nazwa"
                text = f"{numer} {nazwa}".strip()
                if text:
                    texts_to_copy.append(text)
            
            if not texts_to_copy:
                messagebox.showwarning("Brak danych", "Zaznaczone wiersze nie zawierają numerów ani nazw!")
                return
            
            # Połącz wszystkie teksty (każdy w nowej linii)
            final_text = "\n".join(texts_to_copy)
            
            # Kopiuj do schowka
            self.clipboard_clear()
            self.clipboard_append(final_text)
            self.update()  # Upewnij się że schowek jest zaktualizowany
            
            # Krótkie potwierdzenie
            count = len(texts_to_copy)
            if count == 1:
                print(f"📋 Skopiowano do schowka: {texts_to_copy[0]}")
            else:
                print(f"📋 Skopiowano {count} pozycji do schowka")
            
            # Flashuj przycisk na zielono
            try:
                if hasattr(self, 'btn_copy_name'):
                    original_bg = self.btn_copy_name.cget('bg')
                    self.btn_copy_name.config(bg='#27ae60')  # Zielony
                    self.after(200, lambda: self.btn_copy_name.config(bg=original_bg))
            except:
                pass
                
        except Exception as e:
            messagebox.showerror("Błąd kopiowania", f"Nie udało się skopiować:\n{e}")
            import traceback
            traceback.print_exc()
    
    def open_scanner_window(self):
        """Otwórz okno skanera kodów kreskowych dla DOSTARCZONO"""
        if not self.have_lock:
            messagebox.showerror("Brak locka", "Musisz przejąć lock projektu, aby skanować dostawy!")
            return
        
        if not self.current_project_id:
            messagebox.showerror("Błąd", "Nie wybrano projektu!")
            return
        
        # Oznacz że okno skanera jest otwarte (wyłącz filtr szybkiego pisania)
        self._scanner_window_open = True
        
        # Utwórz okno
        scanner_win = tk.Toplevel(self)
        scanner_win.title("📱 SKANER - Uzupełnianie DOSTARCZONO")
        scanner_win.geometry("700x620")
