    # ========================================================================
    # MODUŁ BACKUPÓW
    # ========================================================================
    
    def check_and_run_daily_backup(self):
        """
        Sprawdź czy dzisiaj był już backup i jeśli nie - wykonaj
        
        Backup jest wykonywany RAZ DZIENNIE przy pierwszym uruchomieniu aplikacji.
        Sprawdza czy istnieje backup master DB z dzisiejszą datą - jeśli nie, wykonuje
        backup master + wszystkich projektów.
        """
        try:
            from datetime import datetime
            today = datetime.now().strftime("%Y-%m-%d")
            
            # Sprawdź czy istnieje backup master z dzisiejszą datą
            master_backup_file = self.backup_manager.master_backup_dir / f"master_{today}.sqlite"
            
            if master_backup_file.exists():
                print(f"  ℹ️  Backup już wykonany dzisiaj ({today}), pomijam")
                return
            
            # Wykonaj codzienny backup (master + wszystkie projekty)
            print(f"  📦 Wykonuję codzienny backup ({today})...")
            self.backup_manager.run_daily_backup()
            print(f"  ✅ Codzienny backup zakończony")
        
        except Exception as e:
            print(f"  ⚠️  Błąd backupu (niegroźne): {e}")
            import traceback
            traceback.print_exc()
    
    def run_backup_in_background(self):
        """Uruchom backup w tle bez blokowania GUI"""
        def do_backup():
            try:
                self.check_and_run_daily_backup()
            except Exception as e:
                print(f"⚠️ Błąd backupu w tle: {e}")
        
        # Backup w osobnym wątku (NIE dotyka GUI, więc bezpieczne)
        import threading
        backup_thread = threading.Thread(target=do_backup, daemon=True)
        backup_thread.start()
        print("🔄 Backup uruchomiony w tle...")
    
    
    def menu_view_backups(self):
        """Menu: Podgląd backupów"""
        self.backups_view_dialog()
    
    def menu_run_backup_now(self):
        """Menu: Wykonaj backup teraz"""
        if not messagebox.askyesno("Potwierdź backup", "Wykonać backup master DB i wszystkich projektów?"):
            return
        
        try:
            self.backup_manager.run_daily_backup()
        except Exception as e:
            messagebox.showerror("Błąd", f"Nie udało się wykonać backupu:\n{e}")
    
    def menu_restore_backup(self):
        """Menu: Przywróć backup (tylko ADMIN)"""
        if self.current_user_role != "ADMIN":
            messagebox.showerror("Brak uprawnień", "Tylko ADMIN może przywracać backupy!")
            return
        
        self.backups_restore_dialog()
    
    def toggle_backup_on_release(self):
        """Przełącz opcję backup przy release_lock (tylko ADMIN)"""
        # Sprawdź czy master DB jest połączona
        if not self.db_manager or not self.db_manager.master_con:
            messagebox.showerror("Błąd", "Baza danych nie jest połączona!")
            # Przywróć poprzednią wartość
            self.backup_on_release_var.set(not self.backup_on_release_var.get())
            return
        
        if self.current_user_role != "ADMIN":
            messagebox.showerror("Brak uprawnień", "Tylko ADMIN może zmieniać ustawienia backupów!")
            # Przywróć poprzednią wartość
            self.backup_on_release_var.set(not self.backup_on_release_var.get())
            return
        
        # Zapisz ustawienie do master DB
        enabled = self.backup_on_release_var.get()
        status = "WŁĄCZONY" if enabled else "WYŁĄCZONY"
        
        try:
            # Upewnij się że tabela istnieje
            self.db_manager.master_con.execute("""
                CREATE TABLE IF NOT EXISTS settings (
                    key TEXT PRIMARY KEY,
                    value TEXT,
                    updated_at TEXT
                )
            """)
            self.db_manager.master_con.commit()
            
            # Sprawdź czy rekord istnieje
            cursor = self.db_manager.master_con.execute("""
                SELECT value FROM settings WHERE key = 'backup_on_release'
            """)
            row = cursor.fetchone()
            
            if row:
                # Aktualizuj istniejący rekord
                self.db_manager.master_con.execute("""
                    UPDATE settings 
                    SET value = ?, updated_at = ?
                    WHERE key = 'backup_on_release'
                """, (str(int(enabled)), datetime.now().isoformat()))
            else:
                # Wstaw nowy rekord
                self.db_manager.master_con.execute("""
                    INSERT INTO settings (key, value, updated_at)
                    VALUES ('backup_on_release', ?, ?)
                """, (str(int(enabled)), datetime.now().isoformat()))
            
            self.db_manager.master_con.commit()
            
            print(f"✅ Zapisano ustawienie backup_on_release = {int(enabled)}")
            
            messagebox.showinfo(
                "Ustawienia backupu",
                f"Backup przy zwalnianiu locka: {status}\n\n"
                f"{'✅ Każde zwolnienie locka utworzy backup projektu' if enabled else '❌ Backup tylko codzienny (przy starcie aplikacji)'}\n\n"
                f"⚠️ Ustawienie zapisane w centralnej bazie - działa na wszystkich komputerach."
            )
        except Exception as e:
            messagebox.showerror("Błąd", f"Nie udało się zapisać ustawienia:\n{e}")
            print(f"❌ Błąd zapisu settings: {e}")
            import traceback
            traceback.print_exc()
    
    def backups_view_dialog(self):
        """Dialog podglądu backupów"""
        win = tk.Toplevel(self)
        win.title("📋 Podgląd backupów")
        win.geometry("1000x650")
        win.transient(self)
        
        # Wycentruj
        win.update_idletasks()
        x = self.winfo_x() + (self.winfo_width() // 2) - (win.winfo_width() // 2)
        y = self.winfo_y() + (self.winfo_height() // 2) - (win.winfo_height() // 2)
        win.geometry(f"+{x}+{y}")
        
        # Główny frame
        main_frame = tk.Frame(win, bg="#f0f0f0", padx=15, pady=15)
        main_frame.pack(fill=tk.BOTH, expand=True)
        
        # Wybór typu backupu
        top_frame = tk.Frame(main_frame, bg="#f0f0f0")
        top_frame.pack(fill=tk.X, pady=(0, 10))
        
        tk.Label(top_frame, text="Typ backupu:", bg="#f0f0f0", font=("Arial", 10, "bold")).pack(side=tk.LEFT, padx=(0, 10))
        
        backup_type_var = tk.StringVar(value="master")
        tk.Radiobutton(top_frame, text="🗄️ Baza główna (Master)", variable=backup_type_var, value="master",
                      bg="#f0f0f0", font=("Arial", 10), command=lambda: load_backups()).pack(side=tk.LEFT, padx=10)
        tk.Radiobutton(top_frame, text="📁 Projekty", variable=backup_type_var, value="projects",
                      bg="#f0f0f0", font=("Arial", 10), command=lambda: load_backups()).pack(side=tk.LEFT, padx=10)
        
        # Wybór projektu (jeśli typ=projects)
        project_frame = tk.Frame(main_frame, bg="#f0f0f0")
        project_frame.pack(fill=tk.X, pady=(0, 10))
        
        tk.Label(project_frame, text="Projekt:", bg="#f0f0f0", font=("Arial", 10)).pack(side=tk.LEFT, padx=(0, 10))
        
        project_combo = ttk.Combobox(project_frame, state="readonly", width=40, font=("Arial", 10))
        project_combo.pack(side=tk.LEFT, padx=5)
        
        # Lista backupów
        list_frame = tk.Frame(main_frame, bg="white", relief=tk.SUNKEN, bd=1)
        list_frame.pack(fill=tk.BOTH, expand=True, pady=(0, 10))
        
        # Treeview
        columns = ("Data", "Rozmiar", "Typ")
        tree = ttk.Treeview(list_frame, columns=columns, show="headings", height=15)
        tree.heading("Data", text="Data backupu")
        tree.heading("Rozmiar", text="Rozmiar (MB)")
        tree.heading("Typ", text="Typ")
        
        tree.column("Data", width=200)
        tree.column("Rozmiar", width=120)
        tree.column("Typ", width=150)
        
        scrollbar = ttk.Scrollbar(list_frame, orient=tk.VERTICAL, command=tree.yview)
        tree.configure(yscrollcommand=scrollbar.set)
        
        tree.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        scrollbar.pack(side=tk.RIGHT, fill=tk.Y)
        
        # Panel podglądu
        preview_frame = tk.LabelFrame(main_frame, text="Podgląd zawartości", bg="#f0f0f0", font=("Arial", 10, "bold"))
        preview_frame.pack(fill=tk.BOTH, pady=(0, 10))
        
        preview_text = tk.Text(preview_frame, height=8, bg="white", font=("Courier", 9), wrap=tk.WORD)
        preview_text.pack(fill=tk.BOTH, expand=True, padx=5, pady=5)
        
        # Cache backupów
        backups_cache = {}
        
        def load_projects_list():
            """Załaduj listę projektów do combobox"""
            try:
                projects = fetch_projects(self.db_manager.master_con)
                # fetch_projects zwraca krotki: (id, name, path) lub (id, name, path, active)
                project_combo['values'] = [f"{p[0]}: {p[1]}" for p in projects]
                if projects:
                    project_combo.current(0)
            except Exception as e:
                print(f"⚠️  Błąd ładowania projektów: {e}")
        
        def load_backups():
            """Załaduj listę backupów"""
            tree.delete(*tree.get_children())
            preview_text.delete("1.0", tk.END)
            backups_cache.clear()
            
            backup_type = backup_type_var.get()
            
            try:
                if backup_type == "master":
                    project_frame.pack_forget()
                    backups = self.backup_manager.list_master_backups()
                    
                    for b in backups:
                        tree.insert("", tk.END, values=(
                            b['date'],
                            f"{b['size_mb']:.2f}",
                            "Master DB"
                        ))
                        backups_cache[b['date']] = b
                
                else:  # projects
                    project_frame.pack(fill=tk.X, pady=(0, 10))
                    
                    # Pobierz wybrane ID projektu
                    sel = project_combo.get()
                    if not sel:
                        return
                    
                    project_id = int(sel.split(':')[0])
                    backups = self.backup_manager.list_project_backups(project_id)
                    
                    for b in backups:
                        tree.insert("", tk.END, values=(
                            b['date'],
                            f"{b['size_mb']:.2f}",
                            f"Projekt {project_id}"
                        ))
                        backups_cache[b['date']] = b
            
            except Exception as e:
                messagebox.showerror("Błąd", f"Nie udało się załadować backupów:\n{e}")
        
        def on_backup_selected(event):
            """Podgląd backupu"""
            sel = tree.selection()
            if not sel:
                return
            
            item = tree.item(sel[0])
            date = item['values'][0]
            
            if date not in backups_cache:
                return
            
            backup_info = backups_cache[date]
            
            try:
                preview_data = self.backup_manager.get_backup_preview_data(
                    backup_info['path'],
                    backup_info['type']
                )
                
                # Wyświetl podgląd
                preview_text.delete("1.0", tk.END)
                preview_text.insert("1.0", f"📁 Plik: {preview_data['file']}\n")
                preview_text.insert(tk.END, f"📏 Rozmiar: {preview_data['size_mb']:.2f} MB\n")
                preview_text.insert(tk.END, f"🕐 Zmodyfikowano: {preview_data['modified'][:19]}\n\n")
                
                if backup_info['type'] == 'master':
                    preview_text.insert(tk.END, f"📊 Statystyki:\n")
                    preview_text.insert(tk.END, f"  • Projektów: {preview_data['projects_count']}\n")
                    preview_text.insert(tk.END, f"  • Użytkowników: {preview_data['users_count']}\n")
                    preview_text.insert(tk.END, f"  • Dostawców: {preview_data['suppliers_count']}\n\n")
                    
                    if preview_data['projects']:
                        preview_text.insert(tk.END, "📋 Lista projektów:\n")
                        for p in preview_data['projects'][:10]:
                            status = "✅" if p['active'] else "❌"
                            preview_text.insert(tk.END, f"  {status} #{p['id']}: {p['name']}\n")
                
                elif backup_info['type'] == 'project':
                    preview_text.insert(tk.END, f"📊 Statystyki:\n")
                    preview_text.insert(tk.END, f"  • Items: {preview_data['items_count']}\n\n")
                    
                    if preview_data['items_sample']:
                        preview_text.insert(tk.END, "📋 Próbka items (10 pierwszych):\n")
                        for item in preview_data['items_sample']:
                            preview_text.insert(tk.END, f"  • {item['drawing_no'] or '???'}: {item['name'] or 'bez nazwy'} (qty: {item['qty'] or 0})\n")
            
            except Exception as e:
                preview_text.delete("1.0", tk.END)
                preview_text.insert("1.0", f"❌ Błąd podglądu: {e}")
        
        tree.bind("<<TreeviewSelect>>", on_backup_selected)
        project_combo.bind("<<ComboboxSelected>>", lambda e: load_backups())
        
        # Przyciski
        btn_frame = tk.Frame(main_frame, bg="#ecf0f1", height=50)
        btn_frame.pack(fill=tk.X)
        btn_frame.pack_propagate(False)
        
        btn_inner = tk.Frame(btn_frame, bg="#ecf0f1")
        btn_inner.pack(pady=10)
        
        tk.Button(btn_inner, text="🔄 Odśwież", command=load_backups, width=15,
                 bg="#16a085", fg="white", font=("Arial", 10)).pack(side=tk.LEFT, padx=5)
        
        if self.current_user_role == "ADMIN":
            def restore_selected():
                """Przywróć wybrany backup"""
                sel = tree.selection()
                if not sel:
                    messagebox.showwarning("Brak wyboru", "Zaznacz backup do przywrócenia!")
                    return
                
                item = tree.item(sel[0])
                date = item['values'][0]
                backup_info = backups_cache.get(date)
                
                if not backup_info:
                    return
                
                # Potwierdź
                if not messagebox.askyesno(
                    "⚠️ Potwierdź przywracanie",
                    f"Czy na pewno przywrócić backup z {date}?\n\n"
                    "⚠️ Bieżąca baza zostanie nadpisana!\n"
                    "(Zostanie utworzony backup awaryjny przed nadpisaniem)",
                    icon='warning'
                ):
                    return
                
                try:
                    if backup_info['type'] == 'master':
                        self.backup_manager.restore_master(date)
                    
                    elif backup_info['type'] == 'project':
                        self.backup_manager.restore_project(backup_info['project_id'], date)
                        self.refresh_data()
                
                except Exception as e:
                    messagebox.showerror("Błąd", f"Nie udało się przywrócić backupu:\n{e}")
            
            tk.Button(btn_inner, text="🔄 Przywróć wybrany", command=restore_selected, width=18,
                     bg="#e74c3c", fg="white", font=("Arial", 10, "bold")).pack(side=tk.LEFT, padx=5)
        
        tk.Button(btn_inner, text="✖ Zamknij", command=win.destroy, width=15,
                 bg="#95a5a6", fg="white", font=("Arial", 10)).pack(side=tk.LEFT, padx=5)
        
        # Początkowe załadowanie
        load_projects_list()
        load_backups()
    
    def backups_restore_dialog(self):
        """Dialog przywracania backupów (tylko ADMIN)"""
        # Dla uproszczenia - użyj backups_view_dialog z przyciskiem przywracania
        self.backups_view_dialog()
    
    # ========================================================================
    # KONIEC MODUŁU BACKUPÓW
    # ========================================================================


    # ========================================================================
    # MODUŁ ZARZĄDZANIA PROJEKTAMI
    # ========================================================================
    
    # === Menu handlers dla maszyn ===
    def menu_add_project_machine(self):
        """Menu: Dodaj maszynę…"""
        self.add_project_dialog(project_type="MACHINE")
    
    def menu_list_projects_machine(self):
        """Menu: Lista maszyn…"""
        self.projects_list_dialog(project_type="MACHINE")
    
    # === Menu handlers dla magazynów ===
    def menu_add_project_warehouse(self):
        """Menu: Dodaj magazyn…"""
        self.add_project_dialog(project_type="WAREHOUSE")
    
    def menu_list_projects_warehouse(self):
        """Menu: Lista magazynów…"""
        self.projects_list_dialog(project_type="WAREHOUSE")
    
    def add_project_dialog(self, project_type="MACHINE", on_created=None):
        """Dialog dodawania nowego projektu
        
        Args:
            project_type: 'MACHINE' lub 'WAREHOUSE'
            on_created: opcjonalny callback wywoływany po pomyślnym utworzeniu projektu
        """
        # Uprawnienia zależne od typu projektu:
        # MACHINE: ADMIN, USER$$
        # WAREHOUSE: ADMIN, USER$
        if project_type == "MACHINE":
            allowed_roles = ("ADMIN", "USER$$")
            error_msg = "Tworzenie maszyn jest dostępne tylko dla ADMIN i USER$$."
        else:  # WAREHOUSE
            allowed_roles = ("ADMIN", "USER$", "USER$$")
            error_msg = "Tworzenie magazynów jest dostępne tylko dla ADMIN, USER$$ i USER$."
        
        if self.current_user_role not in allowed_roles:
            messagebox.showinfo("Brak uprawnień", error_msg)
            return
        
        win = tk.Toplevel(self)
        title = "➕ Nowa maszyna" if project_type == "MACHINE" else "➕ Nowy magazyn"
        win.title(title)
        win.geometry("600x270")
        win.resizable(False, False)
        win.transient(self)
        win.grab_set()
        
        # Wycentruj względem głównego okna
        win.update_idletasks()
        x = self.winfo_x() + (self.winfo_width() // 2) - (win.winfo_width() // 2)
        y = self.winfo_y() + (self.winfo_height() // 2) - (win.winfo_height() // 2)
        win.geometry(f"+{x}+{y}")
        
        frm = tk.Frame(win, padx=25, pady=20, bg="#f0f0f0")
        frm.pack(fill="both", expand=True)
        
        # Nazwa projektu
        label_text = "Nazwa maszyny:" if project_type == "MACHINE" else "Nazwa magazynu:"
        tk.Label(frm, text=label_text, font=("Arial", 10, "bold"), bg="#f0f0f0").grid(
            row=0, column=0, sticky="e", pady=(0, 12), padx=(0, 10)
        )
        var_name = tk.StringVar()
        ent_name = tk.Entry(frm, textvariable=var_name, width=45, font=("Arial", 10))
        ent_name.grid(row=0, column=1, columnspan=2, sticky="ew", pady=(0, 12))
        
        # Ścieżka (opcjonalnie)
        tk.Label(frm, text="Ścieżka (opcjonalnie):", font=("Arial", 10), bg="#f0f0f0").grid(
            row=1, column=0, sticky="e", pady=(0, 12), padx=(0, 10)
        )
        var_path = tk.StringVar()
        ent_path = tk.Entry(frm, textvariable=var_path, width=38, font=("Arial", 10))
        ent_path.grid(row=1, column=1, sticky="ew", pady=(0, 12))
        
        def browse():
            from tkinter import filedialog
            d = filedialog.askdirectory(title="Wybierz katalog projektu")
            if d:
                var_path.set(d)
        
        tk.Button(
            frm, text="📁", command=browse, width=3, font=("Arial", 9)
        ).grid(row=1, column=2, padx=(5, 0), pady=(0, 12))
        
        # Konstruktor (opcjonalnie)
        tk.Label(frm, text="Konstruktor:", font=("Arial", 10), bg="#f0f0f0").grid(
            row=2, column=0, sticky="e", pady=(0, 12), padx=(0, 10)
        )
        var_designer = tk.StringVar()
        ent_designer = tk.Entry(frm, textvariable=var_designer, width=45, font=("Arial", 10))
        ent_designer.grid(row=2, column=1, columnspan=2, sticky="ew", pady=(0, 12))
        
        # Przyciski
        btn_frame = tk.Frame(frm, bg="#f0f0f0")
        btn_frame.grid(row=3, column=0, columnspan=3, pady=(10, 0))
        
        def ok():
            name = var_name.get().strip()
            path = var_path.get().strip()
            designer = var_designer.get().strip()
            
            if not name:
                label = "maszyny" if project_type == "MACHINE" else "magazynu"
                messagebox.showwarning("Błąd", f"Podaj nazwę {label}!", parent=win)
                return
            
            try:
                # Debugowanie - sprawdź czy połączenie jest READ-WRITE
                print(f"\n➕ Tworzenie projektu ({project_type}): {name}")
                try:
                    cur = self.db_manager.master_con.execute("PRAGMA query_only")
                    is_readonly = cur.fetchone()[0]
                    print(f"   PRAGMA query_only = {is_readonly} ({'READ-ONLY' if is_readonly else 'READ-WRITE'})")
                    if is_readonly:
                        print("   🔄 Master jest READ-ONLY, przełączam na READ-WRITE...")
                        self.db_manager.reconnect_master_rw()
                except Exception as pragma_err:
                    print(f"   ⚠️  Błąd sprawdzania PRAGMA: {pragma_err}")
                    self.db_manager.reconnect_master_rw()
                
                # Utwórz projekt w master.sqlite
                pid_new = create_project(
                    self.db_manager.master_con, 
                    name=name, 
                    root_path=path or None,
                    project_type=project_type,
                    designer=designer or None,
                    status='PROJEKT'  # Stara kolumna (backward compatibility)
                )
                
                # Ustaw domyślny status w nowym systemie (PRZYJETY)
                set_project_statuses(
                    self.db_manager.master_con,
                    pid_new,
                    ["PRZYJETY"],  # Domyślny status dla nowego projektu
                    set_by=self.current_user
                )
                
                self.db_manager.master_con.commit()
                print(f"   ✅ Projekt {pid_new} ({project_type}) utworzony i zatwierdzony")
                print(f"      Status: PRZYJETY (domyślny)")
                if designer:
                    print(f"      Konstruktor: {designer}")
                
                # Utwórz pusty plik bazy projektu
                base_dir = self.db_manager.projects_mag_dir if project_type == "WAREHOUSE" else self.db_manager.projects_dir
                project_db_path = get_project_db_path(base_dir, pid_new, project_type)
                project_db_path.parent.mkdir(parents=True, exist_ok=True)
                
                # Użyj DatabaseManager do utworzenia struktury
                temp_con = _open_baza_connection(project_db_path, row_factory=False, timeout=30.0)
                # PEŁNA struktura items (63 kolumny) - skopiowana z działającej project_1.sqlite
                temp_con.execute("""
                    CREATE TABLE IF NOT EXISTS items (
                        id INTEGER PRIMARY KEY AUTOINCREMENT,
                        project_id INTEGER,
                        source TEXT,
                        src_doc TEXT,
                        src_row INTEGER,
                        src_uid TEXT,
                        src_pos TEXT,
                        src_drawing_no TEXT,
                        src_name TEXT,
                        src_desc TEXT,
                        src_qty INTEGER,
                        src_material_text TEXT,
                        src_supplier_text TEXT,
                        norm_drawing_no TEXT,
                        norm_name_key TEXT,
                        work_drawing_no TEXT,
                        work_name TEXT,
                        work_desc TEXT,
                        work_qty REAL,
                        order_qty REAL,
                        delivered_qty REAL,
                        delivered_updated_at TEXT,
                        supplier_id INTEGER,
                        drawing_over INTEGER,
                        name_over INTEGER,
                        desc_over INTEGER,
                        order_qty_over INTEGER,
                        supplier_over INTEGER,
                        mat_over INTEGER,
                        class_auto TEXT,
                        class_manual TEXT,
                        class_effective TEXT,
                        mat_auto_text TEXT,
                        mat_manual_text TEXT,
                        mat_effective_text TEXT,
                        mat_grade TEXT,
                        thickness_mm REAL,
                        thickness_src TEXT,
                        has_dxf INTEGER,
                        has_dwf INTEGER,
                        has_idw INTEGER,
                        has_stp INTEGER,
                        has_stl INTEGER,
                        alarm_date TEXT,
                        alarm_offset INTEGER,
                        alarm_unit TEXT,
                        deadline_date TEXT,
                        ordered_at TEXT,
                        ordered_flag INTEGER,
                        price_pln REAL,
                        status TEXT,
                        notes TEXT,
                        is_manual INTEGER,
                        dwf_biblioteka INTEGER,
                        is_hidden INTEGER,
                        min_qty REAL,
                        rank INTEGER,
                        created_at TEXT,
                        updated_at TEXT,
                        sync_error TEXT,
                        sync_hash TEXT,
                        sync_last_at TEXT,
                        sync_status TEXT
                    )
                """)
                temp_con.commit()
                temp_con.close()
                
                print(f"✅ Utworzono projekt #{pid_new}: {name}")
                print(f"   Plik: {project_db_path}")
                
                # Zamknij dialog
                win.destroy()
                
                # Odśwież listę projektów
                self.load_projects()
                
                # Wywołaj callback (np. odświeżenie listy projektów w dialogu)
                if on_created:
                    try:
                        on_created()
                    except Exception as cb_err:
                        print(f"⚠️  Błąd callback on_created: {cb_err}")
                
                # Ustaw nowy projekt jako aktywny i załaduj dane
                try:
                    # Znajdź indeks nowego projektu w odświeżonej liście
                    print(f"🔍 Szukam projektu #{pid_new} w liście...")
                    for i, (pid, pname) in enumerate(self.projects_list):
                        if pid == pid_new:
                            print(f"✅ Znaleziono projekt #{pid} na pozycji {i}: {pname}")
                            # Ustaw w combobox
                            self.project_combo.current(i)
                            print(f"📋 Ustawiono combobox na indeks {i}")
                            
                            # WAŻNE: Dla nowego projektu automatycznie przejmij lock
                            # aby umożliwić import BOM (wymaga zapisu)
                            print(f"🔒 Automatyczne przejęcie locka dla nowego projektu...")
                            
                            # Wywołaj on_project_selected (otworzy projekt read-only)
                            self.on_project_selected()
                            
                            # Następnie od razu przejmij lock (otworzy read-write)
                            try:
                                self.acquire_lock()
                                print(f"✅ Lock przejęty - projekt gotowy do edycji!")
                            except Exception as lock_err:
                                print(f"⚠️  Nie udało się przejąć locka: {lock_err}")
                                messagebox.showwarning(
                                    "Brak locka",
                                    f"Projekt został utworzony, ale nie udało się przejąć locka.\n\n"
                                    f"Przejmij lock ręcznie aby móc importować dane.\n\n"
                                    f"Błąd: {lock_err}"
                                )
                            
                            break
                    else:
                        print(f"❌ Nie znaleziono projektu #{pid_new} w liście!")
                        print(f"   Lista projektów: {self.projects_list}")
                except Exception as e:
                    print(f"⚠️  Nie udało się ustawić nowego projektu: {e}")
                    import traceback
                    traceback.print_exc()
            
            except Exception as e:
                try:
                    self.db_manager.master_con.rollback()
                except:
                    pass
                messagebox.showerror("Błąd", f"Nie udało się utworzyć projektu:\n{e}", parent=win)
        
        tk.Button(
            btn_frame, text="✔ Utwórz", command=ok, width=12,
            bg="#27ae60", fg="white", font=("Arial", 10, "bold")
        ).pack(side=tk.LEFT, padx=8)
        
        tk.Button(
            btn_frame, text="✖ Anuluj", command=win.destroy, width=12,
            bg="#95a5a6", fg="white", font=("Arial", 10)
        ).pack(side=tk.LEFT, padx=8)
        
        frm.columnconfigure(1, weight=1)
        ent_name.focus_set()
        
        # Bind klawiszy
        ent_name.bind("<Return>", lambda e: ent_path.focus())
        ent_path.bind("<Return>", lambda e: ok())
        win.bind("<Escape>", lambda e: win.destroy())
    
    def projects_list_dialog(self, project_type="MACHINE"):
        """Lista projektów z możliwością edycji"""
        
        # Sprawdź/dodaj kolumny statystyk jeśli jeszcze nie istnieją
        try:
            if not self.db_manager.ensure_stats_columns_exist():
                print(f"⚠️  Kolumny statystyk nie zostały dodane - lista projektów może nie wyświetlać wszystkich danych")
        except Exception as e:
            print(f"⚠️  Błąd sprawdzania kolumn statystyk: {e}")
        
        win = tk.Toplevel(self)
        title = "📋 Lista maszyn" if project_type == "MACHINE" else "📋 Lista magazynów"
        win.title(title)
        win.geometry("1600x550")  # Szerokość zwiększona dla kolumn z datami
        win.resizable(True, True)
        win.transient(self)
        
        # Wycentruj względem głównego okna
        win.update_idletasks()
        x = self.winfo_x() + (self.winfo_width() // 2) - (win.winfo_width() // 2)
        y = self.winfo_y() + (self.winfo_height() // 2) - (win.winfo_height() // 2)
        win.geometry(f"+{x}+{y}")
        
        # Checkbox: Pokaż nieaktywne
        var_show_inactive = tk.BooleanVar(value=False)
        
        # Frame dla Treeview
        tree_frame = tk.Frame(win)
        tree_frame.pack(fill="both", expand=True, padx=10, pady=10)
        
        # Scrollbary
        vsb = tk.Scrollbar(tree_frame, orient="vertical")
        vsb.pack(side=tk.RIGHT, fill=tk.Y)
        
        hsb = tk.Scrollbar(tree_frame, orient="horizontal")
        hsb.pack(side=tk.BOTTOM, fill=tk.X)
        
        # Treeview
        cols = ("id", "active", "name", "designer", "status", "created", "montaz", "fat", "completed", "locked", "path", "db_file")
        tree = ttk.Treeview(
            tree_frame, 
            columns=cols, 
            show="headings",
            yscrollcommand=vsb.set,
            xscrollcommand=hsb.set
        )
        
        tree.heading("id", text="ID")
        tree.heading("active", text="Aktywny")
        tree.heading("name", text="Nazwa")
        tree.heading("designer", text="Konstruktor")
