        def reload():
            """Przeładuj listę projektów"""
            for iid in tree.get_children():
                tree.delete(iid)
            
            try:
                from project_manager import colnames, pick_col
                
                # Sprawdź jakie kolumny istnieją w tabeli projects
                cols = colnames(self.db_manager.master_con, "projects")
                
                # Znajdź nazwy kolumn (obsługa różnych nazw)
                pk = pick_col(cols, ["id", "project_id"])
                name_col = pick_col(cols, ["name", "project_name"])
                path_col = pick_col(cols, ["root_path", "path"])
                active_col = pick_col(cols, ["is_active", "active", "enabled"])
                type_col = pick_col(cols, ["project_type", "type"])
                designer_col = pick_col(cols, ["designer", "designers"])
                status_col = pick_col(cols, ["status"])
                created_col = pick_col(cols, ["created_at"])
                montaz_col = pick_col(cols, ["montaz", "sat"])  # Kompatybilność wsteczna - sprawdź obie nazwy
                fat_col = pick_col(cols, ["fat"])
                completed_col = pick_col(cols, ["completed_at"])
                received_percent_col = pick_col(cols, ["received_percent"])  # % odebranych (dla RM_MANAGER)
                
                # Buduj SELECT dynamicznie
                select_cols = [pk, name_col, path_col, active_col, type_col]
                if designer_col:
                    select_cols.append(designer_col)
                if status_col:
                    select_cols.append(status_col)
                if created_col:
                    select_cols.append(created_col)
                if montaz_col:
                    select_cols.append(montaz_col)
                if fat_col:
                    select_cols.append(fat_col)
                if completed_col:
                    select_cols.append(completed_col)
                if received_percent_col:
                    select_cols.append(received_percent_col)
                
                # WHERE clause
                where_clause = ""
                if not var_show_inactive.get():
                    where_clause = f"WHERE COALESCE({active_col}, 1) = 1"
                if project_type:
                    if where_clause:
                        where_clause += f" AND {type_col} = '{project_type}'"
                    else:
                        where_clause = f"WHERE {type_col} = '{project_type}'"
                
                sql = f"""
                    SELECT {', '.join(select_cols)}
                    FROM projects
                    {where_clause}
                """
                rows = self.db_manager.master_con.execute(sql).fetchall()
                
                # Sortuj w Pythonie - cyfry malejąco, potem litery A-Z (z numerami malejąco)
                def sort_key_projects(row):
                    # row[1] = name
                    name = (row[1] or "").lower()
                    
                    # Sprawdź czy zaczyna się od cyfry
                    if name and name[0].isdigit():
                        # Wyciągnij początkowy numer
                        import re
                        match = re.match(r'^(\d+)', name)
                        if match:
                            num = int(match.group(1))
                            # Zwróć (0, -num) - cyfry na początku malejąco
                            return (0, -num, name)
                    
                    # Zaczyna się od litery
                    import re
                    # Wyciągnij część literową i ewentualny numer
                    match = re.match(r'^([a-z]+)(\d+)?', name)
                    if match:
                        letter_part = match.group(1)  # np. "zp", "fh"
                        num_part = match.group(2)      # np. "163", "01"
                        
                        if num_part:
                            # Ma numer - sortuj alfabetycznie A-Z, potem numery malejąco
                            return (1, letter_part, -int(num_part), name)
                        else:
                            # Brak numeru - sortuj po nazwie A-Z
                            return (1, letter_part, 0, name)
                    
                    # Fallback - alfabetycznie
                    return (1, name, 0, "")
                
                rows = sorted(rows, key=sort_key_projects)
                
                for row in rows:
                    idx = 0
                    pid = row[idx]
                    idx += 1
                    name = row[idx] or ""
                    idx += 1
                    pth = row[idx] or ""
                    idx += 1
                    is_act = row[idx]
                    idx += 1
                    ptype = row[idx] or "MACHINE"
                    idx += 1
                    
                    # Pobierz designer jeśli kolumna istnieje
                    designer = ""
                    if designer_col and len(row) > idx:
                        designer = row[idx] or ""
                        idx += 1
                    
                    # STATUS: Czytaj bezpośrednio z kolumny projects.status (TEXT z RM_MANAGER)
                    status = ""
                    if status_col and len(row) > idx:
                        status = row[idx] or ""
                        idx += 1
                    
                    # Pobierz daty
                    created_at = ""
                    if created_col and len(row) > idx:
                        created_at = row[idx] or ""
                        # Format daty: YYYY-MM-DD HH:MM:SS -> DD-MM-YYYY
                        if created_at and len(created_at) >= 10:
                            try:
                                parts = created_at[:10].split('-')
                                if len(parts) == 3:
                                    created_at = f"{parts[2]}-{parts[1]}-{parts[0]}"
                            except:
                                created_at = created_at[:10]
                        idx += 1
                    
                    montaz_date = ""
                    if montaz_col and len(row) > idx:
                        montaz_date = row[idx] or ""
                        # Format daty: YYYY-MM-DD HH:MM:SS -> DD-MM-YYYY
                        if montaz_date and len(montaz_date) >= 10:
                            try:
                                parts = montaz_date[:10].split('-')
                                if len(parts) == 3:
                                    montaz_date = f"{parts[2]}-{parts[1]}-{parts[0]}"
                            except:
                                montaz_date = montaz_date[:10]
                        idx += 1
                    
                    fat = ""
                    if fat_col and len(row) > idx:
                        fat = row[idx] or ""
                        # Format daty: YYYY-MM-DD HH:MM:SS -> DD-MM-YYYY
                        if fat and len(fat) >= 10:
                            try:
                                parts = fat[:10].split('-')
                                if len(parts) == 3:
                                    fat = f"{parts[2]}-{parts[1]}-{parts[0]}"
                            except:
                                fat = fat[:10]
                        idx += 1
                    
                    completed_at = ""
                    if completed_col and len(row) > idx:
                        completed_at = row[idx] or ""
                        # Format daty: YYYY-MM-DD HH:MM:SS -> DD-MM-YYYY
                        if completed_at and len(completed_at) >= 10:
                            try:
                                parts = completed_at[:10].split('-')
                                if len(parts) == 3:
                                    completed_at = f"{parts[2]}-{parts[1]}-{parts[0]}"
                            except:
                                completed_at = completed_at[:10]
                        idx += 1
                    
                    base_dir = self.db_manager.projects_mag_dir if ptype == "WAREHOUSE" else self.db_manager.projects_dir
                    db_file = get_project_db_path(base_dir, pid, ptype).name
                    
                    # Sprawdź czy projekt jest zlockowany
                    lock_info = self.lock_manager.get_project_lock_owner(pid)
                    if lock_info:
                        username = lock_info.get('user', '')  # LOGIN
                        locked_by = self._get_user_display_name(username)  # NAZWA
                    else:
                        locked_by = ""
                    
                    tree.insert(
                        "", "end",
                        values=(pid, "TAK" if is_act else "NIE", name, designer, status, created_at, montaz_date, fat, completed_at, locked_by, pth, db_file),
                        tags=(() if is_act else ("inactive",))
                    )
            
            except Exception as e:
                import traceback
                print(f"❌ Błąd reload projektów: {e}")
                traceback.print_exc()
                messagebox.showerror("Błąd", f"Nie udało się pobrać projektów:\n{e}", parent=win)
        
        def get_selected():
            """Pobierz zaznaczony projekt"""
            sel = tree.selection()
            if not sel:
                return None
            vals = tree.item(sel[0], "values")
            try:
                # Kolumny: id, active, name, designer, status, created, montaz, fat, completed, locked, path, db_file
                return {
                    "id": int(vals[0]),
                    "active": vals[1] == "TAK",
                    "name": str(vals[2] or ""),
                    "designer": str(vals[3] or ""),
                    "status": str(vals[4] or "W_REALIZACJI"),
                    "created_at": str(vals[5] or ""),
                    "montaz": str(vals[6] or ""),
                    "fat": str(vals[7] or ""),
                    "completed_at": str(vals[8] or ""),
                    "path": str(vals[10] or "")
                }
            except Exception:
                return None
        
        def edit_selected():
            """Edytuj zaznaczony projekt"""
            proj = get_selected()
            if not proj:
                messagebox.showwarning("Brak wyboru", "Zaznacz projekt do edycji!", parent=win)
                return
            
            # Pobierz pełne dane projektu z bazy (designer, status, montaz, fat, completed_at)
            try:
                from project_manager import colnames, pick_col
                
                # Sprawdź jakie kolumny istnieją
                cols = colnames(self.db_manager.master_con, "projects")
                pk = pick_col(cols, ["id", "project_id"])
                designer_col = pick_col(cols, ["designer", "designers"])
                status_col = pick_col(cols, ["status"])
                montaz_col = pick_col(cols, ["montaz", "sat"])  # Kompatybilność wsteczna
                fat_col = pick_col(cols, ["fat"])
                completed_col = pick_col(cols, ["completed_at"])
                received_percent_col = pick_col(cols, ["received_percent"])  # % odebranych (dla RM_MANAGER)
                
                # Buduj SELECT dynamicznie
                select_cols = []
                if designer_col:
                    select_cols.append(designer_col)
                if status_col:
                    select_cols.append(status_col)
                if montaz_col:
                    select_cols.append(montaz_col)
                if fat_col:
                    select_cols.append(fat_col)
                if completed_col:
                    select_cols.append(completed_col)
                if received_percent_col:
                    select_cols.append(received_percent_col)
                
                if select_cols:
                    sql = f"""
                        SELECT {', '.join(select_cols)}
                        FROM projects
                        WHERE {pk}=?
                    """
                    cur = self.db_manager.master_con.execute(sql, (proj['id'],))
                    row = cur.fetchone()
                    if row:
                        idx = 0
                        if designer_col:
                            proj['designer'] = row[idx] or ""
                            idx += 1
                        if status_col:
                            proj['status'] = row[idx] or "W_REALIZACJI"
                            idx += 1
                        if montaz_col:
                            proj['montaz'] = row[idx] or ""
                            idx += 1
                        if fat_col:
                            proj['fat'] = row[idx] or ""
                            idx += 1
                        if completed_col:
                            proj['completed_at'] = row[idx] or ""
                            idx += 1
                        if received_percent_col:
                            proj['received_percent'] = row[idx] or ""
                            idx += 1
                else:
                    # Brak nowych kolumn - użyj wartości domyślnych
                    proj['designer'] = proj.get('designer', "")
                    proj['status'] = proj.get('status', "W_REALIZACJI")
                    proj['montaz'] = ""
                    proj['fat'] = ""
                    proj['completed_at'] = ""
                    proj['received_percent'] = ""
                    
            except Exception as e:
                import traceback
                print(f"⚠️  Błąd pobierania danych projektu: {e}")
                traceback.print_exc()
                # Ustaw domyślne wartości
                if 'designer' not in proj:
                    proj['designer'] = ""
                if 'status' not in proj:
                    proj['status'] = "W_REALIZACJI"
                proj['montaz'] = ""
                proj['fat'] = ""
                proj['completed_at'] = ""
            
            # Uprawnienia zależne od typu projektu:
            # MACHINE: ADMIN, USER$$
            # WAREHOUSE: ADMIN, USER$
            if project_type == "MACHINE":
                allowed_roles = ("ADMIN", "USER$$")
                error_msg = "Tylko ADMIN i USER$$ mogą edytować maszyny!"
            else:  # WAREHOUSE
                allowed_roles = ("ADMIN", "USER$")
                error_msg = "Tylko ADMIN i USER$ mogą edytować magazyny!"
            
            if self.current_user_role not in allowed_roles:
                messagebox.showerror("Brak uprawnień", error_msg, parent=win)
                return
            
            # Dialog edycji
            dlg = tk.Toplevel(win)
