            x = win.winfo_x() + (win.winfo_width() // 2) - (dlg.winfo_width() // 2)
            y = win.winfo_y() + (win.winfo_height() // 2) - (dlg.winfo_height() // 2)
            dlg.geometry(f"+{x}+{y}")
            
