    def reload_suppliers(self):
        """Odśwież mapę dostawców z bazy"""
        try:
            # 🔄 Sprawdź żywotność połączenia (bezpiecznie, bez blokowania GUI)
            if not self._safe_ensure_master_alive():
                return
            
            # Dynamiczne wykrywanie kolumn (jak v6)
            cursor = self.db_manager.master_con.execute("SELECT * FROM suppliers LIMIT 0")
            cols = [desc[0] for desc in cursor.description]
            
            # Znajdź kolumnę ID
            id_col = None
            for candidate in ["id", "supplier_id", "sup_id"]:
                if candidate in cols:
                    id_col = candidate
                    break
            
            if not id_col:
                # Użyj pierwszej kolumny
                id_col = cols[0] if cols else "id"
            
            # Znajdź kolumnę NAME
            name_col = None
            for candidate in ["name", "nazwa", "supplier_name", "display_name"]:
                if candidate in cols:
                    name_col = candidate
                    break
            
            if not name_col:
                print("⚠️  Nie znaleziono kolumny nazwy w suppliers!")
                self.suppliers_map = {}
                return
            
            # Znajdź kolumnę ACTIVE
            active_col = None
            for candidate in ["is_active", "active", "enabled"]:
                if candidate in cols:
                    active_col = candidate
                    break
            
            # Pobierz dostawców
            if active_col:
                sql = f"SELECT {id_col}, {name_col} FROM suppliers WHERE {active_col} = 1 ORDER BY {name_col} COLLATE NOCASE"
            else:
                sql = f"SELECT {id_col}, {name_col} FROM suppliers ORDER BY {name_col} COLLATE NOCASE"
            
            # RETRY LOOP - 3 próby z opóźnieniem (sieć + WAL + I/O errors)
            cursor = None
            for attempt in range(3):
                try:
                    # NIE commit'ujemy przed SELECT — to czysty read, a commit na SMB
                    # zajmuje writer-lock i blokuje innych klientów. Jeśli była otwarta
                    # transakcja write, rollback ją zamyka bez I/O.
                    try:
                        if self.db_manager.master_con.in_transaction:
                            self.db_manager.master_con.rollback()
                    except Exception:
                        pass
                    cursor = self.db_manager.master_con.execute(sql)
                    break
                except sqlite3.OperationalError as e:
                    err_msg = str(e).lower()
                    if "locked" in err_msg and attempt < 2:
                        print(f"⚠️  reload_suppliers: database locked (próba {attempt+1}/3), czekam 200ms...")
                        time.sleep(0.2)
                    elif "disk i/o error" in err_msg and attempt < 2:
                        print(f"⚠️  reload_suppliers: disk I/O error (próba {attempt+1}/3), wymuszam reconnect...")
                        # Wymusz reconnect
                        try:
                            self.db_manager.master_con.close()
                        except:
                            pass
                        self.db_manager.master_con = None
                        if self.current_user_role in ("ADMIN", "USER$$", "USER$"):
                            self.db_manager.reconnect_master_rw()
                        else:
                            self.db_manager.connect_master()
                        time.sleep(0.2)
                    else:
                        raise
            
            if cursor is None:
                raise sqlite3.OperationalError("reload_suppliers: nie udało się wykonać SELECT po 3 próbach")
            
            self.suppliers_map = {}
            for row in cursor.fetchall():
                sid, name = row
                self.suppliers_map[sid] = name
            
            # Zaktualizuj wartości w filtrze dostawców
            # 🔍 Filtruj dostawców - pokaż tylko tych, którzy występują w aktualnym projekcie
            try:
                # Pobierz unikalne supplier_id z items dla bieżącego projektu
                project_supplier_ids = set()
                if self.current_project_id and self.db_manager and self.db_manager.project_con:
                    try:
                        # Pobierz unikalne supplier_id z tabeli items dla bieżącego projektu
                        proj_cursor = self.db_manager.project_con.execute(
                            "SELECT DISTINCT supplier_id FROM items WHERE supplier_id IS NOT NULL"
                        )
                        project_supplier_ids = {row[0] for row in proj_cursor.fetchall()}
                    except Exception as proj_e:
                        print(f"⚠️  Nie udało się pobrać dostawców z projektu: {proj_e}")
                        # Przy błędzie - pokaż wszystkich dostawców (fallback)
                        project_supplier_ids = set(self.suppliers_map.keys())
                
                # Jeśli nie ma projektu lub błąd - pokaż wszystkich
                if not project_supplier_ids:
                    project_supplier_ids = set(self.suppliers_map.keys())
                
                # Filtruj listę dostawców - tylko ci z aktualnego projektu
                supplier_filter_values = [FILTER_SUPPLIER_ALL] + [
                    name for sid, name in sorted(self.suppliers_map.items(), key=lambda x: x[1].lower())
                    if sid in project_supplier_ids and name != SUPPLIER_EMPTY
                ]
                self.cmb_filter_supplier['values'] = supplier_filter_values
                
                print(f"✅ Filtr dostawców: {len(supplier_filter_values)-1} z {len(self.suppliers_map)} (projekt: {self.current_project_id})")
            except Exception as e:
                print(f"⚠️  Nie udało się zaktualizować filtra dostawców: {e}")
            
            print(f"✅ Załadowano {len(self.suppliers_map)} dostawców (kolumny: {id_col}, {name_col})")
        
        except Exception as e:
            print(f"⚠️  Błąd ładowania dostawców: {e}")
            import traceback
            traceback.print_exc()
            self.suppliers_map = {}
    
    def add_supplier_dialog(self, refresh_callback=None):
        """Dialog dodawania nowego dostawcy
        
        Args:
            refresh_callback: Opcjonalna funkcja wywoływana po dodaniu (np. load_data z okna listy)
        """
        # Sprawdź uprawnienia
        if self.current_user_role not in ("ADMIN", "USER$$"):
            messagebox.showinfo("Brak uprawnień", "Dodawanie dostawców jest dostępne tylko dla ADMIN i USER$$.")
            return
        
        dlg = tk.Toplevel(self)
        dlg.title("➕ Dodaj podwykonawcę")
        dlg.geometry("500x280")
        dlg.transient(self)
        dlg.grab_set()
        dlg.resizable(False, False)
        
        # Wycentruj względem głównego okna
        dlg.update_idletasks()
        x = self.winfo_x() + (self.winfo_width() // 2) - (dlg.winfo_width() // 2)
        y = self.winfo_y() + (self.winfo_height() // 2) - (dlg.winfo_height() // 2)
        dlg.geometry(f"+{x}+{y}")
        
        main_frame = tk.Frame(dlg, padx=25, pady=20, bg="#f0f0f0")
        main_frame.pack(fill=tk.BOTH, expand=True)
        
        tk.Label(main_frame, text="Nazwa:", bg="#f0f0f0", font=("Arial", 10, "bold")).grid(row=0, column=0, sticky="e", padx=10, pady=8)
        e_name = tk.Entry(main_frame, width=35, font=("Arial", 10))
        e_name.grid(row=0, column=1, padx=10, pady=8, sticky="ew")
        
        tk.Label(main_frame, text="Kontakt:", bg="#f0f0f0", font=("Arial", 10)).grid(row=1, column=0, sticky="e", padx=10, pady=8)
        e_contact = tk.Entry(main_frame, width=35, font=("Arial", 10))
        e_contact.grid(row=1, column=1, padx=10, pady=8, sticky="ew")
        
        tk.Label(main_frame, text="Telefon:", bg="#f0f0f0", font=("Arial", 10)).grid(row=2, column=0, sticky="e", padx=10, pady=8)
        e_phone = tk.Entry(main_frame, width=35, font=("Arial", 10))
        e_phone.grid(row=2, column=1, padx=10, pady=8, sticky="ew")
        
        tk.Label(main_frame, text="Email:", bg="#f0f0f0", font=("Arial", 10)).grid(row=3, column=0, sticky="e", padx=10, pady=8)
        e_email = tk.Entry(main_frame, width=35, font=("Arial", 10))
        e_email.grid(row=3, column=1, padx=10, pady=8, sticky="ew")
        
        tk.Label(main_frame, text="Opis:", bg="#f0f0f0", font=("Arial", 10)).grid(row=4, column=0, sticky="e", padx=10, pady=8)
        e_desc = tk.Entry(main_frame, width=35, font=("Arial", 10))
        e_desc.grid(row=4, column=1, padx=10, pady=8, sticky="ew")
        
        def save():
            name = e_name.get().strip()
            if not name:
                messagebox.showwarning("Błąd", "Podaj nazwę dostawcy!")
                return
            
            contact = e_contact.get().strip() or None
            phone = e_phone.get().strip() or None
            email = e_email.get().strip() or None
            desc = e_desc.get().strip() or None
            
            try:
                # Dynamiczne wykrywanie kolumn
                cursor = self.db_manager.master_con.execute("SELECT * FROM suppliers LIMIT 0")
                cols_db = [desc[0] for desc in cursor.description]
                
                name_col = next((c for c in ["name", "nazwa", "supplier_name"] if c in cols_db), "name")
                contact_col = next((c for c in ["contact", "contact_info"] if c in cols_db), None)
                phone_col = next((c for c in ["phone", "phone_default"] if c in cols_db), None)
                email_col = next((c for c in ["email", "email_default"] if c in cols_db), None)
                desc_col = next((c for c in ["description", "desc", "opis", "note", "notes"] if c in cols_db), None)
                active_col = next((c for c in ["is_active", "active", "enabled"] if c in cols_db), None)
                
                # Sprawdź czy istnieje
                cursor = self.db_manager.master_con.execute(
                    f"SELECT {cols_db[0]} FROM suppliers WHERE {name_col} = ?", (name,))
                if cursor.fetchone():
                    messagebox.showwarning("Błąd", f"Dostawca '{name}' już istnieje!")
                    return
                
                # Buduj INSERT
                insert_cols = [name_col]
                insert_vals = [name]
                
                if contact_col and contact:
                    insert_cols.append(contact_col)
                    insert_vals.append(contact)
                
                if phone_col and phone:
                    insert_cols.append(phone_col)
                    insert_vals.append(phone)
                
                if email_col and email:
                    insert_cols.append(email_col)
                    insert_vals.append(email)
                
                if desc_col and desc:
                    insert_cols.append(desc_col)
                    insert_vals.append(desc)
                
                if active_col:
                    insert_cols.append(active_col)
                    insert_vals.append(1)
                
                placeholders = ", ".join(["?"] * len(insert_vals))
                sql = f"INSERT INTO suppliers ({', '.join(insert_cols)}) VALUES ({placeholders})"
                
                # Upewnij się że master jest w trybie READ-WRITE
                try:
                    cur = self.db_manager.master_con.execute("PRAGMA query_only")
                    if cur.fetchone()[0] == 1:
                        print("🔄 Master jest READ-ONLY, przełączam na READ-WRITE...")
                        self.db_manager.reconnect_master_rw()
                except Exception:
                    self.db_manager.reconnect_master_rw()
                
                self.db_manager.master_con.execute(sql, tuple(insert_vals))
                self.db_manager.master_con.commit()
                
                # Odśwież mapę
                self.reload_suppliers()
                
                # Wywołaj callback jeśli podano (odświeżenie okna listy)
                if refresh_callback:
                    try:
                        refresh_callback()
                    except:
                        pass
                
                # Odśwież okno listy dostawców jeśli jest otwarte
                messagebox.showinfo("Sukces", f"Dodano dostawcę: {name}")
                
                dlg.destroy()
            
            except Exception as e:
                messagebox.showerror("Błąd", f"Nie udało się dodać:\n{e}")
                import traceback
                traceback.print_exc()
        
        btn_frame = tk.Frame(main_frame, bg="#f0f0f0")
        btn_frame.grid(row=5, column=0, columnspan=2, pady=15)
        
        tk.Button(btn_frame, text="✔ Zapisz", command=save, width=12,
                 bg="#27ae60", fg="white", font=("Arial", 10, "bold")).pack(side=tk.LEFT, padx=8)
        tk.Button(btn_frame, text="✖ Anuluj", command=dlg.destroy, width=12,
                 bg="#95a5a6", fg="white", font=("Arial", 10)).pack(side=tk.LEFT, padx=8)
        
        main_frame.columnconfigure(1, weight=1)
        
        # Bind klawiszy
        e_name.bind("<Return>", lambda e: e_contact.focus())
        e_contact.bind("<Return>", lambda e: e_phone.focus())
        e_phone.bind("<Return>", lambda e: e_email.focus())
        e_email.bind("<Return>", lambda e: e_desc.focus())
        e_desc.bind("<Return>", lambda e: save())
        dlg.bind("<Escape>", lambda e: dlg.destroy())
        
        e_name.focus()
    
