    def _set_supplier(self, item_id, supplier_id, supplier_name, row, col):
        """Ustaw dostawcę dla item"""
        try:
            # Pobierz starą wartość dla UNDO
            cursor = self.db_manager.project_con.execute(
                "SELECT supplier_id FROM items WHERE id = ?", (item_id,)
            )
            old_data = cursor.fetchone()
            old_supplier_id = old_data[0] if old_data else None
            
            # Ustaw nową wartość
            self.db_manager.project_con.execute("""
                UPDATE items 
                SET supplier_id = ?, updated_at = ?
                WHERE id = ?
            """, (supplier_id, datetime.now().isoformat(), item_id))
            self.db_manager.project_con.commit()
            
            # Zapisz UNDO do starego systemu (_last_undo_action)
            self._last_undo_action = {
                'type': 'edit_supplier',
                'item_id': item_id,
                'row': row,
                'col': col,
                'old_supplier_id': old_supplier_id,
                'new_supplier_id': supplier_id
            }
            self._last_redo_action = None  # Wyczyść redo
            print(f"💾 UNDO: Zapisano zmianę dostawcy item {item_id}: {old_supplier_id} → {supplier_id}")
            
            # Loguj zmianę do audit trail
            old_name = self.suppliers_map.get(old_supplier_id, "BRAK") if old_supplier_id else None
            new_name = supplier_name if supplier_name else None
            self._log_item_change(item_id, 'EDIT', 'supplier_id', old_name, new_name)
            
            # Ustaw w arkuszu
            self.sheet.set_cell_data(row, col, supplier_name if supplier_name else "")
            
            print(f"✅ Dostawca item {item_id}: {supplier_name if supplier_name else '(brak)'}")

            # Odśwież filtr dostawców w comboboxie (może pojawić się nowy dostawca w projekcie)
            self.load_suppliers()

            # Odśwież kolory zachowując podświetlenie wiersza
            self._rebuild_all_cell_colors_with_selection()
        
        except Exception as e:
            messagebox.showerror("Błąd", f"Nie udało się zapisać:\n{e}")
    
