    def add_user_dialog(self):
        """Dialog dodawania nowego użytkownika"""
        dlg = tk.Toplevel(self)
        dlg.title("Dodaj użytkownika")
        dlg.geometry("500x350")
        dlg.transient(self)
        dlg.grab_set()
        dlg.resizable(False, False)
        
        # Wycentruj względem głównego okna
        dlg.update_idletasks()
        x = self.winfo_x() + (self.winfo_width() // 2) - (dlg.winfo_width() // 2)
        y = self.winfo_y() + (self.winfo_height() // 2) - (dlg.winfo_height() // 2)
        dlg.geometry(f"+{x}+{y}")
        
        # Frame główny z paddingiem
        main_frame = tk.Frame(dlg, padx=25, pady=20, bg="#f0f0f0")
        main_frame.pack(fill=tk.BOTH, expand=True)
        
        tk.Label(main_frame, text="Login (username):", bg="#f0f0f0", font=("Arial", 10)).grid(row=0, column=0, sticky="e", padx=10, pady=8)
        e_username = tk.Entry(main_frame, width=30, font=("Arial", 10))
        e_username.grid(row=0, column=1, padx=10, pady=8, sticky="ew")
        
        tk.Label(main_frame, text="Nazwa wyświetlana:", bg="#f0f0f0", font=("Arial", 10)).grid(row=1, column=0, sticky="e", padx=10, pady=8)
        e_display = tk.Entry(main_frame, width=30, font=("Arial", 10))
        e_display.grid(row=1, column=1, padx=10, pady=8, sticky="ew")
        
        tk.Label(main_frame, text="Hasło:", bg="#f0f0f0", font=("Arial", 10)).grid(row=2, column=0, sticky="e", padx=10, pady=8)
        e_password = tk.Entry(main_frame, width=30, show="*", font=("Arial", 10))
        e_password.grid(row=2, column=1, padx=10, pady=8, sticky="ew")
        
        tk.Label(main_frame, text="Powtórz hasło:", bg="#f0f0f0", font=("Arial", 10)).grid(row=3, column=0, sticky="e", padx=10, pady=8)
        e_password2 = tk.Entry(main_frame, width=30, show="*", font=("Arial", 10))
        e_password2.grid(row=3, column=1, padx=10, pady=8, sticky="ew")
        
        tk.Label(main_frame, text="Rola:", bg="#f0f0f0", font=("Arial", 10)).grid(row=4, column=0, sticky="ne", padx=10, pady=8)
        var_role = tk.StringVar(value="USER")
        role_frame = tk.Frame(main_frame, bg="#f0f0f0")
        role_frame.grid(row=4, column=1, sticky="w", padx=10, pady=8)
        
        # Górny rząd - ADMIN, USER$$, USER$
        top_row = tk.Frame(role_frame, bg="#f0f0f0")
        top_row.pack(fill="x", pady=1)
        tk.Radiobutton(top_row, text="ADMIN", variable=var_role, value="ADMIN", bg="#f0f0f0", font=("Arial", 9)).pack(side=tk.LEFT, padx=3)
        tk.Radiobutton(top_row, text="USER$$", variable=var_role, value="USER$$", bg="#f0f0f0", font=("Arial", 9)).pack(side=tk.LEFT, padx=3)
        tk.Radiobutton(top_row, text="USER$", variable=var_role, value="USER$", bg="#f0f0f0", font=("Arial", 9)).pack(side=tk.LEFT, padx=3)
        
        # Dolny rząd - USER, GUEST
        bottom_row = tk.Frame(role_frame, bg="#f0f0f0")
        bottom_row.pack(fill="x", pady=1)
        tk.Radiobutton(bottom_row, text="USER", variable=var_role, value="USER", bg="#f0f0f0", font=("Arial", 9)).pack(side=tk.LEFT, padx=3)
        tk.Radiobutton(bottom_row, text="GUEST", variable=var_role, value="GUEST", bg="#f0f0f0", font=("Arial", 9)).pack(side=tk.LEFT, padx=3)
        
        def save():
            username = e_username.get().strip()
            if not username:
                messagebox.showwarning("Błąd", "Podaj login użytkownika!")
                return
            
            # WALIDACJA: Nie pozwalaj na same cyfry w username
            if username.isdigit() and len(username) <= 4:
                messagebox.showwarning(
                    "Nieprawidłowy login",
                    f"Login '{username}' składa się tylko z cyfr!\n\n"
                    "To prawdopodobnie pomyłka. Użyj sensownej nazwy użytkownika\n"
                    "(np. 'jan.kowalski', 'admin2', 'user_produkcja')."
                )
                return
            
            display_name = e_display.get().strip() or username
            password = e_password.get()
            password2 = e_password2.get()
            role = var_role.get()
            
            # Walidacja hasła
            if password != password2:
                messagebox.showwarning("Błąd", "Hasła nie są identyczne!")
                return
            
            if len(password) < 4:
                messagebox.showwarning("Błąd", "Hasło musi mieć co najmniej 4 znaki!")
                return
            
            try:
                # Przełącz na tryb RW
                try:
                    self.db_manager.reconnect_master_rw()
                except Exception as rw_err:
                    messagebox.showerror("Błąd połączenia", f"Nie można połączyć się z bazą master w trybie zapisu:\n{rw_err}")
                    return
                
                con = self.db_manager.master_con
                if con is None:
                    messagebox.showerror("Błąd", "Brak połączenia z bazą master po reconnect!")
                    return
                
                # Sprawdź czy username już istnieje
                cursor = con.execute(
                    "SELECT id FROM users WHERE username = ?", (username,))
                if cursor.fetchone():
                    messagebox.showwarning("Błąd", f"Użytkownik '{username}' już istnieje!")
                    return
                
                # Hash hasła
                import hashlib
                password_hash = hashlib.sha256(password.encode()).hexdigest()
                
                # INSERT
                sql = """
                    INSERT INTO users (username, display_name, password_hash, role, is_active, created_at)
                    VALUES (?, ?, ?, ?, 1, datetime('now'))
                """
                con.execute(sql, (username, display_name, password_hash, role))
                con.commit()
                
                # LOG: Dodano użytkownika
                try:
                    new_user_id = con.execute(
                        "SELECT id FROM users WHERE username = ?", (username,)
                    ).fetchone()[0]
                    
                    con.execute("""
                        INSERT INTO user_changes_log 
                        (action, user_id, username, display_name, role, changed_by, timestamp, details)
                        VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                    """, (
                        'ADD',
                        new_user_id, username, display_name, role,
                        self.current_user or 'UNKNOWN',
                        datetime.now().isoformat(),
                        f'Added by {self.current_user or "UNKNOWN"}'
                    ))
                    con.commit()
                except Exception as log_err:
                    print(f"⚠️  Błąd logowania ADD do audytu: {log_err}")
                
                messagebox.showinfo("Sukces", f"Użytkownik '{username}' został dodany pomyślnie!")
                
                # Odśwież dropdown
                self.load_users()
                
                dlg.destroy()
            
            except sqlite3.OperationalError as e:
                # Konkretny błąd "database is locked"
                if "locked" in str(e).lower():
                    messagebox.showerror(
                        "Baza zablokowana",
                        f"Nie można dodać użytkownika - baza danych jest zajęta przez innego klienta.\n\n"
                        f"Szczegóły: {e}\n\n"
                        f"Spróbuj ponownie za chwilę."
                    )
                else:
                    messagebox.showerror("Błąd bazy danych", f"Nie udało się dodać:\n{e}")
                import traceback
                traceback.print_exc()
            
            except Exception as e:
                messagebox.showerror("Błąd", f"Nie udało się dodać:\n{e}")
                import traceback
                traceback.print_exc()
        
        btn_frame = tk.Frame(main_frame, bg="#f0f0f0")
        btn_frame.grid(row=5, column=0, columnspan=2, pady=20)
        
        tk.Button(btn_frame, text="✔ Zapisz", command=save, width=12, 
                 bg="#27ae60", fg="white", font=("Arial", 10, "bold")).pack(side=tk.LEFT, padx=8)
        tk.Button(btn_frame, text="✖ Anuluj", command=dlg.destroy, width=12, 
                 bg="#95a5a6", fg="white", font=("Arial", 10)).pack(side=tk.LEFT, padx=8)
        
        main_frame.columnconfigure(1, weight=1)
        e_username.focus()
        
        # Bind Enter
        e_username.bind("<Return>", lambda e: e_display.focus())
        e_display.bind("<Return>", lambda e: e_password.focus())
        e_password.bind("<Return>", lambda e: e_password2.focus())
        e_password2.bind("<Return>", lambda e: save())
        dlg.bind("<Escape>", lambda e: dlg.destroy())
    
    def users_list_dialog(self):
        """Dialog listy użytkowników z edycją"""
        dlg = tk.Toplevel(self)
        dlg.title("📋 Lista użytkowników")
        dlg.geometry("900x550")
        dlg.transient(self)
        
        # Wycentruj względem głównego okna
        dlg.update_idletasks()
        x = self.winfo_x() + (self.winfo_width() // 2) - (dlg.winfo_width() // 2)
        y = self.winfo_y() + (self.winfo_height() // 2) - (dlg.winfo_height() // 2)
        dlg.geometry(f"+{x}+{y}")
        
        # Treeview
        frame_tree = tk.Frame(dlg)
        frame_tree.pack(fill=tk.BOTH, expand=True, padx=10, pady=10)
        
        cols = ("ID", "Login", "Nazwa", "Rola", "Aktywny")
        tree = ttk.Treeview(frame_tree, columns=cols, show="headings", height=15)
        
        for col in cols:
            tree.heading(col, text=col)
            tree.column(col, width=120)
        
        tree.column("ID", width=50)
        tree.column("Login", width=150)
        tree.column("Nazwa", width=200)
        tree.column("Rola", width=100)
        tree.column("Aktywny", width=80)
        
        scrollbar = ttk.Scrollbar(frame_tree, orient=tk.VERTICAL, command=tree.yview)
        tree.configure(yscroll=scrollbar.set)
        
        tree.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        scrollbar.pack(side=tk.RIGHT, fill=tk.Y)
        
        def load_data():
            tree.delete(*tree.get_children())
            
            # Sprawdź żywotność połączenia master
            if not self.db_manager.ensure_master_alive():
                messagebox.showerror("Błąd połączenia", 
                    "Nie można połączyć się z bazą master.\n"
                    "Sprawdź połączenie sieciowe.")
                return
            
            try:
                sql = "SELECT id, username, display_name, role, is_active FROM users ORDER BY username COLLATE NOCASE"
                cursor = self.db_manager.master_con.execute(sql)
                
                for row in cursor.fetchall():
                    uid, username, display_name, role, active = row
                    active_str = "TAK" if active else "NIE"
                    tree.insert("", tk.END, values=(uid, username or "", display_name or "", role or "", active_str))
            
            except Exception as e:
                messagebox.showerror("Błąd", f"Nie udało się załadować:\n{e}")
                import traceback
                traceback.print_exc()
        
        def edit_selected():
            if self.current_user_role != "ADMIN":
                messagebox.showerror("Brak uprawnień", "Tylko ADMIN może edytować użytkowników!")
                return
            
            sel = tree.selection()
            if not sel:
                messagebox.showwarning("Brak wyboru", "Zaznacz użytkownika do edycji!")
                return
            
            item = tree.item(sel[0])
            values = item['values']
            uid, username, display_name, role, active_str = values
            
            # Dialog edycji
            edit_dlg = tk.Toplevel(dlg)
            edit_dlg.title(f"✏️ Edytuj: {username}")
            edit_dlg.geometry("600x450")
            edit_dlg.transient(dlg)
            edit_dlg.grab_set()
            edit_dlg.resizable(False, False)
            
            # Wycentruj względem listy użytkowników
            edit_dlg.update_idletasks()
            x = dlg.winfo_x() + (dlg.winfo_width() // 2) - (edit_dlg.winfo_width() // 2)
            y = dlg.winfo_y() + (dlg.winfo_height() // 2) - (edit_dlg.winfo_height() // 2)
            edit_dlg.geometry(f"+{x}+{y}")
            
            # Frame główny z paddingiem
            edit_frame = tk.Frame(edit_dlg, padx=25, pady=20, bg="#f0f0f0")
            edit_frame.pack(fill=tk.BOTH, expand=True)
            
            tk.Label(edit_frame, text="Login:", bg="#f0f0f0", font=("Arial", 10)).grid(row=0, column=0, sticky="e", padx=10, pady=8)
            e_username = tk.Entry(edit_frame, width=35, font=("Arial", 10))
            e_username.insert(0, username)
            e_username.grid(row=0, column=1, padx=10, pady=8, sticky="ew")
            e_username.config(state="readonly")  # Nie pozwalaj zmienić loginu
            
            tk.Label(edit_frame, text="Nazwa wyświetlana:", bg="#f0f0f0", font=("Arial", 10)).grid(row=1, column=0, sticky="e", padx=10, pady=8)
            e_display = tk.Entry(edit_frame, width=35, font=("Arial", 10))
            e_display.insert(0, display_name if display_name else "")
            e_display.grid(row=1, column=1, padx=10, pady=8, sticky="ew")
            
            tk.Label(edit_frame, text="Nowe hasło:", bg="#f0f0f0", font=("Arial", 10)).grid(row=2, column=0, sticky="e", padx=10, pady=8)
            tk.Label(edit_frame, text="(puste = bez zmiany)", bg="#f0f0f0", font=("Arial", 8), fg="#7f8c8d").grid(row=2, column=1, sticky="w", padx=10)
            e_password = tk.Entry(edit_frame, width=35, show="*", font=("Arial", 10))
            e_password.grid(row=3, column=1, padx=10, pady=8, sticky="ew")
            
            tk.Label(edit_frame, text="Powtórz hasło:", bg="#f0f0f0", font=("Arial", 10)).grid(row=4, column=0, sticky="e", padx=10, pady=8)
            e_password2 = tk.Entry(edit_frame, width=35, show="*", font=("Arial", 10))
            e_password2.grid(row=4, column=1, padx=10, pady=8, sticky="ew")
            
            tk.Label(edit_frame, text="Rola:", bg="#f0f0f0", font=("Arial", 10)).grid(row=5, column=0, sticky="ne", padx=10, pady=8)
            var_role = tk.StringVar(value=role)
            role_frame = tk.Frame(edit_frame, bg="#f0f0f0")
            role_frame.grid(row=5, column=1, sticky="w", padx=10, pady=8)
            
            # Górny rząd - ADMIN, USER$$, USER$
            top_row = tk.Frame(role_frame, bg="#f0f0f0")
            top_row.pack(fill="x", pady=1)
            tk.Radiobutton(top_row, text="ADMIN", variable=var_role, value="ADMIN", bg="#f0f0f0", font=("Arial", 9)).pack(side=tk.LEFT, padx=3)
            tk.Radiobutton(top_row, text="USER$$", variable=var_role, value="USER$$", bg="#f0f0f0", font=("Arial", 9)).pack(side=tk.LEFT, padx=3)
            tk.Radiobutton(top_row, text="USER$", variable=var_role, value="USER$", bg="#f0f0f0", font=("Arial", 9)).pack(side=tk.LEFT, padx=3)
            
            # Dolny rząd - USER, GUEST
            bottom_row = tk.Frame(role_frame, bg="#f0f0f0")
            bottom_row.pack(fill="x", pady=1)
            tk.Radiobutton(bottom_row, text="USER", variable=var_role, value="USER", bg="#f0f0f0", font=("Arial", 9)).pack(side=tk.LEFT, padx=3)
            tk.Radiobutton(bottom_row, text="GUEST", variable=var_role, value="GUEST", bg="#f0f0f0", font=("Arial", 9)).pack(side=tk.LEFT, padx=3)
            
            tk.Label(edit_frame, text="Aktywny:", bg="#f0f0f0", font=("Arial", 10)).grid(row=6, column=0, sticky="e", padx=10, pady=8)
            var_active = tk.BooleanVar(value=(active_str == "TAK"))
            tk.Checkbutton(edit_frame, variable=var_active, bg="#f0f0f0", font=("Arial", 10)).grid(row=6, column=1, sticky="w", padx=10, pady=8)
            
            def save_edit():
                new_username = e_username.get().strip()
                if not new_username:
                    messagebox.showwarning("Błąd", "Podaj login!")
                    return
                
                new_display = e_display.get().strip() or new_username
                new_password = e_password.get()
                new_password2 = e_password2.get()
                new_role = var_role.get()
                new_active = 1 if var_active.get() else 0
                
                # Walidacja hasła (jeśli podano)
                if new_password or new_password2:
                    if new_password != new_password2:
                        messagebox.showwarning("Błąd", "Hasła nie są identyczne!")
                        return
                    if len(new_password) < 4:
                        messagebox.showwarning("Błąd", "Hasło musi mieć co najmniej 4 znaki!")
                        return
                
                try:
                    # Przełącz na tryb RW
                    try:
                        self.db_manager.reconnect_master_rw()
                    except Exception as rw_err:
                        messagebox.showerror("Błąd połączenia", f"Nie można połączyć się z bazą master w trybie zapisu:\n{rw_err}")
                        return
                    
                    con = self.db_manager.master_con
                    if con is None:
                        messagebox.showerror("Błąd", "Brak połączenia z bazą master po reconnect!")
                        return
                    
                    # Zbierz co się zmieniło (dla audytu)
                    changes = []
                    if str(display_name) != new_display:
                        changes.append(f"display_name: '{display_name}' → '{new_display}'")
                    if str(role) != new_role:
                        changes.append(f"role: '{role}' → '{new_role}'")
                    old_active = 1 if active_str == "TAK" else 0
                    if old_active != new_active:
                        changes.append(f"is_active: {old_active} → {new_active}")
                    if new_password:
                        changes.append("password: zmienione")
                    
                    # Aktualizacja
                    uid_int = int(uid)
                    if new_password:
                        import hashlib
                        password_hash = hashlib.sha256(new_password.encode()).hexdigest()
                        sql = """
                            UPDATE users
                            SET username = ?, display_name = ?, password_hash = ?, role = ?, is_active = ?
                            WHERE id = ?
                        """
                        con.execute(sql, (new_username, new_display, password_hash, new_role, new_active, uid_int))
                    else:
                        sql = """
                            UPDATE users
                            SET username = ?, display_name = ?, role = ?, is_active = ?
                            WHERE id = ?
                        """
                        con.execute(sql, (new_username, new_display, new_role, new_active, uid_int))
                    
                    con.commit()
                    
                    # LOG: Edycja użytkownika
                    if changes:
                        try:
                            con.execute("""
                                INSERT INTO user_changes_log 
                                (action, user_id, username, display_name, role, changed_by, timestamp, details)
                                VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                            """, (
                                'EDIT',
                                uid_int, new_username, new_display, new_role,
                                self.current_user or 'UNKNOWN',
                                datetime.now().isoformat(),
                                f'Changed: {"; ".join(changes)}'
                            ))
                            con.commit()
                        except Exception as log_err:
                            print(f"⚠️  Błąd logowania EDIT do audytu: {log_err}")
                    
                    messagebox.showinfo("Sukces", f"Użytkownik '{new_username}' został zaktualizowany!")
                    
                    # Odśwież dropdown
                    self.load_users()
                    
                    edit_dlg.destroy()
                    load_data()
                
                except Exception as e:
                    messagebox.showerror("Błąd", f"Nie udało się zapisać:\n{e}")
                    import traceback
                    traceback.print_exc()
            
            btn_frame = tk.Frame(edit_frame, bg="#f0f0f0")
            btn_frame.grid(row=7, column=0, columnspan=2, pady=20)
            
            tk.Button(btn_frame, text="✔ Zapisz", command=save_edit, width=12, 
                     bg="#27ae60", fg="white", font=("Arial", 10, "bold")).pack(side=tk.LEFT, padx=8)
            tk.Button(btn_frame, text="✖ Anuluj", command=edit_dlg.destroy, width=12, 
                     bg="#95a5a6", fg="white", font=("Arial", 10)).pack(side=tk.LEFT, padx=8)
            
            edit_frame.columnconfigure(1, weight=1)
            e_display.focus()
            
            # Bind klawiszy
            e_display.bind("<Return>", lambda e: e_password.focus())
            e_password.bind("<Return>", lambda e: e_password2.focus())
            e_password2.bind("<Return>", lambda e: save_edit())
            edit_dlg.bind("<Escape>", lambda e: edit_dlg.destroy())
        
        def delete_selected():
            if self.current_user_role != "ADMIN":
                messagebox.showerror("Brak uprawnień", "Tylko ADMIN może usuwać użytkowników!")
                return
            
            sel = tree.selection()
            if not sel:
                messagebox.showwarning("Brak wyboru", "Zaznacz użytkownika do usunięcia!")
                return
            
            item = tree.item(sel[0])
            uid = int(item['values'][0])  # Treeview zwraca string!
            username = str(item['values'][1])
            
            # Nie pozwól usunąć samego siebie
            if uid == self.current_user_id:
                messagebox.showerror("Błąd", "Nie możesz usunąć aktualnie zalogowanego użytkownika!")
                return
            
            # Ochrona kont wbudowanych
            if username.upper() in ("ADMIN", "GUEST"):
                messagebox.showerror("Błąd", f"Konto '{username}' jest kontem wbudowanym i nie może zostać usunięte!")
                return
            
            if not messagebox.askyesno("Potwierdź", f"Czy na pewno usunąć użytkownika:\n{username}?"):
                return
            
            try:
                # Przełącz na tryb RW
                try:
                    self.db_manager.reconnect_master_rw()
                except Exception as rw_err:
                    messagebox.showerror("Błąd połączenia", f"Nie można połączyć się z bazą master w trybie zapisu:\n{rw_err}")
                    return
                
                # Pobierz lokalne referencje do połączenia
                con = self.db_manager.master_con
                if con is None:
                    messagebox.showerror("Błąd", "Brak połączenia z bazą master po reconnect!")
                    return
                
                # LOG: Przed usunięciem - zapisz dane
                user_data = con.execute(
                    "SELECT username, display_name, role FROM users WHERE id = ?", (uid,)
                ).fetchone()
                
                con.execute("DELETE FROM users WHERE id = ?", (uid,))
                con.commit()
                
                # LOG: Usunięcie użytkownika
                if user_data:
                    try:
                        con.execute("""
                            INSERT INTO user_changes_log 
                            (action, user_id, username, display_name, role, changed_by, timestamp, details)
                            VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                        """, (
                            'DELETE',
                            uid, user_data[0], user_data[1], user_data[2],
                            self.current_user or 'UNKNOWN',
                            datetime.now().isoformat(),
                            f'Deleted by {self.current_user or "UNKNOWN"}'
                        ))
                        con.commit()
                    except Exception as log_err:
                        print(f"⚠️  Błąd logowania DELETE do audytu: {log_err}")
                
                messagebox.showinfo("Sukces", f"Użytkownik '{username}' został usunięty!")
                
                # Odśwież dropdown
                self.load_users()
                
                load_data()
            
            except Exception as e:
                messagebox.showerror("Błąd", f"Nie udało się usunąć:\n{e}")
                import traceback
                traceback.print_exc()
        
        # Przyciski
        btn_frame = tk.Frame(dlg, bg="#ecf0f1", height=60)
        btn_frame.pack(fill=tk.X, pady=0)
        btn_frame.pack_propagate(False)
        
        btn_inner = tk.Frame(btn_frame, bg="#ecf0f1")
        btn_inner.pack(pady=12)
        
        tk.Button(btn_inner, text="➕ Dodaj", command=self.menu_add_user, width=12, 
                 bg="#3498db", fg="white", font=("Arial", 10, "bold")).pack(side=tk.LEFT, padx=8)
        tk.Button(btn_inner, text="✏️ Edytuj", command=edit_selected, width=12, 
                 bg="#f39c12", fg="white", font=("Arial", 10, "bold")).pack(side=tk.LEFT, padx=8)
        tk.Button(btn_inner, text="🗑️ Usuń", command=delete_selected, width=12, 
                 bg="#e74c3c", fg="white", font=("Arial", 10, "bold")).pack(side=tk.LEFT, padx=8)
