                # Pobierz logi (od najnowszych)
                action_filter = filter_var.get()
                search_text = search_var.get().strip().lower()
                user_filter = user_filter_var.get()
                
                sql = """
                    SELECT change_id, action, drawing_no, item_name, field_name, 
                           old_value, new_value, changed_by, timestamp
                    FROM items_changes_log
                    WHERE 1=1
                """
                params = []
                
                if action_filter != "WSZYSTKO":
                    sql += " AND action = ?"
                    params.append(action_filter)
                
                if search_text:
                    sql += " AND (LOWER(drawing_no) LIKE ? OR LOWER(item_name) LIKE ?)"
                    params.append(f"%{search_text}%")
                    params.append(f"%{search_text}%")
                
                if user_filter != "WSZYSCY":
                    sql += " AND changed_by = ?"
                    params.append(user_filter)
                
                sql += " ORDER BY change_id DESC LIMIT 1000"
                
                cursor = self.db_manager.project_con.execute(sql, params)
                
                count = 0
                for row in cursor.fetchall():
                    change_id, action, drawing_no, item_name, field_name, old_value, new_value, changed_by, timestamp = row
                    
                    # Formatuj timestamp (usuń mikrosekundy jeśli są, dodaj spacje)
                    if timestamp and 'T' in timestamp:
                        # Stary format ISO: 2026-02-14T12:34:56.123456 -> 2026-02-14     12:34:56
                        timestamp = timestamp.split('.')[0].replace('T', '     ')
                    
                    # Mapuj roboczą nazwę pola na przyjazną
                    display_field_name = field_names_map.get(field_name, field_name) if field_name else ""
                    
                    # Skróć długie wartości
                    if old_value and len(str(old_value)) > 50:
                        old_value = str(old_value)[:47] + "..."
                    if new_value and len(str(new_value)) > 50:
                        new_value = str(new_value)[:47] + "..."
                    
                    # Koloruj różne akcje
                    tree.insert("", tk.END, values=(
                        change_id or "",
                        action or "",
                        drawing_no or "",
                        item_name or "",
                        display_field_name,
                        old_value or "",
                        new_value or "",
                        changed_by or "",
                        timestamp or ""
                    ), tags=(action,))
                    count += 1
                
                # Kolorowanie
                tree.tag_configure('ADD', background='#d4edda')
                tree.tag_configure('DELETE', background='#f8d7da')
                tree.tag_configure('EDIT', background='#fff3cd')
                tree.tag_configure('HIDE', background='#e2e3e5')
                tree.tag_configure('RESTORE', background='#d1ecf1')
                
