        status_label = tk.Label(status_frame, text="", bg="#ecf0f1", font=("Arial", 9))
        status_label.pack(side=tk.LEFT, padx=10)
        
        # Przyciski
        btn_frame = tk.Frame(dlg, bg="#ecf0f1", height=60)
        btn_frame.pack(fill=tk.X, pady=0)
        btn_frame.pack_propagate(False)
        
        btn_inner = tk.Frame(btn_frame, bg="#ecf0f1")
        btn_inner.pack(pady=12)
        
        tk.Button(btn_inner, text="🔄 Odśwież", command=load_logs, width=12, 
                 bg="#16a085", fg="white", font=("Arial", 10)).pack(side=tk.LEFT, padx=8)
        tk.Button(btn_inner, text="✖ Zamknij", command=dlg.destroy, width=12, 
                 bg="#95a5a6", fg="white", font=("Arial", 10)).pack(side=tk.LEFT, padx=8)
        
        # Bind filtrów
        filter_combo.bind("<<ComboboxSelected>>", lambda e: load_logs())
        search_entry.bind("<KeyRelease>", lambda e: load_logs())
        user_filter_combo.bind("<<ComboboxSelected>>", lambda e: load_logs())
        
        load_logs()
    
