    def _on_filter_toggle(self, kind: str):
        """Pilnuje filtrów wzajemnie wykluczających się"""
        try:
            if kind == "ordered" and int(self.only_ordered_var.get() or 0) == 1:
                self.only_to_order_var.set(0)
            elif kind == "to_order" and int(self.only_to_order_var.get() or 0) == 1:
                self.only_ordered_var.set(0)
            elif kind == "yellow" and int(self.only_alarm_yellow_var.get() or 0) == 1:
                self.only_alarm_red_var.set(0)
            elif kind == "red" and int(self.only_alarm_red_var.get() or 0) == 1:
                self.only_alarm_yellow_var.set(0)
            elif kind == "delivered" and int(self.only_delivered_var.get() or 0) == 1:
                self.only_not_delivered_var.set(0)
            elif kind == "not_delivered" and int(self.only_not_delivered_var.get() or 0) == 1:
                self.only_delivered_var.set(0)
        except Exception:
            pass
        self.refresh_data()
    
    def _clear_filter_vars(self):
        """Wyczyść wszystkie zmienne filtrów (bez odświeżania widoku)"""
        self.filter_class_var.set("(WSZYSTKO)")
        self.filter_supplier_var.set(FILTER_SUPPLIER_ALL)
        self.search_var.set("")
        self.only_missing_supplier_var.set(0)
        self.only_overdue_var.set(0)
        self.only_biblioteka_var.set(0)
        self.only_manual_var.set(0)
        self.only_ordered_var.set(0)
        self.only_to_order_var.set(0)
        self.only_alarm_yellow_var.set(0)
        self.only_alarm_red_var.set(0)
        self.only_delivered_var.set(0)
        self.only_not_delivered_var.set(0)
        self.filter_modul_selected.clear()
        self.filter_grub_selected.clear()
        self._update_modul_filter_button()
        self._update_grub_filter_button()
    
    def clear_filters(self):
        """Wyczyść wszystkie filtry"""
        try:
            self._clear_filter_vars()
            self.refresh_data()
        except Exception as e:
            print(f"⚠️  Błąd podczas czyszczenia filtrów: {e}")
    
    def _schedule_refresh(self, delay_ms: int = 250):
        """Zbiorcze auto-odświeżanie (debounce), żeby nie przeładowywać listy po każdej literze."""
        try:
            if self._refresh_after_id is not None:
                self.after_cancel(self._refresh_after_id)
        except Exception:
            pass
        self._refresh_after_id = self.after(delay_ms, self.refresh_data)
    
    def _get_all_moduls_from_project(self):
        """Zbierz wszystkie unikalne moduły z aktualnego projektu"""
        if not self.current_project_id:
            return []
        
        try:
            # Pobierz WSZYSTKIE items (bez filtrów, ale z is_hidden)
            show_hidden = self.show_hidden_var.get()
            items = self.db_manager.get_project_items(self.current_project_id, show_hidden=show_hidden)
            
            moduls_set = set()
            
            for item in items:
                # Pobierz modul_disp (COALESCE work/src)
                modul_val = ""
                try:
                    # sqlite3.Row i dict mają różny sposób dostępu
                    if isinstance(item, dict):
                        modul_val = item.get('modul_disp') or ""
                    else:
                        # sqlite3.Row - dostęp przez klucz
                        modul_val = item['modul_disp'] if item['modul_disp'] else ""
                except (KeyError, TypeError, IndexError):
                    # Stara baza bez kolumny moduł lub None
                    continue
                
                if not modul_val or not modul_val.strip():
                    continue
                
                # Parsuj dwa formaty:
                # 1. Z nawiasami (WAREHOUSE): "NAZWA_PROJEKTU(2), WE(5)x2, HF(3)"
                # 2. Bez nawiasów (MACHINES): "MODUŁ1, MODUŁ2, MODUŁ3"
                import re
                parts = [p.strip() for p in modul_val.split(',')]
                for part in parts:
                    if not part:
                        continue
                    # Spróbuj dopasować format z nawiasem: NAZWA(ilość)xmnożnik lub NAZWA(ilość)
                    match = re.match(r'([^(]+)\s*\((\d+)\)(?:x(\d+))?', part)
                    if match:
                        # Format z nawiasem
                        modul_name = match.group(1).strip()
                        if modul_name:
                            moduls_set.add(modul_name)
                    else:
                        # Format bez nawiasu - dodaj całą wartość
                        modul_name = part.strip()
                        if modul_name:
                            moduls_set.add(modul_name)
            
            # Sortuj alfabetycznie
            return sorted(moduls_set)
        except Exception as e:
            print(f"⚠️  Błąd podczas zbierania modułów: {e}")
            import traceback
            traceback.print_exc()
            return []
    
    def _update_modul_filter_button(self):
        """Aktualizuj tekst przycisku filtru Moduł"""
        try:
            count = len(self.filter_modul_selected)
            
            # Sprawdź czy są mnożniki różne od 1 (tylko dla WAREHOUSE)
            has_multipliers = False
            project_type = self._get_internal_project_type()
            if project_type == "WAREHOUSE":
                # Sprawdź czy w bazie są mnożniki
                multipliers = self._get_multipliers_from_database()
                has_multipliers = any(m != 1 for m in multipliers.values() if m is not None)
            
            # Tekst przycisku
            if has_multipliers:
                self.btn_filter_modul.config(text=f"Moduł ({count}) ×")
            else:
                self.btn_filter_modul.config(text=f"Moduł ({count})")
            
            # Zmień kolor gdy aktywny
            if count > 0:
                self.btn_filter_modul.config(bg="#27ae60")  # Zielony
            else:
                self.btn_filter_modul.config(bg="#7f8c8d")  # Szary
        except Exception as e:
            print(f"⚠️  Błąd aktualizacji przycisku Moduł: {e}")
    
    def _update_grub_filter_button(self):
        """Aktualizuj tekst przycisku filtru Grubość"""
        try:
            count = len(self.filter_grub_selected)
            self.btn_filter_grub.config(text=f"Grubość ({count})")
            # Zmień kolor gdy aktywny
            if count > 0:
                self.btn_filter_grub.config(bg="#27ae60")  # Zielony
            else:
                self.btn_filter_grub.config(bg="#7f8c8d")  # Szary
        except Exception as e:
            print(f"⚠️  Błąd aktualizacji przycisku Grubość: {e}")
    
    def _save_multiplier_to_database(self, modul_name, multiplier):
        """Zapisz mnożnik modułu do bazy danych w kolumnie work_modul
        
        Aktualizuje wszystkie pozycje które mają dany moduł, zmieniając format
        z NAZWA(ilość) na NAZWA(ilość)xmnożnik
        
        WAŻNE: Używa aktualnej wartości work_qty (wyświetlanej ILOŚĆ BOM), nie oryginalnej z modułu!
        
        Args:
            modul_name: Nazwa modułu do zaktualizowania
            multiplier: Mnożnik (0 lub więcej)
        """
        if not self.have_lock or not self.current_project_id:
            return
        
        import re
        
        try:
            # Pobierz wszystkie pozycje z projektu (z aktualną ILOŚĆ BOM)
            rows = self.db_manager.project_con.execute(
                """
                SELECT id, 
                       COALESCE(NULLIF(work_modul, ''), src_modul) AS modul_val,
                       src_modul,
                       COALESCE(work_qty, src_qty) AS current_qty_bom
                FROM items
                WHERE project_id = ?
                """,
                (self.current_project_id,)
            ).fetchall()
            
            updated_count = 0
            
            for row in rows:
                item_id, current_modul, src_modul, current_qty_bom = row
                
                if not current_modul:
                    continue
                
                # Parsuj moduły i zaktualizuj mnożnik dla pasującego modułu
                parts = [p.strip() for p in current_modul.split(',')]
                new_parts = []
                modified = False
                
                for part_idx, part in enumerate(parts):
                    if not part:
                        continue
                    
                    # Parsuj: NAZWA(ilość)xmnożnik lub NAZWA(ilość)
                    match = re.match(r'([^(]+)\s*\((\d+)\)(?:x(\d+))?', part)
                    if match:
                        name = match.group(1).strip()
                        old_qty = match.group(2)  # Ilość z modułu (może być stara!)
                        
                        if name == modul_name:
                            # To jest moduł do zaktualizowania
                            # WAŻNE: Użyj aktualnej ILOŚĆ BOM (work_qty) dla pierwszego modułu!
                            if part_idx == 0:
                                # Pierwszy moduł = moduł projektu - użyj aktualnej ILOŚĆ BOM
                                try:
                                    qty = int(round(float(current_qty_bom))) if current_qty_bom is not None else 0
                                except:
                                    qty = old_qty  # Fallback do starej wartości
                            else:
                                # Kolejne moduły - zachowaj oryginalną ilość
                                qty = old_qty
                            
                            if multiplier == 1:
                                # Mnożnik 1 - nie zapisujemy "x1"
                                new_parts.append(f"{name}({qty})")
                            else:
                                # Zapisz z mnożnikiem
                                new_parts.append(f"{name}({qty})x{multiplier}")
                            modified = True
                        else:
                            # Inne moduły - zachowaj bez zmian
                            new_parts.append(part)
                    else:
                        # Format bez nawiasu - zachowaj
                        new_parts.append(part)
                
                if modified:
                    # Zapisz zaktualizowaną wartość do work_modul
                    new_modul_val = ', '.join(new_parts)
                    self.db_manager.project_con.execute(
                        """
                        UPDATE items
                        SET work_modul = ?,
                            updated_at = datetime('now')
                        WHERE id = ?
                        """,
                        (new_modul_val, item_id)
                    )
                    updated_count += 1
            
            # Commit zmian
            if updated_count > 0:
                self.db_manager.project_con.commit()
                print(f"✅ Zaktualizowano mnożnik dla '{modul_name}' = {multiplier} w {updated_count} pozycjach (używając wyświetlanej ILOŚĆ BOM)")
            else:
                print(f"ℹ️  Brak pozycji z modułem '{modul_name}' do zaktualizowania")
                
        except Exception as e:
            print(f"⚠️  Błąd podczas zapisu mnożnika do bazy: {e}")
            import traceback
            traceback.print_exc()
    
    def _get_multipliers_from_database(self):
        """Odczytaj wszystkie mnożniki z bazy danych
        
        Parsuje kolumnę work_modul/src_modul i zwraca słownik {modul_name: multiplier}
        dla wszystkich modułów które mają mnożnik != 1
        
        Returns:
            dict: {modul_name: multiplier}
        """
        if not self.current_project_id:
            return {}
        
        import re
        multipliers = {}
        
        try:
            # Sprawdź czy baza ma kolumny src_modul i work_modul (backward compatibility)
            cursor_check = self.db_manager.project_con.execute("PRAGMA table_info(items)")
            columns = [row[1] for row in cursor_check.fetchall()]
            has_modul_cols = 'src_modul' in columns and 'work_modul' in columns
            
            if not has_modul_cols:
                # Stara baza bez kolumn moduł - brak mnożników
                print(f"  📊 Załadowano 0 mnożników modułów (brak kolumn moduł w bazie)")
                return {}
            
            # Pobierz wszystkie unikalne wartości modułów z projektu
            rows = self.db_manager.project_con.execute(
                """
                SELECT DISTINCT COALESCE(NULLIF(work_modul, ''), src_modul) AS modul_val
                FROM items
                WHERE project_id = ? AND modul_val IS NOT NULL AND modul_val != ''
                """,
                (self.current_project_id,)
            ).fetchall()
            
            for row in rows:
                modul_val = row[0]
                if not modul_val:
                    continue
                
                # Parsuj moduły i wyciągnij mnożniki
                parts = [p.strip() for p in modul_val.split(',')]
                for part in parts:
                    if not part:
                        continue
                    
                    # Parsuj: NAZWA(ilość)xmnożnik lub NAZWA(ilość)
                    match = re.match(r'([^(]+)\s*\((\d+)\)(?:x(\d+))?', part)
                    if match:
                        name = match.group(1).strip()
                        multiplier_str = match.group(3)
                        
                        if multiplier_str:
                            # Ma mnożnik
                            multiplier = int(multiplier_str)
                            # Zapisz najwyższy znaleziony mnożnik dla tego modułu
                            if name not in multipliers or multipliers[name] < multiplier:
                                multipliers[name] = multiplier
                        elif name not in multipliers:
                            # Brak mnożnika - domyślnie 1 (tylko jeśli jeszcze nie mamy)
                            multipliers[name] = 1
            
            return multipliers
            
        except Exception as e:
            print(f"⚠️  Błąd podczas odczytu mnożników z bazy: {e}")
            import traceback
            traceback.print_exc()
            return {}
    
    def open_modul_filter_dialog(self):
        """Otwórz okno dialogowe wyboru modułów"""
        if not self.current_project_id:
            messagebox.showwarning("Brak projektu", "Wybierz projekt najpierw!")
            return
        
        # Zbierz wszystkie moduły z projektu
        all_moduls = self._get_all_moduls_from_project()
        if not all_moduls:
            messagebox.showinfo("Brak modułów", "Projekt nie zawiera żadnych modułów.")
            return
        
        # Stwórz okno dialogowe
        dialog = tk.Toplevel(self)
        dialog.title("Wybierz moduły")
        dialog.geometry("400x500")
        dialog.transient(self)
        dialog.grab_set()
        
        # Tymczasowy zbiór zaznaczonych (kopia)
        temp_selection = set(self.filter_modul_selected)
        
        # Frame na listę checkboxów (scrollable)
        list_frame = tk.Frame(dialog, bg="white")
        list_frame.pack(fill=tk.BOTH, expand=True, padx=10, pady=10)
        
        # Canvas + Scrollbar
        canvas = tk.Canvas(list_frame, bg="white")
        scrollbar = tk.Scrollbar(list_frame, orient="vertical", command=canvas.yview)
        scrollable_frame = tk.Frame(canvas, bg="white")
        
        scrollable_frame.bind(
            "<Configure>",
            lambda e: canvas.configure(scrollregion=canvas.bbox("all"))
        )
        
        canvas.create_window((0, 0), window=scrollable_frame, anchor="nw")
        canvas.configure(yscrollcommand=scrollbar.set)
        
        canvas.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        scrollbar.pack(side=tk.RIGHT, fill=tk.Y)
        
        # Sprawdź typ projektu
        project_type = self._get_internal_project_type()
        is_warehouse = (project_type == "WAREHOUSE")
        
        # Sprawdź czy user ma lock (mnożniki dostępne TYLKO z lockiem)
        has_lock = self.have_lock
        
        # Checkboxy dla każdego modułu (+ mnożniki dla WAREHOUSE z lockiem)
        checkbox_vars = {}
        multiplier_vars = {}  # Tylko dla WAREHOUSE
        original_multiplier_values = {}  # Śledź oryginalne wartości z bazy dla każdego modułu
        
        # Pobierz aktualne mnożniki z bazy (dla WAREHOUSE)
        current_multipliers = {}
        if is_warehouse:
            current_multipliers = self._get_multipliers_from_database()
        
        # Informacja o mnożnikach (jeśli WAREHOUSE bez locka)
        if is_warehouse and not has_lock:
            info_frame = tk.Frame(scrollable_frame, bg="#fff3cd", relief=tk.RIDGE, borderwidth=2)
            info_frame.pack(fill=tk.X, padx=5, pady=(0, 10))
            tk.Label(
                info_frame,
                text="⚠️  Mnożniki modułów dostępne tylko z lockiem projektu",
                bg="#fff3cd",
                fg="#856404",
                font=("Arial", 9, "italic"),
                padx=10,
                pady=5
            ).pack()
        
        for modul in all_moduls:
            var = tk.IntVar(value=1 if modul in temp_selection else 0)
            checkbox_vars[modul] = var
            
            # Frame dla wiersza
            row_frame = tk.Frame(scrollable_frame, bg="white")
            row_frame.pack(fill=tk.X, padx=5, pady=2)
            
            # Checkbox
            cb = tk.Checkbutton(
                row_frame,
                text=modul,
                variable=var,
                bg="white",
                font=("Arial", 10),
                anchor="w"
            )
            cb.pack(side=tk.LEFT, fill=tk.X, expand=True)
            
            # Pole mnożnika dla WAREHOUSE (tylko z lockiem)
            if is_warehouse:
                tk.Label(
                    row_frame,
                    text="×",
                    bg="white",
                    font=("Arial", 10, "bold")
                ).pack(side=tk.LEFT, padx=2)
                
                # Odczytaj aktualny mnożnik z bazy (domyślnie 1)
                current_mult_value = current_multipliers.get(modul, 1)
                mult_var = tk.StringVar(value=str(int(current_mult_value)))
                multiplier_vars[modul] = mult_var
                
                # Zapisz oryginalną wartość dla późniejszego porównania
                original_multiplier_values[modul] = str(int(current_mult_value))
                
                # Zawsze zielone tło na starcie (wartość z bazy)
                mult_entry = tk.Entry(
                    row_frame,
                    textvariable=mult_var,
                    width=5,
                    font=("Arial", 10),
                    justify='center',
                    bg="#d4edda",  # Zawsze zielone na starcie
                    relief=tk.SOLID,
                    borderwidth=2,
                    state='normal' if has_lock else 'disabled'  # Wyłącz bez locka
                )
                mult_entry.pack(side=tk.LEFT, padx=2)
                
                # Binding - sprawdź czy wartość się zmieniła
                def on_value_change(event, entry, mod, mv, orig_val):
                    current_val = mv.get().strip()
                    # Porównaj z oryginalną wartością
                    if current_val != orig_val:
                        # Wartość zmieniona - jasnoczerwone tło (niezapisane)
                        entry.config(bg="#ffe6e6", relief=tk.SUNKEN, borderwidth=1)
                    else:
                        # Wartość taka sama jak oryginał - zielone tło (zgodne z bazą)
                        entry.config(bg="#d4edda", relief=tk.SOLID, borderwidth=2)
                
                mult_entry.bind('<KeyRelease>', lambda e, ent=mult_entry, m=modul, mv=mult_var, orig=original_multiplier_values[modul]: on_value_change(e, ent, m, mv, orig))
                
                # Przycisk Zatwierdź dla tego modułu (tylko z lockiem)
                def make_apply_callback(mod, mv, entry_widget, orig_values_dict):
                    def apply_multiplier():
                        if not self.have_lock:  # Dodatkowa walidacja
                            messagebox.showwarning(
                                "Brak locka",
                                "Mnożniki modułów można zmieniać tylko z lockiem projektu!",
                                parent=dialog
                            )
                            return
                        try:
                            # Walidacja - tylko liczby całkowite (0 lub więcej)
                            multiplier = int(mv.get())
                            if multiplier < 0:
                                multiplier = 0
                                mv.set("0")
                            
                            # ZAPISZ MNOŻNIK DO BAZY w kolumnie work_modul
                            self._save_multiplier_to_database(mod, multiplier)
                            
                            # Aktualizuj oryginalną wartość (teraz to jest nowa wartość bazowa)
                            orig_values_dict[mod] = str(int(multiplier))
                            
                            # WIZUALNA INFORMACJA ZWROTNA - zawsze zielone po zatwierdzeniu
                            entry_widget.config(bg="#d4edda", relief=tk.SOLID, borderwidth=2)
                            
                            # Odśwież widok
                            self._update_modul_filter_button()
                            self.refresh_data()
                            
                        except ValueError:
                            messagebox.showwarning(
                                "Błędna wartość",
                                f"Mnożnik musi być liczbą całkowitą (min. 0)",
                                parent=dialog
                            )
                            mv.set("1")
                    return apply_multiplier
                
                apply_btn = tk.Button(
                    row_frame,
                    text="Zatwierdź",
                    command=make_apply_callback(modul, mult_var, mult_entry, original_multiplier_values),
                    bg="#27ae60" if has_lock else "#95a5a6",  # Szary gdy brak locka
                    fg="white",
                    font=("Arial", 8),
                    width=10,
                    relief=tk.RAISED,
                    state='normal' if has_lock else 'disabled'  # Wyłącz bez locka
                )
                apply_btn.pack(side=tk.LEFT, padx=2)
        
        # Frame na przyciski szybkiego wyboru
        quick_frame = tk.Frame(dialog, bg="#ecf0f1")
        quick_frame.pack(fill=tk.X, padx=10, pady=(0, 10))
        
        def select_all():
            for var in checkbox_vars.values():
                var.set(1)
        
        def deselect_all():
            for var in checkbox_vars.values():
                var.set(0)
        
        tk.Button(
            quick_frame,
            text="Zaznacz wszystkie",
            command=select_all,
            bg="#3498db",
            fg="white",
            font=("Arial", 9)
        ).pack(side=tk.LEFT, padx=5, pady=5, expand=True, fill=tk.X)
        
        tk.Button(
            quick_frame,
            text="Odznacz wszystkie",
            command=deselect_all,
            bg="#e74c3c",
            fg="white",
            font=("Arial", 9)
        ).pack(side=tk.LEFT, padx=5, pady=5, expand=True, fill=tk.X)
        
        # Frame na przyciski OK/Anuluj
        button_frame = tk.Frame(dialog, bg="#ecf0f1")
        button_frame.pack(fill=tk.X, padx=10, pady=(0, 10))
        
        def on_ok():
            # Zapisz zaznaczone moduły
            self.filter_modul_selected.clear()
            for modul, var in checkbox_vars.items():
                if var.get() == 1:
                    self.filter_modul_selected.add(modul)
            
            # Zaktualizuj przycisk i odśwież dane
            self._update_modul_filter_button()
            self.refresh_data()
            dialog.destroy()
        
        def on_cancel():
            dialog.destroy()
        
        tk.Button(
            button_frame,
            text="OK",
            command=on_ok,
            bg="#27ae60",
            fg="white",
            font=("Arial", 10, "bold"),
            width=15
        ).pack(side=tk.LEFT, padx=5, pady=5, expand=True)
        
        tk.Button(
            button_frame,
            text="Anuluj",
            command=on_cancel,
            bg="#95a5a6",
            fg="white",
            font=("Arial", 10),
            width=15
        ).pack(side=tk.LEFT, padx=5, pady=5, expand=True)
        
        # Wyśrodkuj okno
        dialog.update_idletasks()
        x = self.winfo_x() + (self.winfo_width() // 2) - (dialog.winfo_width() // 2)
        y = self.winfo_y() + (self.winfo_height() // 2) - (dialog.winfo_height() // 2)
        dialog.geometry(f"+{x}+{y}")
        
        # Czekaj na zamknięcie okna
        dialog.wait_window()
    
    def _get_all_grub_from_project(self):
        """Zbierz wszystkie unikalne grubości z aktualnego projektu"""
        if not self.current_project_id:
            return []
        
        try:
            # Pobierz WSZYSTKIE items (bez filtrów, ale z is_hidden)
            show_hidden = self.show_hidden_var.get()
            items = self.db_manager.get_project_items(self.current_project_id, show_hidden=show_hidden)
            
            grub_set = set()
            
            for item in items:
                # Użyj tej samej logiki co przy wyświetlaniu kolumny
                thickness_disp = self._get_thickness_display(item)
                
                if thickness_disp and thickness_disp.strip():
                    grub_set.add(thickness_disp)
            
            # Sortuj numerycznie (jeśli możliwe)
            try:
                return sorted(grub_set, key=lambda x: float(x) if x.replace('.', '', 1).replace('-', '', 1).isdigit() else float('inf'))
            except:
                return sorted(grub_set)
        except Exception as e:
            print(f"⚠️  Błąd podczas zbierania grubości: {e}")
            import traceback
            traceback.print_exc()
            return []
    
    def _get_thickness_display(self, item):
        """Pobierz i sformatuj grubość dla danego itemu (ta sama logika co w wyświetlaniu)"""
        thickness_disp = ""
        
        # Bezpieczne pobranie thickness_mm
        try:
            thick_raw = item['thickness_mm']
        except (KeyError, IndexError):
            thick_raw = None
        
        if thick_raw is not None:
            # Formatuj grubość - jeśli liczba całkowita, nie pokazuj dziesiętnych
            try:
                thick_val = float(thick_raw)
                if thick_val == int(thick_val):
                    thickness_disp = str(int(thick_val))
                else:
                    # Usuń końcowe zera
                    thickness_disp = f"{thick_val:.10f}".rstrip('0').rstrip('.')
            except:
                thickness_disp = str(thick_raw)
        else:
            # Auto-parsuj z src_material_text
            try:
                mat_src = item['src_material_text'] or ""
                if mat_src:
                    from import_bom import parse_thickness_mm
                    parsed_thick = parse_thickness_mm(mat_src)
                    if parsed_thick:
                        # Zastosuj te same reguły formatowania
                        try:
                            thick_val = float(parsed_thick)
                            if thick_val == int(thick_val):
                                thickness_disp = str(int(thick_val))
                            else:
                                thickness_disp = f"{thick_val:.10f}".rstrip('0').rstrip('.')
                        except:
                            thickness_disp = str(parsed_thick)
            except:
                pass
        
        return thickness_disp

    
