    def toggle_show_hidden(self):
        """Przełącz wyświetlanie ukrytych pozycji"""
        show_hidden = self.show_hidden_var.get()
        print(f"\n{'='*50}")
        print(f"🔄 TOGGLE_SHOW_HIDDEN wywołany")
        print(f"   Checkbox value (BooleanVar): {show_hidden}")
        print(f"   Type: {type(show_hidden)}")
        if show_hidden:
            print("👁️ Tryb: POKAŻ UKRYTE (tylko is_hidden=1)")
        else:
            print("📋 Tryb: POKAŻ WIDOCZNE (tylko is_hidden=0)")
        print(f"{'='*50}\n")
        
        # DEBUG: pokaż użytkownikowi co się dzieje
        # messagebox.showinfo("DEBUG", f"show_hidden = {show_hidden}")
        
        self.refresh_data()
    
    def hide_selected_items(self):
        """Ukryj zaznaczone pozycje"""
        from datetime import datetime
        
        print(f"\n🔍 hide_selected_items wywołane:")
        print(f"   have_lock: {self.have_lock}")
        print(f"   btn_hide_selected state: {self.btn_hide_selected['state']}")
        
        if not self.have_lock:
            messagebox.showwarning("Brak uprawnień", "Przejmij lock aby edytować!")
            return
        
        # Pobierz zaznaczone wiersze - TYLKO z row index (kliknięcie w LP: 1, 2, 3...)
        selected = self.sheet.get_selected_rows()
        
        print(f"   Zaznaczone wiersze (row index): {selected}")
        
        if not selected:
            messagebox.showinfo(
                "Brak zaznaczenia", 
                "Zaznacz pozycje do ukrycia!\n\n"
                "SPOSÓB ZAZNACZANIA:\n"
                "• Kliknij w numer wiersza (LP: 1, 2, 3...)\n"
                "• Użyj SHIFT lub CTRL dla wielu wierszy\n\n"
                "⚠️ Zaznaczanie komórek NIE działa!"
            )
            return
        
        # Potwierdź
        if not messagebox.askyesno(
            "Ukryj pozycje",
            f"Ukryć {len(selected)} zaznaczonych pozycji?\n\n"
            "Ukryte pozycje nie będą widoczne w arkuszu,\n"
            "ale można je przywrócić przez 'Pokaż ukryte'."
        ):
            return
        
        try:
            # Ukryj każdą zaznaczoną pozycję
            for row_idx in selected:
                if row_idx >= len(self._sheet_row_ids):
                    continue
                
                item_id = self._sheet_row_ids[row_idx]
                if not item_id:
                    continue
                
                self.db_manager.project_con.execute("""
                    UPDATE items 
                    SET is_hidden = 1, updated_at = ?
                    WHERE id = ?
                """, (datetime.now().isoformat(), item_id))
                
                # Loguj ukrycie do audit trail
                self._log_item_change(item_id, 'HIDE', 'is_hidden', 0, 1)
            
            self.db_manager.project_con.commit()
            
            
            print(f"✅ Ukryto {len(selected)} pozycji")
            
            # Odśwież widok
            self.refresh_data()
            
        except Exception as e:
            messagebox.showerror("Błąd", f"Nie udało się ukryć pozycji:\n{e}")
            import traceback
            traceback.print_exc()
    
    def restore_hidden_items(self):
        """Przywróć zaznaczone ukryte pozycje (wymaga checkboxa 'Pokaż ukryte')"""
        from datetime import datetime
        
        if not self.have_lock:
            messagebox.showwarning("Brak uprawnień", "Przejmij lock aby edytować!")
            return
        
        # Sprawdź czy jesteśmy w trybie pokazywania ukrytych
        if not self.show_hidden_var.get():
            messagebox.showwarning(
                "Niepoprawny tryb",
                "Aby przywrócić ukryte pozycje:\n\n"
                "1. Zaznacz checkbox 'Pokaż ukryte'\n"
                "2. Zaznacz pozycje do przywrócenia\n"
                "3. Kliknij 'Przywróć zaznaczone'"
            )
            return
        
        # Pobierz zaznaczone wiersze - TYLKO z row index (kliknięcie w LP: 1, 2, 3...)
        selected = self.sheet.get_selected_rows()
        
        if not selected:
            messagebox.showwarning(
                "Brak zaznaczenia", 
                "Zaznacz pozycje do przywrócenia!\n\n"
                "SPOSÓB ZAZNACZANIA:\n"
                "• Kliknij w numer wiersza (LP: 1, 2, 3...)\n"
                "• Użyj SHIFT lub CTRL dla wielu wierszy\n\n"
                "⚠️ Zaznaczanie komórek NIE działa!"
            )
            return
        
        try:
            # DEBUG: pokaż stan mappingu
            print(f"\n🔍 RESTORE_HIDDEN_ITEMS:")
            print(f"   Zaznaczone wiersze: {selected}")
            print(f"   Długość _sheet_row_ids: {len(self._sheet_row_ids)}")
            if self._sheet_row_ids:
                print(f"   Pierwsze 5 ID: {self._sheet_row_ids[:5]}")
            
            # Zbierz ID pozycji z zaznaczonych wierszy
            item_ids = []
            for row in selected:
                # _sheet_row_ids to LISTA, więc sprawdzamy indeks < długość
                if row < len(self._sheet_row_ids):
                    item_id = self._sheet_row_ids[row]
                    item_ids.append(item_id)
                    print(f"   Wiersz {row} → item_id {item_id}")
                else:
                    print(f"   ⚠️ Wiersz {row} poza zakresem (len={len(self._sheet_row_ids)})")
            
            if not item_ids:
                messagebox.showwarning("Błąd", "Nie znaleziono ID pozycji do przywrócenia")
                return
            
            # Potwierdź
            if not messagebox.askyesno(
                "Przywróć pozycje",
                f"Przywrócić {len(item_ids)} zaznaczonych pozycji?\n\n"
                "Pozycje staną się ponownie widoczne."
            ):
                return
            
            # Przywróć zaznaczone pozycje
            placeholders = ','.join('?' * len(item_ids))
            self.db_manager.project_con.execute(f"""
                UPDATE items 
                SET is_hidden = 0, updated_at = ?
                WHERE id IN ({placeholders})
            """, (datetime.now().isoformat(), *item_ids))
            
            self.db_manager.project_con.commit()
            
            # Loguj przywrócenie do audit trail
            for item_id in item_ids:
                self._log_item_change(item_id, 'RESTORE', 'is_hidden', 1, 0)
            
            
            print(f"✅ Przywrócono {len(item_ids)} pozycji")
            messagebox.showinfo(
                "Sukces",
                f"Przywrócono {len(item_ids)} pozycji.\n\n"
                "Wyłącz 'Pokaż ukryte' aby zobaczyć przywrócone pozycje."
            )
            
            # Jeśli jesteśmy w trybie show_hidden, przełącz na widoczne
            if self.show_hidden_var.get():
                self.show_hidden_var.set(False)
            
            # Odśwież widok
            self.refresh_data()
            
        except Exception as e:
            messagebox.showerror("Błąd", f"Nie udało się przywrócić pozycji:\n{e}")
            import traceback
            traceback.print_exc()
    
    # ====================================================================
    # CHAT
    # ====================================================================
    
    def open_chat_window(self, bring_to_front=False):
        """Otwórz okno chatu (lub odśwież jeśli już otwarte)
        
        Args:
            bring_to_front: Czy podnieść okno na wierzch (True z tray, False z auto-refresh)
        """
        # Sprawdź połączenie z dyskiem sieciowym przed otwarciem chatu
        if not self._safe_ensure_master_alive():
            # Brak połączenia - banner już pokazany przez _safe_ensure_master_alive
            return
        
        if self.chat_window and self.chat_window.winfo_exists():
            # Okno już otwarte - odśwież wiadomości
            self.chat_window.refresh_messages()
            # Podnieś na wierzch (ale NIE wymuszaj topmost - sprawdź checkbox)
            self.chat_window.deiconify()
            if bring_to_front:
                self.chat_window.lift()
            self.chat_window.focus_force()
            try:
                self.chat_window.input_text.focus_set()
            except:
                pass
            # Zaktualizuj timestamp - użytkownik widzi wiadomości
            ts = self.chat_window.get_last_timestamp()
            if ts:
                self._last_chat_timestamp = ts
        else:
            # Twórz nowe okno - NORMALNIE z focusem (użytkownik kliknął klawisz CHAT)
            self.chat_window = ChatWindow(self, self.db_manager, self.current_user, self.current_user_id)
            # NIE nadpisuj _last_chat_timestamp wartością None z niezaładowanego okna
            # check_for_new_messages() już utrzymuje poprawny timestamp
            # Focus ustawiony w _deferred_init po załadowaniu wiadomości
        
        # Oznacz wiadomości jako przeczytane
        self._has_unread_messages = False
        self.update_tray_icon()
    
    def check_new_chat_messages(self):
        """Sprawdź czy pojawiły się nowe wiadomości (odśwież jeśli okno otwarte)"""
        try:
            # Sprawdź połączenie z dyskiem sieciowym przed sprawdzaniem wiadomości
            if not self._safe_ensure_master_alive():
                # Brak połączenia - banner już pokazany, zamknij okno chatu jeśli otwarte
                if self.chat_window and self.chat_window.winfo_exists():
                    self.chat_window.on_close()
                return
            
            # ZAWSZE sprawdź czy są nowe wiadomości (nawet gdy okno otwarte)
            new_msg_info = self.check_for_new_messages()
            if new_msg_info:
                # Sprawdź czy okno czatu jest otwarte i czy ma focus
                chat_has_focus = False
                if self.chat_window and self.chat_window.winfo_exists():
                    try:
                        # Sprawdź czy okno czatu ma focus
                        chat_has_focus = (self.chat_window.focus_get() is not None)
                    except:
                        chat_has_focus = False
                
                # Pokaż powiadomienie jeśli:
                # 1. Okno czatu nie istnieje ALBO
                # 2. Okno czatu istnieje ale NIE MA focusu (jest w tle)
                if not self._has_unread_messages and not chat_has_focus:
                    # Pokaż powiadomienie balonowe w tray
                    self.show_chat_notification(new_msg_info)
                
                self._has_unread_messages = True
                self.update_tray_icon()
            
            # Jeśli okno otwarte - odśwież je (ale NIE czyść flagi nieprzeczytanych)
            if self.chat_window and self.chat_window.winfo_exists():
                self.chat_window.refresh_messages()
            
        except Exception as e:
            # Błąd sprawdzania - nie przeszkadzaj użytkownikowi
            pass
    
    def check_for_new_messages(self):
        """Sprawdź czy są nowe wiadomości (zwraca dict z informacją o wiadomości lub None)"""
        try:
            if not self.db_manager or not self.db_manager.master_path:
                return None
            
            chat_dir = Path(self.db_manager.master_path).parent / "chat"
            if not chat_dir.exists():
                return None
            
            # Szukaj najnowszej wiadomości od innych użytkowników
            latest_timestamp = None
            newest_msg = None
            
            for file_path in chat_dir.glob("*.json"):
                try:
                    with open(file_path, 'r', encoding='utf-8') as f:
                        msg = json.load(f)
                        ts = msg.get('timestamp')
                        
                        # Aktualizuj latest_timestamp dla wszystkich wiadomości
                        if ts and (not latest_timestamp or ts > latest_timestamp):
                            latest_timestamp = ts
                        
                        # Sprawdź czy to nie nasza własna wiadomość i czy jest nowa
                        if ts and msg.get('username') != self.current_user:
                            if not self._last_chat_timestamp or ts > self._last_chat_timestamp:
                                # Zachowaj najnowszą wiadomość od innych
                                if not newest_msg or ts > newest_msg.get('timestamp', ''):
                                    newest_msg = msg
                except:
                    continue
            
            # Zaktualizuj timestamp
            if latest_timestamp:
                self._last_chat_timestamp = latest_timestamp
            
            return newest_msg  # Zwróć dict z informacją lub None
        except:
            return None
    
    def show_chat_notification(self, msg_info):
        """Pokaż powiadomienie balonowe w tray o nowej wiadomości"""
        try:
            # Sprawdź czy powiadomienia są wyciszone
            if self._chat_notifications_muted_until:
                from datetime import datetime
                now = datetime.now()
                if now < self._chat_notifications_muted_until:
                    # Nadal wyciszone - nie pokazuj powiadomienia
                    print(f"🔕 Powiadomienia wyciszone do {self._chat_notifications_muted_until.strftime('%H:%M')}")
                    return
                else:
                    # Czas minął - anuluj wyciszenie
                    self._chat_notifications_muted_until = None
            
            # Pobierz informacje o wiadomości
            username = msg_info.get('display_name') or msg_info.get('username', 'Nieznany')
            message = msg_info.get('message', '')
            
            # Skróć wiadomość jeśli za długa
            if len(message) > 150:
                message = message[:147] + "..."
            
            # Stwórz własne okno powiadomienia (zamiast systemowego notify)
            self.show_custom_notification(username, message)
            
        except Exception as e:
            print(f"⚠️  Błąd powiadomienia: {e}")
    
    def show_custom_notification(self, username, message):
        """Własne okno powiadomienia - nie znika automatycznie"""
        try:
            # Jeśli już jest okno powiadomienia - zamknij stare
            if hasattr(self, '_notification_window') and self._notification_window:
                try:
                    self._notification_window.destroy()
                except:
                    pass
            
            # Utwórz nowe okno powiadomienia
            notif = tk.Toplevel(self)
            self._notification_window = notif
            
            notif.title("RM_BAZA - Nowa wiadomość")
            notif.configure(bg="#2c3e50")
            
            # Ustaw rozmiar i pozycję (prawy dolny róg work area - jak powiadomienia systemowe)
            width = 350
            # Wysokość będzie dynamiczna - tymczasowo ustaw na minimalną
            
            # Zmienne dla pozycjonowania
            x = 0
            monitor_top = 0
            screen_height = 0
            work_bottom = None
            
            # Wykryj work area monitora (obszar bez paska zadań) używając Windows API
            try:
                # Pobierz pozycję aplikacji głównej
                self.update_idletasks()
                app_x = self.winfo_rootx()
                app_y = self.winfo_rooty()
                
                # Metoda 1: Spróbuj użyć win32api (pywin32)
                work_area = None
                try:
                    import win32api
                    import win32con
                    
                    # Znajdź monitor na którym jest aplikacja
                    from win32api import GetMonitorInfo, MonitorFromPoint
                    monitor = MonitorFromPoint((app_x, app_y), win32con.MONITOR_DEFAULTTONEAREST)
                    monitor_info = GetMonitorInfo(monitor)
                    work_area = monitor_info['Work']  # (left, top, right, bottom)
                    print(f"📍 Wykryto work area przez win32api: {work_area}")
                except ImportError:
                    # Metoda 2: Użyj ctypes jeśli win32api nie jest dostępne
                    import ctypes
                    from ctypes import wintypes
                    
                    # Struktura RECT
                    class RECT(ctypes.Structure):
                        _fields_ = [
                            ('left', wintypes.LONG),
                            ('top', wintypes.LONG),
                            ('right', wintypes.LONG),
                            ('bottom', wintypes.LONG)
                        ]
                    
                    # Struktura MONITORINFO
                    class MONITORINFO(ctypes.Structure):
                        _fields_ = [
                            ('cbSize', wintypes.DWORD),
                            ('rcMonitor', RECT),
                            ('rcWork', RECT),
                            ('dwFlags', wintypes.DWORD)
                        ]
                    
                    user32 = ctypes.windll.user32
                    
                    # Znajdź monitor dla punktu aplikacji
                    MONITOR_DEFAULTTONEAREST = 2
                    point = wintypes.POINT(app_x, app_y)
                    hMonitor = user32.MonitorFromPoint(point, MONITOR_DEFAULTTONEAREST)
                    
                    # Pobierz informacje o monitorze
                    mi = MONITORINFO()
                    mi.cbSize = ctypes.sizeof(MONITORINFO)
                    user32.GetMonitorInfoW(hMonitor, ctypes.byref(mi))
                    
                    work_area = (mi.rcWork.left, mi.rcWork.top, mi.rcWork.right, mi.rcWork.bottom)
                    print(f"📍 Wykryto work area przez ctypes: {work_area}")
                
                if work_area:
                    # Work area to (left, top, right, bottom)
                    work_left, work_top, work_right, work_bottom_val = work_area
                    work_bottom = work_bottom_val
                    
                    # Pozycja: prawy dolny róg work area (gdzie są powiadomienia systemowe)
                    x = work_right - width - 10  # 10px marginesu od prawej krawędzi work area
                    monitor_top = work_top
                    screen_height = work_bottom - work_top
                else:
                    raise Exception("Nie udało się wykryć work area")
                    
            except Exception as e:
                print(f"⚠️ Błąd wykrywania work area: {e}, używam fallback")
                # Fallback - użyj prostego podejścia
                screen_width = notif.winfo_screenwidth()
                screen_height = notif.winfo_screenheight()
                x = screen_width - width - 10
                monitor_top = 0
            
            notif.attributes('-topmost', True)  # Zawsze na wierzchu
            notif.lift()  # Podnieś nad wszystkie okna
            # NIE używamy focus_force() - okno ma być widoczne ale BEZ zabierania focusa
            notif.resizable(False, False)
            notif.overrideredirect(True)  # Ukryj ramkę okna (bez paska tytułu)
            
            # Przycisk X do zamknięcia (w prawym górnym rogu)
            close_btn = tk.Label(
                notif,
                text="✕",
                bg="#2c3e50",
                fg="#95a5a6",
                font=("Arial", 14, "bold"),
                cursor="hand2",
                padx=8,
                pady=4
            )
            close_btn.place(relx=1.0, x=-5, y=5, anchor="ne")
            def _close_x_click(e):
                self._has_unread_messages = False
                self.update_tray_icon()
                try:
                    notif.destroy()
                except:
                    pass
                return "break"
            close_btn.bind("<Button-1>", _close_x_click)
            close_btn.bind("<Enter>", lambda e: close_btn.config(fg="white"))
            close_btn.bind("<Leave>", lambda e: close_btn.config(fg="#95a5a6"))
            close_btn._skip_chat_open = True
            
            # Treść
            content = tk.Frame(notif, bg="#2c3e50")
            content.pack(fill=tk.X, padx=15, pady=10)  # Zmienione z fill=tk.BOTH, expand=True
            
            # Ramka z informacją o użytkowniku i przyciskiem Zamknij
            user_header = tk.Frame(content, bg="#2c3e50")
            user_header.pack(fill=tk.X, pady=(0, 5))
            
            tk.Label(
                user_header,
                text=f"Od: {username}",
                bg="#2c3e50",
                fg="#ecf0f1",
                font=("Arial", 10, "bold"),
                anchor="w"
            ).pack(side=tk.LEFT)
            
            # Funkcja zamknięcia bez otwierania chatu - tylko oznacz jako przeczytane
            def close_and_mark_read():
                try:
                    notif.destroy()
                except:
                    pass
                # Oznacz jako przeczytane przy zamknięciu
                self._has_unread_messages = False
                self.update_tray_icon()
            
            close_button = tk.Button(
                user_header,
                text="Zamknij",
                bg="#e74c3c",
                fg="white",
                font=("Arial", 8, "bold"),
                cursor="hand2",
                relief=tk.RAISED,
                padx=10,
                pady=2
            )
            close_button.pack(side=tk.RIGHT)
            # Bind na ButtonRelease zamiast command - żeby kontrolować propagację
            def _close_btn_click(e):
                close_and_mark_read()
                return "break"  # Zatrzymaj propagację do parent
            close_button.bind("<ButtonRelease-1>", _close_btn_click)
            close_button.bind("<Button-1>", lambda e: "break")  # Zatrzymaj propagację kliknięcia
            
            # Text widget dla wiadomości (bez scrollbar)
            msg_frame = tk.Frame(content, bg="#2c3e50")
            msg_frame.pack(fill=tk.X, pady=0)  # Zmienione z fill=tk.BOTH, expand=True
            
            # Tymczasowy Text widget do obliczenia liczby linii
            msg_text = tk.Text(
                msg_frame,
                bg="#34495e",
                fg="white",
                font=("Arial", 9),
                wrap=tk.WORD,
                width=38,  # Szerokość ~320px dla Arial 9
                relief=tk.FLAT,
                padx=3,
                pady=2
            )
            msg_text.pack(side=tk.LEFT, fill=tk.X, expand=True)  # Zmienione z fill=tk.BOTH, expand=True
            
            msg_text.insert("1.0", message)
            msg_text.update_idletasks()  # Wymuś przeliczenie layoutu
            
            # Oblicz liczbę linii na podstawie rzeczywistego tekstu
            # Text widget ma szerokość ~38 znaków, czcionka Arial 9
            lines = message.split('\n') if message else ['']
            total_display_lines = 0
            
            for line in lines:
                if len(line) == 0:
                    total_display_lines += 1  # Pusta linia = 1 linia wyświetlana
                else:
                    # Oblicz ile linii zajmie po word wrap (max ~38 znaków na linię)
                    # word wrap dzieli po słowach, więc przybliżenie
                    chars_per_line = 38
                    words = line.split()
                    current_line_length = 0
                    lines_in_paragraph = 1
                    
                    for word in words:
                        word_len = len(word) + 1  # +1 dla spacji
                        if current_line_length + word_len > chars_per_line:
                            lines_in_paragraph += 1
                            current_line_length = word_len
                        else:
                            current_line_length += word_len
                    
                    total_display_lines += lines_in_paragraph
            
            text_height = max(1, min(5, total_display_lines))  # Od 1 do 5 wierszy
            
            # Ustaw wysokość Text widget
            msg_text.config(height=text_height, state=tk.DISABLED)
            
            # Dostosuj wysokość okna do liczby wierszy
            # Komponenty: user_header(30) + text(text_height*16) + mute(35) + padding(25)
            window_height = 90 + (text_height * 16)
            
            # Oblicz pozycję Y (dolna część work area - jak powiadomienia systemowe)
            if work_bottom is not None:
                # Użyj work area - dokładnie tam gdzie pojawiają się powiadomienia systemowe
                y = work_bottom - window_height - 10  # 10px marginesu od dolnej krawędzi work area
            else:
                # Fallback jeśli nie udało się wykryć work area
                y = notif.winfo_screenheight() - window_height - 40
            
            notif.geometry(f"{width}x{window_height}+{x}+{y}")
            notif.deiconify()  # Pokaż okno w właściwej pozycji
            
            # Funkcja wyciszenia powiadomień
            def mute_notifications(hours):
                from datetime import datetime, timedelta
                self._chat_notifications_muted_until = datetime.now() + timedelta(hours=hours)
                print(f"🔕 Powiadomienia wyciszone na {hours}h do {self._chat_notifications_muted_until.strftime('%H:%M')}")
                notif.destroy()
            
            # Ramka z przyciskami wyciszenia
            mute_frame = tk.Frame(notif, bg="#2c3e50")
            mute_frame.pack(fill=tk.X, padx=15, pady=0)
            
            # Przyciski wyciszenia (pakowane od prawej, w odwrotnej kolejności)
            for hours, label in [(2, "2h"), (1, "1h"), (0.5, "30min")]:
                btn = tk.Button(
                    mute_frame,
                    text=label,
                    bg="#34495e",
                    fg="white",
                    font=("Arial", 8),
                    cursor="hand2",
                    relief=tk.RAISED,
                    padx=8,
                    pady=2
                )
                btn.pack(side=tk.RIGHT, padx=3)
                # Bind na ButtonRelease zamiast command + zatrzymaj propagację
                btn.bind("<ButtonRelease-1>", lambda e, h=hours: (mute_notifications(h), "break")[-1])
                btn.bind("<Button-1>", lambda e: "break")
            
            tk.Label(
                mute_frame,
                text="🔕 Nie powiadamiaj przez:",
                bg="#2c3e50",
                fg="#95a5a6",
                font=("Arial", 8)
            ).pack(side=tk.LEFT)
            
            # Kliknięcie GDZIEKOLWIEK w okno powiadomienia otwiera chat
            def open_and_close(event=None):
                try:
                    notif.destroy()
                except:
                    pass
                self._has_unread_messages = False
                self.update_tray_icon()
                self.open_chat_window(bring_to_front=False)
            
            # Rekurencyjnie binduj kliknięcie do wszystkich widgetów
            # (oprócz przycisków które mają własne akcje)
            def bind_click_recursive(widget):
                # Sprawdź czy widget ma flagę _skip_chat_open - jeśli tak, pomiń go i jego dzieci
                if hasattr(widget, '_skip_chat_open') and widget._skip_chat_open:
                    return
                
                widget_class = widget.winfo_class()
                # Nie binduj do Button (mają własne komendy), Scrollbar, ani Text
                if widget_class not in ('Button', 'Scrollbar', 'Text'):
                    widget.bind("<Button-1>", open_and_close)
                
                # Rekurencyjnie dla dzieci
                for child in widget.winfo_children():
                    bind_click_recursive(child)
            
            bind_click_recursive(notif)
            
            # close_btn X jest już zabezpieczony flagą _skip_chat_open + return "break"
            
        except Exception as e:
            print(f"⚠️  Błąd custom notification: {e}")
    
    # ====================================================================
    # TRAY ICON
    # ====================================================================
    
    def create_tray_image(self, has_notification=False):
        """Stwórz ikonę dla tray (zielona lub czerwona kropka)"""
        # Utwórz obraz 64x64
        width = 64
        height = 64
        image = Image.new('RGB', (width, height), color='white')
        draw = ImageDraw.Draw(image)
        
        # Rysuj koło
        padding = 8
        color = '#FF0000' if has_notification else '#008800'  # Czerwony lub zielony
        draw.ellipse([padding, padding, width-padding, height-padding], fill=color, outline='black', width=2)
        
        # Dodaj literę "C" (Chat)
        # Prosty sposób - rysuj małe białe koło w środku jako "C"
        # (w produkcji użyłbyś czcionki)
        center_x = width // 2
        center_y = height // 2
        inner_radius = 12
        
        return image
    
    def start_tray_icon(self):
        """Uruchom ikonę w tray w osobnym wątku"""
        if not TRAY_AVAILABLE:
            return
        
        def run_tray():
            try:
                # Utwórz ikonę
                image = self.create_tray_image(has_notification=False)
                
                # Menu kontekstowe (prawy przycisk)
                menu = pystray.Menu(
                    pystray.MenuItem("💬 Otwórz Chat", self.tray_open_chat),
                    pystray.MenuItem("🔔 Pokaż okno główne", self.tray_show_window),
                    pystray.Menu.SEPARATOR,
                    pystray.MenuItem("❌ Zamknij aplikację", self.tray_quit)
                )
                
                # Callback dla lewego przycisku - natychmiastowe otwarcie chatu
                def on_left_click(icon, item):
                    try:
                        self.after(0, self._tray_show_chat)
                    except Exception as e:
                        self._safe_print(f"❌ on_left_click: {e}")
                
                self.tray_icon = pystray.Icon(
                    "RM_BAZA",
                    image,
                    "RM_BAZA - Click = Chat",
                    menu=menu,
                    on_activate=on_left_click
                )
                
                # Uruchom w trybie blokującym (w tym wątku)
                self.tray_icon.run()
                
            except Exception as e:
                self._safe_print(f"⚠️  Błąd tray icon: {e}")
                import traceback
                traceback.print_exc()
        
        # Uruchom w osobnym wątku
        self.tray_thread = threading.Thread(target=run_tray, daemon=True)
        self.tray_thread.start()
        self._safe_print("✅ Tray icon uruchomiony")
    
    def update_tray_icon(self):
        """Zaktualizuj ikonę tray (zmień kolor jeśli są nieprzeczytane)"""
        if not self.tray_icon:
            return
        
        try:
            image = self.create_tray_image(has_notification=self._has_unread_messages)
            self.tray_icon.icon = image
        except Exception as e:
            print(f"⚠️  Błąd aktualizacji tray: {e}")
    
    def _tray_show_chat(self):
        """Pokaż/utwórz okno chatu z tray - na wierzchu BEZ zabierania focusa"""
        # Zapamiętaj aktualnie aktywne okno (np. przeglądarkę)
        saved_hwnd = None
        try:
            import ctypes
            saved_hwnd = ctypes.windll.user32.GetForegroundWindow()
        except:
            pass
        
        try:
            if self.chat_window and self.chat_window.winfo_exists():
                self.chat_window.refresh_messages()
                self.chat_window.deiconify()
                self.chat_window.attributes('-topmost', True)
                self.chat_window.lift()
                # Zaktualizuj timestamp - użytkownik widzi wiadomości
                ts = self.chat_window.get_last_timestamp()
                if ts:
                    self._last_chat_timestamp = ts
            else:
                self.chat_window = ChatWindow(self, self.db_manager, self.current_user, self.current_user_id)
                # NIE nadpisuj _last_chat_timestamp wartością None z niezaładowanego okna
            
            self._has_unread_messages = False
            self.update_tray_icon()
        except Exception as e:
            self._safe_print(f"❌ _tray_show_chat: {e}")
        
        # Przywróć focus do poprzedniej aplikacji
        # Trik: symulacja Alt key up zwalnia Windows foreground lock
        # dzięki czemu SetForegroundWindow zadziała dla innego procesu
        if saved_hwnd:
            def _restore_focus():
                try:
                    import ctypes
                    # Symuluj Alt key release - zwalnia foreground lock w Windows
                    ctypes.windll.user32.keybd_event(0x12, 0, 0x0002, 0)
                    # Teraz SetForegroundWindow zadziała
                    ctypes.windll.user32.SetForegroundWindow(saved_hwnd)
                except:
                    pass
            self.after(150, _restore_focus)
    
    def tray_open_chat(self, icon=None, item=None):
        """Callback: otwórz okno chatu z tray (menu kontekstowe)"""
        try:
            self.after(0, self._tray_show_chat)
        except Exception as e:
            self._safe_print(f"❌ tray_open_chat: {e}")
    
    def tray_show_window(self, icon=None, item=None):
        """Callback: pokaż główne okno aplikacji"""
        self.after(0, lambda: (self.deiconify(), self.lift(), self.focus_force()))
    
    def tray_quit(self, icon=None, item=None):
        """Callback: zamknij aplikację"""
        self.after(0, self.on_closing)
    
    def stop_tray_icon(self):
        """Zatrzymaj ikonę tray"""
        if self.tray_icon:
            try:
                self.tray_icon.stop()
            except:
                pass
    
    # ====================================================================
    # ZAMYKANIE
    # ====================================================================
    
    def on_closing(self):
        """Zamykanie aplikacji"""
        if not self._initialized:
            # Inicjalizacja nie zakończona - po prostu zamknij
            self.destroy()
            return
        
        if self.have_lock:
            # Dialog z 3 opcjami: Zwolnić / Anulować / Anuluj zamykanie
            dlg = tk.Toplevel(self)
            dlg.title("⚠️ Masz lock!")
            dlg.geometry("650x250")
            dlg.transient(self)
            dlg.grab_set()
            dlg.resizable(False, False)
            
            # Wycentruj
            dlg.update_idletasks()
            x = self.winfo_x() + (self.winfo_width() // 2) - (325)
            y = self.winfo_y() + (self.winfo_height() // 2) - (125)
            dlg.geometry(f"650x250+{x}+{y}")
            
            result = {"action": None}
            
            # Główny frame
            main_frame = tk.Frame(dlg, bg="#f8f9fa")
            main_frame.pack(fill=tk.BOTH, expand=True, padx=20, pady=20)
            
            # Komunikat
            tk.Label(
                main_frame, 
                text=f"🔒 Masz lock na projekcie {self.current_project_id}",
                bg="#f8f9fa",
                font=("Arial", 12, "bold"),
                fg="#2c3e50"
            ).pack(pady=(0, 10))
            
            tk.Label(
                main_frame, 
                text="Co chcesz zrobić przed zamknięciem aplikacji?",
                bg="#f8f9fa",
                font=("Arial", 10),
                fg="#34495e"
            ).pack(pady=(0, 25))
            
            # Frame na przyciski (wycentrowany)
            btn_frame = tk.Frame(main_frame, bg="#f8f9fa")
            btn_frame.pack(anchor=tk.CENTER)
            
            def on_release():
                result["action"] = "release"
                dlg.destroy()
            
            def on_cancel():
                result["action"] = "cancel"
                dlg.destroy()
            
            def on_abort():
                result["action"] = "abort"
                dlg.destroy()
            
            # Przyciski - 3 w poziomie
            tk.Button(
                btn_frame,
                text="✅ Zwolnić lock\n(zapisz do bazy)",
                command=on_release,
                width=16,
                height=3,
                bg="#27ae60",
                fg="white",
                font=("Arial", 9, "bold"),
                relief=tk.RAISED,
                bd=2,
                cursor="hand2"
            ).grid(row=0, column=0, padx=8, pady=5)
            
            tk.Button(
                btn_frame,
                text="🗑️ Anulować lock\n(DISCARD zmiany)",
                command=on_cancel,
                width=16,
                height=3,
                bg="#e67e22",
                fg="white",
                font=("Arial", 9, "bold"),
                relief=tk.RAISED,
                bd=2,
                cursor="hand2"
            ).grid(row=0, column=1, padx=8, pady=5)
            
            tk.Button(
                btn_frame,
                text="❌ Nie zamykaj\n(pozostaw otwarty)",
                command=on_abort,
                width=16,
                height=3,
                bg="#95a5a6",
                fg="white",
                font=("Arial", 9),
                relief=tk.RAISED,
                bd=2,
                cursor="hand2"
            ).grid(row=0, column=2, padx=8, pady=5)
            
            # Czekaj na wybór
            dlg.wait_window()
            
            # Wykonaj akcję
            if result["action"] == "release":
                self.release_lock()
            elif result["action"] == "cancel":
                cancelled = self.cancel_lock()
                if not cancelled:
                    return  # Użytkownik zrezygnował z anulowania - NIE zamykaj aplikacji
            elif result["action"] == "abort":
                return  # NIE zamykaj aplikacji
            else:
                return  # Zamknięto dialog bez wyboru - NIE zamykaj
        
        # Zatrzymaj timer heartbeat
        self._stop_heartbeat_timer()
        
        # WAŻNE: Zwolnij wszystkie locki przed zamknięciem
        # (na wypadek gdyby coś zostało - zabezpieczenie przed crashem)
        if self.lock_manager:
            print("🧹 Czyszczenie wszystkich locków przed zamknięciem...")
            try:
                # Spróbuj cleanup w tle BEZ czekania (aby nie blokować zamknięcia)
                import threading
                cleanup_thread = threading.Thread(
                    target=self._cleanup_locks_best_effort,
                    daemon=True
                )
                cleanup_thread.start()
                # NIE używamy join() - niech działa w tle, nie blokujemy zamknięcia
                print("  → Cleanup locków uruchomiony w tle")
            except Exception as cleanup_err:
                print(f"⚠️  Błąd podczas uruchamiania cleanup locków: {cleanup_err}")
        
        # Zapisz szerokości kolumn przed zamknięciem (lokalny plik - szybkie)
        try:
            self._save_column_widths()
        except Exception as e:
            print(f"⚠️  Błąd zapisu szerokości kolumn: {e}")
        
        # Zamknij połączenia - BEZ czekania (może się zawiesić na dysku sieciowym)
        if self.db_manager:
            try:
                print("🔌 Zamykanie połączeń z bazą (w tle)...")
                import threading
                close_thread = threading.Thread(
                    target=self._close_db_best_effort,
                    daemon=True
                )
                close_thread.start()
                # NIE używamy join() - niech działa w tle
                print("  → Zamykanie połączeń uruchomione w tle")
            except Exception as db_err:
                print(f"⚠️  Błąd zamykania połączeń: {db_err}")
        
        # Usuń app lock (lokalny plik - szybkie)
        if self.app_lock_file:
            try:
                release_single_instance_lock(self.app_lock_file)
            except Exception as e:
                print(f"⚠️  Błąd usuwania app lock: {e}")
        
        # Zatrzymaj tray icon
        self.stop_tray_icon()
        
        # NATYCHMIASTOWE zamknięcie procesu - nie czekaj na wątki/cleanup
        # os._exit() pomija wszystkie cleanup handlery i zamyka proces TERAZ
        print("👋 Zamykanie aplikacji...")
        import os
        os._exit(0)  # Exit code 0 = sukces
    
    def _cleanup_locks_best_effort(self):
        """Helper: cleanup locków z obsługą błędów (uruchamiany w wątku)"""
        try:
            self.lock_manager.cleanup_all_my_locks()
            print("  ✅ Cleanup locków zakończony")
        except Exception as e:
            print(f"  ⚠️  Cleanup locków failed: {e}")
    
    def _close_db_best_effort(self):
        """Helper: zamknięcie bazy z obsługą błędów (uruchamiany w wątku)"""
        try:
            self.db_manager.close_all()
            print("  ✅ Połączenia zamknięte")
        except Exception as e:
            print(f"  ⚠️  Zamykanie połączeń failed: {e}")


