    def _load_ui_layout_from_db(self):
        """Wczytaj ui_layout bezpośrednio z sync_config.json (przed inicjalizacją db_manager)"""
        print("🔍 Próbuję wczytać ui_layout z sync_config.json...")
        try:
            import sqlite3
            # Użyj globalnej zmiennej CONFIG_FILE (LOCAL_DIR/sync_config.json)
            global CONFIG_FILE
            print(f"  📁 Config: {CONFIG_FILE}")
            if CONFIG_FILE.exists():
                print("  ✅ sync_config.json istnieje")
                with open(CONFIG_FILE) as f:
                    config = json.load(f)
                    # Odczytaj ui_layout z sekcji ui
                    ui_layout = config.get('ui', {}).get('layout')
                    print(f"  📊 ui.layout z pliku: {ui_layout}")
                    if ui_layout and ui_layout in ['NORMAL', 'MINI']:
                        print(f"  ✅ Wczytano ui_layout: {ui_layout}")
                        return ui_layout
                    else:
                        # Ustaw domyślną wartość i zapisz do configu
                        default_layout = 'NORMAL'
                        print("  ℹ️  Brak ui.layout - ustawiam domyślnie: NORMAL")
                        try:
                            self.save_ui_layout_setting(default_layout)
                        except Exception:
                            pass
                        return default_layout
            else:
                print(f"  ❌ sync_config.json nie istnieje: {CONFIG_FILE}")
        except Exception as e:
            print(f"  ⚠️  Błąd wczytywania ui_layout: {e}")
            import traceback
            traceback.print_exc()
        print("  ℹ️  Używam domyślnego ui_layout: NORMAL")
        return 'NORMAL'
    
    def refresh_ui_layout(self):
        """Przebuduj UI po zmianie ui_layout (bez restartu)"""
        # Ta metoda nie jest obecnie używana - zamiast tego robimy restart
        # Mogłaby przebudować top_frame, top_frame2, bottom_frame
        # Ale to wymaga dużo pracy, więc zostawiamy restart
        pass
    
    def load_ui_layout_setting(self):
        """Wczytaj ustawienie ui_layout z sync_config.json (domyślnie NORMAL)"""
        try:
            global CONFIG_FILE
            if CONFIG_FILE and CONFIG_FILE.exists():
                with open(CONFIG_FILE) as f:
                    config = json.load(f)
                    layout = config.get('ui', {}).get('layout')
                    if layout in ['NORMAL', 'MINI']:
                        return layout
        except Exception as e:
            print(f"⚠️  Błąd odczytu ui_layout: {e}")
        return 'NORMAL'  # Domyślnie
    
    def save_ui_layout_setting(self, layout):
        """Zapisz ustawienie ui_layout do sync_config.json"""
        try:
            global CONFIG_FILE
            # Wczytaj istniejący config
            if CONFIG_FILE.exists():
                with open(CONFIG_FILE) as f:
                    config = json.load(f)
            else:
                config = {}
            
            # Aktualizuj ui.layout
            if 'ui' not in config:
                config['ui'] = {}
            config['ui']['layout'] = layout
            
            # Zapisz
            with open(CONFIG_FILE, 'w') as f:
                json.dump(config, f, indent=2)
            
            print(f"✅ Zapisano ui_layout={layout} do {CONFIG_FILE}")
            return True
        except Exception as e:
            print(f"⚠️  Błąd zapisu ui_layout: {e}")
            import traceback
            traceback.print_exc()
            return False
    
