    def reload_ui(self):
        """Restart aplikacji (zamknij i uruchom ponownie)"""
        try:
            import sys
            import os
            
            messagebox.showinfo(
                "Restart",
                "Aplikacja zostanie teraz zrestartowana.\n\nPo ponownym uruchomieniu widok będzie zaktualizowany."
            )
            
            # Zamknij bieżącą aplikację
            self.on_closing()
            
            # Uruchom ponownie
            python = sys.executable
            os.execl(python, python, *sys.argv)
            
        except Exception as e:
            messagebox.showerror("Błąd", f"Nie udało się zrestartować:\n{e}")
            import traceback
            traceback.print_exc()
    
