        def browse_file(entry, title):
            """Przeglądaj plik"""
            filename = filedialog.askopenfilename(
                title=title,
                filetypes=[("SQLite DB", "*.sqlite"), ("Wszystkie pliki", "*.*")]
            )
            if filename:
                entry.delete(0, tk.END)
                entry.insert(0, filename)
        
        def browse_dir(entry, title):
            """Przeglądaj folder"""
            dirname = filedialog.askdirectory(title=title)
            if dirname:
                entry.delete(0, tk.END)
                entry.insert(0, dirname)
        
        def save_and_close():
            """Zapisz konfigurację i zamknij dialog"""
            master_path = e_master.get().strip()
            projects_dir = e_projects.get().strip()
            local_dir = e_local.get().strip()
            locks_dir = e_locks.get().strip()
            backup_dir = e_backup.get().strip()
            
            # Walidacja
            if not master_path:
                messagebox.showerror("Błąd", "Musisz podać ścieżkę do master.sqlite!", parent=dlg)
                return
            
            if not Path(master_path).exists():
                response = messagebox.askyesno(
                    "Plik nie istnieje",
                    f"Plik nie istnieje:\n{master_path}\n\nCzy chcesz kontynuować?",
                    parent=dlg
                )
                if not response:
                    return
            
            # Zapisz do configu
            try:
                config = {
                    "client": {
                        "name": socket.gethostname(),
                        "rank": 1
                    },
                    "paths": {
                        "master": master_path,
                        "projects_dir": projects_dir,
                        "local_dir": local_dir,
                        "locks_dir": locks_dir,
                        "backup_dir": backup_dir
                    },
                    "locks": {
                        "folder": locks_dir
                    }
                }
                
                # Utwórz folder lokalny
                Path(local_dir).mkdir(parents=True, exist_ok=True)
                
                # Zapisz config
                config_path = Path(local_dir) / "sync_config.json"
                with open(config_path, 'w') as f:
                    json.dump(config, f, indent=2)
                
                print(f"✅ Konfiguracja zapisana: {config_path}")
                
                # Aktualizuj globalne zmienne
                global MASTER_PATH, PROJECTS_DIR, LOCAL_DIR, LOCKS_DIR, BACKUP_DIR, CONFIG_FILE
                MASTER_PATH = master_path
                PROJECTS_DIR = projects_dir
                LOCAL_DIR = local_dir
                LOCKS_DIR = locks_dir
                BACKUP_DIR = backup_dir
                CONFIG_FILE = config_path
                
                result_var.set(True)
                dlg.destroy()
                
            except Exception as e:
                messagebox.showerror("Błąd zapisu", f"Nie można zapisać konfiguracji:\n{e}", parent=dlg)
        
        # Przyciski
        btn_frame = tk.Frame(main_frame, bg="#ecf0f1")
        btn_frame.pack(pady=(25, 0))
        
        tk.Button(
            btn_frame,
            text="💾 Zapisz i kontynuuj",
            command=save_and_close,
            bg="#27ae60",
            fg="white",
            font=("Arial", 12, "bold"),
            padx=25,
            pady=10,
            relief=tk.RAISED,
            bd=3,
            cursor="hand2"
        ).pack(side=tk.LEFT, padx=10)
        
        tk.Button(
            btn_frame,
            text="❌ Anuluj",
            command=dlg.destroy,
            bg="#e74c3c",
            fg="white",
            font=("Arial", 12, "bold"),
            padx=25,
            pady=10,
            relief=tk.RAISED,
            bd=3,
            cursor="hand2"
        ).pack(side=tk.LEFT, padx=10)
        
        # Czekaj na zamknięcie dialogu
        dlg.wait_window()
        
        return result_var.get()
    
