    def _safe_filename_part(self, text: str) -> str:
        """Bezpieczna część nazwy pliku (bez znaków specjalnych)"""
        if not text:
            return ""
        safe = re.sub(r'[<>:"/\\|?*]', '_', str(text))
        safe = safe.replace('\n', '_').replace('\r', '_')
        return safe.strip()
    
    def _save_print_column_selection(self, selected_cols):
        """Zapisz wybór kolumn do druku w lokalnym pliku JSON"""
        try:
            global CONFIG_FILE
            CONFIG_FILE.parent.mkdir(parents=True, exist_ok=True)
            
            # Wczytaj istniejący config lub utwórz nowy
            config = {}
            if CONFIG_FILE.exists():
                try:
                    with open(CONFIG_FILE, 'r') as f:
                        config = json.load(f)
                except Exception as e:
                    print(f"  ⚠️  Nie można wczytać config: {e}")
            
            # Dodaj/zaktualizuj wybrane kolumny do druku
            config['print_columns_selected'] = selected_cols
            
            # Zapisz
            with open(CONFIG_FILE, 'w') as f:
                json.dump(config, f, indent=2)
            
            print(f"  ✅ Zapisano wybór kolumn do druku: {selected_cols}")
            
        except Exception as e:
            print(f"⚠️  Błąd zapisu wyboru kolumn: {e}")
    
    def _load_print_column_selection(self):
        """Wczytaj wybór kolumn do druku z lokalnego pliku JSON"""
        try:
            global CONFIG_FILE
            
            # Sprawdź czy plik config istnieje
            if not CONFIG_FILE.exists():
                return None
            
            # Wczytaj config
            try:
                with open(CONFIG_FILE, 'r') as f:
                    config = json.load(f)
            except Exception as e:
                print(f"  ⚠️  Błąd wczytywania config: {e}")
                return None
            
            # Pobierz wybrane kolumny
            if 'print_columns_selected' not in config:
                return None
            
            selected = config['print_columns_selected']
            # Konwertuj wszystkie wartości na int (na wypadek gdyby JSON zapisał jako stringi)
            selected = [int(x) for x in selected]
            print(f"  📋 Wczytano zapisany wybór kolumn do druku: {selected}")
            return selected
            
        except Exception as e:
            print(f"⚠️  Błąd wczytania wyboru kolumn: {e}")
            return None
    
    def print_to_default_printer(self):
        """Drukuj widoczne dane bezpośrednio na domyślną drukarkę z wyborem kolumn"""
        # Sprawdź uprawnienia
        allowed_roles = ["USER", "USER$", "USER$$", "ADMIN"]
        if self.current_user_role not in allowed_roles:
            messagebox.showwarning(
                "Brak uprawnień", 
                "Tylko użytkownicy z rolą USER, USER$, USER$$ lub ADMINISTRATOR mogą drukować dane."
            )
            return
        
        if not self.current_project_id:
            messagebox.showwarning("Błąd", "Nie wybrano projektu!")
            return
        
        # Sprawdź czy jest reportlab
        try:
            from reportlab.lib.pagesizes import A4, landscape
            from reportlab.lib import colors
            from reportlab.lib.units import mm
            from reportlab.platypus import SimpleDocTemplate, Table, TableStyle, Paragraph
            from reportlab.lib.styles import getSampleStyleSheet
        except ImportError:
            messagebox.showerror(
                "Brak biblioteki",
                "Drukowanie wymaga biblioteki reportlab.\n\n"
                "Zainstaluj: pip install reportlab"
            )
            return
        
        # Dialog wyboru kolumn
        dialog = tk.Toplevel(self)
        dialog.title("Wybierz kolumny do druku")
        dialog.geometry("400x600")
        dialog.transient(self)
        dialog.grab_set()
        # Wycentruj na ekranie
        dialog.update_idletasks()
        sw = dialog.winfo_screenwidth()
        sh = dialog.winfo_screenheight()
        x = (sw - 400) // 2
        y = (sh - 600) // 2
        dialog.geometry(f"400x600+{x}+{y}")
        
        tk.Label(
            dialog,
            text="Zaznacz kolumny do wydrukowania:",
            font=("Arial", 12, "bold"),
            pady=10
        ).pack()
        
        # Wszystkie możliwe kolumny (indeksy jak w GUI) + LP na początku
        all_columns = [
            (-1, "LP"),  # Kolumna LP (numer porządkowy) - zawsze dodawana
            (0, "Nr rysunku"),
            (1, "Nazwa"),
            (2, "Opis"),
            (3, "Ilość BOM"),
            (4, "Ilość (zam.)"),
            (5, "Δ"),
            (6, "Ilość dostarczonych"),
            (7, "Typ"),
            (8, "Materiał"),
            (9, "Grubość [mm]"),
            (10, "Dostawca"),
            (11, "Cena PLN"),
            (12, "Zamówiono"),
            (13, "Termin dostawy"),
            (14, "ALARM"),
            (15, "Uwagi"),
            # 16 - DWF_BIB ukryta
            (17, "ODEBRANE"),
            (18, "Moduł")
        ]
        
        # Wczytaj zapisane kolumny z JSON lub użyj domyślnych
        saved_selected = self._load_print_column_selection()
        if saved_selected is not None:
            default_selected = saved_selected
        else:
            # Domyślnie wybrane kolumny (podstawowe) + LP
            default_selected = [-1, 0, 1, 3, 4, 8, 9, 10, 13]  # LP, Nr, Nazwa, Ilość BOM/Zam, Mat, Grub, Dostawca, Termin
        
        column_vars = {}
        
        frame = tk.Frame(dialog)
        frame.pack(fill=tk.BOTH, expand=True, padx=20, pady=10)
        
        # Scrollbar
        canvas = tk.Canvas(frame)
        scrollbar = tk.Scrollbar(frame, orient="vertical", command=canvas.yview)
        scrollable_frame = tk.Frame(canvas)
        
        scrollable_frame.bind(
            "<Configure>",
            lambda e: canvas.configure(scrollregion=canvas.bbox("all"))
        )
        
        canvas.create_window((0, 0), window=scrollable_frame, anchor="nw")
        canvas.configure(yscrollcommand=scrollbar.set)
        
        for col_idx, col_name in all_columns:
            var = tk.BooleanVar(value=(col_idx in default_selected))
            column_vars[col_idx] = var
            tk.Checkbutton(
                scrollable_frame,
                text=col_name,
                variable=var,
                font=("Arial", 10)
            ).pack(anchor="w", pady=2)
        
        canvas.pack(side="left", fill="both", expand=True)
        scrollbar.pack(side="right", fill="y")
        
        result = {"cancelled": True, "selected_cols": [], "action": "print"}
        
        def on_print():
            result["selected_cols"] = [idx for idx, var in column_vars.items() if var.get()]
            if not result["selected_cols"]:
                messagebox.showwarning("Brak kolumn", "Zaznacz przynajmniej jedną kolumnę!", parent=dialog)
                return
            result["cancelled"] = False
            result["action"] = "print"
            # Zapisz wybór do JSON
            self._save_print_column_selection(result["selected_cols"])
            dialog.destroy()
        
        def on_save_pdf():
            result["selected_cols"] = [idx for idx, var in column_vars.items() if var.get()]
            if not result["selected_cols"]:
                messagebox.showwarning("Brak kolumn", "Zaznacz przynajmniej jedną kolumnę!", parent=dialog)
                return
            result["cancelled"] = False
            result["action"] = "save"
            # Zapisz wybór do JSON
            self._save_print_column_selection(result["selected_cols"])
            dialog.destroy()
        
        def on_cancel():
            dialog.destroy()
        
        btn_frame = tk.Frame(dialog)
        btn_frame.pack(pady=10)
        
        tk.Button(
            btn_frame,
            text="� ZAPISZ PDF",
            command=on_save_pdf,
            bg="#3498db",
            fg="white",
            font=("Arial", 10, "bold"),
            padx=20
        ).pack(side=tk.LEFT, padx=5)
        
        tk.Button(
            btn_frame,
            text="�🖨️ Drukuj",
            command=on_print,
            bg="#27ae60",
            fg="white",
            font=("Arial", 10, "bold"),
            padx=20
        ).pack(side=tk.LEFT, padx=5)
        
        tk.Button(
            btn_frame,
            text="❌ Anuluj",
            command=on_cancel,
            bg="#95a5a6",
            fg="white",
            font=("Arial", 10),
            padx=20
        ).pack(side=tk.LEFT, padx=5)
        
        dialog.wait_window()
        
        if result["cancelled"]:
            return
        
        # Upewnij się że wszystkie indeksy są intami
        selected_cols = [int(x) for x in sorted(result["selected_cols"])]
        action = result.get("action", "print")
        
        # Ustaw row_factory aby móc używać dict() na wynikach zapytań
        original_row_factory = self.db_manager.project_con.row_factory
        
        # Generuj PDF i drukuj lub zapisz
        try:
            import tempfile
            import subprocess
            import platform
            import os
            from datetime import datetime
            
            # Wykryj system operacyjny (potrzebne do wyboru czcionek)
            system = platform.system()
            
            # Określ ścieżkę PDF w zależności od akcji
            if action == "save":
                # Zapisz w C:\RMPAK_CLIENT\PDF\ z nazwą projektu
                save_dir = r"C:\RMPAK_CLIENT\PDF"
                os.makedirs(save_dir, exist_ok=True)
                
                # Pobierz nazwę projektu wcześniej aby użyć w nazwie pliku
                cursor = self.db_manager.master_con.execute(
                    "SELECT name FROM projects WHERE project_id = ?",
                    (self.current_project_id,)
                )
                row = cursor.fetchone()
                project_name_raw = row[0] if row else f"Projekt_{self.current_project_id}"
                
                # Nazwa pliku: NazwaProjektu_YYYYMMDD_HHMMSS.pdf
                safe_name = "".join(c if c.isalnum() or c in (' ', '_', '-') else '_' for c in project_name_raw)
                timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
                pdf_filename = f"{safe_name}_{timestamp}.pdf"
                pdf_path = os.path.join(save_dir, pdf_filename)
            else:
                # Tryb drukowania - użyj tymczasowego pliku
                with tempfile.NamedTemporaryFile(suffix=".pdf", delete=False) as tmp:
                    pdf_path = tmp.name
            
            # Pobierz nazwę projektu
            cursor = self.db_manager.master_con.execute(
                "SELECT name FROM projects WHERE project_id = ?",
                (self.current_project_id,)
            )
            row = cursor.fetchone()
            project_name = row[0] if row else f"Projekt {self.current_project_id}"
            
            # Buduj informację o filtrach (jak w export_to_xlsx)
            filter_parts = []
            
            # Klasa
            class_filter = self.filter_class_var.get()
            if class_filter and class_filter not in ("(WSZYSTKO)", "(WSZYSCY)"):
                filter_parts.append(f"Klasa: {class_filter}")
            
            # Dostawca
            supplier_filter = self.filter_supplier_var.get()
            if supplier_filter and supplier_filter not in (FILTER_SUPPLIER_ALL, "(WSZYSCY)", "(WSZYSTKO)"):
                if supplier_filter == SUPPLIER_EMPTY:
                    filter_parts.append("Dostawca: BRAK")
                else:
                    filter_parts.append(f"Dostawca: {supplier_filter}")
            
            # Filtry checkboxowe
            if self.only_missing_supplier_var.get():
                filter_parts.append("Brak dostawcy")
            if self.only_overdue_var.get():
                filter_parts.append("Po terminie")
            if self.only_biblioteka_var.get():
                filter_parts.append("Biblioteka")
            if self.only_manual_var.get():
                filter_parts.append("Dodane ręcznie")
            if self.only_ordered_var.get():
                filter_parts.append("Zamówione")
            if self.only_to_order_var.get():
                filter_parts.append("Do zamówienia")
            if self.only_alarm_yellow_var.get():
                filter_parts.append("Żółty alarm")
            if self.only_alarm_red_var.get():
                filter_parts.append("Czerwony alarm")
            if self.only_delivered_var.get():
                filter_parts.append("Dostarczono")
            if self.only_not_delivered_var.get():
                filter_parts.append("Nie dostarczono")
            
            # Moduł
            if self.filter_modul_selected:
                moduls_sorted = sorted(self.filter_modul_selected)
                if len(moduls_sorted) <= 3:
                    moduls_str = ", ".join(moduls_sorted)
                    filter_parts.append(f"Moduł: {moduls_str}")
                else:
                    filter_parts.append(f"Moduł: {len(moduls_sorted)} wybranych")
            
            # Grubość
            if self.filter_grub_selected:
                grub_sorted = sorted(self.filter_grub_selected, key=lambda x: float(x) if x.replace('.', '', 1).replace('-', '', 1).isdigit() else float('inf'))
                if len(grub_sorted) <= 3:
                    grub_str = ", ".join(grub_sorted)
                    filter_parts.append(f"Grubość: {grub_str} mm")
                else:
                    filter_parts.append(f"Grubość: {len(grub_sorted)} wybranych")
            
            # Backup
            if self.viewing_backup and self.backup_date:
                filter_parts.append(f"Backup: {self.backup_date}")
            
            # Utwórz string z filtrami
            filter_text = " | ".join(filter_parts) if filter_parts else "Brak filtrów"
            
            # Buduj dane do druku
            # all_columns ma format [(idx, name), ...] gdzie idx=-1 to LP
            headers = []
            col_mapping = {}  # Mapowanie: pozycja w selected_cols -> idx kolumny
            for pos, col_idx in enumerate(selected_cols):
                col_idx = int(col_idx)  # Upewnij się że to int
                # Znajdź nazwę kolumny
                for idx, name in all_columns:
                    if int(idx) == col_idx:
                        headers.append(name)
                        col_mapping[pos] = col_idx
                        break
            
            # Przygotuj style dla Paragraph (zawijanie tekstu)
            from reportlab.lib.styles import ParagraphStyle
            from reportlab.lib.enums import TA_LEFT
            
            data_rows = [headers]
            row_number = 1  # LP zaczyna się od 1
            
            # Ustaw row_factory dlaSQL Row objects
            self.db_manager.project_con.row_factory = sqlite3.Row
            
            # Pobierz widoczne wiersze
            for row_idx in range(len(self._sheet_row_ids)):
                item_id = self._sheet_row_ids[row_idx]
                cursor = self.db_manager.project_con.execute(
                    "SELECT * FROM items WHERE id = ?", (item_id,)
                )
                item = cursor.fetchone()
                if not item:
                    continue
                
                item_dict = dict(item)
                
                # Buduj wiersz zgodnie z logiką z refresh_data
                row_data = []
                
                for pos, col_idx in enumerate(selected_cols):
                    # ZAWSZE NAJPIERW sprawdź LP - to nie jest kolumna z bazy!
                    col_idx = int(col_idx)  # Upewnij się że to int
                    
                    if col_idx == -1:  # LP (numer porządkowy) - bez dostępu do bazy
                        val = str(row_number)
                    elif col_idx == 0:  # Nr rysunku
                        val = item_dict.get("work_drawing_no") or item_dict.get("src_drawing_no") or ""
                    elif col_idx == 1:  # Nazwa
                        val = item_dict.get("work_name") or item_dict.get("src_name") or ""
                    elif col_idx == 2:  # Opis
                        val = item_dict.get("work_desc") or item_dict.get("src_desc") or ""
                    elif col_idx == 3:  # Ilość BOM
                        work_qty = item_dict.get("work_qty")
                        src_qty = item_dict.get("src_qty") or 0
                        qty_bom = work_qty if work_qty is not None else src_qty
                        val = str(int(qty_bom)) if qty_bom else ""
                    elif col_idx == 4:  # Ilość zam
                        order_qty = item_dict.get("order_qty")
                        val = str(int(order_qty)) if order_qty else ""
                    elif col_idx == 5:  # Delta
                        order_qty = item_dict.get("order_qty")
                        work_qty = item_dict.get("work_qty")
                        src_qty = item_dict.get("src_qty") or 0
                        qty_bom = work_qty if work_qty is not None else src_qty
                        if order_qty is not None and qty_bom:
                            delta = int(order_qty) - int(qty_bom)
                            val = str(delta)
                        else:
                            val = ""
                    elif col_idx == 6:  # Ilość dostarczona
                        delivered = item_dict.get("delivered_qty")
                        val = str(int(delivered)) if delivered else ""
                    elif col_idx == 7:  # Typ
                        val = item_dict.get("class_effective") or ""
                        # Skróć ZNORMALIZOWANE -> ZNORM
                        if val == "ZNORMALIZOWANE":
                            val = "ZNORM"
                    elif col_idx == 8:  # Materiał
                        val = item_dict.get("mat_effective_text") or ""
                    elif col_idx == 9:  # Grubość
                        thick = item_dict.get("thickness_mm")
                        val = f"{thick} mm" if thick else ""
                    elif col_idx == 10:  # Dostawca
                        sup_id = item_dict.get("supplier_id")
                        if sup_id:
                            sup_row = self.db_manager.master_con.execute(
                                "SELECT name FROM suppliers WHERE supplier_id = ?", (sup_id,)
                            ).fetchone()
                            val = sup_row[0] if sup_row else ""
                        else:
                            val = ""
                    elif col_idx == 11:  # Cena
                        price = item_dict.get("price_pln")
                        val = f"{price:.2f}" if price else ""
                    elif col_idx == 12:  # Zamówiono
                        ordered_flag = item_dict.get("ordered_flag")
                        ordered_at = item_dict.get("ordered_at") or ""
                        if ordered_flag:
                            od = ordered_at[:10] if len(ordered_at) >= 10 else ordered_at
                            val = f"✓ {od}" if od else "✓"
                        else:
                            val = ""
                    elif col_idx == 13:  # Termin
                        deadline = item_dict.get("deadline_date")
                        val = deadline if deadline else ""
                    elif col_idx == 14:  # ALARM
                        val = ""  # Pomiń ALARM w druku
                    elif col_idx == 15:  # Uwagi
                        val = item_dict.get("notes") or ""
                    elif col_idx == 17:  # ODEBRANE
                        # Sprawdź czy delivered_qty >= order_qty (lub qty_bom jeśli order_qty brak)
                        delivered = item_dict.get("delivered_qty")
                        order_qty_check = item_dict.get("order_qty")
                        if order_qty_check is None:
                            work_qty_check = item_dict.get("work_qty")
                            src_qty_check = item_dict.get("src_qty") or 0
                            order_qty_check = work_qty_check if work_qty_check is not None else src_qty_check
                        if delivered is not None and order_qty_check is not None:
                            val = "●" if float(delivered) >= float(order_qty_check) else ""
                        else:
                            val = ""
                    elif col_idx == 18:  # Moduł
                        val = item_dict.get("work_modul") or item_dict.get("src_modul") or ""
                    else:
                        val = ""
                    
                    row_data.append(str(val))  # Tymczasowo jako string, zamienimy później
                
                data_rows.append(row_data)
                row_number += 1  # Inkrementuj LP
            
            # Twórz PDF
            doc = SimpleDocTemplate(
                pdf_path,
                pagesize=A4,  # Portrait (pionowo)
                topMargin=10*mm,
                bottomMargin=10*mm,
                leftMargin=10*mm,
                rightMargin=10*mm
            )
            
            # Zarejestruj czcionkę obsługującą polskie znaki (Unicode)
            from reportlab.pdfbase import pdfmetrics
            from reportlab.pdfbase.ttfonts import TTFont
            
            font_name = "Helvetica"  # Domyślna
            font_name_bold = "Helvetica-Bold"
            
            # Spróbuj użyć czcionek systemowych obsługujących Unicode
            try:
                if system == "Windows":
                    # Windows - Arial.ttf
                    pdfmetrics.registerFont(TTFont('ArialUnicode', 'arial.ttf'))
                    pdfmetrics.registerFont(TTFont('ArialUnicode-Bold', 'arialbd.ttf'))
                    font_name = 'ArialUnicode'
                    font_name_bold = 'ArialUnicode-Bold'
                    print("✅ Użyto czcionki Arial (Unicode)")
                elif system == "Linux":
                    # Linux - DejaVuSans.ttf
                    pdfmetrics.registerFont(TTFont('DejaVuSans', '/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf'))
                    pdfmetrics.registerFont(TTFont('DejaVuSans-Bold', '/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf'))
                    font_name = 'DejaVuSans'
                    font_name_bold = 'DejaVuSans-Bold'
                    print("✅ Użyto czcionki DejaVuSans (Unicode)")
                elif system == "Darwin":
                    # macOS - Helvetica (system)
                    pdfmetrics.registerFont(TTFont('ArialUnicode', '/System/Library/Fonts/Supplemental/Arial.ttf'))
                    pdfmetrics.registerFont(TTFont('ArialUnicode-Bold', '/System/Library/Fonts/Supplemental/Arial Bold.ttf'))
                    font_name = 'ArialUnicode'
                    font_name_bold = 'ArialUnicode-Bold'
                    print("✅ Użyto czcionki Arial (Unicode)")
            except Exception as font_err:
                print(f"⚠️  Nie udało się załadować czcionki Unicode: {font_err}")
                print("⚠️  Użycie domyślnej Helvetica (polskie znaki mogą być niepoprawne)")
            
            # Stwórz style dla Paragraph (automatyczne zawijanie tekstu)
            header_style = ParagraphStyle(
                'HeaderStyle',
                fontName=font_name_bold,
                fontSize=10,
                textColor=colors.black,
                alignment=TA_LEFT,
                leading=12,
                wordWrap='CJK'
            )
            data_style = ParagraphStyle(
                'DataStyle',
                fontName=font_name,
                fontSize=9,
                textColor=colors.black,
                alignment=TA_LEFT,
                leading=11,
                wordWrap='CJK'
            )
            
            # Oblicz optymalne szerokości kolumn na podstawie zawartości
            page_width = A4[0] - 20*mm  # Portrait (pionowo)
            max_widths = []
            
            for col_idx in range(len(headers)):
                # Szerokość nagłówka
                try:
                    header_width = pdfmetrics.stringWidth(str(data_rows[0][col_idx]), font_name_bold, 10)
                except:
                    header_width = len(str(data_rows[0][col_idx])) * 6  # Fallback: 6pt na znak
                
                max_width = header_width + 15  # Header + padding
                
                # Szerokość najdłuższej wartości w kolumnie
                for row_idx in range(1, len(data_rows)):
                    cell_text = str(data_rows[row_idx][col_idx])
                    try:
                        width = pdfmetrics.stringWidth(cell_text, font_name, 9)
                    except:
                        width = len(cell_text) * 5  # Fallback: 5pt na znak
                    
                    max_width = max(max_width, width + 12)  # Data + padding
                
                # Ogranicz szerokość (min 30pt, max 40% strony)
                max_width = max(30, min(max_width, page_width * 0.4))
                max_widths.append(max_width)
            
            # Znormalizuj szerokości aby suma = page_width
            total_width = sum(max_widths)
            if total_width > page_width:
                # Zmniejsz proporcjonalnie jeśli za szerokie
                col_widths = [(w / total_width) * page_width for w in max_widths]
            else:
                # Użyj rzeczywistych szerokości jeśli mieszczą się
                col_widths = max_widths
            
            # Zamień nagłówki i dane na Paragraph dla zawijania tekstu
            data_rows[0] = [Paragraph(str(h), header_style) for h in data_rows[0]]
            for i in range(1, len(data_rows)):
                data_rows[i] = [Paragraph(str(cell), data_style) for cell in data_rows[i]]
            
            # Styl tabeli - BEZ tła nagłówka, z automatycznym zawijaniem
            table = Table(data_rows, colWidths=col_widths, repeatRows=1)
            table.setStyle(TableStyle([
                # USUNIĘTO: ('BACKGROUND', (0, 0), (-1, 0), colors.grey) - brak tła nagłówka
                ('TEXTCOLOR', (0, 0), (-1, 0), colors.black),  # Czarny tekst nagłówka
                ('ALIGN', (0, 0), (-1, -1), 'LEFT'),
                ('BOTTOMPADDING', (0, 0), (-1, 0), 8),
                ('GRID', (0, 0), (-1, -1), 0.5, colors.black),
                ('VALIGN', (0, 0), (-1, -1), 'TOP'),  # TOP zamiast MIDDLE dla zawijanych tekstów
                ('LEFTPADDING', (0, 0), (-1, -1), 3),
                ('RIGHTPADDING', (0, 0), (-1, -1), 3),
            ]))
            
            # Dodaj tytuł i informację o filtrach
            styles = getSampleStyleSheet()
            # Użyj tej samej czcionki dla tytułu
            styles['Title'].fontName = font_name_bold
            styles['Normal'].fontName = font_name
            
            title = Paragraph(f"<b>{project_name}</b>", styles['Title'])
            
            # Dodaj informację o filtrach pod tytułem
            filter_style = ParagraphStyle(
                'FilterStyle',
                parent=styles['Normal'],
                fontName=font_name,
                fontSize=9,
                textColor=colors.grey,
                alignment=TA_LEFT,
                spaceAfter=10
            )
            filter_info = Paragraph(f"<i>{filter_text}</i>", filter_style)
            
            elements = [title, filter_info, table]
            doc.build(elements)
            
            print(f"📄 PDF wygenerowany: {pdf_path}")
            
            # Obsłuż akcję: save lub print
            if action == "save":
                # Tryb zapisu - otwórz PDF w przeglądarce BEZ powiadomienia
                try:
                    os.startfile(pdf_path)
                    print(f"✅ PDF zapisany: {pdf_path}")
                except Exception as e:
                    print(f"✅ PDF zapisany (nie otwarto): {pdf_path} - {e}")
            else:
                # Tryb drukowania - wyślij na drukarkę (w zależności od systemu)
                try:
                    if system == "Windows":
                        # Windows - otwórz PDF normalnie, użytkownik kliknie Ctrl+P
                        os.startfile(pdf_path)
                        print(f"✅ Otwarto PDF: {pdf_path}")
                    
                    elif system == "Linux":
                        # Linux - użyj lp (CUPS)
                        result = subprocess.run(
                            ["lp", pdf_path],
                            capture_output=True,
                            text=True,
                            timeout=10
                        )
                        
                        if result.returncode == 0:
                            messagebox.showinfo(
                                "Drukowanie",
                                f"Dokument wysłany na drukarkę!\n\n"
                                f"Projekt: {project_name}\n"
                                f"Wierszy: {len(data_rows)-1}\n"
                                f"Kolumn: {len(headers)}"
                            )
                            print(f"✅ Wysłano na drukarkę: {result.stdout}")
                        else:
                            messagebox.showerror(
                                "Błąd drukowania",
                                f"Nie udało się wysłać na drukarkę:\n\n{result.stderr}"
                            )
                            print(f"❌ Błąd drukowania: {result.stderr}")
                        
                    elif system == "Darwin":
                        # macOS - użyj lpr
                        result = subprocess.run(
                            ["lpr", pdf_path],
                            capture_output=True,
                            text=True,
                            timeout=10
                        )
                        
                        if result.returncode == 0:
                            messagebox.showinfo(
                                "Drukowanie",
                                f"Dokument wysłany na drukarkę!\n\n"
                                f"Projekt: {project_name}\n"
                                f"Wierszy: {len(data_rows)-1}\n"
                                f"Kolumn: {len(headers)}"
                            )
                            print(f"✅ Wysłano na drukarkę macOS")
                        else:
                            messagebox.showerror(
                                "Błąd drukowania",
                                f"Nie udało się wysłać na drukarkę:\n\n{result.stderr}"
                            )
                            print(f"❌ Błąd drukowania: {result.stderr}")
                    else:
                        # Nieznany system
                        messagebox.showwarning(
                            "Nieobsługiwany system",
                            f"Automatyczne drukowanie nie jest obsługiwane na {system}.\n\n"
                            f"PDF zapisany w: {pdf_path}\n\n"
                            "Otwórz plik ręcznie i wydrukuj."
                        )
                    
                except FileNotFoundError:
                    messagebox.showerror(
                        "Brak systemowego polecenia druku",
                        f"Nie znaleziono polecenia drukowania dla {system}.\n\n"
                        f"PDF zapisany w: {pdf_path}\n\n"
                        "Otwórz plik ręcznie i wydrukuj."
                    )
                except subprocess.TimeoutExpired:
                    messagebox.showerror(
                        "Timeout",
                        "Przekroczono czas oczekiwania na drukarkę."
                    )
                except Exception as print_err:
                    messagebox.showerror(
                        "Błąd drukowania",
                        f"Nie udało się wysłać na drukarkę:\n\n{print_err}\n\n"
                        f"PDF zapisany w: {pdf_path}\n\n"
                        "Otwórz plik ręcznie i wydrukuj."
                    )
            
        except Exception as e:
            messagebox.showerror("Błąd", f"Błąd drukowania:\n\n{e}")
            import traceback
            traceback.print_exc()
        finally:
            # Przywróć oryginalny row_factory
            self.db_manager.project_con.row_factory = original_row_factory
    
    def export_to_xlsx(self):
        """Export widocznych danych do XLSX z nazwą: PROJEKT + FILTRY"""
        # Sprawdź uprawnienia - tylko USER, USER$, USER$$, ADMINISTRATOR
        allowed_roles = ["USER", "USER$", "USER$$", "ADMIN"]
        if self.current_user_role not in allowed_roles:
            messagebox.showwarning(
                "Brak uprawnień", 
                "Tylko użytkownicy z rolą USER, USER$, USER$$ lub ADMINISTRATOR mogą exportować dane."
            )
            return
        
        if not openpyxl:
            messagebox.showerror("Błąd", "Brak biblioteki openpyxl!\n\nZainstaluj: pip install openpyxl")
            return
        
        if not self.current_project_id:
            messagebox.showwarning("Błąd", "Nie wybrano projektu!")
            return
        
        # Ustaw row_factory aby móc używać dict() na wynikach zapytań
        original_row_factory = self.db_manager.project_con.row_factory
        self.db_manager.project_con.row_factory = sqlite3.Row
        
        try:
            # Pobierz nazwę projektu
            cursor = self.db_manager.master_con.execute(
                "SELECT name FROM projects WHERE project_id = ?",
                (self.current_project_id,)
            )
            row = cursor.fetchone()
            project_name = row[0] if row else f"PROJEKT_{self.current_project_id}"
            
            # Buduj nazwę pliku z filtrami
            name_parts = [self._safe_filename_part(project_name)]
            
            # Dodaj aktywne filtry do nazwy
            class_filter = self.filter_class_var.get()
            if class_filter and class_filter not in ("(WSZYSTKO)", "(WSZYSCY)"):
                name_parts.append(self._safe_filename_part(class_filter))
            
            supplier_filter = self.filter_supplier_var.get()
            if supplier_filter and supplier_filter not in (FILTER_SUPPLIER_ALL, "(WSZYSCY)", "(WSZYSTKO)"):
                if supplier_filter == SUPPLIER_EMPTY:
                    name_parts.append("BRAK_DOSTAWCY")
                else:
                    name_parts.append(self._safe_filename_part(supplier_filter))
            
            if self.only_missing_supplier_var.get():
                name_parts.append("BRAK_DOSTAWCY")
            if self.only_overdue_var.get():
                name_parts.append("PO_TERMINIE")
            if self.only_biblioteka_var.get():
                name_parts.append("BIBLIOTEKA")
            if self.only_manual_var.get():
                name_parts.append("DODANE")
            if self.only_ordered_var.get():
                name_parts.append("ZAMOWIONE")
            if self.only_to_order_var.get():
                name_parts.append("DO_ZAMOWIENIA")
            if self.only_alarm_yellow_var.get():
                name_parts.append("ZOLTY_ALARM")
            if self.only_alarm_red_var.get():
                name_parts.append("CZERWONY_ALARM")
            if self.only_delivered_var.get():
                name_parts.append("DOSTARCZONO")
            if self.only_not_delivered_var.get():
                name_parts.append("NIE_DOSTARCZONO")
            
            # Filtr Moduł
            if self.filter_modul_selected:
                # Jeśli zaznaczone moduły, dodaj je do nazwy
                moduls_sorted = sorted(self.filter_modul_selected)
                if len(moduls_sorted) <= 3:
                    # Jeśli max 3 moduły, wypisz wszystkie
                    moduls_str = "_".join([self._safe_filename_part(m) for m in moduls_sorted])
                    name_parts.append(f"MODUL_{moduls_str}")
                else:
                    # Jeśli więcej niż 3, tylko numer
                    name_parts.append(f"MODUL_FILTR_{len(moduls_sorted)}")
            
            # Filtr Grubość
            if self.filter_grub_selected:
                # Jeśli zaznaczone grubości, dodaj je do nazwy
                grub_sorted = sorted(self.filter_grub_selected, key=lambda x: float(x) if x.replace('.', '', 1).replace('-', '', 1).isdigit() else float('inf'))
                if len(grub_sorted) <= 3:
                    # Jeśli max 3 grubości, wypisz wszystkie
                    grub_str = "_".join([self._safe_filename_part(g) for g in grub_sorted])
                    name_parts.append(f"GRUB_{grub_str}")
                else:
                    # Jeśli więcej niż 3, tylko numer
                    name_parts.append(f"GRUB_FILTR_{len(grub_sorted)}")
            
            # Jeśli przeglądamy backup, dodaj datę
            if self.viewing_backup and self.backup_date:
                name_parts.append(f"BACKUP_{self.backup_date}")
            
            initialfile = " - ".join([p for p in name_parts if p]) + ".xlsx"
            
            # Dialog zapisu
            path = filedialog.asksaveasfilename(
                title="Eksport XLSX",
                defaultextension=".xlsx",
                filetypes=[("Excel", "*.xlsx")],
                initialfile=initialfile
            )
            
            if not path:
                return
            
            # Pobierz nagłówki (18 kolumn jak w UI)
            headers = [
                "Nr rysunku", "Nazwa", "Opis",
                "Ilość BOM", "Ilość (zam.)", "Δ", "Ilość dostarczonych",
                "Typ", "Materiał", "Grubość [mm]", "Dostawca",
                "Cena PLN", "Zamówiono", "Termin dostawy", "ALARM",
                "Uwagi", "DWF_BIB", "ODEBRANE", "Moduł"
            ]
            
            # Helper: fmt_qty jak w UI (linie 2990-2999)
            def fmt_qty(val):
                if val is None:
                    return ""
                try:
                    f = float(val)
                    if f == int(f):
                        return str(int(f))
                    return f"{f:.2f}".rstrip('0').rstrip('.')
                except:
                    return str(val)
            
            def fmt_delivered_qty(val):
                """Formatuj ilość dostarczoną - jeśli 0 to pusta komórka"""
                if val is None:
                    return ""
                try:
                    f = float(val)
                    if f == 0:
                        return ""
                    if f == int(f):
                        return str(int(f))
                    return f"{f:.2f}".rstrip('0').rstrip('.')
                except:
                    return str(val)
            
            # Pobierz dane z bazy (widoczne wiersze na arkuszu)
            rows = []
            for row_idx in range(len(self._sheet_row_ids)):
                item_id = self._sheet_row_ids[row_idx]
                
                # Pobierz item z bazy
                cursor = self.db_manager.project_con.execute(
                    "SELECT * FROM items WHERE id = ?", (item_id,)
                )
                item = cursor.fetchone()
                if not item:
                    continue
                
                # Wyciągnij item jako dict
                item_dict = dict(item)
                
                # Buduj wiersz (18 kolumn)
                drawing = item_dict.get("work_drawing_no") or item_dict.get("src_drawing_no") or ""
                name = item_dict.get("work_name") or item_dict.get("src_name") or ""
                desc = item_dict.get("work_desc") or item_dict.get("src_desc") or ""
                
                # qty_bom (Ilość BOM) - COALESCE(work_qty, src_qty) jak w UI
                src_qty = item_dict.get("src_qty") or 0
                work_qty = item_dict.get("work_qty")
                qty_bom = work_qty if work_qty is not None else src_qty
                
                # order_qty (Ilość zam.) - oblicz dla WAREHOUSE z mnożnikami
                order_qty = item_dict.get("order_qty")
                order_qty_display = order_qty if order_qty is not None else qty_bom
                
                # === MNOŻENIE DLA WAREHOUSE ===
                project_type = self._get_internal_project_type()
                if project_type == "WAREHOUSE":
                    # Pobierz MODUŁ
                    modul_raw = item_dict.get("work_modul") or item_dict.get("src_modul") or ""
                    
                    if modul_raw:
                        import re
                        # Parsuj moduły i oblicz wynik mnożenia
                        parts = [p.strip() for p in modul_raw.split(',')]
                        multiplied_qty = 0
                        
                        for part in parts:
                            # Parsuj format: NAZWA(ilość)xmnożnik lub NAZWA(ilość)
                            match = re.match(r'([^(]+)\s*\((\d+)\)(?:x(\d+))?', part)
                            if match:
                                try:
                                    modul_qty = int(match.group(2))
                                    multiplier = int(match.group(3)) if match.group(3) else 1
                                    multiplied_qty += modul_qty * multiplier
                                except:
                                    pass
                        
                        # Jeśli udało się obliczyć - użyj wyniku
                        if multiplied_qty > 0:
                            order_qty_display = multiplied_qty
                
                # Delta = order_qty - qty_bom
                delta_disp = ""
                try:
                    delta_val = int(round(float(order_qty_display) - float(qty_bom)))
                    delta_disp = str(delta_val)
                    # Dodaj kropkę dla pozycji ręcznych (is_manual == 1)
                    if item_dict.get('is_manual') == 1:
                        delta_disp = f"{delta_disp} ●"
                except:
                    delta_disp = ""
                
                delivered = item_dict.get("delivered_qty")
                
                # Oblicz target_qty dla ODEBRANE - użyj order_qty_display (uwzględnia mnożniki WAREHOUSE)
                target_qty = order_qty_display
                
                # Typ: skróć ZNORMALIZOWANE → ZNORM (linie 3296-3298)
                class_eff = item_dict.get("class_effective") or ""
                if class_eff == "ZNORMALIZOWANE":
                    class_eff = "ZNORM"
                
                mat_eff = item_dict.get("mat_effective_text") or ""
                
                # Grubość - jak w UI (linie 3298-3345)
                thickness_disp = ""
                thick_raw = item_dict.get("thickness_mm")
                
                if thick_raw is not None:
                    # Formatuj thickness_mm - jeśli całkowita, bez dziesiętnych
                    try:
                        if float(thick_raw) == int(float(thick_raw)):
                            thickness_disp = str(int(float(thick_raw)))
                        else:
                            thickness_disp = f"{float(thick_raw):.2f}".rstrip('0').rstrip('.')
                    except:
                        thickness_disp = str(thick_raw)
                else:
                    # Sparsuj z materiału (mat_auto_text lub mat_manual_text)
                    try:
                        mat_auto = item_dict.get("mat_auto_text") or ""
                        mat_manual = item_dict.get("mat_manual_text") or ""
                        mat_text = mat_manual if mat_manual else mat_auto
                        
                        if mat_text:
                            # Parsuj "304 gr8mm" → 8.0
                            from import_bom import parse_thickness_mm
                            thick_parsed = parse_thickness_mm(mat_text)
                            if thick_parsed:
                                try:
                                    if float(thick_parsed) == int(float(thick_parsed)):
                                        thickness_disp = str(int(float(thick_parsed)))
                                    else:
                                        thickness_disp = f"{float(thick_parsed):.2f}".rstrip('0').rstrip('.')
                                except:
                                    thickness_disp = str(thick_parsed)
                    except:
                        pass
                
                supplier_id = item_dict.get("supplier_id")
                supplier_name = ""
                if supplier_id:
                    supplier_name = self.suppliers_map.get(supplier_id, "")
                
                # Cena: formatowanie jak w UI (linie 3277-3282) - nie pokazuj 0
                price = ""
                try:
                    price_raw = item_dict.get("price_pln")
                    if price_raw is not None and str(price_raw).strip():
                        price_val = float(price_raw)
                        if price_val != 0:
                            price = f"{price_val:.2f}"
                except:
                    price = ""
                
                # Zamówiono: jak w UI (linie 3256-3260)
                ordered_flag = item_dict.get("ordered_flag") or 0
                ordered_at = item_dict.get("ordered_at") or ""
                ordered_display = ""
                if ordered_flag:
                    od = ordered_at if ordered_at else ""
                    if len(od) >= 10:
                        od = od[:10]
                    ordered_display = f"✓ {od}" if od else "✓"
                
                # Termin dostawy: skróć do 10 znaków jak w UI (linia 3271-3273)
                deadline = item_dict.get("deadline_date") or ""
                if len(deadline) >= 10:
                    deadline = deadline[:10]
                
                # ALARM: sformatowany jak w UI (linie 3262-3268) np. "7d" lub "2w"
                alarm_display = ""
                try:
                    alarm_offset = item_dict.get("alarm_offset")
                    if alarm_offset and int(alarm_offset) > 0:
                        u = (item_dict.get("alarm_unit") or "D").upper()
                        alarm_display = f"{int(alarm_offset)}{u.lower()}"
                except:
                    alarm_display = ""
                
                notes = item_dict.get("notes") or ""
                
                # DWF_BIB: konwersja do int jak w UI (linia 3358)
                try:
                    dwf = str(int(item_dict.get("dwf_biblioteka") or 0))
                except:
                    dwf = "0"
                
                # ODEBRANE: kropka jak w UI (logika z linii 3286-3290)
                odebrane = ""
                if delivered is not None and target_qty is not None:
                    if float(delivered) >= float(target_qty):
                        odebrane = "●"
                
                # Moduł: COALESCE(work_modul, src_modul)
                modul = ""
                try:
                    modul_work = item_dict.get("work_modul")
                    modul_src = item_dict.get("src_modul")
                    modul = modul_work if modul_work else (modul_src or "")
                except (KeyError, TypeError):
                    modul = ""
                
                # ILOŚĆ BOM: jeśli WAREHOUSE i więcej niż jeden moduł, pokaż symbol (jak w UI)
                qty_bom_display = fmt_qty(qty_bom)
                if project_type == "WAREHOUSE" and modul and ',' in modul:
                    qty_bom_display = "●"
                
                row = [
                    drawing, name, desc,
                    qty_bom_display, fmt_qty(order_qty_display), delta_disp, fmt_delivered_qty(delivered),
                    class_eff, mat_eff, thickness_disp, supplier_name,
                    price, ordered_display, deadline, alarm_display,
                    notes, dwf, odebrane, modul
                ]
                rows.append(row)
            
            print(f"📊 Export: {len(rows)} wierszy danych")
            
            # Twórz workbook
            wb = openpyxl.Workbook()
            ws = wb.active
            ws.title = "ITEMS_EXPORT"
            
            # Nagłówki
            ws.append(list(headers))
            
            # Dane
            for r in rows:
                ws.append(list(r))
            
            # Dostosuj szerokości kolumn
            for col_idx, h in enumerate(headers, start=1):
                col_letter = get_column_letter(col_idx)
                
                # Nazwa i Opis - 3cm (około 30 znaków)
                if h in ("Nazwa", "Opis"):
                    ws.column_dimensions[col_letter].width = 30
                else:
                    # Reszta - auto
                    max_len = len(str(h))
                    for row in ws.iter_rows(min_row=2, min_col=col_idx, max_col=col_idx):
                        v = row[0].value
                        if v is not None:
                            max_len = max(max_len, len(str(v)))
                    ws.column_dimensions[col_letter].width = min(max_len + 2, 60)
            
            # Zapisz
            wb.save(path)
            
            print(f"✅ Eksport XLSX: {path}")
            print(f"   Wierszy: {len(rows)}")
            
        except Exception as e:
            messagebox.showerror("Błąd eksportu", f"Nie udało się wyeksportować:\n{e}")
            import traceback
            traceback.print_exc()
        finally:
            # Przywróć oryginalny row_factory
            self.db_manager.project_con.row_factory = original_row_factory
    
    # ========================================================================
    # WYSZUKIWANIE PLIKÓW (DWF, PDF, DXF, STP, STL)
    # ========================================================================
    
    def _scan_directory_for_file(self, directory: Path, drawing_no: str, extension: str, excluded_dirs: set) -> list:
        """Rekurencyjnie skanuj katalog w poszukiwaniu pliku z numerem rysunku i rozszerzeniem.
        
        Args:
            directory: Katalog do przeskanowania
            drawing_no: Numer rysunku do znalezienia
            extension: Rozszerzenie pliku (np. "dwf", "pdf")
            excluded_dirs: Zbiór nazw katalogów do pominięcia
        
        Returns:
            Lista znalezionych plików (Path objects)
        """
        found_files = []
        
        try:
            if not directory.exists() or not directory.is_dir():
                return found_files
            
            # Przeglądaj pliki i podkatalogi
            for item in directory.iterdir():
                # Pomiń wykluczone katalogi
                if item.is_dir():
                    if item.name in excluded_dirs:
                        continue
                    # Rekurencyjnie przeszukaj podkatalog
                    found_files.extend(self._scan_directory_for_file(item, drawing_no, extension, excluded_dirs))
                
                # Sprawdź plik
                elif item.is_file():
                    # Sprawdź czy nazwa pliku zawiera numer rysunku i ma odpowiednie rozszerzenie
                    if item.suffix.lower() == f".{extension.lower()}":
                        # Sprawdź czy nazwa pliku zawiera numer rysunku (case-insensitive)
                        if drawing_no.lower() in item.stem.lower():
                            found_files.append(item)
        
        except PermissionError:
            # Pomiń katalogi do których nie mamy dostępu
            pass
        except Exception as e:
            print(f"⚠️  Błąd skanowania {directory}: {e}")
        
        return found_files
    
    def search_in_project(self):
        """Szukaj plików w katalogu projektu na serwerze"""
        category = self.file_category_var.get()
        
        # Walidacja: czy projekt wybrany
        if not self.current_project_id:
            messagebox.showwarning(
                "Brak projektu",
                "Wybierz projekt aby wyszukać pliki."
            )
            return
        
        # Pobierz zaznaczony wiersz
        try:
            sel = self.sheet.get_currently_selected()
            if not sel:
                messagebox.showwarning(
                    "Brak zaznaczenia",
                    "Zaznacz wiersz z numerem rysunku aby wyszukać plik."
                )
                return
            
            # Parsuj row
            row_idx = None
            if isinstance(sel, dict):
                row_idx = sel.get("row", sel.get("r"))
            elif isinstance(sel, (tuple, list)) and len(sel) >= 1:
                row_idx = sel[0]
            
            if row_idx is None or row_idx < 0:
                messagebox.showwarning(
                    "Błąd zaznaczenia",
                    "Nie można odczytać zaznaczonego wiersza."
                )
                return
            
            # Pobierz numer rysunku z zaznaczonego wiersza (kolumna 0)
            row_data = self.sheet.get_row_data(row_idx)
            if not row_data or len(row_data) == 0:
                messagebox.showwarning(
                    "Błąd danych",
                    "Nie można odczytać danych z zaznaczonego wiersza."
                )
                return
            
            drawing_no = str(row_data[0]).strip()  # Kolumna 0 = Numer rysunku
            
            if not drawing_no:
                messagebox.showwarning(
                    "Brak numeru rysunku",
                    "Zaznaczony wiersz nie ma numeru rysunku."
                )
                return
        
        except Exception as e:
            messagebox.showerror(
                "Błąd",
                f"Nie można odczytać zaznaczonego wiersza:\n{e}"
            )
            return
        
        # Pobierz nazwę projektu z listy
        project_name = None
        for pid, pname in self.projects_list:
            if pid == self.current_project_id:
                project_name = pname
                break
        
        if not project_name:
            messagebox.showerror(
                "Błąd",
                f"Nie znaleziono nazwy projektu dla ID: {self.current_project_id}"
            )
            return
        
        # Wyekstrahuj numer projektu z nazwy (pierwsza część przed spacją)
        # np. "2610 Sigma" -> "2610", "ZP121 Zetor zbiornik" -> "ZP121"
        project_number = project_name.split()[0] if ' ' in project_name else project_name
        
        # Wyekstrahuj prefiks z numeru rysunku (pierwsza część przed myślnikiem)
        # np. "027-200.01 Korpus potrójny" -> "027"
        drawing_prefix = drawing_no.split('-')[0].strip() if '-' in drawing_no else None
        
        print(f"\n🔍 WYSZUKIWANIE PLIKU")
        print(f"   Projekt: {project_name} (ID: {self.current_project_id})")
        print(f"   Numer projektu: {project_number}")
        print(f"   Numer rysunku: {drawing_no}")
        if drawing_prefix and drawing_prefix != project_number:
            print(f"   Prefiks rysunku: {drawing_prefix}")
        print(f"   Typ pliku: {category}")
        print(f"   Serwer: {SERVER_DIR}")
        
        # Sprawdź czy ścieżka serwera istnieje
        server_path = Path(SERVER_DIR)
        if not server_path.exists():
            messagebox.showerror(
                "Błąd",
                f"Ścieżka serwera nie istnieje:\n{SERVER_DIR}\n\n"
                f"Skonfiguruj ścieżkę w:\nUstawienia → Konfiguracja ścieżek → Serwer projekty"
            )
            return
        
        # Znajdź katalogi projektów zaczynające się od numeru projektu
        project_dirs = []
        seen_dirs = set()
        try:
            for item in server_path.iterdir():
                if item.is_dir() and item.name.startswith(project_number):
                    project_dirs.append(item)
                    seen_dirs.add(item.name)
                    print(f"   ✓ Znaleziono katalog (projekt): {item.name}")
            
            # Dodatkowo: katalogi zaczynające się od prefiksu numeru rysunku
            if drawing_prefix and drawing_prefix != project_number:
                for item in server_path.iterdir():
                    if item.is_dir() and item.name.startswith(drawing_prefix) and item.name not in seen_dirs:
                        project_dirs.append(item)
                        seen_dirs.add(item.name)
                        print(f"   ✓ Znaleziono katalog (rysunek {drawing_prefix}): {item.name}")
        except Exception as e:
            messagebox.showerror(
                "Błąd",
                f"Nie można odczytać katalogów na serwerze:\n{e}"
            )
            return
        
        if not project_dirs:
            messagebox.showinfo(
                "Nie znaleziono",
                f"Nie znaleziono katalogów projektu zaczynających się od:\n{project_number}\n\n"
                f"Na serwerze: {SERVER_DIR}"
            )
            return
        
        # Katalogi do wykluczenia (NIGDY nie skanować)
        excluded_dirs = {
            "OldVersions",
            "Design Data",
            "Importowane komponenty",
            "Templates",
            "@Recycle",
            "@recycle",
            "$RECYCLE.BIN"
        }
        
        # Skanuj katalogi w poszukiwaniu pliku
        print(f"\n📂 Skanowanie katalogów...")
        found_files = []
        
        for proj_dir in project_dirs:
            print(f"   Skanowanie: {proj_dir.name}...")
            files = self._scan_directory_for_file(proj_dir, drawing_no, category, excluded_dirs)
            found_files.extend(files)
        
        # Wyświetl wynik
        if found_files:
            print(f"\n✅ ZNALEZIONO {len(found_files)} plik(ów):")
            for f in found_files:
                print(f"   📄 {f}")
            
            # Jeśli więcej niż 1 plik - pokaż listę wyboru
            if len(found_files) > 1:
                self._show_file_list_dialog(found_files, drawing_no, category)
            else:
                # Jeden plik - pokaż standardowy dialog
                self._show_file_open_dialog(found_files[0], drawing_no, category)
            
        else:
            print(f"\n❌ NIE ZNALEZIONO pliku {category.upper()} dla rysunku: {drawing_no}")
            messagebox.showinfo(
                "Nie znaleziono",
                f"Nie znaleziono pliku {category.upper()} dla rysunku:\n{drawing_no}\n\n"
                f"Przeszukane katalogi:\n" + "\n".join([f"• {d.name}" for d in project_dirs])
            )
    
    def _save_file_category_to_config(self, event=None):
        """Zapisz wybraną kategorię pliku do JSON config"""
        try:
            category = self.file_category_var.get()
            
            # Wczytaj config
            if not CONFIG_FILE.exists():
                return
            
            with open(CONFIG_FILE, 'r') as f:
                config = json.load(f)
            
            # Zaktualizuj wartość
            if 'ui' not in config:
                config['ui'] = {}
            config['ui']['last_file_category'] = category
            
            # Zapisz config
            with open(CONFIG_FILE, 'w') as f:
                json.dump(config, f, indent=2)
            
            print(f"💾 Zapisano kategorię pliku: {category}")
        except Exception as e:
            print(f"⚠️ Błąd zapisu kategorii pliku: {e}")
    
    def _show_file_list_dialog(self, file_paths: list, drawing_no: str, category: str):
        """Wyświetl okno dialogowe z listą wielu plików do wyboru
        
        Args:
            file_paths: Lista ścieżek do znalezionych plików
            drawing_no: Numer rysunku
            category: Kategoria pliku (DWF, PDF, etc.)
        """
        from datetime import datetime, timedelta
        
        dialog = tk.Toplevel(self)
        dialog.title("Wybierz plik")
        dialog.resizable(True, True)
        dialog.grab_set()
        dialog.lift()
        dialog.focus_force()
        
        # Frame główny
        main_frame = tk.Frame(dialog, bg="#f0f0f0", padx=20, pady=20)
        main_frame.pack(fill=tk.BOTH, expand=True)
        
        # Nagłówek
        header_frame = tk.Frame(main_frame, bg="#f0f0f0")
        header_frame.pack(fill=tk.X, pady=(0, 15))
        
        title_label = tk.Label(
            header_frame,
            text=f"Znaleziono {len(file_paths)} plików {category.upper()} dla rysunku: {drawing_no}",
            font=("Arial", 12, "bold"),
            bg="#f0f0f0",
            fg="#2c3e50"
        )
        title_label.pack()
        
        # Zbierz informacje o plikach
        file_info = []
        now = datetime.now()
        
        for fp in file_paths:
            mod_time = datetime.fromtimestamp(fp.stat().st_mtime)
            days_ago = (now - mod_time).days
            file_info.append({
                'path': fp,
                'mod_time': mod_time,
                'days_ago': days_ago
            })
        
        # Znajdź najnowszy plik
        newest_file = max(file_info, key=lambda x: x['mod_time'])
        
        # Scrollable frame dla listy plików
        list_frame = tk.Frame(main_frame, bg="white", relief=tk.SUNKEN, bd=2)
        list_frame.pack(fill=tk.BOTH, expand=True)
        
        canvas = tk.Canvas(list_frame, bg="white", highlightthickness=0)
        scrollbar = tk.Scrollbar(list_frame, orient="vertical", command=canvas.yview)
        scrollable_frame = tk.Frame(canvas, bg="white")
        
        scrollable_frame.bind(
            "<Configure>",
            lambda e: canvas.configure(scrollregion=canvas.bbox("all"))
        )
        
        canvas.create_window((0, 0), window=scrollable_frame, anchor="nw")
        canvas.configure(yscrollcommand=scrollbar.set)
        
        canvas.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        scrollbar.pack(side=tk.RIGHT, fill=tk.Y)
        
        # Obsługa scrollowania kółkiem myszy
        def on_mousewheel(event):
            canvas.yview_scroll(int(-1 * (event.delta / 120)), "units")
        
        # Bind mousewheel do canvas i wszystkich jego dzieci
        canvas.bind_all("<MouseWheel>", on_mousewheel)
        
        # Unbind gdy okno zostanie zamknięte
        dialog.bind("<Destroy>", lambda e: canvas.unbind_all("<MouseWheel>"))
        
        # Dodaj każdy plik jako element listy
        for idx, info in enumerate(file_info):
            fp = info['path']
            mod_time = info['mod_time']
            days_ago = info['days_ago']
            is_newest = (info == newest_file)
            
            # Frame dla elementu
            item_frame = tk.Frame(
                scrollable_frame,
                bg="#e8f5e9" if is_newest else "#ffffff",
                relief=tk.RAISED,
                bd=1
            )
            item_frame.pack(fill=tk.X, padx=5, pady=5)
            
            # Lewa strona - informacje o pliku
            info_frame = tk.Frame(item_frame, bg="#e8f5e9" if is_newest else "#ffffff")
            info_frame.pack(side=tk.LEFT, fill=tk.BOTH, expand=True, padx=10, pady=8)
            
            # Znacznik NAJNOWSZY
            if is_newest:
                newest_label = tk.Label(
                    info_frame,
                    text="🌟 NAJNOWSZY",
                    font=("Arial", 9, "bold"),
                    bg="#e8f5e9",
                    fg="#27ae60"
                )
                newest_label.pack(anchor=tk.W)
            
            # Pełna nazwa pliku
            filename_label = tk.Label(
                info_frame,
                text=fp.name,
                font=("Arial", 10, "bold"),
                bg="#e8f5e9" if is_newest else "#ffffff",
                fg="#2c3e50",
                anchor=tk.W,
                justify=tk.LEFT
            )
            filename_label.pack(anchor=tk.W, fill=tk.X)
            
            # Ścieżka pliku (małe litery, mniejsza czcionka)
            path_label = tk.Label(
                info_frame,
                text=str(fp).lower(),
                font=("Arial", 8),
                bg="#e8f5e9" if is_newest else "#ffffff",
                fg="#7f8c8d",
                anchor=tk.W,
                justify=tk.LEFT
            )
            path_label.pack(anchor=tk.W, fill=tk.X)
            
            # Data modyfikacji + ile dni temu (małe litery)
            date_str = mod_time.strftime("%Y-%m-%d %H:%M:%S")
            if days_ago == 0:
                days_str = "dzisiaj"
            elif days_ago == 1:
                days_str = "1 dzień temu"
            elif days_ago < 5:
                days_str = f"{days_ago} dni temu"
            else:
                days_str = f"{days_ago} dni temu"
            
            date_label = tk.Label(
                info_frame,
                text=f"{date_str} ({days_str})".lower(),
                font=("Arial", 8),
                bg="#e8f5e9" if is_newest else "#ffffff",
                fg="#7f8c8d",
                anchor=tk.W
            )
            date_label.pack(anchor=tk.W)
            
            # Prawa strona - przyciski
            btn_frame = tk.Frame(item_frame, bg="#e8f5e9" if is_newest else "#ffffff")
            btn_frame.pack(side=tk.RIGHT, padx=10, pady=5)
            
            # Przycisk Folder
            btn_folder = tk.Button(
                btn_frame,
                text="📁",
                bg="#3498db",
                fg="white",
                font=("Arial", 10, "bold"),
                padx=10,
                pady=5,
                relief=tk.RAISED,
                bd=2,
                cursor="hand2",
                command=lambda p=fp: self._open_file_folder(p, dialog)
            )
            btn_folder.pack(side=tk.LEFT, padx=2)
            
            # Przycisk Plik
            btn_file = tk.Button(
                btn_frame,
                text="📄",
                bg="#27ae60",
                fg="white",
                font=("Arial", 10, "bold"),
                padx=10,
                pady=5,
                relief=tk.RAISED,
                bd=2,
                cursor="hand2",
                command=lambda p=fp: self._open_file_directly(p, dialog)
            )
            btn_file.pack(side=tk.LEFT, padx=2)
        
        # Przycisk Anuluj na dole
        bottom_frame = tk.Frame(main_frame, bg="#f0f0f0")
        bottom_frame.pack(fill=tk.X, pady=(15, 0))
        
        btn_cancel = tk.Button(
            bottom_frame,
            text="✖ Zamknij",
            bg="#95a5a6",
            fg="white",
            font=("Arial", 11, "bold"),
            padx=30,
            pady=10,
            relief=tk.RAISED,
            bd=3,
            cursor="hand2",
            command=dialog.destroy
        )
        btn_cancel.pack()
        
        # Ustaw rozmiar okna w zależności od liczby plików
        height = min(600, 200 + len(file_paths) * 100)
        dialog.geometry(f"900x{height}")
        
        # Wycentruj
        dialog.update_idletasks()
        x = self.winfo_x() + (self.winfo_width() // 2) - 450
        y = self.winfo_y() + (self.winfo_height() // 2) - (height // 2)
        dialog.geometry(f"+{x}+{y}")
        
        # Escape zamyka dialog
        dialog.bind("<Escape>", lambda e: dialog.destroy())
        
        # Pokaż okno na wierzchu (już było wcześniej, ale dla pewności)
        dialog.lift()
        dialog.focus_force()
    
    def _open_file_folder(self, file_path: Path, dialog):
        """Otwórz folder zawierający plik"""
        try:
            import subprocess
            # Użyj Popen dla explorer - nie blokuje i nie sprawdza return code
            subprocess.Popen(f'explorer /select,"{str(file_path)}"')
            dialog.destroy()
        except Exception as e:
            messagebox.showerror(
                "Błąd",
                f"Nie można otworzyć folderu:\n{e}",
                parent=dialog
            )
    
    def _open_file_directly(self, file_path: Path, dialog):
        """Otwórz plik bezpośrednio"""
        try:
            import os
            os.startfile(str(file_path))
            dialog.destroy()
        except Exception as e:
            messagebox.showerror(
                "Błąd",
                f"Nie można otworzyć pliku:\n{e}",
                parent=dialog
            )
    
    def _show_file_open_dialog(self, file_path: Path, drawing_no: str, category: str):
        """Wyświetl okno dialogowe z opcjami otwarcia znalezionego pliku
        
        Args:
            file_path: Ścieżka do znalezionego pliku
            drawing_no: Numer rysunku
            category: Kategoria pliku (DWF, PDF, etc.)
        """
        dialog = tk.Toplevel(self)
        dialog.title("Otwórz")
        dialog.resizable(False, False)
        dialog.grab_set()
        
        # Frame główny
        main_frame = tk.Frame(dialog, bg="#f0f0f0", padx=20, pady=20)
        main_frame.pack(fill=tk.BOTH, expand=True)
        
        # Nagłówek
        tk.Label(
            main_frame,
            text=f"Znaleziono plik dla rysunku: {drawing_no}",
            font=("Arial", 12, "bold"),
            bg="#f0f0f0"
        ).pack(pady=(0, 15))
        
        # Informacja o pliku
        info_frame = tk.Frame(main_frame, bg="#ffffff", relief=tk.RIDGE, bd=2)
        info_frame.pack(fill=tk.BOTH, expand=True, pady=(0, 20))
        
        tk.Label(
            info_frame,
            text=f"📄 {file_path.name}",
            font=("Arial", 11, "bold"),
            bg="#ffffff",
            fg="#2c3e50",
            anchor="w"
        ).pack(fill=tk.X, padx=15, pady=(15, 5))
        
        tk.Label(
            info_frame,
            text=f"📁 {file_path.parent}",
            font=("Arial", 9),
            bg="#ffffff",
            fg="#7f8c8d",
            anchor="w",
            wraplength=550,
            justify=tk.LEFT
        ).pack(fill=tk.X, padx=15, pady=(0, 15))
        
        # Frame przycisków
        btn_frame = tk.Frame(main_frame, bg="#f0f0f0")
        btn_frame.pack(pady=(10, 0))
        
        def open_file():
            """Otwórz plik domyślną aplikacją (jak Enter)"""
            try:
                import subprocess
                import os
                
                if os.name == 'nt':  # Windows
                    os.startfile(str(file_path))
                else:  # Linux/Mac
                    subprocess.run(['xdg-open', str(file_path)])
                
                print(f"📂 Otwarty plik: {file_path}")
                dialog.destroy()
            except Exception as e:
                messagebox.showerror(
                    "Błąd",
                    f"Nie można otworzyć pliku:\n{e}",
                    parent=dialog
                )
        
        def open_folder():
            """Otwórz folder i podświetl plik"""
            try:
                import subprocess
                import os
                
                if os.name == 'nt':  # Windows
                    # Użyj Popen dla explorer - nie blokuje i nie sprawdza return code
                    subprocess.Popen(f'explorer /select,"{str(file_path)}"')
                else:  # Linux/Mac
                    # Otwórz folder (bez podświetlenia - nie wszystkie DE to wspierają)
                    subprocess.Popen(['xdg-open', str(file_path.parent)])
                
                print(f"📁 Otwarty folder: {file_path.parent}")
                dialog.destroy()
            except Exception as e:
                messagebox.showerror(
                    "Błąd",
                    f"Nie można otworzyć folderu:\n{e}",
                    parent=dialog
                )
        
        # Rozmiary przycisków (normalne i powiększone o 30%)
        normal_font_size = 11
        normal_padx = 30
        normal_pady = 10
        normal_bd = 3
        
        large_font_size = int(normal_font_size * 1.30)
        large_padx = int(normal_padx * 1.30)
        large_pady = int(normal_pady * 1.30)
        large_bd = int(normal_bd * 1.30)
        
        # Stan przycisków (który jest aktywny)
        current_focus = [2]  # Index: 0=Anuluj, 1=Folder, 2=Plik (domyślnie Plik)
        
        def resize_button(btn, is_focused):
            """Zmień rozmiar przycisku w zależności od focusa"""
            if is_focused:
                btn.config(
                    font=("Arial", large_font_size, "bold"),
                    padx=large_padx,
                    pady=large_pady,
                    bd=large_bd
                )
            else:
                btn.config(
                    font=("Arial", normal_font_size, "bold"),
                    padx=normal_padx,
                    pady=normal_pady,
                    bd=normal_bd
                )
        
        def set_focus_to_button(index):
            """Ustaw focus na przycisk o danym indeksie"""
            buttons = [btn_cancel, btn_folder, btn_file]
            
            # Zmniejsz wszystkie przyciski
            for i, btn in enumerate(buttons):
                resize_button(btn, False)
            
            # Powiększ wybrany przycisk
            resize_button(buttons[index], True)
            buttons[index].focus_set()
            current_focus[0] = index
        
        def navigate_left(event=None):
            """Strzałka w lewo - poprzedni przycisk"""
            new_index = (current_focus[0] - 1) % 3
            set_focus_to_button(new_index)
        
        def navigate_right(event=None):
            """Strzałka w prawo - następny przycisk"""
            new_index = (current_focus[0] + 1) % 3
            set_focus_to_button(new_index)
        
        # Przycisk Anuluj
        btn_cancel = tk.Button(
            btn_frame,
            text="✖ Anuluj",
            bg="#95a5a6",
            fg="white",
            font=("Arial", normal_font_size, "bold"),
            padx=normal_padx,
            pady=normal_pady,
            relief=tk.RAISED,
            bd=normal_bd,
            cursor="hand2"
        )
        btn_cancel.pack(side=tk.LEFT, padx=5)
        btn_cancel.bind("<Button-1>", lambda e: (set_focus_to_button(0), dialog.destroy()))
        
        # Przycisk Folder
        btn_folder = tk.Button(
            btn_frame,
            text="📁 Folder",
            bg="#3498db",
            fg="white",
            font=("Arial", normal_font_size, "bold"),
            padx=normal_padx,
            pady=normal_pady,
            relief=tk.RAISED,
            bd=normal_bd,
            cursor="hand2"
        )
        btn_folder.pack(side=tk.LEFT, padx=5)
        btn_folder.bind("<Button-1>", lambda e: (set_focus_to_button(1), open_folder()))
        
        # Przycisk Plik (domyślny focus - POWIĘKSZONY o 30%)
        btn_file = tk.Button(
            btn_frame,
            text="📄 Plik",
            bg="#27ae60",
            fg="white",
            font=("Arial", large_font_size, "bold"),
            padx=large_padx,
            pady=large_pady,
            relief=tk.RAISED,
            bd=large_bd,
            cursor="hand2"
        )
        btn_file.pack(side=tk.LEFT, padx=5)
        btn_file.focus_set()  # Domyślny focus
        btn_file.bind("<Button-1>", lambda e: (set_focus_to_button(2), open_file()))
        
        def execute_current_button(event=None):
            """Wykonaj akcję aktualnie wybranego przycisku"""
            if current_focus[0] == 0:
                dialog.destroy()
            elif current_focus[0] == 1:
                open_folder()
            elif current_focus[0] == 2:
                open_file()
        
        # Bind Enter do wykonania akcji aktualnego przycisku
        dialog.bind("<Return>", execute_current_button)
        dialog.bind("<Escape>", lambda e: dialog.destroy())
        
        # Bind strzałek do nawigacji
        dialog.bind("<Left>", navigate_left)
        dialog.bind("<Right>", navigate_right)
        
        # Wycentruj okno (po utworzeniu całej zawartości)
        dialog.update_idletasks()
        dialog_width = dialog.winfo_reqwidth()
        dialog_height = dialog.winfo_reqheight()
        x = self.winfo_x() + (self.winfo_width() // 2) - (dialog_width // 2)
        y = self.winfo_y() + (self.winfo_height() // 2) - (dialog_height // 2)
        dialog.geometry(f"{dialog_width}x{dialog_height}+{x}+{y}")
        
        # Pokaż okno na wierzchu
        dialog.lift()
        dialog.focus_force()
    
    def search_on_server(self):
        """Szukaj plików na serwerze (cały SERVER_DIR) - z wielowątkowością i progress barem"""
        category = self.file_category_var.get()
        
        # Pobierz zaznaczony wiersz
        try:
            sel = self.sheet.get_currently_selected()
            if not sel:
                messagebox.showwarning(
                    "Brak zaznaczenia",
                    "Zaznacz wiersz z numerem rysunku aby wyszukać plik."
                )
                return
            
            # Parsuj row
            row_idx = None
            if isinstance(sel, dict):
                row_idx = sel.get("row", sel.get("r"))
            elif isinstance(sel, (tuple, list)) and len(sel) >= 1:
                row_idx = sel[0]
            
            if row_idx is None or row_idx < 0:
                messagebox.showwarning(
                    "Błąd zaznaczenia",
                    "Nie można odczytać zaznaczonego wiersza."
                )
                return
            
            # Pobierz numer rysunku z zaznaczonego wiersza (kolumna 0)
            row_data = self.sheet.get_row_data(row_idx)
            if not row_data or len(row_data) == 0:
                messagebox.showwarning(
                    "Błąd danych",
                    "Nie można odczytać danych z zaznaczonego wiersza."
                )
                return
            
            drawing_no = str(row_data[0]).strip()  # Kolumna 0 = Numer rysunku
            
            if not drawing_no:
                messagebox.showwarning(
                    "Brak numeru rysunku",
                    "Zaznaczony wiersz nie ma numeru rysunku."
                )
                return
        
        except Exception as e:
            messagebox.showerror(
                "Błąd",
                f"Nie można odczytać zaznaczonego wiersza:\n{e}"
            )
            return
        
        print(f"\n🔍 WYSZUKIWANIE PLIKU NA SERWERZE")
        print(f"   Numer rysunku: {drawing_no}")
        print(f"   Typ pliku: {category}")
        print(f"   Serwer: {SERVER_DIR}")
        
        # Sprawdź czy ścieżka serwera istnieje
        server_path = Path(SERVER_DIR)
        if not server_path.exists():
            messagebox.showerror(
                "Błąd",
                f"Ścieżka serwera nie istnieje:\n{SERVER_DIR}\n\n"
                f"Skonfiguruj ścieżkę w:\nUstawienia → Konfiguracja ścieżek → Serwer projekty"
            )
            return
        
        # Uruchom skanowanie w osobnym wątku z progress barem
        self._search_on_server_with_progress(server_path, drawing_no, category)
    
    def _search_on_server_with_progress(self, server_path: Path, drawing_no: str, category: str):
        """Skanuj serwer z progress barem i wielowątkowością"""
        import threading
        from concurrent.futures import ThreadPoolExecutor, as_completed
        
        # Katalogi do wykluczenia
        excluded_dirs = {
            "OldVersions",
            "Design Data",
            "Importowane komponenty",
            "Templates",
            "$RECYCLE.BIN",
            "System Volume Information",
            "@Recycle",
            "@recycle",
            ".git",
            ".svn",
            "node_modules"
        }
        
        # Stwórz progress dialog
        progress_dialog = tk.Toplevel(self)
        progress_dialog.title("Skanowanie serwera")
        progress_dialog.geometry("500x150")
        progress_dialog.resizable(False, False)
        progress_dialog.grab_set()
        
        # Wycentruj
        progress_dialog.update_idletasks()
        x = self.winfo_x() + (self.winfo_width() // 2) - 250
        y = self.winfo_y() + (self.winfo_height() // 2) - 75
        progress_dialog.geometry(f"+{x}+{y}")
        
        # Frame
        frame = tk.Frame(progress_dialog, padx=20, pady=20)
        frame.pack(fill=tk.BOTH, expand=True)
        
        # Label - status
        status_label = tk.Label(
            frame,
            text="Przygotowywanie...",
            font=("Arial", 10)
        )
        status_label.pack(pady=(0, 10))
        
        # Progress bar
        progress_bar = ttk.Progressbar(
            frame,
            mode='determinate',
            length=460
        )
        progress_bar.pack(pady=(0, 10))
        
        # Label - szczegóły
        detail_label = tk.Label(
            frame,
            text="",
            font=("Arial", 8),
            fg="gray"
        )
        detail_label.pack()
        
        # Przycisk anuluj
        cancelled = [False]  # Flaga anulowania
        
        def cancel_scan():
            cancelled[0] = True
            if status_label.winfo_exists():
                status_label.config(text="Anulowanie...")
        
        # Obsługa zamknięcia okna krzyżykiem
        progress_dialog.protocol("WM_DELETE_WINDOW", cancel_scan)
        
        btn_cancel = tk.Button(
            frame,
            text="Anuluj",
            command=cancel_scan,
            bg="#e74c3c",
            fg="white",
            font=("Arial", 9, "bold"),
            padx=20,
            pady=5
        )
        btn_cancel.pack()
        
        # Wyniki
        found_files = []
        scan_error = [None]
        
        def scan_worker():
            """Wątek skanujący"""
            try:
                # Pobierz listę katalogów głównych do przeskanowania
                dirs_to_scan = []
                try:
                    for item in server_path.iterdir():
                        if item.is_dir() and item.name not in excluded_dirs:
                            dirs_to_scan.append(item)
                except Exception as e:
                    scan_error[0] = f"Nie można odczytać katalogu serwera:\n{e}"
                    return
                
                total_dirs = len(dirs_to_scan)
                
                if total_dirs == 0:
                    scan_error[0] = "Brak katalogów do przeskanowania na serwerze"
                    return
                
                print(f"\n📂 Znaleziono {total_dirs} katalogów głównych do przeskanowania")
                
                # Aktualizuj UI
                self.after(0, lambda: status_label.winfo_exists() and status_label.config(
                    text=f"Skanowanie {total_dirs} katalogów..."
                ))
                self.after(0, lambda: progress_bar.winfo_exists() and progress_bar.config(maximum=total_dirs))
                
                # Wielowątkowe skanowanie (4-8 wątków równolegle)
                with ThreadPoolExecutor(max_workers=6) as executor:
                    # Zakolejkuj wszystkie zadania
                    futures = {
                        executor.submit(
                            self._scan_directory_for_file,
                            dir_path,
                            drawing_no,
                            category,
                            excluded_dirs
                        ): dir_path
                        for dir_path in dirs_to_scan
                    }
                    
                    # Przetwarzaj wyniki w miarę ukończenia
                    completed = 0
                    for future in as_completed(futures):
                        if cancelled[0]:
                            # Anuluj pozostałe zadania
                            executor.shutdown(wait=False, cancel_futures=True)
                            break
                        
                        dir_path = futures[future]
                        completed += 1
                        
                        try:
                            files = future.result()
                            found_files.extend(files)
                            
                            # Aktualizuj progress bar (sprawdź czy okno istnieje)
                            if not cancelled[0] and progress_dialog.winfo_exists():
                                self.after(0, lambda c=completed: progress_bar.winfo_exists() and progress_bar.config(value=c))
                                self.after(0, lambda c=completed, t=total_dirs: 
                                    status_label.winfo_exists() and status_label.config(text=f"Przeskanowano {c}/{t} katalogów"))
                                self.after(0, lambda d=dir_path.name: 
                                    detail_label.winfo_exists() and detail_label.config(text=f"Ostatnio: {d}"))
                            
                            if files:
                                print(f"   ✓ {dir_path.name}: znaleziono {len(files)} plik(ów)")
                        
                        except Exception as e:
                            print(f"   ⚠️ Błąd w {dir_path.name}: {e}")
                
            except Exception as e:
                scan_error[0] = f"Błąd podczas skanowania:\n{e}"
                import traceback
                traceback.print_exc()
        
        # Uruchom skanowanie w osobnym wątku
        scan_thread = threading.Thread(target=scan_worker, daemon=True)
        scan_thread.start()
        
        # Czekaj na zakończenie skanowania
        def check_completion():
            if not progress_dialog.winfo_exists():
                # Okno zamknięte krzyżykiem - czekaj na wątek
                if not scan_thread.is_alive() and not cancelled[0]:
                    cancelled[0] = True
                return
            if scan_thread.is_alive():
                # Wątek nadal pracuje - sprawdź ponownie za 100ms
                progress_dialog.after(100, check_completion)
            else:
                # Skanowanie zakończone
                progress_dialog.destroy()
                
                # Sprawdź czy był błąd
                if scan_error[0]:
                    messagebox.showerror("Błąd", scan_error[0])
                    return
                
                # Sprawdź czy anulowano
                if cancelled[0]:
                    return
                
                # Wyświetl wyniki
                if found_files:
                    print(f"\n✅ ZNALEZIONO {len(found_files)} plik(ów):")
                    for f in found_files:
                        print(f"   📄 {f}")
                    
                    # Jeśli więcej niż 1 plik - pokaż listę wyboru
                    if len(found_files) > 1:
                        self._show_file_list_dialog(found_files, drawing_no, category)
                    else:
                        # Jeden plik - pokaż standardowy dialog
                        self._show_file_open_dialog(found_files[0], drawing_no, category)
                else:
                    print(f"\n❌ NIE ZNALEZIONO pliku {category.upper()} dla rysunku: {drawing_no}")
                    messagebox.showinfo(
                        "Nie znaleziono",
                        f"Nie znaleziono pliku {category.upper()} dla rysunku:\n{drawing_no}\n\n"
                        f"Przeszukano cały serwer: {server_path}"
                    )
        
        # Rozpocznij sprawdzanie zakończenia
        progress_dialog.after(100, check_completion)
    
    def search_in_library(self):
        """Szukaj plików w bibliotece (B:\\) - z wielowątkowością i progress barem"""
        category = self.file_category_var.get()
        
        # Ścieżka biblioteki (hardcoded)
        LIBRARY_PATH = "B:\\"
        
        # Pobierz zaznaczony wiersz
        try:
            sel = self.sheet.get_currently_selected()
            if not sel:
                messagebox.showwarning(
                    "Brak zaznaczenia",
                    "Zaznacz wiersz z numerem rysunku aby wyszukać plik."
                )
                return
            
            # Parsuj row
            row_idx = None
            if isinstance(sel, dict):
                row_idx = sel.get("row", sel.get("r"))
            elif isinstance(sel, (tuple, list)) and len(sel) >= 1:
                row_idx = sel[0]
            
            if row_idx is None or row_idx < 0:
                messagebox.showwarning(
                    "Błąd zaznaczenia",
                    "Nie można odczytać zaznaczonego wiersza."
                )
                return
            
            # Pobierz numer rysunku z zaznaczonego wiersza (kolumna 0)
            row_data = self.sheet.get_row_data(row_idx)
            if not row_data or len(row_data) == 0:
                messagebox.showwarning(
                    "Błąd danych",
                    "Nie można odczytać danych z zaznaczonego wiersza."
                )
                return
            
            drawing_no = str(row_data[0]).strip()  # Kolumna 0 = Numer rysunku
            
            if not drawing_no:
                messagebox.showwarning(
                    "Brak numeru rysunku",
                    "Zaznaczony wiersz nie ma numeru rysunku."
                )
                return
        
        except Exception as e:
            messagebox.showerror(
                "Błąd",
                f"Nie można odczytać zaznaczonego wiersza:\n{e}"
            )
            return
        
        print(f"\n🔍 WYSZUKIWANIE PLIKU W BIBLIOTECE")
        print(f"   Numer rysunku: {drawing_no}")
        print(f"   Typ pliku: {category}")
        print(f"   Biblioteka: {LIBRARY_PATH}")
        
        # Sprawdź czy ścieżka biblioteki istnieje
        library_path = Path(LIBRARY_PATH)
        if not library_path.exists():
            messagebox.showerror(
                "Błąd",
                f"Ścieżka biblioteki nie istnieje:\n{LIBRARY_PATH}\n\n"
                f"Sprawdź czy dysk B:\\ jest dostępny."
            )
            return
        
        # Uruchom skanowanie w osobnym wątku z progress barem
        self._search_in_library_with_progress(library_path, drawing_no, category)
    
    def _search_in_library_with_progress(self, library_path: Path, drawing_no: str, category: str):
        """Skanuj bibliotekę z progress barem i wielowątkowością"""
        import threading
        from concurrent.futures import ThreadPoolExecutor, as_completed
        
        # Katalogi do wykluczenia
        excluded_dirs = {
            "OldVersions",
            "Design Data",
            "Importowane komponenty",
            "Templates",
            "$RECYCLE.BIN",
            "System Volume Information",
            "@Recycle",
            "@recycle",
            ".git",
            ".svn",
            "node_modules"
        }
        
        # Stwórz progress dialog
        progress_dialog = tk.Toplevel(self)
        progress_dialog.title("Skanowanie biblioteki")
        progress_dialog.geometry("500x150")
        progress_dialog.resizable(False, False)
        progress_dialog.grab_set()
        
        # Wycentruj
        progress_dialog.update_idletasks()
        x = self.winfo_x() + (self.winfo_width() // 2) - 250
        y = self.winfo_y() + (self.winfo_height() // 2) - 75
        progress_dialog.geometry(f"+{x}+{y}")
        
        # Frame
        frame = tk.Frame(progress_dialog, padx=20, pady=20)
        frame.pack(fill=tk.BOTH, expand=True)
        
        # Label - status
        status_label = tk.Label(
            frame,
            text="Przygotowywanie...",
            font=("Arial", 10)
        )
        status_label.pack(pady=(0, 10))
        
        # Progress bar
        progress_bar = ttk.Progressbar(
            frame,
            mode='determinate',
            length=460
        )
        progress_bar.pack(pady=(0, 10))
        
        # Label - szczegóły
        detail_label = tk.Label(
            frame,
            text="",
            font=("Arial", 8),
            fg="gray"
        )
        detail_label.pack()
        
        # Przycisk anuluj
        cancelled = [False]  # Flaga anulowania
        
        def cancel_scan():
            cancelled[0] = True
            if status_label.winfo_exists():
                status_label.config(text="Anulowanie...")
        
        # Obsługa zamknięcia okna krzyżykiem
        progress_dialog.protocol("WM_DELETE_WINDOW", cancel_scan)
        
        btn_cancel = tk.Button(
            frame,
            text="Anuluj",
            command=cancel_scan,
            bg="#e74c3c",
            fg="white",
            font=("Arial", 9, "bold"),
            padx=20,
            pady=5
        )
        btn_cancel.pack()
        
        # Wyniki
        found_files = []
        scan_error = [None]
        
        def scan_worker():
            """Wątek skanujący"""
            try:
                # Pobierz listę katalogów głównych do przeskanowania
                dirs_to_scan = []
                try:
                    for item in library_path.iterdir():
                        if item.is_dir() and item.name not in excluded_dirs:
                            dirs_to_scan.append(item)
                except Exception as e:
                    scan_error[0] = f"Nie można odczytać katalogu biblioteki:\n{e}"
                    return
                
                total_dirs = len(dirs_to_scan)
                
                if total_dirs == 0:
                    scan_error[0] = "Brak katalogów do przeskanowania w bibliotece"
                    return
                
                print(f"\n📂 Znaleziono {total_dirs} katalogów głównych do przeskanowania")
                
                # Aktualizuj UI
                self.after(0, lambda: status_label.winfo_exists() and status_label.config(
                    text=f"Skanowanie {total_dirs} katalogów..."
                ))
                self.after(0, lambda: progress_bar.winfo_exists() and progress_bar.config(maximum=total_dirs))
                
                # Wielowątkowe skanowanie (4-8 wątków równolegle)
                with ThreadPoolExecutor(max_workers=6) as executor:
                    # Zakolejkuj wszystkie zadania
                    futures = {
                        executor.submit(
                            self._scan_directory_for_file,
                            dir_path,
                            drawing_no,
                            category,
                            excluded_dirs
                        ): dir_path
                        for dir_path in dirs_to_scan
                    }
                    
                    # Przetwarzaj wyniki w miarę ukończenia
                    completed = 0
                    for future in as_completed(futures):
                        if cancelled[0]:
                            # Anuluj pozostałe zadania
                            executor.shutdown(wait=False, cancel_futures=True)
                            break
                        
                        dir_path = futures[future]
                        completed += 1
                        
                        try:
                            files = future.result()
                            found_files.extend(files)
                            
                            # Aktualizuj progress bar (sprawdź czy okno istnieje)
                            if not cancelled[0] and progress_dialog.winfo_exists():
                                self.after(0, lambda c=completed: progress_bar.winfo_exists() and progress_bar.config(value=c))
                                self.after(0, lambda c=completed, t=total_dirs: 
                                    status_label.winfo_exists() and status_label.config(text=f"Przeskanowano {c}/{t} katalogów"))
                                self.after(0, lambda d=dir_path.name: 
                                    detail_label.winfo_exists() and detail_label.config(text=f"Ostatnio: {d}"))
                            
                            if files:
                                print(f"   ✓ {dir_path.name}: znaleziono {len(files)} plik(ów)")
                        
                        except Exception as e:
                            print(f"   ⚠️ Błąd w {dir_path.name}: {e}")
                
            except Exception as e:
                scan_error[0] = f"Błąd podczas skanowania:\n{e}"
                import traceback
                traceback.print_exc()
        
        # Uruchom skanowanie w osobnym wątku
        scan_thread = threading.Thread(target=scan_worker, daemon=True)
        scan_thread.start()
        
        # Czekaj na zakończenie skanowania
        def check_completion():
            if not progress_dialog.winfo_exists():
                # Okno zamknięte krzyżykiem - czekaj na wątek
                if not scan_thread.is_alive() and not cancelled[0]:
                    cancelled[0] = True
                return
            if scan_thread.is_alive():
                # Wątek nadal pracuje - sprawdź ponownie za 100ms
                progress_dialog.after(100, check_completion)
            else:
                # Skanowanie zakończone
                progress_dialog.destroy()
                
                # Sprawdź czy był błąd
                if scan_error[0]:
                    messagebox.showerror("Błąd", scan_error[0])
                    return
                
                # Sprawdź czy anulowano
                if cancelled[0]:
                    return
                
                # Wyświetl wyniki
                if found_files:
                    print(f"\n✅ ZNALEZIONO {len(found_files)} plik(ów):")
                    for f in found_files:
                        print(f"   📄 {f}")
                    
                    # Jeśli więcej niż 1 plik - pokaż listę wyboru
                    if len(found_files) > 1:
                        self._show_file_list_dialog(found_files, drawing_no, category)
                    else:
                        # Jeden plik - pokaż standardowy dialog
                        self._show_file_open_dialog(found_files[0], drawing_no, category)
                else:
                    print(f"\n❌ NIE ZNALEZIONO pliku {category.upper()} dla rysunku: {drawing_no}")
                    messagebox.showinfo(
                        "Nie znaleziono",
                        f"Nie znaleziono pliku {category.upper()} dla rysunku:\n{drawing_no}\n\n"
                        f"Przeszukano całą bibliotekę: {library_path}"
                    )
        
        # Rozpocznij sprawdzanie zakończenia
        progress_dialog.after(100, check_completion)


