class ChatWindow(tk.Toplevel):
    """Okno chatu - komunikacja między użytkownikami (JSON files)"""
    
    def __init__(self, parent, db_manager, username, user_id):
        super().__init__()  # Niezależne okno - BEZ parent!
        
        self.parent = parent
        self.db_manager = db_manager
        self.username = username
        self.user_id = user_id
        
        self.withdraw()  # Ukryj na czas budowania UI
        
        self.title("💬 Chat - RM_BAZA")
        self.configure(bg="#2c3e50")
        
        # Zapobiegnij wielokrotnemu otwieraniu
        self.protocol("WM_DELETE_WINDOW", self.on_close)
        
        self._refresh_after_id = None
        self._last_timestamp = None
        self._max_prefix_len = 0
        
        # Zmienna dla "Zawsze na wierzchu"
        self.always_on_top = tk.BooleanVar(value=False)
        
        # Utwórz folder chat
        if db_manager and db_manager.master_path:
            master_dir = Path(db_manager.master_path).parent
            self.chat_dir = master_dir / "chat"
        else:
            self.chat_dir = Path(CHAT_DIR)
        
        try:
            self.chat_dir.mkdir(parents=True, exist_ok=True)
        except Exception as e:
            messagebox.showerror("Błąd", f"Nie można utworzyć folderu chat:\n{e}")
            self.destroy()
            return
        
        # Buduj UI
        self.create_ui()
        
        # Oblicz pozycję
        chat_width = 600
        chat_height = 500
        try:
            # Zaktualizuj geometrię okna parent przed odczytem (ważne dla wielu monitorów)
            parent.update_idletasks()
            # Użyj rootx/rooty dla absolutnych współrzędnych ekranowych
            parent_x = parent.winfo_rootx()
            parent_y = parent.winfo_rooty()
            parent_width = parent.winfo_width()
            parent_height = parent.winfo_height()
        except:
            parent_x, parent_y, parent_width, parent_height = 100, 100, 800, 600
        
        margin = 20
        bottom_margin = 80  # Większy margines dolny aby nie zasłaniać belki z klawiszami
        chat_x = parent_x + parent_width - chat_width - margin
        chat_y = parent_y + parent_height - chat_height - bottom_margin
        self.geometry(f"{chat_width}x{chat_height}+{chat_x}+{chat_y}")
        
        # Pokaż okno
        self.deiconify()
        # NIE ustawiaj '-topmost' na start - użytkownik może to włączyć checkboxem
        
        # Ciężkie operacje po chwili
        self.after(50, self._deferred_init)
    
    def _deferred_init(self):
        """Operacje które nie muszą blokować pokazania okna"""
        try:
            self.cleanup_old_messages()
            self.load_messages()
            self.schedule_refresh()
        except Exception as e:
            print(f"⚠️  _deferred_init error: {e}")
        
        # Zaktualizuj _last_chat_timestamp w parent po załadowaniu wiadomości
        try:
            if self._last_timestamp and self.parent:
                self.parent._last_chat_timestamp = self._last_timestamp
        except:
            pass
        
        # Focus na pole tekstowe - użytkownik kliknął CHAT
        try:
            self.focus_force()
            self.input_text.focus_set()
        except:
            pass
        
        # Bindy do zamykania okna powiadomienia przy interakcji z chatem
        self.bind("<FocusIn>", self.on_chat_interaction)
        self.bind("<Button-1>", self.on_chat_interaction)
    
    def create_ui(self):
        """Stwórz UI chatu"""
        # Header
        header = tk.Frame(self, bg="#34495e", height=50)
        header.pack(fill=tk.X, side=tk.TOP)
        
        tk.Label(
            header,
            text="💬 Chat",
            bg="#34495e",
            fg="white",
            font=("Arial", 14, "bold")
        ).pack(side=tk.LEFT, padx=10, pady=10)
        
        # Checkbox "Zawsze na wierzchu" (po środku)
        tk.Checkbutton(
            header,
            text="📌 Zawsze na wierzchu",
            variable=self.always_on_top,
            command=self.toggle_always_on_top,
            bg="#34495e",
            fg="white",
            selectcolor="#2c3e50",
            activebackground="#34495e",
            activeforeground="white",
            font=("Arial", 9)
        ).pack(side=tk.LEFT, padx=20, pady=10)
        
        tk.Label(
            header,
            text=f"Zalogowany: {self.username}",
            bg="#34495e",
            fg="#ecf0f1",
            font=("Arial", 10)
        ).pack(side=tk.RIGHT, padx=10, pady=10)
        
        # Ramka wiadomości
        msg_frame = tk.Frame(self, bg="#2c3e50")
        msg_frame.pack(fill=tk.BOTH, expand=True, padx=10, pady=10)
        
        # Canvas ze scrollbarem dla wiadomości
        canvas = tk.Canvas(msg_frame, bg="#ecf0f1", highlightthickness=0)
        scrollbar = tk.Scrollbar(msg_frame, orient="vertical", command=canvas.yview)
        self.messages_container = tk.Frame(canvas, bg="#ecf0f1")
        
        # Konfiguruj canvas
        canvas.configure(yscrollcommand=scrollbar.set)
        scrollbar.pack(side=tk.RIGHT, fill=tk.Y)
        canvas.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        
        # Utwórz okno w canvas dla frame
        canvas_window = canvas.create_window((0, 0), window=self.messages_container, anchor="nw")
        
        # Bind do aktualizacji scroll region
        def on_frame_configure(event):
            canvas.configure(scrollregion=canvas.bbox("all"))
        
        def on_canvas_configure(event):
            # Dostosuj szerokość frame do szerokości canvas
            canvas.itemconfig(canvas_window, width=event.width)
        
        self.messages_container.bind("<Configure>", on_frame_configure)
        canvas.bind("<Configure>", on_canvas_configure)
        
        # Bind scroll z myszką
        def on_mousewheel(event):
            canvas.yview_scroll(int(-1*(event.delta/120)), "units")
        
        # Funkcja do bindowania scroll rekurencyjnie do wszystkich dzieci
        def bind_to_mousewheel(widget):
            widget.bind("<MouseWheel>", on_mousewheel)
            for child in widget.winfo_children():
                bind_to_mousewheel(child)
        
        # Bind do canvas i rekurencyjnie do wszystkich dzieci messages_container
        canvas.bind("<MouseWheel>", on_mousewheel)
        bind_to_mousewheel(self.messages_container)
        
        # Zapisz funkcję żeby można było bindować nowe widgety
        self._bind_mousewheel = bind_to_mousewheel
        
        self.canvas = canvas
        self.message_widgets = []  # Lista widgetów wiadomości
        
        # Ramka input (mniejszy padding niż msg_frame)
        input_frame = tk.Frame(self, bg="#34495e")
        input_frame.pack(fill=tk.X, side=tk.BOTTOM, padx=10, pady=(0, 10))
        
        # NAJPIERW przycisk Wyślij (po prawej stronie) - stała szerokość
        send_btn = tk.Button(
            input_frame,
            text="📤\nWyślij",
            command=self.send_message,
            bg="#3498db",
            fg="white",
            font=("Arial", 9, "bold"),
            width=8,
            height=2
        )
        send_btn.pack(side=tk.RIGHT, padx=(5, 5))
        
        # POTEM pole tekstowe (wypełnia resztę)
        self.input_text = tk.Text(
            input_frame,
            bg="white",
            fg="#2c3e50",
            font=("Arial", 10),
            height=1,  # Zaczyna od 1 linii
            wrap=tk.WORD
        )
        self.input_text.pack(fill=tk.BOTH, expand=True, side=tk.LEFT, padx=(5, 0))
        
        # Zmienna do śledzenia ostatniej wysokości (zapobiega migotaniu)
        self._last_input_height = 1
        
        # Bind Enter do wysyłania (Shift+Enter = nowa linia)
        self.input_text.bind("<Return>", self.on_enter_pressed)
        
        # Bind do dynamicznego rozszerzania wysokości
        # <<Modified>> - wywoływany za każdym razem gdy zawartość się zmienia
        self.input_text.bind("<<Modified>>", self.on_text_modified)
        
        # Zmienna dla Modified event (resetuje flagę)
        self._text_modified = False
    
    def on_text_modified(self, event=None):
        """Obsługa zdarzenia modyfikacji tekstu"""
        try:
            # Resetuj flagę modified (inaczej event będzie wywoływany ciągle)
            if self.input_text.edit_modified():
                self.input_text.edit_modified(False)
                # Zaktualizuj wysokość
                self.adjust_input_height()
        except:
            pass
    
    def adjust_input_height(self, event=None):
        """Dostosuj wysokość pola input do zawartości (dynamicznie)"""
        try:
            # Użyj after_idle aby wykonać po zakończeniu renderowania
            self.input_text.after_idle(self._update_input_height)
        except:
            pass
    
    def _update_input_height(self):
        """Wykonaj aktualizację wysokości"""
        try:
            # Pobierz całą treść
            content = self.input_text.get("1.0", "end-1c")
            
            # Jeśli puste - 1 linia
            if not content or content == '':
                num_lines = 1
            else:
                # Licz wszystkie \n w treści
                num_lines = content.count('\n') + 1
            
            # Logowanie dla debugowania (możesz usunąć potem)
            # print(f"DEBUG: content length={len(content)}, newlines={content.count(chr(10))}, num_lines={num_lines}")
            
            # Ogranicz wysokość: min 1, max 8 linii
            new_height = max(1, min(num_lines, 8))
            
            # Ustaw nową wysokość tylko jeśli się zmieniła (zapobiega migotaniu)
            if self._last_input_height != new_height:
                self._last_input_height = new_height
                self.input_text.config(height=new_height)
        except Exception as e:
            # print(f"DEBUG ERROR: {e}")
            pass
    
    def on_enter_pressed(self, event):
        """Obsługa Enter - wyślij wiadomość"""
        # Shift+Enter = nowa linia (domyślne zachowanie)
        if event.state & 0x1:  # Shift
            # Pozwól na dodanie nowej linii, <<Modified>> event zaktualizuje wysokość
            return
        
        # Enter bez Shift = wyślij
        self.send_message()
        return "break"  # Zapobiegnij dodaniu nowej linii
    
    def load_messages(self):
        """Załaduj wiadomości z plików JSON"""
        try:
            # Sprawdź połączenie z dyskiem sieciowym przed załadowaniem wiadomości
            if not self.parent._safe_ensure_master_alive():
                # Brak połączenia - banner już pokazany, zamknij okno chatu
                self.destroy()
                return
            
            # Pobierz wszystkie pliki JSON z folderu chat
            json_files = list(self.chat_dir.glob("*.json"))
            
            # Parsuj wiadomości
            messages = []
            for file_path in json_files:
                try:
                    with open(file_path, 'r', encoding='utf-8') as f:
                        msg = json.load(f)
                        messages.append(msg)
                except Exception as e:
                    print(f"⚠️  Błąd odczytu {file_path.name}: {e}")
                    continue
            
            # Sortuj po timestamp
            messages.sort(key=lambda x: x.get('timestamp', ''))
            
            # Weź ostatnie 200
            messages = messages[-200:]
            
            # Wyczyść container wiadomości
            for widget in self.message_widgets:
                widget.destroy()
            self.message_widgets.clear()
            
            # Wyświetl wiadomości
            for idx, msg in enumerate(messages):
                self.display_message(
                    msg.get('username', '?'),
                    msg.get('display_name'),
                    msg.get('message', ''),
                    msg.get('timestamp', ''),
                    message_index=idx
                )
                # Zapamiętaj ostatni timestamp
                if msg.get('timestamp'):
                    self._last_timestamp = msg['timestamp']
            
            # Dodaj padding na dole aby ostatnia wiadomość była w pełni widoczna
            padding_frame = tk.Frame(self.messages_container, bg="#ecf0f1", height=20)
            padding_frame.pack(fill=tk.X)
            self.message_widgets.append(padding_frame)
            
            # Bind scroll do padding_frame
            if hasattr(self, '_bind_mousewheel'):
                self._bind_mousewheel(padding_frame)
            
            # Aktualizuj scroll region
            self.messages_container.update_idletasks()
            self.canvas.configure(scrollregion=self.canvas.bbox("all"))
            
            # Przewiń na dół (przy pierwszym załadowaniu zawsze pokazuj najnowsze)
            try:
                self.canvas.update_idletasks()
                self.canvas.yview_moveto(1.0)
            except:
                pass
            
        except Exception as e:
            print(f"⚠️  Błąd ładowania wiadomości: {e}")
            import traceback
            traceback.print_exc()
    
    def display_message(self, username, display_name, message, timestamp, message_index=0):
        """Wyświetl pojedynczą wiadomość w dwóch kolumnach"""
        from datetime import datetime
        
        # Parsuj timestamp
        try:
            dt = datetime.fromisoformat(timestamp)
            time_str = dt.strftime("%H:%M:%S")
        except:
            time_str = timestamp[:8] if len(timestamp) >= 8 else timestamp
        
        name_to_display = display_name or username
        is_my_message = (username == self.username)
        
        # Wybierz kolor tła (przemienne kolory)
        bg_color = "#fff3cd" if message_index % 2 == 0 else "#ffcccc"
        
        # Stwórz ramkę dla wiadomości używając Grid dla lepszej kontroli
        msg_frame = tk.Frame(self.messages_container, bg=bg_color, relief=tk.FLAT, bd=0)
        msg_frame.pack(fill=tk.X, padx=2, pady=1)
        
        # Konfiguruj kolumny grid
        msg_frame.grid_columnconfigure(0, minsize=160, weight=0)  # Lewa kolumna - stała
        msg_frame.grid_columnconfigure(1, minsize=2, weight=0)    # Separator
        msg_frame.grid_columnconfigure(2, weight=1)                # Prawa kolumna - rozciągliwa
        
        # Kolumna 1: Timestamp + Username
        left_container = tk.Frame(msg_frame, bg=bg_color)
        left_container.grid(row=0, column=0, sticky="nsew", padx=5, pady=5)
        
        # Timestamp - czarny
        timestamp_label = tk.Label(
            left_container,
            text=f"[{time_str}]",
            bg=bg_color,
            fg="#000000",
            font=("Arial", 10),
            anchor="w"
        )
        timestamp_label.pack(side=tk.LEFT)
        
        # Spacja
        tk.Label(left_container, text=" ", bg=bg_color, font=("Arial", 10)).pack(side=tk.LEFT)
        
        # Username - ciemnoniebieski pogrubiony
        username_label = tk.Label(
            left_container,
            text=name_to_display,
            bg=bg_color,
            fg="#003366",  # Ciemnoniebieski
            font=("Arial", 10, "bold"),
            anchor="w"
        )
        username_label.pack(side=tk.LEFT)
        
        # Pionowa linia oddzielająca
        separator_vertical = tk.Frame(msg_frame, bg="#000000", width=2)
        separator_vertical.grid(row=0, column=1, sticky="ns")
        
        # Kolumna 2: Message - użyj Text widget aby można było zaznaczać i kopiować
        message_text = tk.Text(
            msg_frame,
            bg=bg_color,
            fg="#000000",
            font=("Arial", 10),
            wrap=tk.WORD,
            width=50,
            height=1,
            relief=tk.FLAT,
            borderwidth=0,
            highlightthickness=0,
            cursor="xterm"  # Kursor tekstowy
        )
        message_text.grid(row=0, column=2, sticky="nsew", padx=5, pady=5)
        
        # Wstaw tekst
        message_text.insert(1.0, message)
        
        # Policz dokładną liczbę linii z Text widget (po zawijaniu)
        # index('end-1c') zwraca 'linia.znak' ostatniego znaku
        line_count = int(message_text.index('end-1c').split('.')[0])
        message_text.config(height=line_count)
        
        # Ustaw jako tylko do odczytu (ale z możliwością zaznaczania)
        message_text.config(state="disabled")
        
        # Dodaj separator poziomy (linia oddzielająca wiadomości)
        separator = tk.Frame(self.messages_container, bg="#cccccc", height=1)
        separator.pack(fill=tk.X)
        
        # Zapamiętaj widget
        self.message_widgets.append(msg_frame)
        self.message_widgets.append(separator)
        
        # Bind scroll do nowych widgetów (rekurencyjnie)
        if hasattr(self, '_bind_mousewheel'):
            self._bind_mousewheel(msg_frame)
            self._bind_mousewheel(separator)
    
    def send_message(self):
        """Wyślij wiadomość (zapisz jako JSON)"""
        try:
            # Sprawdź połączenie z dyskiem sieciowym przed wysłaniem wiadomości
            if not self.parent._safe_ensure_master_alive():
                # Brak połączenia - banner już pokazany, nie wysyłaj wiadomości
                messagebox.showwarning(
                    "Brak połączenia",
                    "Nie można wysłać wiadomości - utracono połączenie z dyskiem sieciowym."
                )
                return
            
            # Pobierz tekst
            message = self.input_text.get(1.0, tk.END).strip()
            
            if not message:
                return
            
            if len(message) > 2000:
                messagebox.showwarning("Za długa", "Wiadomość może mieć max 2000 znaków")
                return
            
            # Pobierz display_name z bazy users
            display_name = self.username
            try:
                if self.db_manager and self.db_manager.master_con:
                    cursor = self.db_manager.master_con.execute(
                        "SELECT display_name FROM users WHERE id = ?", (self.user_id,)
                    )
                    row = cursor.fetchone()
                    if row and row[0]:
                        display_name = row[0]
            except:
                pass
            
            # Utwórz strukturę wiadomości
            from datetime import datetime
            import time
            
            timestamp = datetime.now().isoformat()
            unix_time = int(time.time() * 1000000)  # Mikro-sekundy dla unikalności
            
            msg_data = {
                'timestamp': timestamp,
                'username': self.username,
                'display_name': display_name,
                'message': message
            }
            
            # Nazwa pliku: YYYY-MM-DD_HH-MM-SS_username_unixtime.json
            dt = datetime.now()
            safe_username = re.sub(r'[^a-zA-Z0-9_-]', '_', self.username)
            filename = f"{dt.strftime('%Y-%m-%d_%H-%M-%S')}_{safe_username}_{unix_time}.json"
            file_path = self.chat_dir / filename
            
            # Zapisz do pliku
            with open(file_path, 'w', encoding='utf-8') as f:
                json.dump(msg_data, f, ensure_ascii=False, indent=2)
            
            print(f"💬 Wysłano: {filename}")
            
            # Wyczyść input
            self.input_text.delete(1.0, tk.END)
            
            # Zresetuj wysokość do 1 linii
            self._last_input_height = 1
            self.input_text.config(height=1)
            
            # Zresetuj flagę modified
            self.input_text.edit_modified(False)
            
            # Odśwież wiadomości (dodaj tylko nową)
            self.refresh_messages()
            
        except Exception as e:
            messagebox.showerror("Błąd", f"Nie udało się wysłać wiadomości:\n{e}")
            import traceback
            traceback.print_exc()
    
    def refresh_messages(self):
        """Odśwież wiadomości (dodaj tylko nowe)"""
        try:
            # Sprawdź połączenie z dyskiem sieciowym przed odświeżeniem wiadomości
            if not self.parent._safe_ensure_master_alive():
                # Brak połączenia - banner już pokazany, nie odświeżaj
                return
            
            # Pobierz wszystkie pliki JSON
            json_files = list(self.chat_dir.glob("*.json"))
            
            # Parsuj tylko nowe wiadomości (timestamp > _last_timestamp)
            new_messages = []
            for file_path in json_files:
                try:
                    with open(file_path, 'r', encoding='utf-8') as f:
                        msg = json.load(f)
                        # Sprawdź czy nowa
                        if not self._last_timestamp or msg.get('timestamp', '') > self._last_timestamp:
                            new_messages.append(msg)
                except Exception as e:
                    continue
            
            # Jeśli są nowe wiadomości - dodaj je (bez przeładowywania całości!)
            if new_messages:
                # Usuń padding frame jeśli istnieje (ostatni element listy)
                if self.message_widgets and len(self.message_widgets) > 0:
                    last_widget = self.message_widgets[-1]
                    # Sprawdź czy to padding frame (wysokość 20)
                    try:
                        if isinstance(last_widget, tk.Frame) and last_widget.cget('height') == 20:
                            last_widget.destroy()
                            self.message_widgets.pop()
                    except:
                        pass
                
                # Sortuj nowe wiadomości po timestamp
                new_messages.sort(key=lambda x: x.get('timestamp', ''))
                
                # Policz aktualne wiadomości (każda wiadomość = msg_frame + separator)
                current_msg_count = len(self.message_widgets) // 2
                
                # Dodaj nowe wiadomości
                for msg in new_messages:
                    self.display_message(
                        msg.get('username', '?'),
                        msg.get('display_name'),
                        msg.get('message', ''),
                        msg.get('timestamp', ''),
                        message_index=current_msg_count
                    )
                    current_msg_count += 1
                    # Zapamiętaj ostatni timestamp
                    if msg.get('timestamp'):
                        self._last_timestamp = msg['timestamp']
                
                # Dodaj z powrotem padding frame na końcu
                padding_frame = tk.Frame(self.messages_container, bg="#ecf0f1", height=20)
                padding_frame.pack(fill=tk.X)
                self.message_widgets.append(padding_frame)
                
                # Bind scroll do padding_frame
                if hasattr(self, '_bind_mousewheel'):
                    self._bind_mousewheel(padding_frame)
                
                # Aktualizuj scroll region
                self.messages_container.update_idletasks()
                self.canvas.configure(scrollregion=self.canvas.bbox("all"))
                
                # Przewiń na dół przy nowej wiadomości
                try:
                    self.canvas.update_idletasks()
                    self.canvas.yview_moveto(1.0)
                except:
                    pass
                
        except Exception as e:
            # Błąd odświeżania - nie przeszkadzaj użytkownikowi
            pass
    
    def cleanup_old_messages(self):
        """Usuń najstarsze pliki, zachowaj tylko 200 najnowszych"""
        try:
            # Pobierz wszystkie pliki JSON
            json_files = list(self.chat_dir.glob("*.json"))
            
            # Jeśli mniej niż 200 - nic nie rób
            if len(json_files) <= 200:
                return
            
            # Sortuj po dacie modyfikacji (najstarsze najpierw)
            json_files.sort(key=lambda f: f.stat().st_mtime)
            
            # Ile trzeba usunąć
            to_delete = len(json_files) - 200
            
            # Usuń najstarsze
            deleted_count = 0
            for file_path in json_files[:to_delete]:
                try:
                    file_path.unlink()
                    deleted_count += 1
                except Exception as e:
                    print(f"⚠️  Błąd usuwania {file_path.name}: {e}")
                    continue
            
            if deleted_count > 0:
                print(f"🗑️  Usunięto {deleted_count} najstarszych wiadomości (limit: 200)")
                
        except Exception as e:
            print(f"⚠️  Błąd cleanup wiadomości: {e}")
    
    def toggle_always_on_top(self):
        """Przełącz opcję 'Zawsze na wierzchu'"""
        is_topmost = self.always_on_top.get()
        self.attributes('-topmost', is_topmost)
        print(f"💬 Chat - Zawsze na wierzchu: {'TAK' if is_topmost else 'NIE'}")
    
    def on_chat_interaction(self, event=None):
        """Zamknij okno powiadomienia przy interakcji z chatem i oznacz jako przeczytane"""
        try:
            if self.parent and hasattr(self.parent, '_notification_window'):
                if self.parent._notification_window and self.parent._notification_window.winfo_exists():
                    self.parent._notification_window.destroy()
                    self.parent._notification_window = None
            # Oznacz wiadomości jako przeczytane przy interakcji z chatem
            if self.parent:
                self.parent._has_unread_messages = False
                # Zaktualizuj timestamp żeby te same wiadomości nie triggerowały ponownie
                if self._last_timestamp:
                    self.parent._last_chat_timestamp = self._last_timestamp
                self.parent.update_tray_icon()
        except:
            pass
    
    def schedule_refresh(self):
        """Zaplanuj auto-refresh co 5 sekund"""
        if self._refresh_after_id:
            self.after_cancel(self._refresh_after_id)
        
        self.refresh_messages()
        self._refresh_after_id = self.after(5000, self.schedule_refresh)
    
    def get_last_timestamp(self):
        """Zwróć timestamp ostatniej wiadomości"""
        return self._last_timestamp
    
    def on_close(self):
        """Zamknij okno"""
        if self._refresh_after_id:
            self.after_cancel(self._refresh_after_id)
        
        self.parent.chat_window = None
        self.destroy()


